window.BEAUBIRD_BIRD_PROFILE_SHARDS["shard-038.json"] = [{"name":"巴士拉苇莺","english_name":"Basra Reed Warbler","scientific_name":"Acrocephalus griseldis","overview":"巴士拉苇莺（英文名：Basra Reed Warbler，学名：Acrocephalus griseldis），是雀形目苇莺科苇莺属的小型鸟类。其冷灰橄榄色的羽毛和白色的下体是其显著特征。该鸟种分布于伊拉克南部及相邻的伊朗西南部，主要栖息于幼发拉底河和底格里斯河沿岸的广阔芦苇丛中。全球数量稀少，据估计仅存约2500至10000只。","appearance":"巴士拉苇莺体长约17-18厘米，体重介于12-29克之间，体型中等偏瘦，具有一根长而细的喙，翼较长，尾较短。头部上方有一条显眼的白色眉纹延伸至眼后，上体颜色均匀，呈现冷色调的橄榄褐色，羽翼颜色较深，尾巴比其余羽毛更暗。喉咙纯白，下体呈白色，侧腹有时带有奶油黄色调，胸部可能有轻微的斑纹。虹膜深色，喙上部深棕色，下部主要为粉色，舌黄色，腿色浅灰至铅灰色。雌雄外观相似，幼鸟色彩更鲜艳，上体温暖色系，下体更深，略带肉桂色。","call":"叫声为尖锐的'charr'声，比苇莺的叫声更深沉。鸣唱较为安静缓慢，混合着低沉的画眉鸟般的音符。","habits":"巴士拉苇莺在繁殖季节选择生长茂密的芦苇（Phragmites）、香蒲（Typha）等水生植被作为栖息地。非繁殖期间，它们会在非洲东部的湿润灌木丛、水边高草和沟渠旁的莎草丛中活动。这是一种候鸟，冬季迁徙至东非，包括索马里南部到莫桑比克中部，以及马拉维。","breeding":"关于巴士拉苇莺的繁殖信息有限，推测其繁殖行为与大苇莺相似。2007年，在以色列北部发现了其繁殖记录。","identification":"与大苇莺相比，巴士拉苇莺体型较小，下体更白，喙更细长且尖锐。腿色为灰色而非褐色。","protection":"IUCN：EN（濒危）","distribution":"繁殖于伊拉克南部（幼发拉底河和底格里斯河流域）和伊朗西南部（沙德甘湿地）。非繁殖季节分布于东非，从索马里南部南至莫桑比克和马拉维。近年来，该物种在科威特（贾赫拉湿地）和以色列（胡拉谷）也有繁殖记录。","other":"由于美索不达米亚湿地在上世纪80年代和90年代的排水工程，巴士拉苇莺的本土栖息地遭受了严重破坏，导致其数量急剧下降。"},{"name":"佛得角苇莺","english_name":"Cape Verde Warbler","scientific_name":"Acrocephalus brevipennis","overview":"佛得角苇莺（英文名：Cape Verde Warbler，学名：Acrocephalus brevipennis），是雀形目苇莺科苇莺属的鸟类。体型中等，长喙，短翼，长尾，特有于佛得角群岛。上体呈灰褐色，下体较浅，喉部和腹部泛黄。繁殖主要在芦苇丛中，但也适应了糖蔗和咖啡种植园。","appearance":"体长约13.5厘米，体重15至17克。长喙，尾长，具灰色眼眉，上体灰褐，头部最淡，背部橄榄色，臀部赤褐色，翅膀边缘橄榄至灰褐色，尾巴棕色，下体灰白，颏、喉及腹部在新羽时泛黄色，两胁浅棕色，覆尾羽肉桂色，虹膜深褐色，上喙角质色，下喙主要橙黄色，腿蓝灰色。雌雄相似，幼鸟上体比成鸟更偏红棕色，下体更黄，两胁棕色较浅。","call":"鸣唱独特，液泡状，带标志性颤音，无尖锐音符，类似'weet weet wee del-weedel rikikikikiki-weet'。叫声为喉咙发出的'kerr-chow'或'grug'。","habits":"栖息于低地至海拔500米处，偶尔更高，尤其偏好巨芦苇丛、糖蔗和香蕉种植园，亦见于乡村和小镇花园。活动于小树冠层，以昆虫为主食，有时食用无花果果实。","breeding":"繁殖期可能有两个主时段，春季（2月至3月）和夏季雨后（6月至11月）。巢为深锥形，由干草、玉米叶条或香蕉树皮纤维构成，内衬细草，高悬于水面上或地面以上0.6至5米，位于芦苇或糖蔗间，或灌木丛中。","identification":"长喙和长尾是辨识要点，上体灰褐色，下体泛黄，区别于其他苇莺属物种。","protection":"IUCN：VU（易危）","distribution":"分布于佛得角群岛的圣尼古劳岛、圣蒂亚戈岛、福戈岛，曾存在于布拉瓦岛，现已灭绝。","other":"全球估计数量约1500至2000只成熟个体，受干旱和人口增长威胁，种群数量下降。"},{"name":"大沼泽苇莺","english_name":"Greater Swamp Warbler","scientific_name":"Acrocephalus rufescens","overview":"大沼泽苇莺（英文名：Greater Swamp Warbler，学名：Acrocephalus rufescens），是雀形目苇莺科苇莺属的鸟类。广泛分布在非洲西部和中部，包括安哥拉、博茨瓦纳、布隆迪等国。其自然生境主要为湿地中的芦苇丛。","appearance":"大沼泽苇莺是一种大型、不起眼、长尾长喙的湿地鸣禽。其主要栖息在纸莎草沼泽中，偶尔也会出现在其他类型的芦苇丛和湿润灌木丛中。与较小型的细嘴苇莺相比，大沼泽苇莺体型更大，喙更长，缺乏淡色的眼纹。同时，它与大苇莺相似，但翼展较短，颜色更深，呈灰暗色调，同样没有眼纹。","call":"大沼泽苇莺频繁地鸣唱，其歌声缓慢低沉，由粗糙的音符和更为悦耳的音符混合组成，最后以颤音结束。","habits":"这种鸟类相当害羞且隐秘，偏好栖息在湿地区域，如沼泽和芦苇丛。它们的栖息地通常位于较低纬度，海拔不高，部分个体有迁徙习性。","identification":"大沼泽苇莺与细嘴苇莺和大苇莺的区别在于其更大的体型、较长的喙，以及没有淡色眼纹的特征。","protection":"IUCN：LC（无危）","distribution":"大沼泽苇莺在非洲西部和中部广泛分布，具体国家包括安哥拉、博茨瓦纳、布隆迪、喀麦隆、中非共和国、乍得、刚果共和国、刚果民主共和国、赤道几内亚、加蓬、加纳、肯尼亚、马里、毛里塔尼亚、纳米比亚、尼日利亚、卢旺达、塞内加尔、南苏丹、坦桑尼亚、多哥、乌干达、赞比亚和津巴布韦。"},{"name":"细嘴苇莺","english_name":"Lesser Swamp Warbler","scientific_name":"Acrocephalus gracilirostris","overview":"细嘴苇莺（英文名：Lesser Swamp Warbler，学名：Acrocephalus gracilirostris），是雀形目苇莺科苇莺属的鸟类。小型的、不显眼的苇莺，拥有长尾巴和长喙，主要栖息于湿地环境中的芦苇丛，包括纸莎草沼泽。细嘴苇莺的背部颜色从橄榄褐色到锈褐色不等，腹部纯白至淡褐色。相比大苇莺更小，比非洲苇莺更大，翼展比大苇莺短。在非洲东部、南部地区常见。","appearance":"体长17-18厘米，雄鸟平均重16.1克，雌鸟平均重14.2克。细嘴苇莺体型较大且健壮，具长喙、圆翅和强壮的腿脚。指名亚种为白色眉纹、灰褐色颊部和耳羽，眼后有一稍深色线；头顶及上体呈暖褐色，臀部颜色最浓，头部和颈背颜色较暗、偏灰色；飞羽和大型上翼覆羽深棕色，边缘呈黄褐色，较小覆羽暖棕色；尾羽深棕色，边缘黄褐色；下巴和喉部白色，向下渐变为淡黄褐色至上胸，再渐变为深黄褐色，侧腹和大腿更深的肉桂黄褐色，尾下覆羽较浅黄褐色；下体在磨损羽毛时更白；腋窝和下翼覆羽黄白色；虹膜深棕色；喙黑色角质，下颚基部黄色；腿深绿色或蓝灰色角质。两性相似。幼鸟的上体比成鸟更温暖，更赤褐色。不同亚种在大小和色调上有所差异。","call":"其歌声通常从水面以上1-2米处发出，由丰富的旋律短语组成，例如“klieru, klikliu-klikliu-klikliu-klee, kliew-klikliklikli”，类似鸫鸟的歌声，但不如大多数同类持续。叫声包括响亮的“kierok”，低沉的“chuck”和喋喋不休的“chuk-uk-uk-k-k”。","habits":"细嘴苇莺栖息于湖泊、河口、河流、水坝、沼泽和湖泊的芦苇丛、香蒲和纸莎草等湿地环境中。海拔高度可达1500米，局部地区在埃塞俄比亚和肯尼亚可达2400米。物种全年留居在非洲东部、南部的湿地。","breeding":"繁殖期在肯尼亚和坦桑尼亚为3月至12月，在马拉维为1月至8月，在赞比亚为2月，在津巴布韦为8月至5月，在博茨瓦纳为8月、11月和2月，在南非为8月至2月，主要在雨季繁殖。可能是单配偶制。领域性明显。巢穴为深锥形杯状，由干草叶、干芦苇条和水生植物构成，内部衬以细草条和细草，有时含有少量羽毛，建在水面上方的垂直茎上，或在密集植被或灌木中，通常位于0.2-1.8米的高度。一窝产卵2-3枚，极少4枚，在南非平均2.3枚；双亲共同孵卵；关于孵化期和雏鸟期的持续时间信息不明。","identification":"与大苇莺相比更小，与非洲苇莺相比更大，翼展比大苇莺短。不同亚种在大小和颜色上有细微差别，如冬季底部的亚种比指名亚种片更灰，侧面和尾下覆羽无黄褐色；cunenensis亚种比指名亚种片略小，上方更橄榄褐色，下方更淡，白色延伸至腹部和侧面。","protection":"IUCN：LC（无危）","distribution":"非洲东部和南部，包括刚果民主共和国、乍得和埃塞俄比亚至南非。在刚果民主共和国、乍得、埃塞俄比亚、南苏丹、莱索托、乍得西部、埃塞俄比亚西北部的塔纳湖等地分布。"},{"name":"马岛沼泽苇莺","english_name":"Madagascar Swamp Warbler","scientific_name":"Acrocephalus newtoni","overview":"马岛沼泽苇莺（英文名：Madagascar Swamp Warbler，学名：Acrocephalus newtoni），是雀形目苇莺科苇莺属的鸟类。马达加斯加特有种。体型中等，尾部较长，毛色灰褐色，胸腹部有明显的条纹，眉线淡色。主要栖息于沼泽地带，也会出现在红树林、山地灌木丛和湿润灌丛中。","appearance":"马岛沼泽苇莺长约18厘米，体重介于14.5至20.5克之间。拥有细长的身形、长喙、相对较大的脚和强壮的腿，尾羽呈阶梯状，翅膀较短且圆。上体颜色从暗灰色到深棕色不等，下体呈灰白色，两胁和腹部带有淡黄色至浅棕灰色，喉部和胸部有棕色条纹。眼睛深红棕色，上喙黑色，下喙粉灰色带黑尖，腿深灰色。雌雄相似，幼鸟与成鸟类似，但下方较无条纹，裸露部分颜色更深。","call":"其歌声清脆响亮，由一系列高低起伏、富有旋律感的音符组成，穿插着低沉的喉音。叫声为尖锐的“chak”声，有时会连续发出。","habits":"偏好各种淡水生境，尤其在流速缓慢或静止的水域，如孤立的沼泽和死水沼泽，常见于香蒲和芦苇丛，也见于莎草。在极少数情况下，出现在干燥的山顶部的密集矮小灌木林中。海拔高度从海平面至约2100米。","identification":"与刷莺相似，但具有更明显胸部条纹和白色眉线，且通常栖息于沼泽而非干燥灌丛或森林。","protection":"IUCN：LC（无危）","distribution":"分布仅限于非洲的马达加斯加岛。"},{"name":"塞岛苇莺","english_name":"Seychelles Warbler","scientific_name":"Acrocephalus sechellensis","appearance":"塞舌尔苇莺体长约14厘米，体重介于15至16.8克之间。其拥有中等长度且略粗壮的喙和长长的尾巴。头部上方有一条白色眉纹，眼线暗淡模糊，眼圈颜色变化不一；冠部和背部呈暗黄色橄榄绿，臀部较浅，翼羽较深呈褐色；尾羽深色，尖端白色；腹部下方呈淡黄色，胸部可能有轻微的条纹；虹膜红棕色；喙角质色，基部粉红色，上喙边缘深色；腿灰蓝色。雌雄相似，幼鸟眼睛灰蓝或灰棕色。","call":"塞舌尔苇莺的鸣唱活泼欢快，是一连串快速的音乐般的颤音，呈现起伏的模式。此外，还会发出粗糙的叫声。","habits":"塞舌尔苇莺栖息于浓密的灌木林和高大的Pisonia grandis森林中。它们几乎完全以昆虫为食，99.8%的食物来自小昆虫，其中98%是在树叶下觅得。偶尔也会在空中捕捉昆虫。主要在Pisonia、Ficus reflexa和Morinda citrifolia中觅食。它们偏好在Morinda中觅食，因为那里昆虫密度最高。","breeding":"塞舌尔苇莺展现出合作繁殖的特性，成年雄鸟和雌鸟助手协助亲鸟喂养幼鸟。在高质量的领地上，雌鸟更倾向于成为助手而非迁移到低质量领地繁殖。在资源丰富的领地上，雌鸟倾向于产双卵，而非单卵，且卵倾向于产生雌鸟后代。这表明塞舌尔苇莺可能有预卵前控制后代性别的能力。","identification":"塞舌尔苇莺与塞舌尔绣眼鸟相似，但体型更大，尾巴更长，下部颜色更淡，没有醒目的白色眼圈。与其他同属物种相比，其具有独特的鸣唱和行为习性。","protection":"IUCN：NT（近危）","distribution":"历史上分布更为广泛，但在1960年代被限制在Cousin岛上。通过重新引入计划，现已分布于Aride、Cousine、Denis和Frégate等岛屿。最近的人口估计显示，Cousin岛上约有320只，Cousine岛上约有210只，Aride岛上约有1850只，Denis岛上约有600只，Frégate岛上约有200只。","other":"过去几十年间，由于人类干扰和栖息地破坏，塞舌尔苇莺曾濒临灭绝，仅剩26只生存于Cousin岛上。通过保护措施，包括栖息地管理和重新引入计划，其种群数量已显著增加。"},{"name":"罗岛苇莺","english_name":"Rodrigues Warbler","scientific_name":"Acrocephalus rodericanus","appearance":"罗德里格斯苇莺体长约13.5厘米，体重11至13克，具有相对较长的喙和腿，尾羽长而呈阶梯状，翅膀短小。头部有黄色眉纹，短而深色的眼纹；头顶和背部均匀橄榄棕色，脸颊较淡，眼周淡黄；腹部在新羽毛时呈淡柠檬黄色，旧羽毛时变为灰白色，略带黄色调；眼睛深色，喙大多为粉黄色，基部暗色；腿灰色，足底黄色。雌雄外观相似。幼鸟描述未详。","call":"其鸣唱柔和而旋律优美，由一系列快速上扬下降的音符组成。叫声包括‘chek’音和尖锐的斥责声。","habits":"罗德里格斯苇莺栖息于由非本土树木和灌木主导的密集灌丛和林地，如玫瑰苹果树（Eugenia jambos）、桃花心木（Swietenia mahogoni）、金钟花（Tabebuia pallida）和诺福克岛松（Araucaria cunninghamii）种植园中。它们以昆虫为主食，包括同翅目昆虫和鳞翅目成虫及幼虫，觅食时在树冠层和亚树冠层中觅食，常摇摆尾巴。","breeding":"繁殖季节为9月底至3月，可能每季产两窝。以对的形式繁殖，偶尔可能有合作繁殖现象。领地性明显。巢穴为小型杯状，内部深，用少量羽毛铺垫，外部结构可能相当高，给人倒置锥形的印象，但通常巢穴矮胖，底部平坦；巢位高度0.5至9米，支撑于树的细枝叉间，如草莓番石榴（Psidium cattleianum）、玫瑰苹果树或金钟花。通常产2至3枚卵，双亲共同孵化，孵化期未知；雏鸟期约14天。","identification":"罗德里格斯苇莺在罗德里格斯岛上没有其他类似物种，因此识别较为简单。其独特的橄榄色外观和特定的鸣唱模式帮助区分。","protection":"IUCN：NT（近危）；CITES III级。该物种受到老鼠（Rattus）和野猫捕食巢穴、外来物种竞争、人类干扰、栖息地破坏和退化、持续干旱和飓风影响的威胁。自1982年以来，数量和分布范围稳步增加，2012年估计数量约为4000只。","distribution":"罗德里格斯苇莺仅分布于印度洋中的罗德里格斯岛（Rodrigues），属于东马斯卡林群岛（e Mascarenes）的一部分。","other":"在1960年代被认为濒临灭绝，1970年代重新发现后，数量有所回升。"},{"name":"大苇莺","english_name":"Great Reed Warbler","scientific_name":"Acrocephalus arundinaceus","overview":"大苇莺（英文名：Great Reed Warbler，学名：Acrocephalus arundinaceus），是雀形目苇莺科苇莺属的鸟类。别名: 苇串儿、芦稿鸟、剖苇。体型较大，是欧洲最大的苇莺之一，分布于欧洲至中亚的广阔地带，中国境内仅新疆有其踪迹。被列入国家林业局2000年《国家保护的有益的或者有重要经济、科学研究价值的陆生野生动物名录》。","appearance":"体长约19-20厘米，体重约22-31克，具有厚重的喙和圆形的尾羽。头部比例较大，喙部强健，具有一条宽而模糊的浅色眉纹，从喙后延伸至耳羽顶部的一半左右。上体橄榄褐色，腰部和尾上覆羽呈红褐色，下体主要为奶油色，两胁带有暖色调的斑纹，喉部和腹部呈白色，有时喉部有淡淡的灰色条纹。幼鸟色泽比成鸟鲜艳，上体红褐色，下体偏黄。","call":"鸣声独特，短促而响亮，重复的'karra-karra-karra gurk gurk gurk chirrr-chirrr karra karra'，叫声为尖锐的'krrrrr'。","habits":"繁殖期间栖息于湿地的芦苇丛中，尤其偏好高大的芦苇和靠近水面的位置。冬季迁徙至非洲热带地区的芦苇地、沼泽植被、灌木丛和稻田等地。以昆虫为主食，也摄食蜘蛛、蜗牛和小型脊椎动物。","breeding":"繁殖期从5月中旬至7月，每窝产卵3-6枚，多数为5枚，由雌鸟孵卵，孵化期约13-15天。双亲共同喂养雏鸟，巢期11-15天。雏鸟离巢后12-14天独立。","identification":"与东方大苇莺相比，体型更大，喙部更粗壮，眉纹更宽，色彩更深。鸣叫声亦有显著差异。","protection":"IUCN：LC（无危）","distribution":"繁殖于欧洲至中亚，中国新疆有分布。冬季迁徙至非洲热带地区。","other":"近年来，其在东欧的分布有所增加，但在西欧部分地区数量减少。"},{"name":"东方大苇莺","english_name":"Oriental Reed Warbler","scientific_name":"Acrocephalus orientalis","overview":"东方大苇莺（英文名：Oriental Reed Warbler，学名：Acrocephalus orientalis），是雀形目苇莺科苇莺属的鸟类。包括中国北方、蒙古、俄罗斯东南部、韩国和日本等地。该鸟拥有暖褐色的羽毛，腹部略淡，具有独特的白色眉纹和短小的羽冠，常在芦苇丛中活动。","appearance":"体长17-19厘米，体重18-47克，平均约25.5克。上体橄榄棕色，下体稍淡，喉部和腹部白色，两胁带有温暖的黄褐色，腹下部呈现淡黄色。翅膀边缘和上翼覆羽有更暖色调，幼鸟的下体有时带轻微黄色调。眼睛周围有暗色眼线，虹膜灰暗至深棕色，喙上部暗棕色，下部粉肉色，脚铅灰色。雌雄相似，幼鸟与成鸟类似，但有细微差异。","call":"发出响亮、粗糙的‘kiruk kiruk kiruk, jee jee jee’的叫声，与大苇莺的鸣唱类似。","habits":"栖息于湖泊旁的芦苇床、沿海湿地、河口、河流和沟渠边的高草丛和灌木丛中。适应稻田环境，利用分散的芦苇床筑巢，接近居住区的小片芦苇丛也是它们的栖息地。活动于低地，最高可达1000米。迁徙期间，主要在东南亚至苏门答腊、婆罗洲和菲律宾过冬。","breeding":"繁殖季节为5月至7月，一般一夫一妻制，部分雄鸟会吸引2-4个雌鸟。巢为深圆柱形杯状，由编织的草茎、各种茎和芦苇花组成，通常位于水面以上80-260厘米，附着于2-6根垂直的芦苇茎上。每窝产3-6枚蛋，平均孵化期12-14天，雏鸟由双亲喂养，离巢期10-15天。繁殖成功率在36.3%-72%，平均每个巢可产生2.6只离巢幼鸟。","identification":"与噪大苇莺相比，东方大苇莺嘴较钝、短且粗，尾较短且尾端色浅，下体颜色更深且胸具深色纵纹；与大苇莺相比，体型较小，初级飞羽的凸出较短，胸侧多纵纹。","protection":"IUCN：LC（无危）","distribution":"繁殖于蒙古中部、俄罗斯东南部南部至中国北部、东部、朝鲜半岛和日本；冬季迁徙至东南亚、菲律宾和印尼群岛。","other":"在一些地区，如中国长江口的岛屿，高达39%的巢穴因蟹类的捕食而损失。"},{"name":"噪大苇莺","english_name":"Clamorous Reed Warbler","scientific_name":"Acrocephalus stentoreus","overview":"噪大苇莺（英文名：Clamorous Reed Warbler，学名：Acrocephalus stentoreus），是雀形目苇莺科苇莺属的鸟类。分布区域广阔，从埃及向东延伸至巴基斯坦、阿富汗、印度北部，直至中国南部和东南亚地区。此鸟体型较大，长约19厘米，具有橄榄褐色的背部和白色的腹部。不同亚种的羽毛色调有所差异，北方亚种上体颜色最深，斯里兰卡亚种则最为暗沉。","appearance":"噪大苇莺体长18至20厘米，体重介于23至34克之间，拥有显著的眉纹，上体呈橄榄褐色，腰、尾及尾上覆羽带棕色调，下体色淡，近白色，两胁及尾下覆羽呈浅黄褐色。喙强健且尖锐，眼睛深色，上颚角质色，下颚粉红带角质尖，腿色从深灰至绿角质不等。雌雄相似，幼鸟比成鸟色彩更鲜明，部分亚种存在独特的深色型态。","call":"其鸣声非常响亮，结合了刺耳的摩擦音和清脆的音符，典型重复的旋律为“karra-karra-kareet-kareet-kareet”或“prit-prit-pritik”，比大苇莺的鸣声更高亢、更尖细，经常模仿其他鸟类的声音。叫声包括响亮的“chack”和低沉的“churr”。","habits":"栖息于各种湿地环境，包括淡水沼泽、湖岸、红树林，甚至农田。在迁徙期间也会出现在干燥地区，如金合欢灌木丛、柽柳林、甘蔗田和其他农地。主要以昆虫为食，包括蜻蜓、蜉蝣、石蛾、蚱蜢、螳螂、半翅目昆虫、鳞翅目成虫和幼虫、毛翅目、双翅目、膜翅目、鞘翅目等，偶尔食用软体动物、幼蛙和水生植物种子。通常在芦苇或灌木低处觅食，有时在水面或漂浮植被上捕食，亦会在靠近水源的地面跳跃寻食。","breeding":"繁殖季节在不同地区有所不同，如埃及为3月至6月，以色列为4月至7月底，塔吉克斯坦为5月中旬至8月，印度次大陆为3月至8月。单配偶制，部分多配偶制。巢由雌鸟主要建造，位于水面上方10至200厘米的芦苇或其他水生植被中，呈深而坚固的圆柱形杯状，外部直径9.3至13.2厘米，高度8.4至23厘米，内部直径4.8至6.6厘米，杯深5至7厘米。每窝产卵3至6枚，仅雌鸟孵化，孵化期13至15天，雏鸟由双亲共同照料和喂食，离巢期11至13天。","identification":"与大苇莺相比，噪大苇莺的腰、尾及尾上覆羽较多棕色，下体色淡，体型较大，嘴较细尖而强悍，喉部无深色纵纹，尾较大且尾端无浅色。与东方大苇莺的区别在于体型更大，嘴更细尖，喉部无条纹，尾更大。","protection":"IUCN：LC（无危）","distribution":"广泛分布于亚洲，包括中央亚洲、南亚、东南亚以及中东部分地区。中央亚洲种群更倾向于迁徙，北方繁殖种群冬季迁至印度次大陆。东南亚和中东种群主要为留鸟，零星分布于中东，延伸至东北非洲。","other":"不同亚种在羽毛色调上有细微差异，某些亚种展现出独特的暗色形态。"},{"name":"澳洲苇莺","english_name":"Australian Reed Warbler","scientific_name":"Acrocephalus australis","overview":"澳洲苇莺（英文名：Australian Reed Warbler，学名：Acrocephalus australis），是雀形目苇莺科苇莺属的鸟类。小型旧世界苇莺科鸟类，仅分布于澳大利亚，偶尔在巴布亚新几内亚和邻近岛屿可见。具有平顶状的冠羽，故名Acrocephalus，意为“顶上之头”。种名australis源于拉丁文，意为“南方的”，指其分布于澳大利亚。在当地原住民语言中，西部地区称之为\"Koordjikotji\"。","appearance":"体长约15-16厘米，为中等体型的Acrocephalus苇莺，翼短、尾长、喙细长。整体呈褐色，无条纹，外观不显眼。成鸟头部至背部淡褐色，腹部淡色，喉部和腹中部更白，侧胸和胁部呈肉桂色。虹膜深色，喙棕色，下颚较浅，腿黑褐色。两性相似。幼鸟比成鸟更深的褐色。","call":"鸣声丰富、持久而悦耳，带有多种变化，包括急促的\"twitchy-twitchy-twitchy-quarty-quarty-quarty\"。叫声为干燥的责备式颤音或卷舌音，边界争端时发出，频率不高。","habits":"栖息于淡水湿地的芦苇丛、湖边、泉水、溪流、水坝、排水沟、污水池和粘土洼地；也见于灌溉作物和Pandanus。繁殖季节主要在芦苇（Phragmites）和灯心草（Typha）丛中筑巢。北方种群大多留居，而南方种群冬季向北迁徙。","breeding":"部分迁徙。北部种群留居，南部种群冬季至少部分向北迁移。繁殖季为9月至2月，每年产两窝。巢置于水面、泥地或干地上方30-200厘米处，由芦苇叶、草、芦苇花序、纤维、腐烂水生植物、植物绒毛、灯心草穗、羽毛和线构成。","identification":"与噪大苇莺相比，体型明显较小，颜色较深，色调更丰富。与迁徙性的东方大苇莺相比，翅膀更短，尾巴更长，喙更粗。根据范围，不太可能与其他Acrocephalus苇莺混淆。","protection":"IUCN：LC（无危）；局部数量丰富，繁殖密度极高。易受烧毁、清除和排水导致的栖息地破坏威胁，但得益于澳大利亚农业景观中广泛分布的小型灌溉和牲畜池塘的创造。","distribution":"分布于澳大利亚东部和南部，包括塔斯马尼亚和南澳大利亚，向北迁徙。在西南澳大利亚，4月消失，8月返回，但在珀斯周围全年存在。新几内亚、俾斯麦群岛东部和所罗门群岛也有记录。","other":"已知有两个亚种。"},{"name":"夏威夷苇莺","english_name":"Millerbird","scientific_name":"Acrocephalus familiaris","overview":"夏威夷苇莺（英文名：Millerbird，学名：Acrocephalus familiaris），是雀形目苇莺科苇莺属的特有鸟类，仅分布在夏威夷群岛的Nihoa和Laysan两岛，为旧世界莺类中唯一成功殖民至夏威夷的种类。现存的Nihoa亚种为岛上特有种，而已灭绝的Laysan亚种曾独占Laysan岛。夏威夷苇莺体小、色泽暗淡，以活跃的昆虫捕食习性著称。","appearance":"夏威夷苇莺体型小巧，约13厘米长，上体呈深橄榄色到橄榄棕色，羽缘灰白；翼和尾羽暗褐色；下体白色，侧腹略带灰橄榄色，两胁呈黄褐色。喙细长，黑色；跗跖和趾黑色灰色。雄雌相似，但雌鸟略小。与Laysan亚种相比，Nihoa亚种体型稍大，颜色更深，喉部、胸部和腹部更偏灰黄色，耳区颜色更深。","call":"其鸣唱和叫声表现为刺耳的啾啾声和连续的颤音。","habits":"偏好密集低矮的植被，通常隐蔽难以观察，但在繁殖季节，雄鸟会从显眼的栖木上鸣唱。栖息地为太平洋夏威夷群岛的特定岛屿，食物主要为昆虫，具有一定的领地意识。","breeding":"形成长期的配偶关系，保卫领地数年，繁殖期因食物丰度而异，通常从一月至九月。","identification":"与Laysan亚种相比，Nihoa亚种体型较大，颜色更深，嘴和跗跖较长。与其他岛上物种，如尼岛拟管舌雀相比，夏威夷苇莺体色较为暗淡，没有明显标记。","protection":"IUCN：EN（濒危）","distribution":"分布于夏威夷群岛的Nihoa岛和曾经的Laysan岛，后者现已灭绝。目前仅在Nihoa岛有野生种群。","other":"由于栖息地的脆弱性和有限的研究访问，夏威夷苇莺的自然历史信息有限。"},{"name":"歌鸲苇莺","english_name":"Nightingale Reed Warbler","scientific_name":"Acrocephalus luscinius","overview":"歌鸲苇莺（英文名：Nightingale Reed Warbler，学名：Acrocephalus luscinius），是雀形目苇莺科苇莺属的已灭绝鸟类。又称Guam reed-warbler。原生于关岛，具有非常长的喙和头部蓬乱的羽毛，雄鸟的平均体重为35.9克，雌鸟平均32克。其分布受限于太平洋西部的马里亚纳群岛。","appearance":"这种相对较大的苇莺拥有约18厘米的身长，喙长而尖锐，头部羽毛常显得凌乱。指名亚种为luscinius的亚种有黄色眉纹，黑色眼线；头顶和上部呈锈褐色，主翼羽和次级飞羽边缘狭窄呈淡黄色，尾羽尖端亦如此；下部浅黄色至乳白色，两胁呈黄褐色至淡黄色；虹膜深色；上喙灰色带黄色边缘，下喙肉粉色带黄色边缘；腿灰蓝。雌雄羽毛相似，雄鸟略大。幼鸟描述未详。nijoi亚种喙较短，上部颜色更少锈红，两胁和腹部颜色更深，更偏褐色。","call":"其歌声响亮、旋律优美，音调多样复杂，由哨声、颤音和颤鸣组成，长时间持续，有时连续数分钟不断；常在夜间歌唱；雄鸟在黎明时合唱，日间唱歌频率降低。叫声为响亮的“chuck”或“tchack”。","habits":"歌鸲苇莺栖息于象草与Leucaena交织的环境，以及红树Bruguiera gymnorrhiza沼泽、Phragmites karka芦苇丛、Hibiscus灌木丛；也见于台风造成的森林空隙地带，草地植被和灌木丛，以及树木林丛。它全年居住于此，主要以昆虫、蜥蜴、蜘蛛和蜗牛为食，主要在地面觅食，从叶片（包括活叶和死叶）上获取无脊椎动物，探查枯枝。","breeding":"繁殖高峰期在一月至三月和七月至九月。一夫一妻制。巢由雌鸟建造，为较深的杯状，分为两种类型：一种紧密编织紧凑，另一种较大且外层材料厚重；主要由干藤茎、干草叶、干树皮条、蛛网、叶柄和小枝构成，外径8.3-12.7厘米，高5.7-17.7厘米，内径4.6-8.6厘米，杯深2.9-5.8厘米；通常建在树（主要是引入的Leucaena）上，高度2.3-10米。每七个领地平均面积为9338平方米，是领地的十倍。每次产卵2-4枚（平均2.5枚）；关于孵化和育雏期的信息未知。成年雄鸟年存活率至少为82%。","identification":"歌鸲苇莺与其他苇莺属物种的区别在于其较长的喙，头部蓬乱的羽毛，以及独特的鸣叫声。不同亚种之间主要在喙长、上部颜色和下部颜色上有细微差别。","protection":"IUCN：EX（绝灭）。歌鸲苇莺是关岛特有的物种，目前估计总数量约为3700只，全部属于指名亚种luscinius：2010年Alamagan岛有946只，2007年Saipan岛有2742只。指名亚种在关岛已灭绝，最后记录为1969年的一只个体。yamashinae亚种在1981年前于Pagan I岛灭绝。nijoi亚种几乎确定已在Aguijan岛灭绝，自1995年后未再观察到。现存种群正在迅速减少：自1982年以来的三十年中减少了59%，且下降速度正在加快。主要原因包括农业、住宅建设、旅游设施导致的栖息地丧失，以及入侵物种如棕色树蛇、巨蜥、野猫和鼠的捕食，农药使用和大火。","distribution":"歌鸲苇莺原生地为关岛（马里亚纳群岛南部，密克罗尼西亚西部）。目前仅存于Alamagan和Saipan岛。","other":"歌鸲苇莺曾被认为包含帕岛苇莺、马里亚纳苇莺和塞班苇莺作为其亚种，但在2011年被国际鸟类联盟（IOC）认定为独立物种。"},{"name":"塞班苇莺","english_name":"Saipan Reed Warbler","scientific_name":"Acrocephalus hiwae","overview":"塞班苇莺（英文名：Saipan Reed Warbler，学名：Acrocephalus hiwae），是雀形目苇莺科苇莺属的鸣禽。体型相对较大，呈灰橄榄褐色，腹部淡黄色，以塞班岛和Alamagan岛为栖息地。其长喙是所有Acrocephalus属中最长的比例之一。","appearance":"成鸟体长18至19厘米，体重27至38克。具有非常长的喙，头部羽毛在歌唱时显得蓬乱，翅膀短而圆，初级飞羽短小。成年个体拥有从喙基到耳羽后方的黄或浅奶油色眉纹，黑色眼纹，锈棕色的冠羽和背部，下体颜色由淡黄色至奶油色，两胁和尾下覆羽呈棕黄色至淡奶油棕色。雄鸟和雌鸟在羽毛上相似，但雄鸟的翼、尾和跗跖测量值略大。幼鸟外观与成鸟相似，但缺乏明显的眉纹，全身羽毛呈褐色，胸至尾下覆羽呈奶油色至淡黄色。","call":"其鸣唱为缓慢、响亮、旋律优美的口哨声、颤音、尖锐的“chak”音和颤音组合，持续约4至8秒，频率范围1至5千赫兹，之后是类似时长的停顿，然后转换为另一个略有不同的乐句。常在夜间鸣唱。","habits":"栖息于高大的象草、剑草和tangan-tangan树林，以及红树林、芦苇沼泽、海边木槿、紫檀和铁木灌丛。活动于地面，以昆虫、小型蜥蜴、蜘蛛和蜗牛为主食，主要在叶片上寻找无脊椎动物。","breeding":"可能全年繁殖，高峰在一月至三月和七月至九月。巢由雌鸟几乎独力建造，偶尔有雄鸟协助。巢为两种类型：紧密编织的深杯状或较大的紧密编织型，主要由干藤茎、干草叶、干树皮条、蜘蛛网、叶柄和枝条构成。每窝产2至4枚白色至奶油色或象牙色的椭圆形蛋，带有灰色、棕色、黑色和锈色斑点。幼鸟孵化时裸身，皮肤暗灰色至黑色，14天左右离巢。","identification":"与歌鸲苇莺相比，塞班苇莺的喙更长，上体颜色更深，且分布区域局限于北马里亚纳群岛。","protection":"IUCN：EN（濒危）。面临农业、住宅建设和旅游设施导致的栖息地丧失，以及外来物种的捕食威胁。","distribution":"分布于北马里亚纳群岛的Alamagan岛和塞班岛，具体为美属北马里亚纳群岛的这两个岛屿。","other":"塞班苇莺的种群数量自二战后有所扩张，部分归功于战后引入的Leucaena leucocephala，但近年来因人类活动和入侵物种的影响而下降。"},{"name":"马里亚纳苇莺","english_name":"Aguiguan Reed Warbler","scientific_name":"Acrocephalus nijoi","overview":"马里亚纳苇莺（英文名：Aguiguan Reed Warbler，学名：Acrocephalus nijoi），是雀形目苇莺科苇莺属的鸟类。仅发现于太平洋美属北马里亚纳群岛的Aguigan岛。","appearance":"关于马里亚纳苇莺的具体外形特征描述资料有限，通常这类苇莺具有细长的喙和尾巴，身体长度一般在10到20厘米之间，颜色以橄榄绿为主，腹部偏白，两翼和尾巴呈暗褐色。","habits":"生活在Aguigan岛上的苇丛中，具体的生活习性和饮食偏好不详，但苇莺通常以昆虫和其他小型无脊椎动物为食。","breeding":"繁殖习性的细节未知，但苇莺类通常会在春季至夏季间繁殖，雌雄共同筑巢，巢通常建在隐蔽的植被中。","identification":"与其他苇莺种类相比，马里亚纳苇莺可能在体型、羽色上有细微差别，但由于记录稀少，具体辨识特征不详。","protection":"IUCN：EX（绝灭）。自1995年后，马里亚纳苇莺再未被目击，尽管进行了广泛的搜索，显示其可能已灭绝或极度濒危。","distribution":"仅限于太平洋的美属北马里亚纳群岛中的Aguigan岛，该岛位于密克罗尼西亚西部。","other":"马里亚纳苇莺被认为是夜莺苇莺的一个亚种，但自1995年以来未有目击报告，其生存状况令人担忧。"},{"name":"帕岛苇莺","english_name":"Pagan Reed Warbler","scientific_name":"Acrocephalus yamashinae","overview":"帕岛苇莺（英文名：Pagan Reed Warbler，学名：Acrocephalus yamashinae），是雀形目苇莺科苇莺属的鸟类，原生于太平洋美属北马里亚纳群岛的帕甘岛。至20世纪70年代末，因未能再次发现其踪迹，被推断已灭绝。","appearance":"","protection":"IUCN：EX (灭绝)","distribution":"分布仅限于太平洋美属北马里亚纳群岛的帕甘岛，属于非繁殖区域的特有物种。"},{"name":"曼岛苇莺","english_name":"Mangareva Reed Warbler","scientific_name":"Acrocephalus astrolabii","overview":"曼岛苇莺（英文名：Mangareva Reed Warbler，学名：Acrocephalus astrolabii），是雀形目苇莺科苇莺属的已灭绝鸟类。仅在法属波利尼西亚的甘比尔群岛（Gambier Islands）中的曼加雷瓦岛（Mangareva）被发现过。根据两个已知标本，推测其在19世纪中期因森林破坏和外来捕食者的引入而消失。","appearance":"曼岛苇莺长约17厘米。上体呈灰橄榄色，眼眉淡黄色，下体颜色较浅，眼线深色。喙上部黑色，下部肉色，眼睛深棕色，腿脚灰色。雌鸟体型略小于雄鸟。与同样灭绝的歌鸲苇莺极为相似，但体型更大，喙相对较短，脚和爪异常粗壮。","habits":"具体的生活习性不明，但可推测与近缘物种类似，可能栖息于芦苇丛生的湿地环境中。","identification":"与歌鸲苇莺相比，曼岛苇莺具有更大的体型，更短的喙，以及异常粗壮的脚和爪。","protection":"IUCN：EX（已灭绝）","distribution":"曼岛苇莺的分布限于太平洋的甘比尔群岛中的曼加雷瓦岛，位于土阿莫土群岛东南部，属于法属波利尼西亚东部。","other":"两个标本由Jules Dumont d'Urville收集，最初被错误地记录来自不同的岛屿，后经分子和形态分析确认其真实来源。"},{"name":"瑙鲁苇莺","english_name":"Nauru Reed Warbler","scientific_name":"Acrocephalus rehsei","overview":"瑙鲁苇莺（英文名：Nauru Reed Warbler，学名：Acrocephalus rehsei），是雀形目苇莺科苇莺属的鸟类。作为岛上仅有的两种本土陆栖繁殖鸟类之一，也是唯一在岛上发现的鸣禽。体长约15厘米，上体呈深褐色，下体颜色较淡，脸部图案不明显，拥有明显的浅色眉纹。广泛分布于岛上的花园、海岸灌木丛和悬崖森林中。","appearance":"中等体型，全长约15厘米，拥有细长而直的喙和圆润的翅膀。头部、肩部和背部带有赤褐色调，上体灰色橄榄色，臀部和上尾覆羽色彩更为鲜艳。翅膀和尾巴呈暗褐色，飞羽边缘微带赤褐色，尾羽尖端淡赤褐色。下巴和喉部呈黄白色，腹部淡赤褐色，最鲜艳的部分位于两胁、尾下覆羽和翼下覆羽。虹膜深色，喙基部一半暗角棕色，下颌骨基部淡粉色，腿呈铅灰色。雌雄相似，幼鸟特征未详述。","call":"声音了解甚少，但其歌声据说悦耳且类似鸫鸟。","habits":"栖息于瑙鲁岛的花园、海岸灌木丛和悬崖森林中，常见于岛上因磷酸盐开采形成的灌木丛地以及中央高原剩余的森林地带。在海岸附近的花园和杂草丛生区域也很容易观察到。物种全年定居于瑙鲁，不进行迁徙。","breeding":"筑杯状巢，由草和小枝编织而成，有时会包含Cassytha filiformis藤蔓或Casuarina equisetifolia针叶。巢通常固定在直立的茎上，类似于其他苇莺的筑巢方式。巢可能建在树和灌木上，高度介于2至8米之间，也可能在地面筑巢，但地面巢中的幼鸟可能更易受到鼠类的捕食。繁殖季节不详，但报告中提到了12月和7月的繁殖活动。一窝产2-3枚白色蛋，孵化和育雏周期未知。","identification":"与卡罗琳苇莺相比略小，色彩较浅，眉毛对比更弱。歌鸲苇莺则体型显著更大。由于它是岛上唯一的鸣禽，因此不会与其他物种混淆。","protection":"IUCN：NT（近危）","distribution":"太平洋：瑙鲁（密克罗尼西亚中南部）。在整个岛上广泛分布，特别是在岛屿的陡峭斜坡上残留的森林中最为常见。","other":"尽管其确切生态和行为细节尚不清楚，但已知它以昆虫为食，尤其是龙虱。潜在的捕食者包括野猫、狗、波利尼西亚鼠和tanezumi鼠。"},{"name":"卡罗琳苇莺","english_name":"Caroline Reed Warbler","scientific_name":"Acrocephalus syrinx","overview":"卡罗琳苇莺（英文名：Caroline Reed Warbler，学名：Acrocephalus syrinx），是雀形目苇莺科苇莺属的小型鸟类。其主要特征为中等体型，外表呈暗褐色，广泛分布于密克罗尼西亚的卡罗琳群岛，适应多种生境，包括原生森林至退化的沿海灌木丛和高草地带。","appearance":"该鸟长约15厘米，喙长而尖。头部有宽阔的黄褐色眉纹，黑色眼纹；背部为棕色，臀部颜色较淡，带黄色调；翅膀和尾羽边缘有细薄的黄褐色边缘；腹部为黄白色，带有肉桂色的色调；眼睛深色；上喙黑色，下喙灰白色；腿灰色。性别相似，幼鸟特征未详述。","call":"其鸣唱为一系列复杂的颤音和颤鸣，通常被分割成短促的爆发，其间歇有停顿，不如歌鸲苇莺持续时间长。","habits":"栖息于各种生境，包括森林、灌木丛和高草地，常在地面觅食，也会攀爬到树冠层。饮食详情未记载，但其行为显示它可能以昆虫和其他小型无脊椎动物为食。","breeding":"关于繁殖行为的信息尚未详细记录。","identification":"与歌鸲苇莺相比，卡罗琳苇莺具有明显较短的喙。","protection":"IUCN状态未知，需进一步确认。","distribution":"仅分布于太平洋的卡罗琳群岛，具体包括丘克州（=Truk，加罗林群岛中部）、Pohnpei（=Ponape）、Kosrae（可能已灭绝）及其相关环礁（加罗林群岛东部，密克罗尼西亚中部）。","other":"该物种在Kosrae岛的状态存疑，可能已灭绝。"},{"name":"基里巴斯苇莺","english_name":"Bokikokiko","scientific_name":"Acrocephalus aequinoctialis","overview":"基里巴斯苇莺（英文名：Bokikokiko，学名：Acrocephalus aequinoctialis），是雀形目苇莺科苇莺属的鸟类。这中等体型的冷灰色苇莺，常见于基里巴斯的Kiritimati和Washington岛上，全球数量约2500只，呈下降趋势。","appearance":"体长约15厘米，重19克，主要呈现冷灰色，翼羽暗色带淡边，赋予其凌乱外观。头顶至背部橄榄灰，颈侧及肩部中性灰，许多羽毛边缘泛白，尤其在臀部和尾上覆羽更为明显。腹部全白，胸部侧面略带淡灰，胸中心和腹部隐约泛黄。虹膜深色，上喙黑色，下喙角质或淡粉色，腿脚石板色。幼鸟比成鸟更显明亮的灰色。","call":"常见鸣声包括\"cha\"、\"che\"和\"churr\"音节，其歌声相比同类较为简单，由这些鸣叫声组合变化而成。","habits":"栖息于开阔地带，有散落的Tournefortia argentea树和茂密灌木丛，有时伴有椰子树。主要以昆虫为食，包括苍蝇和蜻蜓，偶尔捕食小型蜥蜴。大部分时间在地面或低矮植被中觅食，飞行能力较弱。","breeding":"繁殖季节至少从二月至七月。一夫一妻制。巢为深杯状，由草、根须、椰壳纤维构成，偶尔混有线和塑料，置于成熟海滩heliotrope的枝杈间，高度1.8-8.1米。每窝产卵2-4枚，孵化和育雏由双亲共同承担，幼鸟在出生地停留数月。","identification":"与同属其他物种的区别在于其独特的羽毛颜色和叫声。亚种pistor与指名亚种在体型上稍大。","protection":"IUCN：EN（濒危）","distribution":"主要分布在太平洋莱恩群岛西北部（波利尼西亚东部），具体包括Kiritimati和Teraina岛。","other":"人类活动如引入的猪、鼠和野猫，以及气候变化导致的海平面上升对其生存构成威胁。"},{"name":"北马岛苇莺","english_name":"Northern Marquesan Reed Warbler","scientific_name":"Acrocephalus percernis","appearance":"北马克萨斯苇莺体长18至22厘米，拥有明亮的黄色下体和绿色上体，中等长度且略微弯曲的喙，尾巴尖端呈黄色。性别相似，幼鸟特征不详。不同亚种在颜色深浅和体型上有细微差异。","call":"其鸣唱为一连串响亮且变化丰富的颤音和‘churr’音符组成的旋律，叫声包括刺耳的颤音和‘tchak’声。","habits":"栖息于各种植被类型，尤其是密集的灌木丛、灌木丛生的次生林和椰子林中。分布海拔从海平面到约1100米。成功地在入侵植物如Leucaena leucocephala和Acacia farnesiana形成的环境中繁衍。","breeding":"筑巢、领地行为和其他繁殖生态与近似种南马克萨斯苇莺相似，但具体比较研究资料缺乏。2010年估计，Nuku Hiva岛上约有7700个北马克萨斯苇莺的领域。","identification":"与异域分布的南马克萨斯苇莺难以在野外区分，但可通过栖息环境、鸣叫声和行为特征进行辨别。","protection":"IUCN：LC（无危）。在Nuku Hiva岛上，虽然部分栖息地被非本土树种取代，但北马克萨斯苇莺的数量仍相对稳定。","distribution":"主要分布于太平洋的马克萨斯群岛北部，包括Nuku Hiva、Hatutu、Eiao和Ua Huka等岛屿。","other":"尽管某些亚种数量稀少，如Hatutu岛上的postremus亚种和Eiao岛上的aquilonis亚种，但在适宜的环境中它们仍能维持生存。"},{"name":"长嘴苇莺","english_name":"Tahiti Reed Warbler","scientific_name":"Acrocephalus caffer","overview":"长嘴苇莺（英文名：Tahiti Reed Warbler，学名：Acrocephalus caffer），是雀形目苇莺科苇莺属的大型、细长的鸟类，以比例上过长的喙、短翅膀和长尾巴为显著特征。仅分布于太平洋的塔希提岛（社会群岛东南部，波利尼西亚东部），受威胁的物种，被IUCN列为濒危。","appearance":"成年长嘴苇莺身长17至20厘米，具有鲜明的金黄色眉纹和深色眼纹，头部和上体呈斑驳的橄榄棕色，翼羽边缘较浅，使外观显得杂乱无章。初级飞羽和尾羽暗棕色，尾羽尖端黄白色；喉咙和下体淡金黄色。存在全黑或烟灰色变异型，自1920年代起数量逐渐增多。雄鸟和雌鸟相似，但雄鸟的平均尺寸更大，尤其是翼展和尾长。幼鸟颜色比成鸟更深，虹膜呈暗褐色。","call":"其鸣唱是一系列悠长而节奏缓慢的颤音和‘churr’声，穿插着响亮的哨音，整个曲调类似于欧洲观察者的耳朵所熟悉的欧歌鸫的歌声。报警声包括粗糙的‘chrr’、‘gaaark’、‘shroo’或‘rroo’声，通常在歌唱前发出。","habits":"栖息于河岸林地、山地森林、波利尼西亚竹子（Schizostachyum glaucifolium）丛生地带，以及purau树（Hibiscus tiliaceus）和椰子（Cocos nucifera）种植园，海拔高度一般在50至700米之间。食物包括昆虫、小蜥蜴、小鱼、软体动物、小龙虾（Astacus）、蜗牛、种子、果实和花蜜。单独觅食，主要在树冠层通过捕食方式获取食物。","breeding":"繁殖季节为双峰模式，高峰期在8月至12月，次高峰在2月至6月。巢筑于hibiscus树林或竹丛中，高达15米以上。巢呈杯状，较大，由草、根须和苔藓等植物材料精心构建。巢的内部直径平均9厘米，高17厘米，杯深12厘米。","identification":"长嘴苇莺与其他苇莺属物种的区别在于其较大的体型、极长的喙、短圆翅和长尾。暗色型个体全身暗棕或烟灰，与典型的黄色型有明显区别。","protection":"IUCN：VU（易危）","distribution":"长嘴苇莺仅分布于塔希提岛（社会群岛东南部，波利尼西亚东部），在海拔50至700米的区域活动，现在可能局限于600米以下的高度。","other":"历史上，长嘴苇莺在18至19世纪可能是局部地区常见的鸟类，但在20世纪逐渐变得稀少和分散。"},{"name":"莫岛苇莺","english_name":"Moorea Reed Warbler","scientific_name":"Acrocephalus longirostris","overview":"莫岛苇莺（英文名：Moorea Reed Warbler，学名：Acrocephalus longirostris），是雀形目苇莺科苇莺属的鸟类。体型较大，曾被认为是长嘴苇莺的亚种。主要分布在太平洋Moorea岛（社会群岛东南部，波利尼西亚东部），在次生森林中生存。","appearance":"体长20–22厘米，比南非鹨更大，除跗蹠长度外，全身测量值均超过。成鸟上体大多为暗橄榄色，多数羽毛边缘呈稻草黄色，翼羽基部和次级飞羽尖端白色或乳白色，翅膀弯曲处黄色，尾羽大部分为淡奶油至黄白色。具有窄黄色眉纹，眼先、脸颊和整个下体颜色相似，但两侧胸、侧腹、眼先和脸颊可能带有暗橄榄色羽毛。虹膜橄榄棕色，上喙角质色，下喙粉红色，腿和脚板岩灰色。雌雄相似。幼鸟特征未详述。无暗色型个体，与近缘种南非鹨有别，最明显的差异在于尾羽图案，除中央尾羽外，其余尾羽主要为淡奶油色。","call":"关于鸣唱细节知之甚少，但其歌声被认为类似于南非鹨。然而，目前尚无声音录音资料。","habits":"栖息于海拔300–600米的次生森林中，活动于河谷和山坡的Polynesian 'ohe灌丛中，可能仅在此类环境中繁殖。","breeding":"关于生长繁殖的详细信息缺失。","identification":"与南非鹨相比，可通过尾羽的颜色模式加以区分，此外，莫岛苇莺有两种色型：浅色型为淡黄色，上部斑驳棕褐色；深色型为橄榄棕色。","protection":"IUCN：CR（极危）。最后一次记录见于1987年，因水电站建设、道路开发、竹子资源利用和外来物种（如miconia树、普通牛椋鸟、野猫）的引入导致的栖息地破坏，一度被认为可能已经灭绝。不过，21世纪的两次未经证实的目击事件表明，该物种可能以极低数量幸存。","distribution":"分布于太平洋Moorea岛（社会群岛东南部，波利尼西亚东部）。","other":"莫岛苇莺曾在18世纪70年代中期库克第二次航行期间被采集到标本，1921年Whitney南太平洋探险队再次发现，之后在1971年至1973年间以及1981年有过目击记录，但在1986年和1987年的调查中未能再次发现。"},{"name":"加氏苇莺","english_name":"Garrett's Reed Warbler","scientific_name":"Acrocephalus musae","overview":"加氏苇莺（英文名：Garrett's Reed Warbler，学名：Acrocephalus musae），是雀形目苇莺科苇莺属的已灭绝的鸟类。曾被认为属于长嘴苇莺的一个亚种，但遗传数据证明其应为独立物种，且可能为单型种。该鸟仅见于太平洋社会群岛西北部（波利尼西亚东部）的Raiatea和Huahine两岛。","appearance":"由于标本稀少，关于加氏苇莺的详细外观描述资料有限。已知信息显示，其外形特征与同属其他苇莺相似，但具体细节因标本遗失而难以详述。","call":"关于加氏苇莺的鸣叫特征记录缺失，无法提供具体描述。","habits":"加氏苇莺的生活习性资料稀缺，仅知其栖息于社会群岛特定岛屿的环境中，可能偏好湿地或沼泽地带。","breeding":"关于加氏苇莺的繁殖生态学信息缺失，无法提供具体描述。","identification":"加氏苇莺与长嘴苇莺在分类上曾有争议，但通过遗传学研究得以区分，两者在形态上的具体差异目前尚不清楚。","protection":"IUCN：EX（已灭绝）","distribution":"加氏苇莺仅分布于太平洋社会群岛西北部的Raiatea和Huahine两岛，位于波利尼西亚东部。","other":"加氏苇莺的最后一个标本收集于1870年代，之后再未有记录，推测引入的鼠类可能是导致其灭绝的原因之一。"},{"name":"马岛苇莺","english_name":"Southern Marquesan Reed Warbler","scientific_name":"Acrocephalus mendanae","appearance":"体长约18至22厘米，下体鲜亮黄色，上体橄榄色至暗绿色，翼和尾黑色，翼羽边缘和尾羽尖端黄色。头部具有白色眉纹和颊斑，耳羽黄色。虹膜深色，喙上部黑褐色，下部角质色或淡粉色，腿灰色或灰蓝色。雌雄相似，幼鸟色泽较浅，翼羽边缘更白或黄白。不同的亚种在颜色深浅和尺寸上有细微差别。","call":"鸣唱由哨音、颤音、颤鸣和嘶哑的责备声混合组成，复杂且变化多端，黄昏时歌唱最为活跃。","habits":"栖息于低地椰林、干燥灌木山坡、村庄、花园和湿润高海拔森林，最高可达1070米。主要以昆虫为食，包括直翅目、双翅目、鞘翅目、膜翅目、小鳞翅目成虫、毛虫、半翅目、蜘蛛、小型陆生蜗牛、水生甲壳类、小型蜥蜴，偶尔也吃种子、果实和花蜜。在树叶间和地面觅食，有时会在空中捕捉昆虫。","breeding":"没有明显的繁殖季节，几乎每个月都有活跃的巢穴被发现。巢为大型杯状，由叶片、树皮碎片、豆荚、草、椰子纤维、蛛丝和植物绒毛构成，内衬柔软材料。巢通常建在森林树或小树的叉枝上，高度从1.5至25米不等。每窝产3至4枚卵，孵化期和雏鸟期的信息未知。","identification":"与同属其他种类相比，南马克萨斯苇莺具有更长的头部外观，下体更明亮的黄色。亚种之间在颜色深浅和体型上有细微差异。","protection":"IUCN：LC（无危）。在马克萨斯群岛的五个主要岛屿上数量丰富，某些亚种的密度和分布受到外来物种和栖息地退化的影响。","distribution":"主要分布在太平洋的马克萨斯群岛南部，包括Uapou、Hivaoa、Tahuata、Motu One和Fatu Hiva等岛屿。","other":"南马克萨斯苇莺的亚种在数量上有所差异，一些亚种面临栖息地减少和外来物种的竞争威胁。"},{"name":"环礁苇莺","english_name":"Tuamotu Reed Warbler","scientific_name":"Acrocephalus atyphus","overview":"环礁苇莺（英文名：Tuamotu Reed Warbler，学名：Acrocephalus atyphus），是雀形目苇莺科苇莺属的鸟类。中等体型的旧世界苇莺科鸟类，主要特征是拥有明显的眼眉纹和深色眼纹，体色多样，常见锈棕色和灰褐色两种形态。该物种仅分布于法属波利尼西亚的土阿莫土群岛，栖息于林地、灌木丛、花园及椰子种植园。","appearance":"环礁苇莺体长约18厘米，体态修长，喙中等长度。锈色形态上体呈锈褐色，下体偏淡，带肉桂色色调；灰色形态上体冷淡灰，下体灰黄色。头部上方具白色眉纹，全身羽毛边缘常带有脏白色，翼与尾部暗灰褐色，尖端白。虹膜深色，上喙黑色，下喙粉红色，腿灰色。两性相似，幼鸟特征未知。不同亚种在体型、色彩上有细微差异。","call":"其叫声为低沉、刺耳的“chru”，常接以短促的哨音歌曲。","habits":"环礁苇莺居住于环礁和珊瑚岛上的林地及灌木丛，也会出现在花园和椰子（Cocos nucifera）种植园中。主要以昆虫为食，如甲虫、苍蝇、膜翅目昆虫，亦会捕食蜘蛛、软体动物、甲壳类、小型蜥蜴及少量植物物质。觅食时，会在枝条间快速跳跃，啄食小生物，有时也会在地面觅食，偶尔在空中捕捉昆虫。","breeding":"可能全年均可繁殖，无明显季节性。巢为深杯状，由草茎、细枝、长叶和藤蔓细枝编织而成，内衬精致纤维和干草，有时包含小绿叶，置于灌木、藤蔓或树（含椰子棕榈）中，离地高度1.5至10米。每窝产卵1至3枚，关于孵化期和雏鸟期的信息未知，双亲共同喂养幼鸟。","identification":"与其他苇莺科鸟类相比，环礁苇莺的识别点在于其独特的体色变化和明显的眉纹。亚种之间在体型和颜色上有细微差别。","protection":"IUCN：LC（无危）。环礁苇莺为限制范围物种，仅见于土阿莫土群岛。在当地较为常见。","distribution":"太平洋：土阿莫土群岛（波利尼西亚东部）。在1999年，Tuanake、Hiti、Tahanea和Tepoto等岛屿上记录为常见至稀有，当年在小岛Tepoto的密度估计为3.1只/公顷。"},{"name":"库岛苇莺","english_name":"Cook Reed Warbler","scientific_name":"Acrocephalus kerearako","overview":"库岛苇莺（英文名：Cook Reed Warbler，学名：Acrocephalus kerearako），是雀形目苇莺科苇莺属的小型鸟类。其温暖色调的细长体型和橄榄棕色上羽，黄色白下羽，使其在库克群岛东南部的Mangaia和Mitiaro岛屿上独树一帜。库岛苇莺在多种生境中可见，包括花园、灌木丛、林地和高草植被。","appearance":"库岛苇莺长约16厘米，拥有直而纤细的喙。其上身橄榄色，下身黄白色。具黄色面部和细长的黄色眉纹。指名亚种为kerearako的亚种，头部、颈背均匀深橄榄色，逐渐变淡至背部的较浅橄榄色。上翼覆羽、背部和臀部带有赭色晕染。上尾覆羽呈淡黄褐色，翅膀和尾巴暗褐色，边缘带有淡灰色尖端和橄榄色边缘。下腹部、两胁和腹侧带有赭色洗染，下翅覆羽淡黄色。眼睛深色，喙黑色，下颚粉红色，腿蓝灰色，足底黄色。性别相似，幼鸟特征未详述。kaoko亚种比指名亚种略大，上体和翅膀、尾巴边缘更暗淡，背部和臀部仅有轻微的赭色，下体更淡黄色，胸部侧面、两胁和腹侧带轻棕色晕染，喉咙和胸部有不明显的灰色条纹。","call":"库岛苇莺的鸣唱由高处暴露的栖息处发出，包含短促响亮的口哨声和颤音，间歇以停顿。叫声是一种刺耳的重复‘chru’。","habits":"库岛苇莺为留鸟，栖息于从芦苇床到花园、灌木、林地和高草植被的各种生境中。它们以昆虫为主食，包括甲虫、鳞翅目、半翅目、直翅目和膜翅目昆虫，偶尔也吃蜘蛛。库岛苇莺在树枝、叶子和草丛中觅食，有时会头朝下悬挂，有时在地面活跃跳跃。","breeding":"繁殖季节未记录。巢为非常深的杯状，椭圆形开口，由薄干茎和各种纤维构成，外部直径8-10.5厘米，内部直径约5厘米，杯深5-7.5厘米，位于地面1-8米高的多种地方，如卡苏里纳树或灌木，有时在分叉枝上。每窝产1枚卵；关于孵化期和雏鸟期的信息未知。","identification":"库岛苇莺与同属其他物种的区别在于其独特的橄榄色上羽和黄白色的下羽，以及细长的黄色眉纹。亚种之间存在细微差异，如kaoko亚种的更大体型和颜色细节。","protection":"IUCN：LC（无危）。库岛苇莺目前虽常见且数量众多，但因引入物种（如家八哥、猫和鼠）、农业开垦和山羊放牧导致的栖息地丧失和破碎化，使其面临潜在风险。","distribution":"库岛苇莺仅分布在太平洋的Mangaia和Mitiaro两个岛屿上，位于库克群岛东南部，东波利尼西亚。","other":"尽管库岛苇莺在当前范围内普遍且数量众多，其受威胁状态提醒人们关注岛上生态平衡的脆弱性和保护的重要性。"},{"name":"瑞岛苇莺","english_name":"Rimatara Reed Warbler","scientific_name":"Acrocephalus rimitarae","overview":"瑞岛苇莺（英文名：Rimatara Reed Warbler，学名：Acrocephalus rimitarae），是雀形目苇莺科苇莺属的鸟类。自然栖息于亚热带或热带的干燥森林和沼泽地带。由于其分布范围极为有限，该物种被 IUCN 列为极度濒危。","appearance":"瑞岛苇莺体长约17厘米，拥有相对较短的喙。头部上方有一条黄色眉纹和深色眼线，头冠和背部呈暗橄榄棕色，喉部和下体为黄白色。其羽毛间常不规则地散布着白色羽毛，形成斑驳的白棕色外观，这种特征在头部、背部、翅膀和尾巴上尤为明显。两性相似，幼鸟与成鸟相似，但缺乏白色斑块。","call":"最常报道的鸣叫声为响亮的训斥声“chack-chack”和一系列啾啾声，后者有时被认定为其歌声，但真正的歌声尚未被记录。","habits":"瑞岛苇莺栖息于灌木林和芦苇丛中，偏好湿润环境。其活动范围局限于瑞岛，一个面积仅有4平方公里的小岛。","breeding":"关于瑞岛苇莺的繁殖信息较为有限，但已知其在岛上低海拔地区广泛分布，具体繁殖生态尚待进一步研究。","identification":"与其他苇莺相比，瑞岛苇莺具有独特的黄色眉纹和深色眼线，以及不规则散布的白色羽毛，形成鲜明的辨识特征。","protection":"IUCN：CR（极危）。瑞岛苇莺面临黑鼠（Rattus rattus）引入等威胁，导致其数量可能急剧下降。2017年评估时，其种群估计在900至3,850个个体之间，成熟个体约为600至2,600个，且怀疑其数量正在减少。","distribution":"瑞岛苇莺的分布限于法属波利尼西亚的瑞岛，位于太平洋东部的南方群岛西北部。","other":"尽管2002年和2004年的估计人口数量有所不同，但最近的估计显示，2017年该物种的数量在1780至2781个个体之间。"},{"name":"亨岛苇莺","english_name":"Henderson Reed Warbler","scientific_name":"Acrocephalus taiti","overview":"亨岛苇莺（英文名：Henderson Reed Warbler，学名：Acrocephalus taiti），是雀形目苇莺科苇莺属的大型鸟类。具有白色头部和身体，橄榄棕色斑点的冠羽和上部，翼羽和尾巴较暗。分布仅限于太平洋皮特凯恩群岛的亨德森岛，栖息于未受干扰的森林中。","appearance":"体长约17厘米，雄鸟体重22.5至30.5克，雌鸟21至25克。拥有相对短喙，头部白色，顶部带有橄榄棕色斑纹，眼睛周围有深色条纹；背部橄榄棕色，翼羽边缘淡色，白色羽毛散布不规则且通常不对称，有时几乎全身白色；下体白色带微黄调；虹膜深色；上颌灰褐色，下颌银肉色，尖端暗色；腿灰色。雄鸟和雌鸟相似，雄鸟的白色羽毛通常比雌鸟多。幼鸟未详细描述，可能比成鸟有更少的白色羽毛。","call":"鸣叫为高音单音节短促声，以及一系列细长音符；后者类似歌声，但未知其唱歌。","habits":"栖息于亨德森岛上未受干扰的森林，常在家庭群中觅食昆虫，包括蛾类、毛虫、蚁类、大黄蜂、蝇类、甲虫、蟑螂，以及陆生蜗牛、种子和果肉。在森林各层活动，从叶面到地面均可见其觅食。","breeding":"繁殖季节定义明确，从8月底至次年1月初，与适宜食物丰富期同步。部分合作繁殖，以对或三人为单位（三人组或两雄一雌或两雌一雄）。领域性。巢由干叶、椰子纤维和其他植物纤维构成的深杯状结构，内部铺细软材料，平均外部直径11.4厘米，高度13.2厘米，内部直径5.9厘米，杯深度5.2厘米，位于离地1.7至7米高的森林下层树冠，巢位多样；领地小，平均0.92公顷。每窝产卵2至3枚；有报告称两雌共巢；孵卵主要由雌鸟承担，有时两鸟同时孵卵，孵卵期15天；雏鸟由双亲喂养，关于巢期时长信息不足；至少在离巢后6周仍接受父母部分喂养。平均每巢成功育雏1.47只；巢损失率低。成年鸟年生存率估计为85至90%。","identification":"与皮岛苇莺的区别在于，亨岛苇莺的白化影响身体前部而非后部。","protection":"IUCN：VU（易危）","distribution":"分布于太平洋皮特凯恩群岛中的亨德森岛。","other":"主要生存威胁是外来物种尤其是掠食性哺乳动物的意外引入。1987年评估总数量约为10,800只，所有可用栖息地均被占据；密度估计在每公顷1.4至10.3只之间。"},{"name":"皮岛苇莺","english_name":"Pitcairn Reed Warbler","scientific_name":"Acrocephalus vaughani","overview":"皮岛苇莺（英文名：Pitcairn Reed Warbler，学名：Acrocephalus vaughani），是雀形目苇莺科苇莺属的鸟类。大型冷色系的苇莺，上体灰褐，下体黄白，翅膀和尾巴呈白色调。皮特凯恩岛上唯一的陆鸟，当地人称之为‘sparrow’。分布于太平洋皮特凯恩岛，为该岛特有种。","appearance":"体长17厘米，体重雄鸟约27克，雌鸟约22克。具有灰色的眉纹和深色的眼纹；脸颊橄榄色，边缘较浅；颈部和上体呈深橄榄棕色，臀部有非常宽的奶油色尖端，覆盖大部分可见的羽毛部分；上尾覆羽主要为暗淡的黄灰色，带有较暗的轴线；上翼可变，不规则但主要为白色，飞羽外缘泛黄；尾巴可变，要么暗褐色带白色尖端，要么大部分为白色；喉咙至腹部黄色，两胁微带奶油色，大腿处暗黄灰色；下尾覆羽奶油色；下翼覆羽白色或奶油色，带有暗色斑点；虹膜深色；上喙深棕色，下喙蓝灰色至粉红色；腿灰色。两性相似。幼鸟上体更红棕色，下体肉桂色，缺乏白色斑块。","call":"发出单调而刺耳的‘chak, chak’叫声，不唱歌。","habits":"主要栖息于高大森林的斑块中，避免开阔地带。以昆虫为食，通常在树和灌木丛中觅食，很少在地面活动。","breeding":"信息缺失。","identification":"通过其独特的大小、颜色和杂乱的外观与其他苇莺区分开来。","protection":"IUCN：EN（濒危）。曾被列为VU（易危），现因其小范围分布和外来黑鼠的威胁，升至EN（濒危）。","distribution":"仅限于太平洋的皮特凯恩岛（Pitcairn），位于皮特凯恩群岛西部，波利尼西亚东南部。","other":"1997年野猫的根除和随后对黑鼠的控制尝试，使种群数量从1998-1999年的估计2000-3000只开始显著增加。"},{"name":"黑眉苇莺","english_name":"Black-browed Reed Warbler","scientific_name":"Acrocephalus bistrigiceps","overview":"黑眉苇莺（英文名：Black-browed Reed Warbler，学名：Acrocephalus bistrigiceps），是雀形目苇莺科苇莺属的鸟类。小型苇莺科鸟类，以暗褐色为主色调，头部具有鲜明的花纹。最显著的特征是其粗厚且轮廓分明的眼眉纹，呈白色，与黑色侧顶纹形成对比。繁殖于蒙古东部、俄罗斯东南部至中国东部和日本，冬季迁徙至东南亚，直至大巽他群岛。在中国大陆，广泛分布于华东、西至陕西和广西等地。","appearance":"体长约13.5至14厘米，体重介于7至11克之间，平均9.4克。典型的Acrocephalus属小苇莺，头部有明显的方形白眉纹，上方有一条厚重的黑褐色条纹；头顶和上体呈红橄榄棕色，臀部和尾上覆羽颜色略带红褐色；下方白色，胸侧和两胁带有暖色的黄褐色；虹膜深褐色；喙上部暗色，下部较浅；腿肉色至暗灰色。雌雄相似，幼鸟与成鸟非常相像，但上体红褐色调更鲜明，两胁颜色较淡。","call":"鸣唱声是一连串快速重复的短语，夹杂着干燥的沙哑音和嘶嘶声，比东方大苇莺的鸣唱更有旋律。叫声柔和的“dzak”声，受惊时发出尖锐的“chur”声。","habits":"栖息于各种靠近水域的植被中，如芦苇丛、莎草、柳树丛和其他灌木，高草丛，水稻田，河流边的柳树，湿润森林边缘，有时也会出现在较为干燥的开阔草地。海拔分布从低地到1500米。迁徙性，冬季在南亚和东南亚度过。","breeding":"繁殖季节为6月至8月。在俄罗斯远东地区，记录到的产卵日期为6月18日至22日，孵化期在6月20日至7月20日之间；在日本，到达本州的时间为5月末至6月末。每巢产卵4至6枚，孵化期13至14天，雏鸟期14至15天，雄鸟参与孵卵和喂养。在日本本州，61.1%的产卵最终孵化出飞鸟。","identification":"与更常见的芦苇莺相似，但黑眉苇莺的上体颜色更深，且不具后者背部和翅膀上的黑色条纹。","protection":"IUCN：LC（无危）。在当地数量可观，在俄罗斯远东地区、中国东部常见，在日本是常见的繁殖访客，某些地区非常普遍。","distribution":"繁殖于蒙古东部、俄罗斯东南部至中国东部和日本；非繁殖期分布于东南亚至大巽他群岛。","other":"叫声和行为模式有助于其在野外的识别。"},{"name":"须苇莺","english_name":"Moustached Warbler","scientific_name":"Acrocephalus melanopogon","overview":"须苇莺（英文名：Moustached Warbler，学名：Acrocephalus melanopogon），是雀形目苇莺科苇莺属的小型鸟类。其特征为具有明显的白色眉纹和喉部，与水蒲苇莺相似但体型略大。繁殖于欧洲南部、亚洲南部温带地区及北非西北部少数地区，部分个体迁徙至阿拉伯、印度和巴基斯坦等地过冬。","appearance":"成鸟长约12至13.5厘米，体重8.5至13克。头部图案明显，具黑色冠顶，方形白眉，耳羽呈灰暗色；背部呈红褐色（新羽几乎呈栗色），颈部两侧和肩部有不规则红褐色斑块；翼短；腿色深（水蒲苇莺腿色较浅）。雌雄同形同色，幼鸟上体颜色较淡，下体更苍白，翼羽更鲜艳。不同亚种间存在差异，如mimicus亚种体型更大，色泽更暗淡。","call":"发出类似石䳭的模糊“treck”声。其歌曲为持续而粗糙的混音，以四音节流畅的前奏为特色，比水蒲苇莺的歌声柔和，含有清晰、甜美、圆润的音符。","habits":"栖息于密集的芦苇床中，常在香蒲丛中发现。主要以小型节肢动物为食，如甲虫、跳虫、昆虫幼虫等，偶尔食用樱桃和接骨木果实。在垂直的水生植被中觅食，结构适应于在水面或近水面处觅食，有时从水中获取食物，罕见于空中捕食。","breeding":"繁殖期从3月末到6月中旬，通常营巢于水上植物茎干之间，高30至130厘米。巢由雌鸟建造，呈深杯状，可能带有部分顶盖，主要由水生植物的叶和茎构成，内衬细植物材料和羽毛。每窝产2至7枚卵，平均3至6枚，孵卵期约13至15天，幼鸟孵化后约12天离巢，离巢后18至22天独立。","identification":"与水蒲苇莺相比，须苇莺体型较大，尾巴尖端更窄，羽毛色泽更深暖。叫声和歌声亦有区别，歌声更柔和、旋律更优美。","protection":"IUCN：LC（无危）","distribution":"在欧洲南部、亚洲南部温带地区繁殖，部分个体迁徙至地中海区域、北非、黎凡特、美索不达米亚、阿富汗东南部、巴基斯坦（印度河谷）和印度西北部过冬。","other":"须苇莺在欧亚大陆北部较为罕见，曾作为迷鸟出现在波兰和丹麦等地，英国也有零星记录，但已被移除官方鸟类名单，因难以与水蒲苇莺或稻田苇莺区分开。"},{"name":"水栖苇莺","english_name":"Aquatic Warbler","scientific_name":"Acrocephalus paludicola","overview":"水栖苇莺（英文名：Aquatic Warbler，学名：Acrocephalus paludicola），是雀形目苇莺科苇莺属的小型鸟类。其特征为厚而淡色的眉纹，暗色冠顶中央有一条淡色纵纹，背部重条纹类似鹬鸟。分布于东欧至西伯利亚的温带地区，繁殖后迁往西非过冬。全球数量估计约11,000-15,000对，面临生境丧失威胁。","appearance":"体长约13厘米，体重9.8-15.5克。头部具特色条纹，翼尖钝圆。上体呈淡橄榄色或金色，背部重重条纹，肩羽和覆羽较轻，翅羽黑色边缘较浅，下体淡奶油色，胸部和两胁常有细纹。虹膜深色，喙黑褐色，腿黄色或棕粉色。性别相似，但雄鸟翼较长，雌鸟嘴部可能更深。幼鸟上体呈亮稻草色，两胁颜色更深，胸胁几乎无条纹，腿色非常浅。","call":"鸣唱快速且叽叽喳喳，间以Acrocephalus特有的口哨声。","habits":"偏好开阔、富营养的沼泽地，以莎草为主，水深几厘米，散有柳树灌木。迁徙时使用芦苇丛。冬季在西非撒哈拉以南的广阔浅水沼泽栖息。迁徙模式为秋季向西南迁移至西非，春季迁徙路线不详，但可能直接返回。","breeding":"最早筑巢于5月9日，平均首次产卵日期为5月中旬，第二次繁殖同步性较低，一般6月底至7月初开始。雌鸟独自抚育后代，巢通常位于3-30厘米高的地面或水中，每窝3-6枚蛋，孵化期12-15天，雏鸟期13-16天。","identification":"与水蒲苇莺相比，整体印象更黄白，头纹更明显，腿部颜色更浅。飞行时尾部尖锐，体色较淡。","protection":"IUCN：VU（易危）","distribution":"繁殖于东北德国至波兰边境，向东局部延伸至立陶宛、白俄罗斯南部和乌克兰西北部。越冬于西非撒哈拉以南地区，主要在塞内加尔的杜久国家公园。","other":"面临的主要威胁是湿地排水、传统农业衰落以及生境被芦苇和灌木过度占据。"},{"name":"水蒲苇莺","english_name":"Sedge Warbler","scientific_name":"Acrocephalus schoenobaenus","overview":"水蒲苇莺（英文名：Sedge Warbler，学名：Acrocephalus schoenobaenus），是雀形目苇莺科苇莺属的鸟类。小型迁徙鸟类。其特征包括明显的淡色眉纹与深色冠纹对比鲜明，上体呈深棕色，下体淡色。广泛分布于欧洲至中亚地区，冬季迁徙至撒哈拉以南非洲。在中国，仅见于新疆西北部，栖息于沼泽地带，偏好芦苇、高草和矮丛环境。","appearance":"水蒲苇莺体型小而修长，全长约13厘米，体重8.1-17.9克，平均11.2克。上体为丰富深棕色，下体淡色，具独特的白色或淡黄色眉纹，与暗色细纹的冠纹形成鲜明对比。颊部和耳羽黄褐色，背部橄榄棕色，翼羽棕褐色，边缘淡棕色。下体白色，喉部和腹部最洁净，其他部位略带奶油或淡黄色，两胁锈色。幼鸟比成鸟更黄更淡，胸部可能有模糊的斑点。雄雌相似。","call":"发出快速、嘈杂的鸣唱，夹杂着甜美的旋律和尖锐的咔哒声，有时包含模仿其他物种的叫声。报警声为清脆的‘chek’声，焦虑叫声为含糊的干涩滚动声。","habits":"栖息于沼泽地带的密集植被中，偏好芦苇、高草和矮丛，通常靠近水源，但也能在较干燥的环境中繁殖。以昆虫为主食，包括多种昆虫及其幼虫，偶尔食用蜘蛛、小型软体动物和植物材料。活动于低矮植被中，从叶片和枝条上捕捉猎物，偶尔从地面取食。","breeding":"繁殖期从4月末开始，持续到5月中下旬。主要一夫一妻制，偶尔出现一雄多雌现象。巢由雌鸟建造，深杯状，位于湿地植被中，离地面不远。每窝产4-7枚蛋，孵化期13-15天，幼鸟期10-14天，出巢后25-30天独立。","identification":"与同属其他物种的区别在于眉纹和冠纹的对比度，以及更偏向黄褐色的上体颜色。幼鸟与成鸟在胸斑上的差异有助于识别。","protection":"IUCN：LC（无危）","distribution":"繁殖区主要在欧洲（除南部和西南部）至西伯利亚东部，土耳其，高加索和哈萨克斯坦；冬季迁徙至撒哈拉以南非洲。在中国，仅新疆西北部有记录。","other":"在英国、爱尔兰和荷兰，密度超过1000对/50平方公里。过去几十年间，种群数量在挪威、芬兰、奥地利和乌克兰有所增加，但在西欧部分国家有所下降。"},{"name":"细纹苇莺","english_name":"Speckled Reed Warbler","scientific_name":"Acrocephalus sorghophilus","overview":"细纹苇莺（英文名：Speckled Reed Warbler，学名：Acrocephalus sorghophilus），是雀形目苇莺科苇莺属的鸟类。神秘而隐秘的旧世界苇莺科鸟类。由Robert Swinhoe于1863年首次描述。在中国东北部及菲律宾有分布，其自然栖息地为沼泽和农田。因栖息地丧失，尤其是菲律宾Candaba沼泽的湿地消失，面临威胁。","appearance":"细纹苇莺长约12-13厘米，重7.2-9.1克。具有渐变的尾羽和狭窄的尾羽尖端。头部两侧有黑色条纹，宽大的奶油色眉纹，黄色脸颊。上身底色为赭橄榄色，头顶、背部有淡黑色条纹或斑点，肩部至腰部为均匀的红橄榄色。翼上覆羽和三级飞羽为深棕色边缘赭橄榄色。翅膀和尾巴为棕色，边缘和尖端为淡黄色。下体为淡黄赭色，喉咙和腹部白色，内侧翼下覆羽边缘为极淡的锈赭色。眼睛为深棕色，上喙黑色带黄色边缘，下喙全为黄色，腿为铅灰色，足底较浅。性别相似，幼鸟与成鸟相似，但下体颜色更偏黄。与水蒲苇莺相比，上体颜色略暖且更深，背部条纹更宽、更模糊，对比度较低，但头顶条纹更明显，且头顶两侧较窄。","call":"发出类似东方大苇莺的沙哑、刺耳的鸣叫声，但据报道声音较为低沉。","habits":"在迁徙途中和冬季，出现在沼泽和潮湿的田野。推测在芦苇和草地沼泽以及柳树林和芦苇床繁殖。主要以昆虫为食，可能也会食用种子，但需更多研究确认。春季迁徙时间为5月底至6月初，秋季迁徙为8月底至9月初。在菲律宾的所有记录都发生在9月至6月。","breeding":"细纹苇莺在长白山区繁殖季节出现在海拔800米以下的低山带，常栖息于近水的灌木丛中。每年5月下旬迁至繁殖地，停留约80-100天。一窝产卵5枚，孵化期大约为13-14天。雌雄双方共同参与育雏，育雏期约为11-12天。雏鸟主要以蚊子、苍蝇、鳞翅目幼虫等为食，能有效消灭害虫。","identification":"与更为常见的黑眉苇莺相比，细纹苇莺具有贯穿整个背脊和头顶的显著条纹，眉纹对比度较低，整体颜色更为淡雅。","protection":"IUCN：CR（极危）。国家二级保护野生动物（2021.02.05）。","distribution":"繁殖区域位于中国东北部，具体可能在河北、辽宁、吉林和黑龙江的湿地。非繁殖季节分布于中国东南部，菲律宾（罕见）。","other":"细纹苇莺被列入《国家保护的有益的或者有重要经济、科学研究价值的陆生野生动物名录》。"},{"name":"钝翅苇莺","english_name":"Blunt-winged Warbler","scientific_name":"Acrocephalus concinens","overview":"钝翅苇莺（英文名：Blunt-winged Warbler，学名：Acrocephalus concinens），是雀形目苇莺科苇莺属的鸟类。又名: 钝翅稻田苇莺，中等体型（约14厘米）的棕褐色无纵纹苇莺。其独特的短圆两翼和几乎不及眼后的白色短眉纹是显著的外部特征。分布于中国北部和中部，常栖息于芦苇地和低山的高草地。","appearance":"中等体型的钝翅苇莺通体呈现单调的棕褐色，缺乏明显的纵纹。最显著的特征是其两翼短而圆，白色的眉纹在眼睛后面逐渐消失，不延伸至眉上。喙尖而细，适于在芦苇丛中觅食昆虫。雌雄鸟在外观上相似，幼鸟的羽毛可能较成鸟略显淡色。","call":"鸣声刺耳，由一系列响亮的颤音和刺耳的蜂鸣声组成，叫声为干涩、粗锉的“tsak”声。","habits":"栖息于湿地周围的茂密植被中，偏好芦苇丛和草丛。在中国北部和中部繁殖，冬季则迁徙至东南亚，包括缅甸、泰国和孟加拉国等地。飞行敏捷，善于在密集的植被中穿梭。","identification":"与稻田苇莺相比，钝翅苇莺的分布区域不同，主要分布在中国北部和中部，而稻田苇莺分布于中国西部。此外，钝翅苇莺的眉纹不过眼，而稻田苇莺的眉纹过眼。还有，钝翅苇莺眉上无纹，而稻田苇莺眉上具有黑色细纹。","protection":"IUCN：LC（无危）","distribution":"繁殖区域主要位于欧亚大陆的中南部和东部，包括阿富汗、巴基斯坦、东北印度和中国；非繁殖区域则位于东南亚，如缅甸、泰国和孟加拉国。"},{"name":"远东苇莺","english_name":"Manchurian Reed Warbler","scientific_name":"Acrocephalus tangorum","overview":"远东苇莺（英文名：Manchurian Reed Warbler，学名：Acrocephalus tangorum），是雀形目苇莺科苇莺属的小型苇莺。隐匿于东北和俄罗斯东南部的偏远沼泽地带繁殖，冬季迁徙至东南亚较干燥的草地生境。整体色调为暖褐色，眉部和喉部呈白色，眉纹宽且延续至眼后，有别于钝翅苇莺。","appearance":"体长13–14·5厘米，体重6·8–9·2克。体羽灰褐，头顶和背部灰褐色，臀部偏土黄褐色；下体白色，侧腹和尾下覆羽转为土黄褐色。冬季换羽后，整体颜色更为红褐色，上体呈现赭红褐色。虹膜深棕色，上喙深色，下喙基部浅色（粉红色），腿色从黄色到橙棕色或橄榄灰色。雌雄外观相似，幼鸟特征未详述。","call":"发出散漫杂乱的鸣声，包含高音颤音和尖锐的咔嗒声，比东方大苇莺的鸣声更为悦耳。","habits":"栖息于沼泽环境，与稻田苇莺的生活习性类似。在东北地区繁殖，冬季迁往东南亚。具体活动范围、觅食方式等细节未知。","breeding":"繁殖生态尚未详细研究，可能与稻田苇莺相似。","identification":"与稻田苇莺极为相似，但远东苇莺的眉纹上方有更深色的带状斑，上体颜色更深且更偏褐色。","protection":"IUCN：VU（易危）。在中国东北繁殖地数量稀少；在东南亚为局部且不常见的非繁殖季访客。全球估计种群数量为2500–10,000只，且数量被认为正在下降。主要威胁是繁殖地和越冬地的芦苇湿地丧失和退化。","distribution":"繁殖于中国东北部和俄罗斯东南部；越冬于东南亚，主要在柬埔寨，但也见于泰国和老挝南部。","other":"曾被视为稻田苇莺的亚种，现已确认为独立物种。"},{"name":"大嘴苇莺","english_name":"Large-billed Reed Warbler","scientific_name":"Acrocephalus orinus","overview":"大嘴苇莺（英文名：Large-billed Reed Warbler，学名：Acrocephalus orinus），是雀形目苇莺科苇莺属的鸟类。曾被誉为‘世界上最鲜为人知的鸟’，仅凭1867年印度采集的单一标本而知名，直至2006年在泰国被重新发现。其显著特征为大嘴、扁平前额和短淡眉纹。与布氏苇莺极其相似，但嘴更长，腿更长，翅膀略短。在高海拔湿地繁殖。","appearance":"大嘴苇莺长约13-14厘米，体重约10.9克。中等体型的苇莺，具有明显的大而强壮的嘴，窄长尾部，末端圆润。上体橄榄褐色，尾羽上覆羽及大覆羽边缘略带红褐色；喉部奶油橄榄色，下体橄榄黄色，侧面更呈橄榄棕色；虹膜深色；上喙深色，边缘淡色，下喙全淡色；腿、趾爪淡棕色。与布氏苇莺的区别在于嘴、腿和爪稍长，上喙通常均匀深色，后爪尖锐。幼鸟比成鸟颜色更暖，红褐色调更明显，上喙略淡，更偏红棕色。","call":"叫声尚未详细描述，但据说比布氏苇莺的鸣声更快、更复杂。","habits":"在山地溪流边、运河和其他湿地的灌木丛中繁殖，如海沙棘和柳树丛。夏季访问中亚，迁徙路径和越冬地尚不明确，但有记录显示在印度北部、缅甸和泰国过冬。","breeding":"一夫一妻制，雌鸟筑巢，巢通常建在离地面1.1至2.1米高的海沙棘枝条、艾蒿、甘草、柳树或芦苇上。每窝产2-5枚蛋，平均3.77枚，蛋壳污白色，偶尔乳白或纯白，带有暗斑点，尺寸约为17.7毫米×13.1毫米，重量约1.5克。两性共同孵卵和喂养雏鸟及幼鸟。筑巢活动主要发生在6月，雏鸟记录见于6月末至7月。","identification":"与布氏苇莺区分在于嘴、腿和爪更长，尾羽尖端更尖锐，翼尖较方，上喙颜色更深。幼鸟与成鸟在颜色上有细微差别。","protection":"IUCN：LC（无危）。直到最近，仅从1867年的单一标本得知，2006年在泰国再次发现，之后在阿富汗、塔吉克斯坦、乌兹别克斯坦东部和哈萨克斯坦东南部发现了繁殖证据。","distribution":"繁殖区域位于中亚山区，从哈萨克斯坦东南部延伸到阿富汗东北部，通过塔吉克斯坦和乌兹别克斯坦东部、吉尔吉斯斯坦部分地区。越冬地不详，但记录显示出现在印度北部、泰国中南部。","other":"2006年在泰国Laem Phak Bia首次野外重获，之后在阿富汗、塔吉克斯坦等地发现更多个体和繁殖证据。"},{"name":"稻田苇莺","english_name":"Paddyfield Warbler","scientific_name":"Acrocephalus agricola","overview":"稻田苇莺（英文名：Paddyfield Warbler，学名：Acrocephalus agricola），是雀形目苇莺科苇莺属的小型鸟类。其名称源于拉丁文，意为\"农民\"，可能与它常在农田附近的栖息地有关。稻田苇莺分布于欧亚大陆的中部，繁殖季节在温带地区，冬季则迁徙至亚洲南部，包括孟加拉国、印度和巴基斯坦等地。","appearance":"该鸟体型接近于欧亚苇莺，长约13厘米，翼展15至17.5厘米，背部呈淡棕色，腹部为温暖的米色，臀部带有褐色调。眉纹明显，呈白色，且延伸至眼后，形成独特的外观。喙短而尖，性别之间无显著差异，幼鸟的下部更偏黄褐色。栖息于低矮植被中，如长草、芦苇和稻田。","call":"稻田苇莺的鸣唱快速而富有旋律，类似于苇莺，包含大量模仿音和典型的苇莺科特有的哨声。其歌声较弱，节奏感强。","habits":"稻田苇莺偏好靠近湖泊和河流的低矮植被环境，以昆虫为主要食物来源。其特有行为包括不停地上扬尾羽和耸立顶冠羽。","breeding":"繁殖期在温带中央帕拉斯区，筑巢于草地中，每窝产4至5枚卵。冬季迁徙至亚洲南部过冬。","identification":"与钝翅苇莺及其他小型Acrocephalus属苇莺难以仅凭视觉区分，但稻田苇莺具有更为明显的白色眉纹，向后加强，以及翅膀显得较长。","protection":"IUCN：LC（无危）","distribution":"繁殖于欧亚中部，冬季迁徙至亚洲南部至缅甸一带。在中国大陆，有小规模的繁殖群体分布在黑海西部沿岸，具体位于保加利亚和罗马尼亚边境附近。","other":"历史上，远东苇莺（东北苇莺）曾被归入作为亚种，但目前通常被视为独立物种。"},{"name":"布氏苇莺","english_name":"Blyth's Reed Warbler","scientific_name":"Acrocephalus dumetorum","overview":"布氏苇莺（英文名：Blyth's Reed Warbler，学名：Acrocephalus dumetorum），是雀形目苇莺科苇莺属的鸟类。最显著的外部特征包括深色的细眼纹、短的白色眉纹和清晰的浅色眼先，但缺乏深色上眉纹。该物种繁殖于欧洲至西北亚，越冬于非洲东北部、喜马拉雅山脉、印度及缅甸地区。","appearance":"布氏苇莺体型小，长度约为12-14厘米，体重8-20克，平均11.2克。其羽毛呈单调冷灰褐色，身体瘦长，翅膀短而圆，喙相对长。头部前方有较明显的白色眉纹，眼睛周围有暗色眼纹；头顶和背部橄榄棕色，翅膀呈均匀的棕色，翼角无明显暗色；腹部颜色淡至近白色，胸侧和两胁带有暗赭色至灰色调；虹膜深棕色；喙色深灰角质，下颚基部淡粉色；腿色通常是暗灰色，有时带粉棕色。雄雌外观相似，幼鸟与成鸟类似，但色调略偏暖棕色。","call":"布氏苇莺的鸣唱复杂多变，包含多种音调，部分粗糙，部分清晰，常插入高超的模仿声，以缓慢节奏重复3-5次（有时多达十次）。鸣唱间歇时，会发出尖锐的“thik”、硬质的“chak”和刮擦般的“cherr”叫声。","habits":"布氏苇莺栖息于潮湿的荆棘丛、沼泽灌丛及草地，偏好森林边缘、灌木丛、沼泽边缘和公园，但并不特地依赖水体。它通常在灌木和树木上歌唱，而非芦苇或草丛中。饮食主要包括昆虫，如石蛾、蜻蜓、石蝇、直翅目昆虫、蠼螋幼虫、半翅目昆虫、绿蛉、鳞翅目昆虫、毛翅目昆虫、双翅目苍蝇（包括摇蚊）、膜翅目昆虫（包括锯蝇、蚂蚁、蜜蜂和黄蜂）、甲虫；蜘蛛、草蜱、蜗牛以及少量种子。觅食时，常在树和灌木的侧面或顶部枝叶间跳跃，也会在地上跳跃，甚至捕捉空中飞虫。","breeding":"繁殖季节，布氏苇莺在灌木中筑巢，每次产4-6枚卵。最佳识别特征是其缓慢而重复的鸣唱，伴有大量模仿其他鸟类的叫声，穿插着音阶和典型的Acrocephalus属特有的哨音。","identification":"布氏苇莺与湿地苇莺相似，但后者翅膀较长，喙较短，腿部颜色较浅。此外，布氏苇莺背部更灰，前额不如湿地苇莺平坦，喙也不如后者强壮和尖锐。","protection":"IUCN：LC（无危）","distribution":"繁殖于欧洲中部、中北部至俄罗斯中部和南部至中东地区；越冬于非洲东北部、喜马拉雅山脉、印度及缅甸。","other":"布氏苇莺以英国动物学家Edward Blyth命名，其学名Acrocephalus源自古希腊语akros（最高）和kephale（头），可能Naumann和Naumann误解akros为‘尖端’之意。"},{"name":"芦苇莺","english_name":"Common Reed Warbler","scientific_name":"Acrocephalus scirpaceus","overview":"芦苇莺（英文名：Common Reed Warbler，学名：Acrocephalus scirpaceus），是雀形目苇莺科苇莺属的小型鸟类。其体长约为13厘米，翼展介于17至21厘米之间，背部呈单一的棕褐色，腹部为淡黄色。额头平坦，喙部强健且尖锐。雌雄外观相似，幼鸟下体色泽更偏暖黄色。广泛分布于欧洲至亚洲中部，非洲北部和撒哈拉以南非洲。在欧洲及温带西部帕拉尔地区繁殖，冬季迁徙至非洲南部。","appearance":"芦苇莺体型中等，全长约13厘米，平均体重在8至19.7克间，翼尖略钝。成鸟背部颜色为暗橄榄色，头顶较深，上眉线及眼环淡黄，与头顶及脸颊的暗色形成对比。上体从颈背至尾部呈现微弱的锈黄色调，翅膀和尾羽颜色更深，翼羽尖端和边缘呈淡黄褐色，下体白色，胸部和下尾覆羽泛淡黄色，两胁偏锈黄色。虹膜深棕色，上喙深棕色，下喙主要为黄色或粉红色，腿脚色从深灰棕色到淡角质色。幼鸟全身色泽比成鸟更鲜亮，上体泛橙色而非淡黄色，下体颜色更深，脸谱通常不明显，眉线和眼环几乎与头顶和脸颊颜色一致。","call":"其鸣唱为一系列尖锐的节奏感强的刮擦声和吱吱声，每音节重复2至3次，例如“kerr-kerr-kerr chirruc chirruc chirruc kek-kek-kek chirr-chirr”，持续时间可达20秒，速度较慢且不如水蒲苇莺的鸣叫那样嘈杂，模仿能力也不及湿地苇莺。","habits":"栖息于成熟的芦苇床（Phragmites）沿湖泊、鱼塘、河流和沟渠，偶尔进入邻近的草本植被、灌木丛和低矮树木，如柳树。非繁殖季节和迁徙期间出现在芦苇、灌木丛、高草地带，常见于河岸、湖畔，也远离水源出现在次生灌木丛、金合欢林、马樱丹灌木、森林边缘和花园篱笆。在西非阿维森尼亚和红树林中支持大量越冬个体。该物种在非洲越冬区非常丰富。","breeding":"繁殖季节为5月至7月或8月，在欧洲和中欧地区。一夫一妻制，偶有双配偶现象。松散的群居繁殖，筑巢由雌鸟主要或独自完成，巢为深杯状，由裂开的芦苇叶、芦苇花序、植物绒毛和草茎编织而成，内衬细软材料，悬挂于2至8根垂直的芦苇茎上，通常位于浅水上方15至200厘米高度。每窝产卵3至5枚，多数为4枚，由双亲共同孵化，孵化期8至13天，平均9至12天。雏鸟由双亲喂养，离巢期为10至12天，偶尔9或13天。寄生率在西欧和中欧平均为8.3%，受大杜鹃寄生。","identification":"与非洲苇莺区别在于上嘴颜色更深，浅色眼先宽且清晰，色彩更深而温暖。无深色上眉纹，区别于远东苇莺及稻田苇莺。与布氏苇莺相比，棕色较少，橄榄色调更重，腰部颜色暗淡，两翼较长。","protection":"IUCN：LC（无危）","distribution":"繁殖区覆盖欧洲至亚洲中部，阿拉伯半岛，非洲北部；越冬区主要在非洲中部至南非，北非部分区域如法国南部、伊比利亚、摩洛哥至土耳其和阿拉伯也有少量越冬个体。","other":"近期欧洲河流和湖泊的富营养化导致芦苇床面积增加，但湿地的开发也造成部分地区数量下降。在英国、比利时和西班牙数量减少，在荷兰、瑞典、芬兰和波罗的海国家数量增加。"},{"name":"非洲苇莺","english_name":"African Reed Warbler","scientific_name":"Acrocephalus baeticatus","overview":"非洲苇莺（英文名：African Reed Warbler，学名：Acrocephalus baeticatus），是雀形目苇莺科苇莺属的鸟类。体长约12至13厘米，体重8.8至12克。分布于非洲大陆，尤其在湿地和沼泽地带常见。非洲苇莺具有短而圆钝的翅膀，上体呈暖棕色，下体偏白，两胁带丰富的黄褐色。其独特的外表和栖息地选择使其在苇莺家族中独具一格。","appearance":"非洲苇莺体型小巧，翼展短小，翼尖圆润。头部不显条纹，具有一条微弱的白色眉线，眼先和耳羽棕色。头顶和背部颜色温暖，棕色略带锈色，尤其是臀部和尾上覆羽。飞行羽深棕色，边缘为较浅的暖棕色，尤其是在三级飞羽上更为明显。尾巴同样为深棕色。腹部白色，胸部和尾下覆羽泛黄褐色，两胁呈丰富黄褐色。腋下和翼下覆羽淡黄褐色。虹膜深棕色，喙上部深棕色，下部黄褐色，腿色为暗角色至肉棕色。幼鸟比成鸟色彩更鲜艳，带有锈色。雌雄外观相似。","call":"非洲苇莺的鸣唱通常来自隐蔽的栖息处，是一系列有节奏的摩擦声和尖锐音符的重复组合，例如“chir-chir-churric-churric...”。叫声为短暂的“churr”。其鸣声与极为相似，难以区分。","habits":"非洲苇莺主要栖息在湿地环境，如芦苇丛、灯芯草丛、水边的灌木丛和河流旁的高草丛。它们也出现在甘蔗田和灌溉渠附近，有时在远离水源的湿润灌木丛中。部分种群迁徙，南非洲的繁殖者五月北迁，八月返回。在苏丹东部，非洲苇莺九月到达繁殖地，八月离开。在赞比亚，非繁殖个体五月到十一月出现，而在东南赞比亚七月到九月可见。以昆虫为食，主要在中低高度的植被中觅食，如芦苇、灯心草和纸莎草中捕食昆虫。","breeding":"非洲苇莺主要在雨季繁殖，时间因地区而异。它们通常是单配偶制，但在纳米比亚的研究显示，12%的领地中有三个成年个体（主要是雄鸟）参与了育雏和喂养幼鸟，这可能暗示了一种多雄制的繁殖系统。巢由芦苇纤维或草制成，内衬精细材料（包括羽毛），直径约7厘米，高8厘米，内部直径4至4.5厘米，深度3.5至5厘米，编织在4至6根直立的芦苇、灯心草或草茎上，有时也会绑在垂下的柳树枝条上。每窝产卵2至3枚，偶尔4枚，平均孵化期为12至13天，孵化和育雏由双亲共同承担。","identification":"非洲苇莺与极为相似，但可以通过较小的体型、较平缓的前额轮廓、较短的翅膀和更温暖的棕色上体颜色来区分。与Acrocephalus gracilis和大沼泽苇莺的区别在于更小的体型、棕色更浓的腿色和更淡雅的外观。","protection":"IUCN：NR（未评估）非洲苇莺在当地常见，但在繁殖范围的北部数量较少，而在南非广泛分布且数量较多。在纳米比亚，沿岸小片芦苇丛中繁殖密度极高。","distribution":"非洲苇莺分布在非洲大陆，主要在湿地和沼泽地带。繁殖季节外，它们也会出现在干燥的栖息地，如河流边的荆棘丛。在肯尼亚，海拔可达1900米。","other":"非洲苇莺与曾被认为是同一物种，但因其不同的迁徙行为和相关联的翅膀结构和换羽模式而被视为独立物种。DNA研究表明，avicenniae亚种可能应归入。"},{"name":"湿地苇莺","english_name":"Marsh Warbler","scientific_name":"Acrocephalus palustris","overview":"湿地苇莺（英文名：Marsh Warbler，学名：Acrocephalus palustris），是雀形目苇莺科苇莺属的鸟类。以模仿多种欧洲和非洲鸟类的叫声而闻名，拥有独特且悦耳的歌声。分布于欧亚大陆的温带地区，从英国到俄罗斯中东部，南至土耳其和伊拉克。在非洲东南部度过非繁殖季节。","appearance":"湿地苇莺体型较小，约13厘米长，平均体重11.9克。外观上，它具有一条短而明显的奶油色眉纹，狭窄的奶油色眼环；脸颊、耳羽和顶冠橄榄棕色，背部和上体橄榄棕色略带绿色调，臀部和尾上覆羽淡橄榄棕色；翅膀黑色，边缘橄榄绿或绿橄榄色；上翼覆羽深棕色，边缘和尖端橄榄棕色；下体白色下巴和喉咙与黄色橄榄色胸部斑块形成鲜明对比，侧腹橄榄色，尾下覆羽白色或奶油色，腋下和翼下覆羽浅黄橄榄色；虹膜深棕色；上喙角质暗色，下喙较浅黄色或肉色；腿通常粉棕色或浅角质色。与相似的芦苇莺相比，湿地苇莺的上体更绿或橄榄色，下体颜色更淡，洗得不那么深的土黄色，与布氏苇莺相比，其绿色和黄色色调更明显，翅膀边缘更突出，嘴稍短，翅膀更长，身体看起来更丰满。雌雄外观相似。幼鸟与成鸟相似，但翅膀、臀部和尾上覆羽可能带有青铜色或暖棕色。","call":"湿地苇莺的鸣叫声非常独特，响亮，富有变化，结合了清澈的液态颤音、笛状短语、钟声般的轰鸣或清脆的刺耳声、鼻音叫声和各种模仿的歌曲和叫声。它的歌几乎完全是模仿性的，已记录到至少模仿99种欧洲物种和113种非洲物种的叫声，甚至机械声音。","habits":"湿地苇莺偏好茂密、高大的草本植被，尤其是荨麻、柳石南、黑莓和其他植物，常在较高的灌木或树木附近。它们也可以在玉米田和其他被低矮灌木或树篱环绕的农业土地上找到。在废弃地、高草丛、草本植物和小灌木中，沿着沟渠的高草本植被中，沼泽植被的边缘，干地上的芦苇，甚至花园中也能发现它们的身影。湿地苇莺主要分布在低地和丘陵地带，最高可达3000米（格鲁吉亚）。在迁徙期间，它们也会出现在干燥的荆棘丛和红树林中。","breeding":"湿地苇莺的繁殖季节为5月下半月至7月，在西欧和中欧。通常一年一窝。它们是单配偶制的，但在机会允许的情况下也可能出现多配偶现象。巢由雌鸟单独建造，偶尔会得到雄鸟的帮助，是一个相对深的圆柱形杯状巢，由荨麻、草和其他植物的叶子和茎构成，内部衬有细植物纤维、非常薄的茎，有时还有植物绒毛和毛发，平均外部直径8.9厘米，高度8.4厘米，内部直径5.3厘米，深度4.6厘米，支撑在2-5（通常3-4）根植物茎上，大多数情况下是荨麻，高度从20厘米到超过200厘米（主要是30-70厘米）。巢的成功率为42.8%-58.4%，每巢平均产生1.7-3.5只雏鸟；损失主要由于天敌捕食，也有弃巢、雏鸟饥饿和人为干扰。","identification":"湿地苇莺与芦苇莺、布氏苇莺等近亲相似，但可通过其更绿或更橄榄色的上体、更淡的下体、更明显的绿色和黄色色调、更突出的翅膀边缘、稍短的嘴、更长的翅膀和更丰满的身体来区分。雄鸟的模仿歌曲是其最显著的辨识特征。","protection":"IUCN：LC（无危）","distribution":"湿地苇莺在欧亚大陆繁殖，范围从中部到俄罗斯中东部和南部至土耳其和伊拉克；非繁殖季节则主要在非洲东南部度过。","other":"湿地苇莺在全球范围内被认为数量正在增加，其全球估计总数量为1000万至2700万只。然而，在英国，由于原因不明的种群下降，它已经接近灭绝状态。"},{"name":"厚嘴苇莺","english_name":"Thick-billed Warbler","scientific_name":"Arundinax aedon","overview":"厚嘴苇莺（英文名：Thick-billed Warbler，学名：Arundinax aedon），是雀形目苇莺科芦莺属的大型苇莺，以其粗厚的喙著称。分布于东帕里亚尔地区，繁殖于南西伯利亚至蒙古西部，冬季迁徙至南亚及东南亚热带地区。","appearance":"体长约18-21厘米，体重22-31克，整体呈现橄榄褐色或棕色，无纵纹。上体色彩较深，头部圆大，喙短而粗，呈肉色，上颌稍弯。尾部长而渐尖，翅膀短小。繁殖羽上体带有橄榄色，下体偏黄白色，胸腹部泛暖色调。虹膜深棕色，腿色蓝至紫色。雄雌相似，幼鸟上体略带红褐色，下体更偏淡黄色。","call":"鸣唱快速而响亮，包含短促的高音节、尖锐的咔嚓声和柔和的颤音。叫声为连续的、节奏不一的‘thk...thk, thk, thk’。","habits":"栖息于密集植被中，如芦苇、灌木和浓密的草丛。偏好森林边缘、灌木丛及杂乱植被。以昆虫为主食，偶尔捕食其他小型猎物。","breeding":"在低矮的树上筑巢，每窝产5-6枚卵。具体繁殖行为细节未知。","identification":"与噪大苇莺相比，嘴部更短、更钝，无眼线或眉纹，叫声不同，对水环境无特定偏好。","protection":"IUCN状态未知。","distribution":"繁殖于欧亚大陆中北部和东北部，越冬于东南亚。","other":"历史上曾被归入单型属Phragmaticola或Acrocephalus，后被确认属于Iduna支系，最终确定学名为。"},{"name":"黄捕蝇莺","english_name":"African Yellow Warbler","scientific_name":"Iduna natalensis","overview":"黄捕蝇莺（英文名：African Yellow Warbler，学名：Iduna natalensis），是雀形目苇莺科靴篱莺属的鸟类。上体呈橄榄黄褐色，下体鲜亮黄色，具飞蛾般的喙，头部颜色随亚种而异，有时黑色有时橄榄绿。广泛分布于东非和南非，常见于湿地附近的灌木丛。","appearance":"中等体型，约13厘米长，体重介于10至15克之间。上体橄榄黄褐色，翼羽边缘黄色，下体明亮黄色。喙部上颌淡色，下颌黑，腿色深灰至黑色。雌雄相似，幼鸟色彩较淡，冠部更棕色，背部微带肉桂色，翅膀和尾巴的羽缘偏黄褐色。","call":"鸣声由快速的喉音和变调音组成，如'chip-chip-chip-whee-lee-wheeo'。报警声为尖锐的'tsk'或'chirr'。","habits":"栖息于湿润植被区，如沿溪流的灌木丛、沼泽边的高草丛或森林边缘。主要以小昆虫及其幼虫为食，如甲虫、蛾类、蝗虫、螳螂和白蚁。低矮处觅食，沿茎移动捕食，偶尔从栖枝上飞扑捕食。","breeding":"繁殖季节主要在雨季，北赤道以北的产卵高峰期为4月至7月，南非则为9月至次年4月，高峰在11月至12月。一夫一妻制，领域性强。巢呈深杯状，由草、根和其他纤维构成，放置于1米高的灌木间或草本植物中，靠近水源。每窝产卵1至3枚，通常2枚，孵化期12天，雏鸟离巢期14至16天。","identification":"与其他黄莺相比，具有更深的帽色和更橄榄绿的背部，栖息环境不同。","protection":"IUCN：LC（无危）","distribution":"广泛分布于东非和南非，从低地到较低的山区，海拔可达2150米（喀麦隆）和2600米（埃塞俄比亚）。在南非沿海的灌木丛中越冬。"},{"name":"山捕蝇莺","english_name":"Mountain Yellow Warbler","scientific_name":"Iduna similis","overview":"山捕蝇莺（英文名：Mountain Yellow Warbler，学名：Iduna similis），是雀形目苇莺科靴篱莺属的鸟类。中等体型的鸟类，以橄榄绿和黄色的羽毛著称。分布于非洲东部的高山地区，如南苏丹南部、乌干达东北部与西南部、刚果民主共和国东部、卢旺达西部、布隆迪西部、肯尼亚、坦桑尼亚北部与东部以及赞比亚与马拉维边境的Nyika高原。","appearance":"山捕蝇莺体长约13厘米，体重介于9至15克之间。上身橄榄绿色，头部颜色均匀，与背部一致；有狭窄的黄色眉纹，脸颊和耳羽橄榄绿色；翅膀覆羽橄榄绿色；飞羽和十二根尾羽深棕色，边缘泛黄绿色；下体鲜亮黄色；虹膜棕色；喙上部暗褐色，下部黄色至淡粉色或淡赭色；腿灰色或黑色。雌雄相似，幼鸟背部比成鸟更偏褐色，臀部和上尾覆羽带有肉桂色，下体较浅的黄色。","call":"鸣唱为短暂多变的混合音，包含悦耳的哨音、颤音和颤鸣，持续时间约4至7秒，常以一系列变化重复，中间穿插短暂间隔。叫声为‘cha-cha-cha’。","habits":"栖息于海拔1800米以上的山区，最高可达肯尼亚的3400米、刚果民主共和国东部的3700米。常见于沿溪流的茂密植被、沼泽谷地的灌木丛、山地森林边缘或空地、次生林、灌木丛、蕨类和荆棘丛生地及过度生长的农田。以昆虫为主食，尤其偏好苍蝇（双翅目）。在低处觅食，也活跃于中层灌木丛乃至高达20米的树冠层。为留鸟，不迁徙。","breeding":"繁殖季节主要在雨季，不同地区的繁殖时间各异，如南苏丹的4月和10月、刚果民主共和国的4月至6月和10月、肯尼亚西部和中部的7月至8月和11月、坦桑尼亚的9月和12月、以及赞比亚-马拉维的12月至2月。领地性明显。巢为厚壁杯状，由草叶和种子头混以羽毛、蕨类、苔藓编织，用蛛丝固定，内部铺垫羽毛、毛发和植物纤维，通常筑于距地面约1米的低矮灌木或灌丛分叉处。每窝通常产2枚卵。","identification":"与黄捕蝇莺相似，但在重叠区域，山捕蝇莺主要分布在较高海拔，通过其橄榄绿色而非黑色的顶冠加以区分。","protection":"IUCN：LC（无危）","distribution":"分布于南苏丹南部（伊马通山脉、东加托纳山脉、迪丁加山）、乌干达东北部与西南部（莫罗戈莱山、西南高地）、刚果民主共和国东部高地、卢旺达西部、布隆迪西部（鲁文佐里山脉至伊图姆贝山和卡博博山）、肯尼亚（库拉尔山、埃尔贡山、西部和中部高地）、坦桑尼亚北部和东部（火山高地东至乞力马扎罗山，以及恩古鲁山和乌卡鲁山南至Njombe）、赞比亚与马拉维边境的Nyika高原。","other":"山捕蝇莺适应能力较强，能在次生环境中茁壮成长，不依赖于森林环境。"},{"name":"靴篱莺","english_name":"Booted Warbler","scientific_name":"Iduna caligata","overview":"靴篱莺（英文名：Booted Warbler，学名：Iduna caligata），是雀形目苇莺科靴篱莺属的鸟类。繁殖季节分布自俄罗斯西部、中部和南部，直至哈萨克斯坦、伊朗、阿富汗和中国西部，冬季则迁徙至印度东南部乃至斯里兰卡。该鸟种近年来已将其繁殖范围扩展至芬兰，显示出其种群健康和繁殖成功的迹象。","appearance":"体长11-12.5厘米，体重7-11克，外形似缩小版的黄喉苇莺或Phylloscopus属的莺鸟。上体灰褐至深红褐色，下体偏白，具明显的淡色眉纹，延伸至眼后1-3毫米处。夏羽因磨损而更显灰白。翼短，尾方，脚灰粉或灰褐色。雌雄相似，幼鸟上体有时带锈红色，尾缘较淡。","call":"鸣唱为快速的颤音，略带沙哑，音节无明显模式或重复，持续约10至25秒，有时更长。叫声为干涩的‘chek’声，类似赛氏篱莺的叫声。","habits":"栖息于低矮灌木覆盖的草原、牧场和杂草丛生的草地，偏好膝高或稍高的灌木，如绣线菊、豌豆等。在非繁殖季节，常见于较高的植被如柽柳和金合欢中觅食。以昆虫和其他无脊椎动物为主食，夏季亦会捕食毛虫。","breeding":"繁殖期为5月至6月初，每年一窝。巢由植物茎、根和细枝构成的杯状结构，位于地面或近地面的浓密灌木中。每窝产4-6枚卵，雌鸟为主孵化，孵化期12-14天，幼鸟在12-14天后离巢。","identification":"与赛氏篱莺相比，体型较小，颜色更接近橄榄色。通过体型、色彩和栖息环境可以区分。","protection":"IUCN：LC（无危）","distribution":"繁殖于欧亚大陆，自俄罗斯西部至哈萨克斯坦、伊朗、阿富汗和中国西部；冬季迁至印度东南部。","other":"近年来，靴篱莺的繁殖范围向西扩张，最远至芬兰，显示其种群稳定且繁殖成功。"},{"name":"赛氏篱莺","english_name":"Sykes's Warbler","scientific_name":"Iduna rama","overview":"赛氏篱莺（英文名：Sykes's Warbler，学名：Iduna rama），是雀形目苇莺科靴篱莺属的鸟类。曾被认为是靴篱莺的亚种，现被确认为独立物种。其分布区域从东北阿拉伯至图尔克斯坦、中国西部及阿富汗，冬季许多种群迁徙至印度次大陆，南至斯里兰卡。赛氏篱莺的名字源于英国驻印度军官威廉·亨利·赛克斯上校。","appearance":"小型鸟类，体长11.5-13厘米，体重7-11克。具较长、较细的尖喙，扁平的前额和顶冠，尾巴较长。上身淡灰褐色，头部和肩部在某些光线下略显橄榄色。背部、三级飞羽和较大的上翼覆羽均匀棕色，缺乏深浅对比。初级飞羽棕色，次级飞羽边缘略淡。尾巴外侧羽毛边缘和尖端较淡。下体主要是偏白色，胸部侧面和两胁有微弱的肉桂色。虹膜深棕色，上喙灰色，下喙粉黄色，通常尖端有淡暗斑。腿灰粉色，趾部常稍暗和灰些。雌雄相似，幼鸟似成鸟。","call":"发出快速混合粗糙和清晰音符的歌曲，有时重复二到三个音节，每个乐句持续约10至25秒，强度均匀。此外，有类似‘早晨歌’，以慢速、断奏的方式发出唧唧声或挤出的音符。叫声包括干燥的舌点击声‘chek’，以及更饱满的‘tslek’声，后者类似蓝喉鸟的焦虑叫声。","habits":"栖息于开阔地带，带有灌木和其他高植被。迁徙性，秋季于8月至9月离开繁殖地，春季从2月末开始返回，多数在3月至5月到达繁殖区。主要以昆虫和蜘蛛为食，夏季会捕食毛虫。在树叶和枝条间积极搜索食物，偶尔落地寻找猎物，每次时间短暂。喂食和移动时，尾巴向上或向侧面抽搐，很少向下。","breeding":"繁殖期在4月至6月/7月，一般只繁殖一窝。部分区域半群居，巢穴间距可达5米。巢由植物茎、根和柔软的枝条构成的坚固杯状，内衬植物绒毛和兽毛，置于树枝叉或茂密灌木丛中，高度通常在0.3至2米之间。每窝产卵4-6枚，若卵丢失则会补产。孵化主要由雌鸟承担，偶尔由雄鸟替换，孵化期12-14天。雏鸟由双亲共同喂养，出巢后12-14天。","identification":"与靴篱莺相比，赛氏篱莺体型更大，颜色更灰。最像水蒲苇莺。区别于布赖斯的芦苇莺，它具有莺类的行为和更长的尾巴，与靴篱莺的区别在于外观不那么紧凑，姿态更平坦，喙更长且大多无黑色尖端，尾巴更长且连接较松，脸型更尖，叫声更硬，偏好树冠顶部。","protection":"IUCN：LC（无危）","distribution":"繁殖区域从伏尔加河下游向东延伸至东哈萨克斯坦（巴尔喀什湖）、中国西部（新疆西部和中部），南至伊朗南部、阿富汗和巴基斯坦西部，局部出现在印度西北部。在阿联酋东北部（霍尔卡尔巴）和阿曼西北部（巴蒂纳海岸红树林）有小规模留鸟群体。非繁殖区域主要在印度次大陆，包括巴基斯坦南部和印度。","other":"无"},{"name":"草绿篱莺","english_name":"Eastern Olivaceous Warbler","scientific_name":"Iduna pallida","overview":"草绿篱莺（英文名：Eastern Olivaceous Warbler，学名：Iduna pallida），是雀形目苇莺科靴篱莺属的鸟类。最显著的外部特征是橄榄灰色的羽毛和不断上下摆动的长尾巴。广泛分布于旧世界，繁殖于东南欧、中东及相邻的西亚地区，越冬于撒哈拉以南非洲。","appearance":"草绿篱莺体长约12至14厘米，体重介于8至16克之间。上体呈灰褐色，头部略大，颈部较粗，喙长而尖，类似的喙型，但更为细长。眉线短且模糊，眼圈白色，头顶及背部均匀地覆盖着暖棕色或淡棕色羽毛，有时带红褐色调。新鲜羽毛的次级飞羽边缘较浅，形成微弱的翼斑。尾巴长而窄，末端方形，外侧尾羽边缘较淡。下体呈淡白色，胸部两侧和胁部略带淡黄色。眼睛深棕色，上颌大部分为暗色，下颌全为粉黄色。腿灰色，有时带粉色或浅棕色。雌雄相似，幼鸟腹部更偏黄色。","call":"鸣叫特征明显，发出干燥而粗糙的‘chack’声。歌声为重复的刮擦音节序列，声音单调，由低沉嘶哑的音符开始，随后是高音鼻音或吱吱声，再回到低沉的刮擦音符，节奏稳定而缓慢。","habits":"栖息于开放的林地、河岸森林以及干旱和半干旱地带，与柽柳灌木丛有密切联系。主要以昆虫为食，如蜻蜓、蚱蜢、白蚁、蝽象、蛾类、蝴蝶、苍蝇、蚂蚁、甲虫和蜘蛛等。也会食用夏季的甲虫和蝴蝶幼虫，以及晚夏的果实，如黑莓和接骨木果。觅食时在树冠层活跃搜索，偶尔会降落到地面觅食。迁徙期间，常在低矮灌木中觅食。","breeding":"草绿篱莺在东南欧、中东及西部亚洲繁殖，冬季迁徙至撒哈拉以南非洲。营巢于灌木或植被低处，每次产卵2至3枚。","identification":"与赛氏篱莺非常相似，但可通过其略大的头部、更厚的颈项、较长的初级飞羽和略短的尾巴来区分。叫声和歌声也是重要的辨识特征。","protection":"IUCN：LC（无危）","distribution":"繁殖区域包括欧亚中南部和非洲北部。非繁殖季节则分布于撒哈拉以南非洲。","other":"历史系统学上，曾被归类为更广泛的'olivaceous warbler'物种的一部分，但现代分类学已将其与西草绿篱莺区分开来。"},{"name":"西草绿篱莺","english_name":"Western Olivaceous Warbler","scientific_name":"Iduna opaca","overview":"西草绿篱莺（英文名：Western Olivaceous Warbler，学名：Iduna opaca），是雀形目苇莺科靴篱莺属的鸟类。体型中等，背部呈淡橄榄灰褐色，腹部色浅，拥有粗壮的喙和长尾。分布于欧洲西南部和非洲西北部，冬季迁徙至撒哈拉以南的非洲。与草绿篱莺在外形和习性上有所区别。","appearance":"西草绿篱莺长约13.5-15厘米，重9-17克。拥有长而饱满的尾巴，折叠时两侧略圆。腿强壮，喙长且宽，尖端钝且厚实。头部和背部淡灰褐或淡棕色，某些光线照射下头部和肩部显微弱橄榄色。翅膀羽色均匀偏棕色，边缘稍浅。下体偏白色，侧胸和胁部有淡淡的灰黄褐色。眼睛深棕色，喙色暗，下颌粉色，腿色灰粉。雌雄相似，幼鸟腹部更偏向淡黄色。","call":"其鸣唱含多种不规则音符和咔哒声，每段持续约15至30秒，有时更长，常以反复的“chek”叫声开始。叫声为喉音‘chek’，带鼻音，有时延长成模糊的颤音。","habits":"栖息于轻度林木花园、果园、种植园、绿洲和密集灌木丛地带。迁徙性，秋季自7月底至10月离开繁殖地，春季于3月末至4月返回北非繁殖区，西班牙一般于5月中旬回归。在撒哈拉以南的非洲过冬，主要位于塞内加尔至尼日尔和乍得西部的萨赫勒地区。","breeding":"繁殖季节为4月末至6月。巢筑于枝桠分叉处，由植物茎和柔软枝条构成，通常距地面1-4米。每次产卵3-4枚，仅雌鸟孵化，周期11-13天。雏鸟由双亲共同喂养，约11-15天后离巢。","identification":"与草绿篱莺相比，西草绿篱莺体型略大，上体颜色更偏棕色，喙更大，尾部静止不动（不像草绿篱莺在觅食时有向下摆动的习惯）。鸣唱更富变化，缺乏单调循环。","protection":"IUCN：LC（无危）","distribution":"繁殖于西班牙东南部、北非西部，包括摩洛哥、阿尔及利亚和突尼斯北部至利比亚西北沿海山脉。冬季迁徙至西非，从塞内加尔东至乍得西部。","other":"过去曾被视为更广泛定义的草绿篱莺莺'物种的一部分，但现代分类学已将其与草绿篱莺明确区分开。"},{"name":"细嘴捕蝇莺","english_name":"Papyrus Yellow Warbler","scientific_name":"Calamonastides gracilirostris","overview":"细嘴捕蝇莺（英文名：Papyrus Yellow Warbler，学名：Calamonastides gracilirostris），是雀形目苇莺科细嘴捕蝇莺属的鸟类。中型树莺，以鲜明的黄色腹部和橄榄绿背部为特征。主要分布于非洲中南部的高地区域，包括布隆迪、刚果民主共和国、肯尼亚、卢旺达、坦桑尼亚、乌干达和赞比亚，其自然栖息地位于沼泽地带。细嘴捕蝇莺的种群规模通常较小且分散，由于栖息地丧失，其数量被认为正在急剧下降。","appearance":"细嘴捕蝇莺是一种中等体型的莺，拥有长而渐尖的尾巴，短而圆的翅膀，长而细的喙，以及长而纤细的脚趾。上体呈现温暖的棕色或橄榄绿色，下体呈淡黄色，常带有橙色调。头部和肩部略带绿色，臀部更显肉桂色。翅膀和尾巴呈深棕色，边缘带有肉桂色。喉咙部分黄色，其余下体颜色较为暗淡。幼鸟下方毛色更偏棕黄色，黄色和绿色调几乎消失，较大的和中间覆羽具有宽大的橙棕色尖端，形成两条翼带。","call":"细嘴捕蝇莺的鸣唱由简单的重复乐句组成，容易被忽视。","habits":"细嘴捕蝇莺独居或成对活动，常见于芦苇沼泽环境，具体的生活习性和生态细节尚不明晰。其分布区域主要位于非洲中东部的高海拔湿地。","breeding":"细嘴捕蝇莺的繁殖生态信息未知。","identification":"在细嘴捕蝇莺的栖息地中，没有明显的混淆物种。与之相似的物种如大沼泽苇莺、细嘴苇莺、非洲苇莺和蒲草短翅莺在体型、颜色、鸣唱和生境上都有明显差异。黄捕蝇莺虽可能出现在芦苇沼泽边缘，但其上体颜色、头冠、翅膀和尾部特征以及鸣唱都与细嘴捕蝇莺不同。","protection":"IUCN：NT（近危）","distribution":"细嘴捕蝇莺分布于非洲中南部的高地区域，包括布隆迪、刚果民主共和国、肯尼亚、卢旺达、坦桑尼亚、乌干达和赞比亚，主要栖息于沼泽地带。"},{"name":"淡色篱莺","english_name":"Upcher's Warbler","scientific_name":"Hippolais languida","overview":"淡色篱莺（英文名：Upcher's Warbler，学名：Hippolais languida），是雀形目苇莺科篱莺属的鸟类。分布自土耳其至巴基斯坦，冬季迁徙至东非，从埃里特里亚和索马里南至坦桑尼亚。栖息于半沙漠地带，偏好灌木丛和柽柳丛，筑巢于低矮的灌木或树木上，产卵数为四至五枚。","appearance":"本种为中等大小的灰棕色篱莺，翼展宽而基部较厚，尾羽呈半展开状态，尾端圆钝。头部具短而模糊的白色眉纹，眼圈白色，上体灰或棕灰色，次级飞羽和覆羽边缘白色，形成明显的翼斑。上尾和露出的初级飞羽尖端深灰色，有时显黑色。外侧尾羽有细白边和突出的白色尖端。下体白色，侧胸和两胁带淡黄灰色或奶油色。虹膜深褐色，上喙大部黑色，下喙粉黄色，腿灰白色，常带淡粉色或浅棕色。雄雌相似，幼鸟上体比成鸟更偏棕色，缺乏纯灰色调。","call":"其鸣唱为充满活力的短句混合了鼻音、硬质音符和清澈、更悦耳的音符，短段落通常被类似或完全相同的方式重复5至8次以上，甚至多达20次，其间穿插着类似叫声的“chak”音符，这与布氏苇莺的歌曲相仿。有时，少重复的歌唱类似于Sylvia物种的副歌。鸣唱长度变化，从10至45秒不等。叫声为喉音、硬舌点击的“chak”，平均比草绿篱莺的声音更响亮。","habits":"主要以昆虫和其他无脊椎动物为食，大部分时间在树冠层和高灌木中觅食，搜寻叶间的昆虫；偶尔在隐蔽处的地面短暂觅食。迁徙期间，多活动于树上，但也一定程度上在低矮灌木中觅食。飞行时有独特的习惯，从一个停栖点到另一个时，常常先进行短距离滑翔，同时尾巴半展开。","breeding":"繁殖季节在半沙漠生境中的灌木丛和柽柳丛中筑巢，每窝产卵4至5枚。","identification":"与草绿篱莺相比，本种具有略强的喙，更长且宽的尾，更深色的上尾和翼尖，以及更为明显的翼斑。尾部的频繁摆动和翼部的快速振动是其独特行为特征。","protection":"IUCN：LC（无危）","distribution":"繁殖区域包括欧亚地区，从土耳其至以色列，向东至哈萨克斯坦南部、吉尔吉斯斯坦、塔吉克斯坦、阿富汗和巴基斯坦。非繁殖区域位于非洲东北部。","other":"由Henry Baker Tristram于1864年重新描述，以纪念他的朋友Henry Morris Upcher，由此得名。"},{"name":"橄榄篱莺","english_name":"Olive-tree Warbler","scientific_name":"Hippolais olivetorum","overview":"橄榄篱莺（英文名：Olive-tree Warbler，学名：Hippolais olivetorum），是雀形目苇莺科篱莺属的鸟类。在东南欧和近东地区繁殖，冬季迁徙至东部和南部非洲，从肯尼亚南至南非。这种小型鸣禽栖息于开放的橡树林、橄榄园、果园和杏仁种植园。会筑巢在低矮的树木或灌木丛中，一次产三到四枚蛋。","appearance":"这是一种中等体型的树莺，与条纹树莺的大小相近，但拥有略长的喙和较短的尾巴。它是Hippolais属中最大的树莺，具有厚实的喙，平坦的头顶，长翅膀和粗壮的腿。成鸟背部呈尘土色或淡褐色，翅膀也是类似颜色，腹部为尘土白色。","call":"它的叫声深沉而粗哑，由一系列响亮的吱嘎声和尖叫组成，音调比其他Hippolais树莺更低，发声速度更慢。","habits":"橄榄篱莺主要以昆虫和其他无脊椎动物为食，夏季也会食用一些水果和浆果，包括无花果。它在树冠层和高大的灌木丛中觅食，由于体型较大，移动较为缓慢，觅食时显得有些笨拙。它会侧向摆动尾巴，有时也会垂直摆动，类似淡色篱莺的行为。","breeding":"繁殖季节在春季，它们会在低矮的树木或灌木上筑巢，通常一次产三到四枚蛋。","identification":"与淡色篱莺相比，橄榄篱莺的尾巴不那么显眼。与Hippolais或Iduna属的较小物种相比，它在灌木和树木间跳跃时动作更为缓慢。","protection":"IUCN状态未提及。","distribution":"繁殖区主要在克罗地亚和希腊至保加利亚，土耳其和以色列一带。非繁殖区位于非洲东部和东南部，包括肯尼亚南至南非。","other":"没有额外信息。"},{"name":"歌篱莺","english_name":"Melodious Warbler","scientific_name":"Hippolais polyglotta","overview":"歌篱莺（英文名：Melodious Warbler，学名：Hippolais polyglotta），是雀形目苇莺科篱莺属的鸟类，以其悦耳的歌声而闻名。体长约12至13厘米，背部橄榄褐色，腹部呈黄色调，喙尖且长，腿呈棕色。分布于欧洲西南部及北非部分地区，冬季迁往撒哈拉以南的非洲。在繁殖季节，常见于灌木丛生的林地、果园和花园。","appearance":"歌篱莺为中等体型的苇莺，体长12至13.5厘米，体重8至14克。上身呈浅橄榄棕色，下身黄色，喙尖且略长，头部圆润，尾巴方正。翼展适中，约为外露三级飞羽长度的一半到三分之二。眼上纹淡黄色，眼周浅色区域营造出“开阔脸庞”的外观。冠部和背部灰褐色，略带橄榄色，三级飞羽边缘、次级飞羽及部分大覆羽呈棕黄色，形成闭合翅膀时微淡的色块。尾巴具细薄的浅色边缘和尖端。喉咙和下身饱和黄色，虹膜深棕色，喙灰色，切割边缘和下颌粉黄色，腿灰棕色或粉灰色。雌雄相似，幼鸟腹部较淡。","call":"鸣唱为多变的颤音，速度和长度不一，通常以极快的速度发出延长的乐句，包含鼻音和类似麻雀的‘tr’r’r’r’r’r’rt’的叽叽喳喳声。叫声包括一系列的舌击‘chek’音，以及模仿其他鸟类的声音，尽管不是专家级别的模仿者。","habits":"栖息于灌木茂密的林地、果园、大而不整的花园、橡树林、浓密的荆棘灌丛、森林边缘的灌丛、过熟的牧场和河岸森林。偏好较低的植被层，不依赖高大树丛的存在，但需有树木。迁徙性鸟类，夏季在欧洲西南部和北非繁殖，冬季迁至西非热带雨林北部的草原。","breeding":"繁殖期为5月至7月，一窝产3至5枚卵。巢由草、植物茎、柔软的枝条构成，外覆树皮碎片、地衣，以蛛丝粘合，内部铺垫细纤维、根、毛发等，置于树叉间，高度约0.5至5米。孵化期由雌鸟承担，持续12至13天；雏鸟由双亲喂养，约11至13天后离巢。","identification":"与绿篱莺相比，歌篱莺上体颜色更偏棕色，下体更偏黄色，翼较短，缺乏淡色斑块。鸣唱更流畅，持续时间较长，但变化较少，不含模仿声音。","protection":"IUCN：LC（无危）","distribution":"繁殖区域覆盖法国、伊比利亚半岛东至比利时南部、荷兰东南部、德国西南部、瑞士、意大利、斯洛文尼亚、克罗地亚西部、科西嘉岛，以及北非（摩洛哥北部、阿尔及利亚北部、突尼斯北部）。冬季迁至西非，从冈比亚和塞内加尔东至尼日利亚和喀麦隆。","other":"自1950年代以来，分布范围向北和向东扩展，数量增加。在比利时首次繁殖记录于1981年，德国（萨尔州）为1984年，荷兰为1990年。"},{"name":"绿篱莺","english_name":"Icterine Warbler","scientific_name":"Hippolais icterina","overview":"绿篱莺（英文名：Icterine Warbler，学名：Hippolais icterina），是雀形目苇莺科篱莺属的鸟类。在欧洲大陆广泛分布，除了西南部，那里由其近亲歌篱莺占据。绿篱莺是迁徙物种，冬季迁往撒哈拉以南非洲。","appearance":"绿篱莺是一种中等体型的莺，长约12.5至14厘米，体重11至16克。它具有尖尖的喙，较大的头部，前冠羽毛常竖立，尾巴看似短而方正。翅膀上有长的初级飞羽投影，占露出三级飞羽长度的四分之三以上。头顶和背部呈灰绿色，飞行羽和上翼覆羽颜色更深。边缘的三级飞羽和次级飞羽，以及在一定程度上的大覆羽，呈白色或淡色，形成闭合翅膀上的明显淡色面板。尾巴的所有羽毛都有薄薄的淡色边缘和尖端。喉咙和下体柠檬黄色，偶尔为较淡的黄奶油色。眼睛暗色，上喙灰色，下喙粉黄色，腿灰色，有时带有轻微的蓝色色调。两性相似，幼鸟的上体颜色略微带有褐色，淡色翼板呈黄灰色或淡绿色，下体通常比成鸟更淡，有时几乎是象牙白，没有明显的黄色。","call":"绿篱莺的鸣唱是一连串响亮且悦耳的尖锐或旋律性的音符，伴有巧妙的模仿其他鸟类的声音，通常能听到重复的鼻音'gih-e'，但也通过交织典型的三音节叫声来识别。叫声为欢快、音乐般的快速'tey-te-dwee'，也可单发'chek'，在警报时会发出一系列尖锐的音符'te-te-te-te-te-tek'。","habits":"绿篱莺栖息于高大的橡树、桦树、山毛榉、桤木和其他落叶树木组成的林地中，但也可见于大型公园和花园，以及混杂有硬叶树的年轻松树林中。偏好开阔森林或密集森林中交错的空地和灌木丛。在分布范围的北部为低地，在南部则可达海拔1500米的山地和山坡。它们是迁徙物种，主要迁徙到非洲南部的赤道以南地区过冬。","breeding":"繁殖期为5月末至7月，大部分在6月开始，通常是单窝繁殖。巢是一个精心建造的杯状结构，由草、植物茎、苔藓和柔软的小枝组成，经常覆盖着桦树皮碎片、地衣、花朵等，部分通过蛛丝粘附，内部衬有细纤维、根、毛发等软质材料。巢通常位于树枝的分叉处，离地面1至4米，有时高达7米。一窝产4-5枚卵，主要由雌鸟孵化，孵化期为12-14天；幼鸟由双亲喂养，大约在13-15天后离巢。","identification":"绿篱莺与歌篱莺的区别在于通常更明显的淡色翼板、较长的翅膀和略短的喙。此外，它的叫声和鸣唱特征也有助于辨别。","protection":"IUCN：LC（无危）绿篱莺在其分布范围内普遍常见，特别是在东欧的优质栖息地中相当常见。估计欧洲（不含俄罗斯）1990年代的种群数量为1,300,000至1,700,000对，其中超过500,000对在白俄罗斯，德国超过150,000对；在俄罗斯可能有3,000,000对或更多。自1970年代以来，瑞典的种群数量有所增加，分布范围略有扩大。","distribution":"繁殖区域：从斯堪的纳维亚和芬兰南部向东延伸至俄罗斯西部（鄂毕河东岸）和偶尔的哈萨克斯坦北部，向南至法国东北部、瑞士、罗马尼亚和巴尔干半岛北部（局部），乌克兰、克里米亚和阿佐夫海东部地区；以及里海南部的伊朗。越冬区域主要在南非。在欧洲中部、中北部至俄罗斯中东部和哈萨克斯坦北部繁殖，冬季迁徙至非洲南部。","other":"绿篱莺的学名''中的'icterina'源于希腊语'icterus'，意为'黄疸'，可能是因为其黄色的下体。"},{"name":"绿莺","english_name":"Green Hylia","scientific_name":"Hylia prasina","overview":"绿莺（英文名：Green Hylia，学名：Hylia prasina），是雀形目拟攀雀科绿莺属的鸟类。广泛分布于热带非洲的湿润森林中，主要栖息于林下层和中层。这独特的鸣禽，曾被暂归入Cettiidae科，但在2019年被明确分类至新设立的Hyliidae科。","appearance":"绿莺拥有深棕色的眼睛、黑色的喙和橄榄绿色的脚。体重约14克，雌雄颜色相似，但雄鸟体型稍大。有两种亚种：H. p. prasina和H. p. poensis，前者喉部和腹部为橄榄绿色，后者喉部和腹部为灰白色。","call":"其最显著的声音是清脆的双音哨声（kee kee）或干涩的责骂般的咔哒声（trrit trrrit），还有一种纯净的两音节歌声，用于警告附近有捕食者的短促叫声。","habits":"绿莺广泛分布于热带非洲，常见于森林边缘、植被间隙和森林内部，偏好完整的半落叶湿润森林。它们主要以树叶上的昆虫为食，通常在树冠和林下层觅食，高度约10米。","breeding":"绿莺通常单独或成对出现，成对时会在巢中一起栖息。巢呈卵圆形，顶部有圆孔，由松散的植物纤维构成，覆盖着细长的纤维条和偶尔的叶子骨架。巢通常建在离地面几英尺高的位置，如年轻棕榈树的垂直叉枝上。","identification":"与乌干达柳莺相比，绿莺体型更大，下体颜色更深。与其他类似莺鸟的区别在于暗色的下体。","protection":"IUCN：LC（无危）","distribution":"绿莺遍布热带非洲的西部和中部，其中亚种H. p. poensis仅分布于几内亚湾的岛屿上，而H. p. prasina从西非冈比亚至东非肯尼亚均有分布。"},{"name":"拟雀莺","english_name":"Tit Hylia","scientific_name":"Pholidornis rushiae","overview":"拟雀莺（英文名：Tit Hylia，学名：Pholidornis rushiae），是雀形目拟攀雀科拟攀雀属的鸟类。隶属于拟攀雀科（Hyliidae），为该科唯一物种。广泛分布于西非和中非的雨林地带，包括安哥拉、贝宁、喀麦隆、中非共和国等地。以其独特的外观和生态习性而闻名。","appearance":"拟雀莺长约8厘米，可能是非洲最小的本地鸟类。头部、颈部和胸部为淡黄褐色，带有深色条纹，自下胸至臀部呈鲜艳的柠檬黄色。背部和翅膀为橄榄绿色，逐渐变淡并带有条纹至头部。喙小而略向下弯曲，腿橙色鲜亮。幼鸟颜色较淡，条纹更细，容易在蜘蛛网中受困。","call":"发出高音的嘶嘶声和‘tsi-tsi-tsi’的叫声，鸣唱时由树冠深处传出，通常包含两段清晰的颤音，第二段比第一段更快，有时以两个摩擦音开头。","habits":"生活在低地常绿森林边缘，包括河流两岸和林间空地，海拔高度从海平面到1200米。偏好小群活动，最多七只一起，直接从一棵树飞向另一棵树。主要以小型昆虫为食，尤其喜爱鳞翅目昆虫。在中上层树冠觅食，偶尔降至较低位置。","breeding":"繁殖期为11月至4月，一夫一妻制。巢穴直径约15厘米，由柔软植物材料制成，入口朝下，位于3至20米高的树上。每窝产卵2枚，孵化和育雏期未知，有时四只成鸟共同喂养幼鸟。","identification":"与其他小型森林鸟类相比，拟雀莺的独特之处在于其前半身有条纹，后半身单一色彩，头部、脸部、喉咙和胸部为黑白条纹，腹部、臀部和臀羽明亮的柠檬黄色。","protection":"IUCN：LC（无危）","distribution":"分布在非洲西中部的雨林地带，包括安哥拉、贝宁、喀麦隆、中非共和国、刚果民主共和国、科特迪瓦、赤道几内亚、加蓬、加纳、几内亚、利比里亚、尼日利亚、塞拉利昂、多哥和乌干达。","other":"曾被归类于Cettiidae科，2019年研究支持其属于新设立的Hyliidae科。"},{"name":"北长尾山雀","english_name":"Long-tailed Tit","scientific_name":"Aegithalos caudatus","overview":"北长尾山雀（英文名：Long-tailed Tit，学名：Aegithalos caudatus），是雀形目长尾山雀科长尾山雀属的鸟类。又称长尾山雀，以其迷人的葡萄红、黑与白色羽毛和极长的尾羽著称。分布于欧亚大陆，自欧洲北部至中国东北部。成鸟头部白色，缺黑色眉纹，下体较白；亚成鸟头部两侧呈褐色，至冬季换羽为成鸟特征。","appearance":"体长13-16厘米，尾长占6-10厘米；体重6.2-10.4克。外形圆润，嘴短而钝，尾羽细长且显著。羽毛主要为黑白色调，夹杂灰色与粉色。成鸟头部、喉咙及大部分下体雪白，两胁至腹股沟粉嫩；上背黑色，下背混合黑、淡粉色至白色，肩羽及臀部微带粉色；尾羽黑色，最外侧尾羽大面积白色；飞羽深棕色，覆羽边缘及翼尖白色；虹膜暗榛色，眼睑黄至红色；喙黑色；腿黑褐。雌雄相似，亚成鸟比成鸟颜色更深，尾羽较短，白色部分染有褐色。","call":"高亢、清脆的‘see-see-see’叫声，尤其在飞行中或与群体分离时发出；还有‘tup’和‘tsirr’的警戒或兴奋叫声，冲突时叫声更响亮、有力。","habits":"栖息于林地、公园、花园和农田中的灌木丛；偏好河岸树林，地中海地区的灌木林和松树林。以昆虫为主食，偶尔食用种子、芽及果实。集群活动，形成稳定的家庭群落，参与混合物种的觅食群。叫声频繁，有助于定位和识别。","breeding":"繁殖期从中欧的3月至日本的6月，单窝产卵，每窝6-15枚，平均8-12枚。巢由苔藓、蛛网和毛发构成，覆盖数千片地衣，隐蔽于低矮的灌木丛或树叉中。雌鸟孵卵，雄鸟喂食，孵化期12-18天，幼鸟由双亲及帮手共同照顾。","identification":"与其他长尾山雀属成员相比，北长尾山雀头部特征明显，尾羽异常长。亚种间在羽色、条纹和体型上有细微差异。","protection":"IUCN：LC（无危）","distribution":"广泛分布于欧亚大陆，从欧洲北部到亚洲东部，包括中国东北部。在中国大陆，分布于森林生境，山地可达2000米，平原至1000米，冬季可能下降至较低海拔。","other":"银喉长尾山雀曾为其亚种。"},{"name":"银喉长尾山雀","english_name":"Silver-throated Bushtit","scientific_name":"Aegithalos glaucogularis","overview":"银喉长尾山雀（英文名：Silver-throated Bushtit，学名：Aegithalos glaucogularis），是雀形目长尾山雀科长尾山雀属的鸟类。小型、活跃，体长约16厘米，头部呈球状，尾羽修长。上体深色，下体色浅，喉部有明显的灰色斑块。分布于中国中部、东北部和中东部的温带森林中，特别是在长江与黄河中下游流域，以及云南横断山脉兰沧江沿岸的小型西南部栖息地。","appearance":"银喉长尾山雀体长约13至16厘米，尾长占6至10厘米，体重6.5至9克。身体圆润，喙短粗，尾羽细长。额部淡黄色，顶冠两侧有光泽的黑色条纹，中央冠纹和颈背淡黄色，可能带有黑色斑点。上体中到深灰色，臀部有窄粉色带，肩羽尖端黑色。尾羽黑色，外侧尾羽外缘白色，内侧尾羽边缘灰色。翼上覆羽黑褐色，初级覆羽边缘黑色，次级覆羽和三级飞羽边缘稍浅。脸颊、耳羽淡灰色，喉部深灰色，胸部淡灰色至黄灰色，腹部更白，两胁、腹下和尾下覆羽淡粉色。虹膜榛色，喙和腿灰黑色。雌雄相似，幼鸟下巴、喉部和胸部酒红色，与白色髭纹区和颈部形成对比，其余下体黄色，肩羽和上翼覆羽有淡色边缘。","call":"发出高音、清脆而穿透力强的“see-see-see”或“see-see-see-sit”的叫声，以及更大声、滑音的“tsirrrup”。叫声类似于北长尾山雀。","habits":"栖息于山地针叶林或针阔混交林中。繁殖期外，结成小群至大群，常见于树冠或灌丛顶部，以空中捕食昆虫为主。食物中95%为害虫，如落叶松鞘蛾、天蛾、尺蠖蛾、蚜虫和象鼻虫，对林木保护有益。","breeding":"繁殖季节为3月至4月，巢建于落叶松枝杈间，每窝产卵6至10枚，卵白色点缀淡红褐色小斑，钝端密集。雌鸟负责孵卵。雏鸟离巢后，亲鸟在巢区内带领多次飞行后，才离开巢区。巢由至少1000根羽毛构成，有时多达2000根，视筑巢位置而定。","identification":"与北长尾山雀区别在于喉部的灰色斑块，以及羽毛颜色的差异。","protection":"IUCN：LC（无危）","distribution":"分布于中国中部、东北部和中东部，包括长江与黄河中下游流域，以及云南横断山脉兰沧江沿岸。在陕西秦岭山区可达海拔1700米，在甘肃可达2925米，在青海可达3020米。南方分布可能限于山区，四川北部可达2590米，云南至少可达3050米。","other":"曾被认为是北长尾山雀的亚种，现已独立。"},{"name":"白颊长尾山雀","english_name":"White-cheeked Bushtit","scientific_name":"Aegithalos leucogenys","overview":"白颊长尾山雀（英文名：White-cheeked Bushtit，学名：Aegithalos leucogenys），是雀形目长尾山雀科长尾山雀属的鸟类。小型鸟类，以其独特的黑色喉部、棕色头冠和黑色眼罩而著称。广泛分布于阿富汗东北部至巴基斯坦北部的开放木林和干燥灌木森林地带。","appearance":"这种小鸟体型娇小，头部较大，喙短，尾巴较长。其显著特征包括白色的颊斑和黑色的喉咙，前额和头顶中部为肉桂色，后部略带橄榄棕色。眉线和环绕眼睛的窄带至颈侧为黑色，但眼后界线模糊，耳羽上部转为灰褐色。脸颊和下耳羽白色，延伸至颈部形成半领状。上体和翼覆羽为淡灰橄榄色，飞羽和尾羽为中至深棕色，初级飞羽边缘较浅（灰橄榄色），最外侧两根尾羽尖端宽幅白色。下巴和喉咙黑色，下缘微带紫红色。上胸部淡灰色，下胸部至腹部逐渐变为暗淡的赭色；胁部和臀部呈淡粉色；虹膜为稻草黄色或灰黄色；喙黑色；腿为淡橙棕色或粉棕色。幼鸟的头冠稍显苍白和更带黄色调，面部暗带略窄，上体颜色更暗淡和偏棕色，颊斑和喉咙淡黄色，胸侧为暗肉桂棕色，其余下体呈淡粉色，上胸可能带有深棕色条纹。","call":"白颊长尾山雀的叫声多样，包含刺耳的断续声、尖锐的吱吱声、颤音和细哨声。联系叫声为连续的“si-si-si-si”，有时结尾略带滑音或轻柔的“si-si-si-si'sisip”。还会发出短促干燥的“tup”或“tep”，穿插着较细的“seeup”或“tsreet”声，以及硬朗、爆炸性的滑音颤音“trrrt”或“trrrp”。此外，它会发出一系列混乱的甜美、吱吱响和婉转动听的音符，但似乎缺乏真正的领域歌曲。","habits":"它们主要栖息在干燥的灌木林和针叶林中，如冬青栎、杜松和松树林，海拔高度在1500-3660米之间繁殖，非繁殖季节则下降至500-2100米，偶尔会在农田边缘、荆棘灌丛和河岸柽柳中活动。白颊长尾山雀以昆虫和蜘蛛为主食，通常在灌木层中觅食，也会在冬青栎树冠和成熟的杜松树中寻找食物。成对出现，从晚夏到次年4月中旬，它们会形成6-12只的小群体，常加入混种觅食群。","breeding":"繁殖季节为3月末至5月。双方共同收集筑巢材料，巢呈竖直椭球形，约110×85毫米，侧面近顶部有入口，由苔藓、草、植物纤维等编织而成，用蛛网加固并内衬羽毛，离地面1-3.5米，通常位于荆棘灌丛、矮冬青栎或杜松中。每窝产5-8枚卵，白色，有时大端有轻微的粉红斑点，尺寸约为14.7×9.9毫米。孵化和育雏期间的信息未知，但双亲都会喂养幼鸟，幼鸟离巢后至少14天仍依赖父母。","identification":"与红头长尾山雀的区别在于头冠较暗淡，缺少白色眉线，头部两侧的黑色带较窄，下巴黑色（围嘴因此延伸至喙），下体颜色较淡且更暗淡；与白喉长尾山雀的区别在于额头和前冠部暗淡和黑色围嘴。雌雄外观相似。","protection":"IUCN：LC（无危）","distribution":"白颊长尾山雀主要分布在阿富汗东北部（努里斯坦，南至萨法德科赫），以及巴基斯坦北部，从奇特拉尔向南至俾路支省北部（兴格尔山脉和齐阿拉特），向东至吉尔吉特、巴尔蒂斯坦、哈扎拉、印度河科希斯坦（帕拉斯谷）和伊斯兰堡附近的玛加拉山丘。"},{"name":"红头长尾山雀","english_name":"Black-throated Bushtit","scientific_name":"Aegithalos concinnus","overview":"红头长尾山雀（英文名：Black-throated Bushtit，学名：Aegithalos concinnus），是雀形目长尾山雀科长尾山雀属的鸟类。俗名: 小老虎、红宝宝儿、红顶山雀、红白面只，直译: 黑喉长尾山雀，小型山林留鸟，体长约为10.5厘米，体重4-9克。头部由橙色、黑色和白色组成，具有独特的黑喉和眼罩。分布于喜马拉雅山脉至越南南部，主要栖息于山地森林和灌木林间，偶尔出现在人类居住地附近的果园、茶园等地。","appearance":"成鸟头部圆润，具明显的黑色喉咙和眼罩，与黄色眼睛形成鲜明对比。背部灰暗，两翼和尾部深灰，腹部白色，两胁带有锈红色。幼鸟头顶灰色，喉部白色，缺乏成鸟的黑色特征。不同亚种在羽色上有细微差别，如印度支那种群有灰色冠羽，喜马拉雅种群有白色的眉斑。雄雌外观相似。","call":"发出尖锐的‘tsip’声和细长的颤音，用于群体间的联系。","habits":"栖息于开阔的阔叶林和松树林，通常在中海拔地区活动。高度社交，结成多达40只的大群，活跃于枝叶间寻找昆虫、蜘蛛、小种子、果实和浆果，尤其是覆盆子。非繁殖季节群体会增大，加入混合物种觅食群。","breeding":"繁殖期相对较早，一般在3月至5月，有时延续到6月。单窝繁殖，有时有1-2个帮手参与喂养。巢呈椭圆形，由苔藓、地衣、根须、树皮碎片、毛发、蜘蛛卵囊和植物纤维编织，内衬羽毛、羊毛、兽毛或植物绒毛。巢位于离地面3米左右的树枝叉或环绕几根小枝，偶尔高达12米。每窝产卵3-8枚，白色或淡粉色，带有红褐色细点，孵化期约14-16天。雏鸟由双亲共同喂养，离巢前依赖父母至少十天。","identification":"与其他长尾山雀属鸟类区分在于其独特的黑喉和眼罩，以及胸部的锈红色带。不同亚种在羽色上有所不同，如帽羽颜色和腹部色调。","protection":"IUCN：LC（无危）","distribution":"分布于喜马拉雅山脉至越南南部，包括印度北部、孟加拉国东北部、尼泊尔、不丹、缅甸北部、越南和中国。在中国，分布于长江以南地区，直至黄河流域，以及台湾。","other":"红头长尾山雀在4-8月间主要以昆虫为食，占其食物的99%，在森林生态系统中扮演重要角色，有助于控制害虫数量。"},{"name":"白喉长尾山雀","english_name":"White-throated Bushtit","scientific_name":"Aegithalos niveogularis","overview":"白喉长尾山雀（英文名：White-throated Bushtit，学名：Aegithalos niveogularis），是雀形目长尾山雀科长尾山雀属的鸟类。小型鸟类，以其独特的白色额头、喉咙和半颈环著称，眼睛呈深色，分布于喜马拉雅山脉西北部的印度、尼泊尔和巴基斯坦。","appearance":"体型极小，平均体重约7.8克，长尾显著。头部较大，前额、喉部及部分颈环白色，头顶中央至颈背呈肉桂棕色，眼先、颊部及头侧黑色，后头至耳羽处肉桂棕色，上体灰至中灰色，臀部有窄粉色带，大覆羽及飞羽暗灰褐色，边缘浅灰，尾羽暗灰褐色，外缘灰色，最外三对尾羽尖端白色，下体浅灰至淡粉棕色，胸带狭窄而明显，虹膜淡至深棕色，喙黑至暗灰色，腿肉黄色至棕色。幼鸟的冠纹较暗，前额沾黄，上体更偏棕色，下颚及喉部颜色较淡，胸带不规则且对比度较低。","call":"发出一系列高音金属调、叽喳声和干涩颤音，包括细薄高音‘tsi-tsi-tsi’、柔和的‘pit’声，兴奋时会发出响亮、急促的下降颤音‘tsirrrrr’。","habits":"栖息于灌木丛如刺柏、玫瑰、柳树、杜鹃花等周边的针叶林、混合桦树云杉林及橡树林边缘地带，春季和初夏以成对形式活动，其余时间通常组成小群，多达20只，参与多种混群觅食。主要以昆虫、昆虫幼虫、蛹及蜘蛛为食，也可能摄取花蕾。在较高海拔地区繁殖，接近林线，冬季则下降至较低海拔。","breeding":"繁殖期在5月至6月，巢呈椭圆或梨形，由苔藓和蛛网构成，外表覆盖地衣，内部密集羽毛，入口位于一侧上方，置于树或灌木叉枝1-3米高处，悬挂于高达10米的树枝上。已知一窝含4枚卵，卵白色，宽端有粉色细斑点，尺寸约为14.2×11毫米。","identification":"与白颊长尾山雀、红头长尾山雀和棕额长尾山雀相比，白喉长尾山雀具有白色喉部、半颈环、前额和前冠，以及深色眼睛。","protection":"IUCN：LC（无危）。在巴基斯坦罕见且分布零散，在印度不常见至局部常见，在尼泊尔总体稀少且分布零散，但在朗谷（西尼泊尔）局部常见。","distribution":"分布于喜马拉雅山脉西北部，具体包括巴基斯坦东北部（帕拉斯、坎迪亚山谷、卡甘山谷和尼尔姆山谷）、克什米尔东部至印度北部（喜马偕尔邦、北阿坎德邦）和尼泊尔西部（东至多尔波和道拉吉里山脉西北侧，偶尔至加利甘达基河谷东侧，单次报道来自戈萨因孔德）。"},{"name":"棕额长尾山雀","english_name":"Rufous-fronted Bushtit","scientific_name":"Aegithalos iouschistos","overview":"棕额长尾山雀（英文名：Black-browed Bushtit，学名：Aegithalos iouschistos），是雀形目长尾山雀科长尾山雀属的小型鸟类。体型纤小，尾特长大而层次分明，额与后颈中央呈肉桂色，头顶具淡肉桂-皮黄色冠纹，头侧自眼先至上耳羽为亮黑色，下耳羽、颊及颈侧肉桂-皮黄，喉胸银灰而腹转为肉桂-红褐色，极为醒目。分布于东起尼泊尔中部，沿喜马拉雅南坡狭窄带状延伸至不丹，并北扩至西藏东南部易贡藏布和波藏布流域，亦见于缅甸西南钦山及中国川滇黔相邻高山。","appearance":"体长约11厘米，体重6–7.5克，体态与同属其他长尾山雀一致，尾长而渐尖。额、头顶前部及后颈中央呈鲜明的肉桂色；宽阔冠纹较淡，为肉桂-皮黄色；头侧自眼先至耳覆羽亮黑色，下延至颈侧；下耳羽、颊及颈侧肉桂-皮黄；一条细窄的锈红色颚纹伸向胸侧。上体暗中等灰色，腰羽略泛粉红；大覆羽及飞羽暗灰褐，羽缘中灰；尾羽暗灰褐，外侧三对羽端色浅。颏及喉侧黑色，形成模糊的倒“V”形；喉及胸中央银灰色，其余下体肉桂-红褐色。虹膜黄白至柠檬黄；喙黑色；腿黄褐至暗褐色。两性同色。幼鸟冠纹更淡，头侧黑色暗淡，颚纹及耳羽淡粉红-皮黄，颈侧及整个下体污淡皮黄，腹与尾下覆羽肉桂-皮黄，具暗灰色斑驳，胸部尤甚。","call":"叫声丰富，包括高而细的“si-si-si”、单声尖锐似虫鸣的“tsit”、短促的“chip”、吱吱的“ip, ip…”及爆发式、带颤音的“trrrrp”。觅食时群体成员常同时发出多种叫声。","habits":"栖息于温带山地森林边缘、林隙及灌丛，主要树种有栎、杜鹃、栲、松、云杉及铁杉，高海拔处亦见于树线以上灌丛，特别是河谷灌丛。西藏东南部生境自干旱灌丛坡至密林皆有。海拔分布：喜马拉雅2200–3770 米，中国西南至少2745–3505 米；繁殖后少量向下扩散，冬季仅在暴雪时短暂降至较低海拔；锡金冬季记录2745–3720 米，极端天气可降至2440 米；不丹夏季上限3400 米，11月中至3月中常降至3200 m以下。几乎不与红头长尾山雀同海拔重叠。以昆虫及其卵、幼虫为主，兼食少量植物性食物；在林冠及灌木层觅食，非繁殖季可结成40只左右大群，常加入混合觅食群，但较同属更常见单种群活动。","breeding":"繁殖期3–7月，群体分散成对。4月7日及5月4日已见衔巢材，不丹5月24日雌鸟输卵管已具卵，5月至6月初见雏鸟；中国西南5月25日仍在筑巢。巢呈球形，侧开口，外覆地衣、内衬羽毛，置于橡树或高枝冷杉、松枝末端。双亲共同饲喂雏鸟，幼鸟能飞即重新合群。","identification":"与红头长尾山雀相比，本种头侧黑色区更大，冠纹淡色而无白色眉纹，无黑色胸兜；与白喉长尾山雀相比，冠纹肉桂-皮黄而非白色，头侧黑色范围大，喉部仅一小块银灰，下体肉桂-红褐色且无深色胸带。种内目前无亚种分化。","protection":"IUCN: NE（未评估）","distribution":"繁殖区：尼泊尔中部及东部沿喜马拉雅南坡狭窄带状向东至不丹，并北伸至西藏东南部易贡藏布与波藏布流域，可能达印度东北部。缅甸西南钦山维多利亚山及敏达一带。中国境内见于西藏东南部、四川中西部、云南西北部、贵州威宁地区和四川中部汶川以北山地。非繁殖季仅进行有限的垂直迁移。","other":"系统分类上，曾基于基因研究建议将本种与黑眉长尾山雀、银脸长尾山雀合并为一，但由于羽色差异显著，银脸长尾山雀目前仍视为独立种，而黑眉长尾山雀则作为亚种。"},{"name":"黑眉长尾山雀","english_name":"Black-browed Bushtit","scientific_name":"Aegithalos bonvaloti","overview":"黑眉长尾山雀（英文名：Black-browed Bushtit，学名：Aegithalos bonvaloti），是雀形目长尾山雀科长尾山雀属的鸟类。小型长尾山雀科鸟类，分布于中国中南部至缅甸东北部。其独特的黑色宽眉纹覆盖头部，仅在头顶中央留有一道棕色条纹，使金黄色的眼睛尤为突出。与近似种黑头长尾山雀相比，黑眉长尾山雀下胸及腹部为白色。","appearance":"黑眉长尾山雀体型纤小，约11-12厘米长，尾部较长。上体灰色，胸部和两侧呈红褐色，腹部白色。头部呈淡色，具有显著的黑色宽眉纹，覆盖大部分头部，仅留头顶中央一条棕色带。面部有白色前额和胸前白色斑块，中央散布黑色斑点。不同亚种之间颜色深浅有所差异。","habits":"黑眉长尾山雀通常结群活动，常在小树和林下植被层中觅食。它们的栖息地包括温带森林和北方森林。在中国中南部和缅甸东北部有分布，与黑头长尾山雀的分布不重叠。","identification":"黑眉长尾山雀与黑头长尾山雀的主要区别在于头部的颜色模式，前者下胸及腹部为白色，而后者为棕褐色。此外，黑眉长尾山雀的黑色眉纹更加显著，覆盖了大部分头部。","distribution":"黑眉长尾山雀的分布范围包括中国中南部以及缅甸东北部，主要栖息在温带和北方森林中。","other":"现为棕额长尾山雀亚种。"},{"name":"缅甸长尾山雀","english_name":"Burmese Bushtit","scientific_name":"Aegithalos sharpei","overview":"缅甸长尾山雀（英文名：Burmese Bushtit，学名：Aegithalos sharpei），是雀形目长尾山雀科长尾山雀属的小型鸟类。原被视为黑眉长尾山雀的亚种，现今确认为独立物种，主要分布在缅甸西南部的Chin Hills。","appearance":"具体外形特征资料不详，但作为长尾山雀属的一员，一般具有细长的尾巴和活泼的体态，羽毛色彩可能以淡褐色为主调，具有一些独特的斑纹或条纹。雄鸟、雌鸟和幼鸟之间的具体差异尚未详细描述。","habits":"生活在温带森林环境中，其活动习性和食物偏好等生活细节有待进一步研究。推测可能以昆虫和其他小型无脊椎动物为主要食物来源，栖息于树冠层。","identification":"与同属其他长尾山雀种类的区别特征不详，可能通过其分布区域、叫声或某些特定的羽毛颜色模式进行辨识。","protection":"IUCN状态未知，但鉴于其分布局限，可能面临一定的生存威胁。","distribution":"主要分布于缅甸西南部，具体为Chin Hills一带。","other":"现为棕额长尾山雀亚种。"},{"name":"银脸长尾山雀","english_name":"Sooty Bushtit","scientific_name":"Aegithalos fuliginosus","overview":"银脸长尾山雀（英文名：Sooty Bushtit，学名：Aegithalos fuliginosus），是雀形目长尾山雀科长尾山雀属的鸟类。为中国中北部特有种。其显著特征为巧克力棕色的胸部与鲜明的白色颈环，分布于中国中部山区，如甘肃南部至四川中部及东北部，陕西南部（秦岭山脉），湖北西部及湖南西北部的石门县附近。","appearance":"该鸟体长约11.5厘米，体重4至8克。上体呈棕色，面部有银灰色斑块，胸带深色明显。头部前额、头顶中央及颈背为暗棕色，侧面较灰；面颊及眼眉区为霜状淡灰色，与棕色颈背形成对比。上体及上翼为暗棕色，臀部偏粉色。尾巴暗棕色，最外侧3至4对尾羽尖端白色，最外侧尾羽外缘白色；喉咙淡灰色，下界为白色颈部及上胸，再往下是宽广的棕色胸带；腹部白色，后腹及臀部粉红色，两侧及肛周可能有棕色或肉桂色斑点，尾下覆羽为棕色与白色混杂。虹膜白色、黄色或黄棕色，喙及腿黑色。雄雌相似，幼鸟头部前额及头顶中央白色，侧冠较暗，脸颊淡灰色，眼后有黑楔，喉咙更纯白，胸带较深，下体余部近白色，缺乏侧腹的粉色。","call":"发出高音、纯净而尖锐的‘see-see-see’联系叫声，以及饱满、短促的‘tup’声，通常穿插单一高音‘tsip’音符；还会发出爆破、滑音、噼啪的‘tchrrrup’声，略显粗糙。","habits":"栖息于混合林中的冷杉（Abies）、沿水道生长的柳树（Salix）和桦树（Betula）落叶灌木丛，以及杜鹃花（Rhododendron）和广泛的竹子下层植被；偏好温带区域的较低地带，可能仅在非繁殖季节延伸到亚热带区域。记录高度约1000至2600米，冬季集中于海拔较低区域。以昆虫和浆果为食，于灌木层觅食。非繁殖季节（自六月起）成群快速移动，曾记录多达40只一起活动。","breeding":"推测在五月中期于四川九寨沟喂养雏鸟，具体繁殖信息尚缺。","identification":"与黑眉长尾山雀的区别在于较为暗淡的棕色胸带和侧面，银色面颊斑块，以及缺乏喉部的暗‘V’形标记和大胆的黑色面具；与红头长尾山雀的区别在于缺乏黑色面具和喉部标记。","protection":"IUCN：LC（无危）。分布范围有限，位于中国中部山区。一般较为罕见，但在陕西南部太白山相对常见。全球分布面积约2万至5万平方公里。","distribution":"繁殖于中国中北部山区，包括甘肃南部至四川中部及东北部，陕西南部（秦岭山脉），湖北西部及湖南西北部的石门县附近。","other":"银脸长尾山雀在繁殖季开始于3月至5月，筑巢于树枝间，多选择背风处。巢材包括苔藓、地衣、树皮及羽毛，有时使用鳞翅目昆虫茧丝加固巢穴。巢建于柳树、松树、茶树或竹林间，一窝产卵6至8枚，卵色粉红或白色，带有红褐色斑点，平均大小15×12毫米。"},{"name":"侏长尾山雀","english_name":"Pygmy Bushtit","scientific_name":"Aegithalos exilis","overview":"侏长尾山雀（英文名：Pygmy Bushtit，学名：Aegithalos exilis），是雀形目长尾山雀科长尾山雀属的最小成员。仅见于印尼爪哇岛的山区，分布于海拔1000米以上的森林与种植园，偶尔降至830米。体长8.5至8.7厘米，为最小的鸣禽之一。","appearance":"体态极小，呈圆灰状，头部暗灰带红褐色调，上体中灰微褐，臀部纯灰；尾羽灰褐，颏喉浅灰，边沿与胸前有淡粉棕斑点；侧胸、上胁及胸部细带灰褐，其余下体淡粉棕；虹膜黄白至白色，嘴角质灰、深褐或黑，腿肉黄或黄。","call":"发出尖锐的‘tsi-tsi-tsi-si-sisi’声，音调渐弱，还有饱满的‘chut’和急促的‘trrrt’颤音，类似同属其他种类的声音。","habits":"活跃于森林上层，常结小群活动，以昆虫为主食，包括蚜虫和毛虫，以及小型蜘蛛；低空觅食，居留性鸟种。","breeding":"繁殖期为3月至5月，8月至11月。筑悬吊式袋状巢，高8至17厘米，直径6至8.5厘米，以叶草制成，内衬苔藓，入口近顶，深3至5.5厘米，离地面3至8米，巢室隐蔽。每窝产2至3枚蛋，白色带细红斑，尺寸11.8至13.4×9.3至10.6毫米。","identification":"长尾山雀属中体型最小，尾羽较长，嘴短而宽基，与同属物种相比，其体型和叫声有明显差异。","protection":"IUCN：LC（无危）","distribution":"分布于爪哇岛的西部和中部山区，包括Gunung Gede-Pangrango国家公园。","other":"曾被归入独立的Psaltria属，后根据分子系统发育研究归入Aegithalos属。"},{"name":"花彩雀莺","english_name":"White-browed Tit-warbler","scientific_name":"Leptopoecile sophiae","overview":"花彩雀莺（英文名：White-browed Tit-warbler，学名：Leptopoecile sophiae），是雀形目长尾山雀科雀莺属的小型鸟类。其特征为胸部栗色帽，淡粉色腹部，以及并不总是显著的浅灰色眉纹。分布于中国、印度、哈萨克斯坦等国，主要栖息于高海拔森林和灌木丛。","appearance":"体型极小，长8.5至10厘米，重6至8克。雄鸟色彩鲜明，有紫蓝和淡紫色斑块。头部具浅黄白色眉毛，上体淡灰，翼覆羽和飞羽暗灰棕色，边缘略浅，下体从喉部至腹部呈淡白色至淡褐色，腹部中央和下胸淡白色，两胁和腹侧有淡紫色亚端斑和更鲜艳的紫蓝色尖端。雌鸟较雄鸟暗淡，眉毛更宽，下体淡棕灰色。幼鸟类似成鸟，但羽毛更柔软、暗淡。","call":"发出清脆响亮的鸣叫声，通常是成对出现，叫声为刺耳的‘sirrrrr’声。","habits":"栖息于高山森林、灌木丛和密林地带。在繁殖季节外，会结成群体。在冬季，它们会下移到较低海拔的丘陵地带。以小昆虫和蜘蛛为主食，也会摄取少量种子和浆果。","breeding":"繁殖期在5月至6月中旬，可能有替换窝蛋直到7月末。巢由两性共同建造，通常位于灌木丛中，离地面约0.5至1.9米。每窝产4至8枚白色带红棕色斑点的蛋，孵化期14至17天。幼鸟在18至20天后离巢，但仍会在附近活动。","identification":"与冠雀莺的区别在于缺乏明显的淡色头部。雄鸟有栗色帽和浅黄白色眉毛，雌鸟的眉毛更宽，下体颜色较暗淡。","protection":"IUCN：LC（无危）","distribution":"繁殖于中亚、喜马拉雅山脉及中国中南部。在中国，分布于甘肃南山海拔3000至3600米的亚高山带，青海西宁地区海拔2700至2600米，西藏海拔3500至5000米。","other":"冬季会下移到低至海拔1800米左右，偏好河谷底部的灌木丛。"},{"name":"凤头雀莺","english_name":"Crested Tit-warbler","scientific_name":"Leptopoecile elegans","overview":"凤头雀莺（英文名：Crested Tit-warbler，学名：Leptopoecile elegans），是雀形目长尾山雀科雀莺属的鸟类。小型鸟类，雄鸟具金属蓝绿翼、银白长冠羽及锈红色面颈，雌雄均具桃红腰侧。分布于中国中部及青藏高原东缘海拔2600–4300米的针叶林与高山灌丛，冬季有短程垂直迁移，常与山雀等混群觅食昆虫。","appearance":"体长约10厘米，雄鸟体重8克。雄鸟头顶具银白丝状短冠羽，冠后羽延长成尖细白端冠；颈侧、胸侧及耳羽锈红；上背靛蓝至蓝黑，腰及尾上覆羽具宽阔绿松石色羽端；尾羽深灰，羽缘闪金属蓝绿；翼覆羽及飞羽橄榄褐，外侧大覆羽及初级飞羽基部缘天蓝色；喉胸肉桂色，腹淡皮黄，下体侧染深紫红；虹膜宝石红，喙黑，足褐。雌鸟黯淡，头颈灰具淡紫洗染，冠羽白端较短；上体灰褐，腰天蓝；翼及尾羽褐而缘淡蓝；喉胸灰白，腹及胁褐并带淡紫；虹膜、嘴、足同雄。雄幼似雌，但冠羽更长白端更宽，腰蓝较暗淡，胁紫较显；雌幼更黯淡。","call":"发出极细而哀婉的下滑“pseee”，与Sophia雀莺相似；另有柔和“dep”声及尖锐单音，类似鹪鹩；其余叫声使人联想到戴菊。","habits":"夏季栖息于海拔约3400–4300米的针叶林，尤喜云杉；非繁殖期可见于桧柏、杜鹃等灌丛，可降至2600–3900米。常与其他小型山雀如Sophia雀莺、戴菊、褐头山雀等混群觅食。觅食方式似戴菊在树梢活动，亦似䴓沿细枝攀爬，食物为昆虫。","breeding":"繁殖资料极缺。曾见巢置于距地约15米的针叶树上，四月下旬雌雄共同衔取蓝马鸡羽毛等巢材，似用于巢内衬垫。","identification":"与同属花彩雀莺相比，本种雄鸟具明显银白冠羽及锈红颈侧，腰侧桃红更为显著；雌鸟头灰而非棕褐，腰蓝明显。","protection":"IUCN: LC（无危）。总体数量不常见，全球不受威胁；最西北印度地区的分布需进一步调查。","distribution":"繁殖区域：青海中部及东部、内蒙古南部（阿拉善山、贺兰山）、宁夏贺兰山、甘肃南部祁连山以南，至西藏东南部及四川西部、中部。非繁殖期：同域内向下垂直迁移。曾于印度东北麦克马洪线记录，可能为留居种群。","other":"曾将西藏理塘以南马拉什地区的个体命名为亚种meissneri，现已视为与指名亚种无法区分，故视为单型种。"},{"name":"短嘴长尾山雀","english_name":"American Bushtit","scientific_name":"Psaltriparus minimus","overview":"短嘴长尾山雀（英文名：American Bushtit，学名：Psaltriparus minimus），是雀形目长尾山雀科短嘴长尾山雀属的鸟类。北美唯一长尾山雀科代表，体型微小，羽色灰褐，尾长，具社会性。分布于北美西部和中美洲高地，常以群居形式出现，数量可达40只以上，偏好橡树林松林混合环境。","appearance":"体长约4.3英寸，体重约0.18-0.21盎司，羽毛呈灰褐色，头大，颈短，尾长，喙短而钝。雄鸟具深褐色至黑色眼睛，雌鸟眼色偏黄。沿海个体冠部棕色，内陆个体面部有棕色或黑色面具。","call":"持续发出轻柔的叽叽声和清脆的铃音，无明显歌曲。","habits":"栖息于混合开放林地，含橡树和灌木丛。常见于花园和公园。以小型昆虫和蜘蛛为主食，参与混合物种觅食群体。海拔适应范围广泛，从海平面到10,000英尺以上。","breeding":"繁殖期筑巢由雌雄共同完成，历时长达一个月。巢悬挂在树上，内部有孵化孔。孵化期11-13天，双亲共同育雏，每年可育1-2窝，老兄妹可能协助喂养新出生的小鸟。","identification":"与其他长尾山雀科物种相比，体型较小，羽毛颜色较暗淡，尾长，喙短。部分区域雄鸟面部有黑色面具，雌鸟为棕色面具。","protection":"IUCN：LC（无危）","distribution":"繁殖区主要位于加拿大西南部至危地马拉，包括美国西部和中美洲高地。非繁殖区分布相似。","other":"曾因黑色耳罩特征被分为两个物种，现已确认为同一物种内的变异。"},{"name":"黄喉柳莺","english_name":"Yellow-throated Woodland Warbler","scientific_name":"Phylloscopus ruficapilla","overview":"黄喉柳莺（英文名：Yellow-throated Woodland Warbler，学名：Phylloscopus ruficapilla），是雀形目柳莺科柳莺属的小型鸟类。其特征是上体呈绿色，具有醒目的黄色喉部和眼纹。分布于非洲东部及南部，包括Eswatini、Kenya、Malawi、Mozambique、South Africa、Tanzania、Zambia和Zimbabwe。","appearance":"黄喉柳莺是一种小型的柳莺，上体颜色为绿褐色，最显著的特征是其黄色的喉部和眼纹。头部颜色因地理位置而异，可能呈现红褐色或绿色。腹部灰色，与鲜艳的黄色领形成鲜明对比。雌雄鸟在外观上相似，幼鸟的特征需进一步研究确认。","call":"其歌声悦耳，由上下起伏的哨音组成，但具体声音模式会有所变化。","habits":"黄喉柳莺偏好湿润的森林环境，尤其在远离南非的山区森林中更为常见。它们活跃于树冠层，以昆虫为食。","breeding":"关于繁殖行为的详细信息尚不充分，但已知它们在适宜的季节进行繁殖，具体细节需进一步观察。","identification":"红褐色头冠的个体容易识别，而绿色头冠的个体可能与其它柳莺混淆。关键的辨识特征在于其灰腹与亮黄色喉部形成的对比。","protection":"IUCN：LC（无危）","distribution":"分布在非洲东部和南部，包括Eswatini、Kenya、Malawi、Mozambique、South Africa、Tanzania、Zambia和Zimbabwe。"},{"name":"劳氏柳莺","english_name":"Laura's Woodland Warbler","scientific_name":"Phylloscopus laurae","overview":"劳氏柳莺（英文名：Laura's Woodland Warbler，学名：Phylloscopus laurae），是雀形目柳莺科柳莺属的鸟类。中等体型的旧世界欧柳莺。其特征为绿色调的外观，亮黄色的喉咙、眉纹和腹部下方，以及淡色的腹部。分布于非洲中南部，栖息于亚热带或热带的干燥森林和沼泽地带。","appearance":"劳氏柳莺呈现绿色调的羽毛，具有鲜明的黄色喉咙、眉纹和腹部下侧，以及较淡的腹部。东部个体颜色比西部的更为鲜艳。幼鸟比成鸟更暗淡，上部羽毛带有褐色色调。成年雌雄鸟外观相似。","call":"劳氏柳莺的鸣唱独特而悦耳，由一系列5至8个有规律重复的音节组成，如“pri-chi-rri, pri-chir-ri, pri-chi-ri”或“twi-li, twi-li-twi-li”。","habits":"劳氏柳莺居住在沼泽和孤立的常绿森林斑块中，通常在森林中层到树冠层捕食昆虫，偏好边缘和空旷地带。它们在米奥姆博林地中是不显眼的居民。","breeding":"有关劳氏柳莺的繁殖习性的具体信息未详述。","identification":"劳氏柳莺与迁徙的欧柳莺相比，后者颜色更暗淡，缺乏清晰的黄色喉咙和白色腹部界限。劳氏柳莺与非洲其他本地木莺无重叠分布。","protection":"IUCN状态未知。","distribution":"劳氏柳莺分布在非洲中南部，具体包括安哥拉、刚果民主共和国、坦桑尼亚和赞比亚。","other":"劳氏柳莺的历史分类学信息未在此处提供。"},{"name":"红脸柳莺","english_name":"Red-faced Woodland Warbler","scientific_name":"Phylloscopus laetus","overview":"红脸柳莺（英文名：Red-faced Woodland Warbler，学名：Phylloscopus laetus），是雀形目柳莺科柳莺属的鸟类。具有鲜明的红脸特征，分布于高海拔森林中，特别是在竹林环境。","appearance":"这是一种小型而美丽的柳莺，上体呈绿色，脸部和喉咙呈现红色，腹部为白色。其体型中等，约11厘米长，拥有绿褐色的上羽，下体较淡，腹部和臀部为偏白的色调。","call":"其特有的鸣唱由高低交替的“spit”音符组成，形成一种较为松散的颤音。","habits":"红脸柳莺栖息于山地森林中，活跃于林冠层，偏好竹林环境。它们通常成双成对或加入小群觅食，主要以昆虫和其他无脊椎动物为食。","breeding":"关于繁殖生物学的信息有限，但已知的是它们会在藤蔓丛中的灌木或树木上建造球状巢，离地面可达10米，每窝产两到三枚蛋，由双亲共同抚育幼鸟。","identification":"与褐林柳莺相似，但腹部颜色更浅，脸部和喉咙的红色更加明显。","protection":"IUCN：LC（无危）","distribution":"分布于非洲中东部，具体包括乌干达西部、刚果民主共和国东部（鲁文佐里山脉）、西南乌干达、卢旺达西部和布隆迪西部，以及刚果民主共和国东部的卡博博山。","other":"形成了一个超物种复合体，与黄色喉部的柳莺和劳拉的柳莺密切相关。"},{"name":"黑顶柳莺","english_name":"Black-capped Woodland Warbler","scientific_name":"Phylloscopus herberti","overview":"黑顶柳莺（英文名：Black-capped Woodland Warbler，学名：Phylloscopus herberti），是雀形目柳莺科柳莺属的鸟类。是非洲中西部特有的一种小型鸟类。主要栖息于喀麦隆、赤道几内亚和尼日利亚的湿润高地森林中，局部地区较为常见。其最显著的特征是黑色的顶冠和独特的淡黄色喉部及脸部，中间穿插一条黑色的眼线。","appearance":"黑顶柳莺体型小巧，活跃于林缘及森林内部。它的下体呈灰色，上体为绿色，头部顶冠为黑色，脸部和喉部有明显的淡黄色，被一条黑色眼线贯穿，形成独特的面部图案。这一特征有助于与其它小型柳莺，尤其是欧洲迁徙而来的柳莺区分开来。","call":"其鸣唱快速而尖锐，由一系列音符组成，通常在大约半秒内发出，形成一串密集的高音。","habits":"黑顶柳莺偏好湿润的高海拔森林环境，活动范围局限于非洲中西部的特定地区。它们的栖息地主要在喀麦隆山脉，包括Bioko岛在内的亚热带或热带湿润山地森林。","breeding":"关于黑顶柳莺的繁殖习性，目前资料有限，但基于其生态习性，预计其繁殖期、筑巢、交配等行为与同属物种相似。","identification":"黑顶柳莺与其它小型柳莺的区别在于其独特的面部图案和局部化的分布。其黑色顶冠和淡黄色的脸部图案，结合其仅在非洲中西部湿润高地森林中的分布，使其易于识别。","protection":"IUCN：LC（无危）","distribution":"黑顶柳莺分布于非洲中西部，具体而言，它们的自然栖息地位于喀麦隆山脉，包括Bioko岛在内的亚热带或热带湿润山地森林。","other":"历史上，黑顶柳莺曾被归类于旧世界柳莺复合群中，后被重新分类至Phylloscopidae科。"},{"name":"乌干达柳莺","english_name":"Uganda Woodland Warbler","scientific_name":"Phylloscopus budongoensis","overview":"乌干达柳莺（英文名：Uganda Woodland Warbler，学名：Phylloscopus budongoensis），是雀形目柳莺科柳莺属的小型鸟类。主要分布在非洲的低地和中海拔森林地带，其自然栖息地为赤道几内亚和喀麦隆至肯尼亚西部和乌干达的亚热带或热带湿润低地森林。","appearance":"乌干达柳莺是一种活跃的小型鸟类，其上体呈现绿色，下体为灰色，最显著的特征是有一条明显的浅色眉纹。与迁徙的柳莺种类相似，尤其是与欧柳莺相像，但乌干达柳莺的下体更偏灰，喉咙颜色较淡，且腹部带黄色调。","call":"其鸣唱为快速而混乱的高音调音符混合，形成独特的歌唱模式。","habits":"乌干达柳莺主要栖息于低地和中海拔的森林下层，偏好亚热带或热带湿润的低地森林环境。","breeding":"关于乌干达柳莺的繁殖信息目前尚不详尽。","identification":"与欧柳莺相比，乌干达柳莺的下体颜色更偏向灰色，喉咙颜色更淡，腹部带有黄色调，这些特征有助于在野外识别两者。","distribution":"乌干达柳莺的分布区域断续出现在喀麦隆南部和赤道几内亚北部，加蓬东北部和刚果西北部，刚果民主共和国东部直至乌干达和肯尼亚西部。","other":"乌干达柳莺的生态学和生物学特性仍有待进一步研究和了解。"},{"name":"褐林柳莺","english_name":"Brown Woodland Warbler","scientific_name":"Phylloscopus umbrovirens","overview":"褐林柳莺（英文名：Brown Woodland Warbler，学名：Phylloscopus umbrovirens），是雀形目柳莺科柳莺属的鸟类。小型的旧世界林栖鸟类，体羽主要呈橄榄褐色，背部略显暗绿，腹部偏淡棕色，翼羽边缘鲜明的黄绿色十分醒目。广泛分布于非洲东部以及阿拉伯半岛的山地森林地带。","appearance":"褐林柳莺体长约11厘米，体重介于8.5至11克之间。头部及上体主要为橄榄褐色，眼眉纹短而模糊，眼线黑褐色，脸颊和耳羽颜色较浅或略带暖色。翅膀、上翼覆羽及尾羽为黑褐色，边缘泛绿。翼弯处呈黄绿色。下体大多为淡棕色或浅棕色，喉部及腹部中央为白色，腋羽带有黄色调。虹膜深褐色，喙黑色，下颚基部黄褐色，腿灰色至蓝灰色。性别间差异不大，幼鸟与成鸟相似，但下体略带黄色。各亚种在羽色的浓淡和色调上有细微差别。","call":"褐林柳莺的叫声为短促的‘tee’或‘teewee’。其歌声音调高亢、清脆且富有旋律，以快速的上下音阶系列构成，如‘chi-cher-chi-cher-chi-cher-chee-chew-chee-chew…’，有时会以华丽的颤音结尾，与欧柳莺的歌声类似但节奏更快，偶尔会发出连续的高低音符串连。","habits":"褐林柳莺栖息于海拔2100米至3600米的山地森林、灌木丛及峡谷地带，偏好在树冠层活动。食物主要包括小昆虫，如双翅目飞虫和蛾类幼虫，以及蜘蛛。通常单独或成对活动，但在非繁殖季节会加入由白眼（Zosterops）和鶲（Muscicapidae）组成的混合物种觅食群。它们在树木的中上层活跃觅食，也会在高大的树苗和灌木丛中搜索食物，或短距离追逐昆虫。","breeding":"褐林柳莺全年均可繁殖，主要在旱季。它们实行一夫一妻制，具有领地意识。巢由干燥的草、苔藓、叶子、植物纤维和羽毛编织而成，通常建在地面、根部、枯叶中，或是小树底部，有时也会在离地面约1米的垂挂苔藓中。每窝产卵2至3枚，关于孵化期和育雏期的具体信息尚不清楚。","identification":"与红脸柳莺相比，褐林柳莺腹部颜色更深，面部和喉部红色较少。与欧柳莺和叽喳柳莺的区别在于翼更短、喙更细、上体颜色更深、眼眉纹较淡、下体颜色普遍更深。与博氏柳莺的区别在于上体颜色更深，眼线深色，腿部颜色更深，下体无白色部分。","protection":"IUCN：LC（无危）","distribution":"分布于非洲东部，包括刚果民主共和国、吉布提、厄立特里亚、埃塞俄比亚、肯尼亚、卢旺达、沙特阿拉伯、索马里、南苏丹、坦桑尼亚、乌干达和也门。在阿拉伯半岛也有分布，特别是在也门和沙特阿拉伯。"},{"name":"欧柳莺","english_name":"Willow Warbler","scientific_name":"Phylloscopus trochilus","overview":"欧柳莺（英文名：Willow Warbler，学名：Phylloscopus trochilus），是雀形目柳莺科柳莺属的鸟类。属于柳莺科柳莺属的小型鸟类。其分布广泛，自爱尔兰东至西伯利亚东部的安纳德尔河盆地，栖息于开放的林地，以柳树、桤木和白桦林为主。具有强烈的迁徙习性，几乎全种群冬季会迁往撒哈拉以南的非洲。","appearance":"体长11-12.5厘米，体重介于6.3-14.6克之间。外观为典型的叶莺，上身绿色带棕色，下身偏白色至淡黄色。翼长，喙尖而长，腿色从粉红到棕红。与叽喳柳莺相比，欧柳莺通常更亮黄，具明显的眼眉纹，腿色偏粉红，尾巴摆动不频繁。幼鸟下方更偏黄色，喉部和胸腹部有黄色条纹或斑点。","call":"鸣唱为愉悦的、略下降的颤音，与叽喳柳莺的歌声显著不同。叫声为柔和的双音节'hooeet'或'huuitt'。","habits":"栖息于各种开放林地，从混合森林到北极苔原的柳树丛，偏好有白桦树、桤木和柳树的环境。夜间迁徙，每日至少飞行100公里。食性以昆虫及其卵、幼虫为主，也摄取少量植物果实和种子。","breeding":"繁殖期在4月至7月，可能单窝或两窝。雄鸟常有多配偶倾向，保卫主要和次要繁殖领地。巢由雌鸟建造，位于地面植被中，有时高达4.8米。每窝产卵4-8枚，孵化期12-14天，雏鸟离巢期11-15天。","identification":"与叽喳柳莺区分在于欧柳莺体型更为细长，上身和下身颜色更明亮或更黄，眼眉纹更明显，腿色更浅，翼展更长。","protection":"IUCN：LC（无危）。欧洲繁殖种群估计超过3400万对，其中瑞典和芬兰最多，约2400万对。","distribution":"繁殖区遍布欧亚大陆，从爱尔兰向东至西伯利亚东部的安纳德尔河盆地。非繁殖期迁至撒哈拉以南的非洲。","other":"欧柳莺的迁徙距离极长，部分种群需迁徙12000公里，是小型鸟类中迁徙距离最长之一。"},{"name":"叽喳柳莺","english_name":"Common Chiffchaff","scientific_name":"Phylloscopus collybita","overview":"叽喳柳莺（英文名：Common Chiffchaff，学名：Phylloscopus collybita），是雀形目柳莺科柳莺属的鸟类。体型略小（约11厘米）、颜色较为朴素的绿褐色柳莺，广泛分布于欧亚大陆。其英文名源于其简单重复的‘chiff-chaff’叫声，这种叫声是春季回归的重要标志之一。该物种在开放的林地和灌木丛中筑巢，通常靠近水源。在繁殖季节，雄鸟会捍卫领地，雌鸟负责筑巢和育雏，而雄鸟主要负责领土防御。","appearance":"成年叽喳柳莺体长约11至12厘米，体重介于6至11克之间。上体橄榄绿色，略带褐色调，下体几乎全为淡白色或乳白色，两胁和侧胸处略染黄色。春季时，眉线呈浅黄色至乳黄色，眼环细白。飞行羽和尾羽棕色，边缘呈淡橄榄绿色。虹膜深棕色，喙多为暗棕色至黑色，腿色黑色或深棕色。雌雄羽毛相似，但雌鸟体型稍小。幼鸟上体呈棕色至灰棕色，下体黄色至灰白色，喉部和胸部带有淡黄色。不同亚种间存在色彩差异，主要体现在上体和下体的颜色色调上。","call":"叽喳柳莺以其重复的‘chiff-chaff chiff-chaff’声闻名，歌声节奏感强，常在迁徙前的越冬地、迁徙途中和繁殖地歌唱。叫声包括柔和的‘hooeet’、‘hweet’或‘huit’，伴侣间的接触音为轻柔的‘it’、‘drit’或‘dik’。","habits":"叽喳柳莺偏好低地落叶林和林地，特别是有低矮灌木覆盖的地方，也会出现在公园、树篱、大型花园和芦苇丛中。在繁殖季节，它们倾向于选择至少有一定数量高大树木的栖息地，但在沿海灌木丛中也能找到它们的踪迹。在阿尔卑斯山脉、喀尔巴阡山脉、高加索山脉和乌拉尔山脉，它们能在混合橡树林和针叶林中繁殖，海拔高达2000米。越冬时，它们会出现在各种林地环境中，从海岸边的小灌木丛到柳树丛，有时还会在芦苇丛中发现，同时也会出现在更开阔的环境，如公园、花园、农田和树篱。","breeding":"叽喳柳莺的繁殖期为4月至8月初，南部地区的第二窝蛋通常在6月产下。它们通常是单配偶制，但在某些地区，雄鸟可能会维护两个领地，暗示可能存在的多配偶制。雄鸟通过在显眼的栖息点上唱歌来宣传和捍卫领地，领地争端很常见。雄鸟在初次遇到雌鸟时会俯冲并追逐雌鸟，随后是雄鸟的大声歌唱和双方的喙击动作。巢是由干燥的草、叶子、苔藓、植物纤维和羽毛构成的球状结构，通常建在地面或离地面不超过5厘米的地方，隐藏在荆棘丛、荨麻丛、草丛或其他茂密植被中。每窝产5至6枚蛋，孵化期为13至15天，由雌鸟单独完成。雌鸟主要负责喂养雏鸟，雄鸟偶尔帮忙，雏鸟期为14至16天。雏鸟离开巢穴后10至19天即可独立。繁殖成功率通常很高。首次繁殖年龄为一岁。","identification":"叽喳柳莺与欧柳莺科其他物种区分的关键在于其较暗的上体颜色、较弱的眉纹、黑色的腿和尾巴的惯性摆动。与欧柳莺相比，叽喳柳莺上体颜色更暗淡，眼纹更深，眉纹较短，眼环白色，腿黑色，主翼羽较短。与靴篱莺和赛氏篱莺相似，但这两者色调偏褐色，腿和喙较暗。","protection":"IUCN：LC（无危）","distribution":"繁殖区遍布欧洲和亚洲，东至西伯利亚东部，北至约70°N，包括孤立的西北非、土耳其北部和西部、伊朗西北部种群。越冬区主要在南欧、西亚和北非。在中国，它们的分布见于新疆等地。","other":"叽喳柳莺在英国和荷兰的记录显示，所有被接受的异域伊比利亚叽喳柳莺记录都与唱歌的雄鸟相关联。"},{"name":"伊比利亚柳莺","english_name":"Iberian Chiffchaff","scientific_name":"Phylloscopus ibericus","appearance":"中等体型，约11-12厘米长，体重7-8.25克。外观较为朴素，具淡黄绿色的眉纹，窄而突出的浅色眼环，对比鲜明的深色眼线，橄榄色的颊部和耳羽。繁殖季时，头部和上体呈黄橄榄绿色，翼羽和尾羽棕色，边缘轻橄榄绿。下体白色，胸部有黄色条纹，腹下部和尾下覆羽柠檬黄色。翼下覆羽和腋羽同样柠檬黄色，可见于闭合翅膀的弯曲处。虹膜深棕色，喙暗棕色至黑色，腿灰褐色至黑色。","call":"接触音为轻微或鼻音的‘piu’或‘pew’，有下降的音调，与红腹灰雀类似。秋季有短促尖锐的‘peep’、‘seep’或‘weep’声。鸣唱为缓慢重复的升降音符，速度慢于叽喳柳莺。","habits":"栖息于落叶林和混交林，偏好阴凉湿润的微气候。繁殖于伊比利亚半岛北部的落叶林地带，冬季迁徙至西非热带地区。春季迁徙始于二月下半月至三月初，秋季迁徙则从八月初持续到十月中旬。","breeding":"繁殖季节为四月中至五月末，产卵数通常为4-5枚，偶尔6枚。雄鸟于三月下半月到达繁殖地，雌鸟稍晚。孵卵期自四月至六月初。幼鸟在六月初开始出现，七月和八月数量最多。","identification":"与叽喳柳莺相比，伊比利亚叽喳柳莺的上体更亮，更显黄橄榄色，眉纹更黄绿，胸和腹部更白，腹下部和尾下覆羽黄色而非淡黄色。最佳辨识依据为鸣唱和叫声。","protection":"IUCN：LC（无危）","distribution":"繁殖于法国西南部、西班牙、葡萄牙和北非西北部。非繁殖季节主要分布于西非热带地区，从塞内加尔东至马里南部、布基纳法索和加纳北部。","other":"曾被误认为Phylloscopus brehmii，现已确认为独立物种。"},{"name":"加岛叽喳柳莺","english_name":"Canary Islands Chiffchaff","scientific_name":"Phylloscopus canariensis","appearance":"该鸟体长约12至14厘米，外观中等大小，羽色平淡。头部有白色的眉纹和细眼圈，对比鲜明的暗色眼线；脸颊和耳羽橄榄棕色，头顶及背部橄榄棕色，背下部至尾上覆羽更鲜绿；飞羽和外侧尾羽边缘淡绿色；喉部偏白色，向下渐变为淡黄色；下胸和腹部淡黄褐色，两胁温暖的黄褐色，肛周至尾下覆羽淡黄白色；翅膀下覆羽和腋羽黄色（通常在闭合翅膀弯曲处明显突出）；虹膜深棕色；喙深角棕色；腿色变化大，从绿色到灰棕色或黄棕色。幼鸟与成鸟相似，但下部羽毛更鲜艳的黄色。exsul亚种比指名亚种略小，颜色更浅或橄榄棕色较淡，跗跖几乎黑色。","call":"叫声为尖锐清晰的‘hwit’、‘huit’、‘huii’、‘tuit’或‘wheet’，类似于叽喳柳莺的叫声；exsul亚种的叫声稍长且粗糙。指名亚种的歌声往往以响亮或爆发性的开始，‘dschi-dsche-sche-schi-sche-schi-schi’，加速至结尾，可能由短暂的‘tuk’、‘che’或‘chk’开头，与叽喳柳莺的歌声相似但更快，音质更丰富或更深沉；不响应后者物种的歌声。没有关于exsul亚种歌声的信息。","habits":"栖息于木林、花园、灌木丛和种植园。以各种小型昆虫为主食，亦食用包括Isoplexis canariensis、Canarina canariensis、Lavatera phoenicea、Aloe spp.、Hibiscus spp.和入侵的Agave americana等植物的花蜜。","identification":"与非常相似的叽喳柳莺主要区别在于更白且略长的眉纹、较暗的上部，下方更带黄褐色而非淡黄色，喙稍长且颜色较浅，腿色较淡，翅膀较短且更圆。","protection":"IUCN：LC（无危）。指名亚种常见且广泛分布，估计有10万至15万对。exsul亚种仅限于兰萨罗特岛的哈里亚山谷，极为罕见，最近没有记录，可能已灭绝。","distribution":"分布于加那利群岛西部和中部，曾经也在兰萨罗特东北部的加那利群岛（位于非洲西北部的马卡罗尼西亚群岛中心）。"},{"name":"东方叽喳柳莺","english_name":"Mountain Chiffchaff","scientific_name":"Phylloscopus sindianus","appearance":"体长约10.5至12厘米，重约5.5至8.5克。头部特征明显，具白色眉纹，暗色眼纹，耳羽灰色或新鲜时呈暖棕色。冠部及大部分上体淡棕色，边缘略带灰棕色。飞羽和尾羽深棕色，边缘橄榄棕色。下体几乎全白，仅侧胸和两胁呈淡黄色至暖棕色。虹膜深棕色，喙黑色，下颚基部黄褐色，腿黑色。雌雄相似，幼鸟上体更棕色，胸部有暗色斑点。亚种lorenzii上体更暖棕色，眉纹尖锐，眼纹更白，胸腹淡棕色，两胁锈棕色。","call":"鸣唱由一系列短语组成，如‘tsvin tsven tsvi tsin’，常重复‘chit-chiss-chyi-chiss-chit-chiss-chyi-chip-chit-chyi’，与叽喳柳莺相似但通常更短促轻快。叫声为‘huit’或‘hweet’，比叽喳柳莺更高调，也有响亮的双音节‘tiss-yip’。","habits":"栖息于海拔2500至4400米的柳林、杨树林、杜鹃林及其他灌木丛，冬季迁徙至较低海拔。主要在亚欧大陆的土耳其到喜马拉雅山脉繁殖，非繁殖季节分布于亚洲南部。","breeding":"具体繁殖信息未知。","identification":"与叽喳柳莺相比，中亚叽喳柳莺上体颜色更深，喉部对比更明显，叫声不同。亚种lorenzii颜色更暖，与普通叽喳柳莺在同一区域时极少杂交。","protection":"IUCN：LC（无危）","distribution":"繁殖于欧亚：土耳其至喜马拉雅山脉，非繁殖于亚洲南部。","other":"在中国，仅分布于新疆和西藏的极西部，较为罕见。"},{"name":"纯色柳莺","english_name":"Plain Leaf Warbler","scientific_name":"Phylloscopus neglectus","overview":"纯色柳莺（英文名：Plain Leaf Warbler，学名：Phylloscopus neglectus），是雀形目柳莺科柳莺属的鸟类。小型的、无显著斑纹的旧世界柳莺科鸟类，分布于伊朗、阿富汗、巴基斯坦等国的山区，以及阿拉伯半岛东南部和印度远西部的非繁殖季节。其自然栖息地为温带森林。","appearance":"体长9至10厘米，体重4.2至7克，略大于戴菊。上体沙灰色，下体淡灰色，具有短而不太明显的淡黄奶油色眉线，窄黑眼纹，窄白眼环或下眼弯。头部和背部几乎全灰棕色，臀部略浅灰色，翼和尾羽稍深，边缘较淡形成翼板。腹部淡白色，胸侧和两胁微泛黄棕色，翼下覆羽白色。虹膜深棕色，喙暗棕色，基部较淡角棕色，腿深灰色或黑色。幼鸟上体比成鸟更亮棕色，眉线乳黄白色，两胁黄色。","call":"歌声为柔和的啾啾鸣叫，包含多种变化的乐句，如‘zilitzwit’、‘twissa twissa’、‘chit-chuwich-chissa’和‘pt-toodle-toodla’，常重复。叫声为独特的尖锐‘chit’，偶尔为‘chick’、‘chip’、‘cheet’或‘tchoit’，常在飞行中发出；还有低沉短促的‘churr’或‘trrr trrr’。","habits":"主要以小昆虫和幼虫为食，冬季通常单独觅食，夏季常成对活动。在树冠层活跃敏捷，取食时多在叶片上或叶间，有时倒挂在细枝上；会突然飞扑捕捉飞过的昆虫。频繁拍翅，但不像叽喳柳莺那样摆尾。","breeding":"繁殖季节在伊朗东部至巴鲁奇斯坦地区较为常见，具体繁殖习性资料有限。","identification":"与中亚叽喳柳莺相比，体型较小，羽毛色调稍偏灰色，缺乏脸颊、胸侧和两胁的暖黄棕色，尾巴较短；与叽喳柳莺的区别在于尾巴较短，上体无绿色或黄绿色，包括翼弯处。","protection":"IUCN：LC（无危）","distribution":"繁殖于伊朗、土库曼斯坦南部、乌兹别克斯坦东部、塔吉克斯坦西部、阿富汗、巴基斯坦的巴鲁奇斯坦；非繁殖期分布于伊朗南部沿海、巴基斯坦南部和印度远西部。"},{"name":"博氏柳莺","english_name":"Western Bonelli's Warbler","scientific_name":"Phylloscopus bonelli","overview":"博氏柳莺（英文名：Western Bonelli's Warbler，学名：Phylloscopus bonelli），是雀形目柳莺科柳莺属的鸟类。别称博氏柳莺，与东部亚种区分后独立为物种。拥有橄榄绿与绿色的上体，与白色的腹部形成鲜明对比。繁殖于欧洲西南部至中部的森林地带，冬季迁徙至非洲中西部。","appearance":"博氏柳莺体长约11.5厘米，体重7-11.5克，属于中等体型的淡褐色柳莺，头部颜色较暗，上体呈淡灰褐色，除绿色的臀部和上尾覆羽外，翼覆羽和飞羽边缘为鲜亮的黄绿色，下体丝白色，侧胸和胁部带淡灰或土黄色。幼鸟与成鸟相似，但上体颜色更暗更褐。","call":"鸣唱为短暂的单音下降颤音，持续约1-2秒，起始响亮后逐渐减弱。叫声包括单调的‘tuit’、双音节的‘huu-eef’或‘swee-eet’，音质鼻音明显，与东方同类有所区别。","habits":"栖息于温带落叶林，如橡树、山毛榉、松树和云杉混交林，海拔高度从海平面至约1900米。非繁殖季节，出现在撒哈拉沙漠南部的开阔灌木丛和干燥草原。","breeding":"繁殖期从四月末至八月，一窝通常产卵4-6枚，由雌鸟孵化，孵化期12-13天。双亲共同照顾雏鸟，雄鸟在头周主要负责喂食。雏鸟离巢期约为12-13天。","identification":"与东博氏柳莺相比，博氏柳莺头部和上体颜色更偏褐色，翼和尾的边缘更鲜亮的绿色，腿部颜色平均更浅或更棕色。","protection":"IUCN：LC（无危）","distribution":"繁殖区域包括伊比利亚半岛北部至法国南部、德国南部，向东延伸至奥地利、斯洛文尼亚和意大利，以及北非西北部。非繁殖区域覆盖中西部非洲，从毛里塔尼亚南部和塞内加尔向东至尼日利亚北部、喀麦隆和乍得。","other":"全球数量估计在150万至400万对之间，大部分分布于西班牙，法国也有较大比例的种群。"},{"name":"东博氏柳莺","english_name":"Eastern Bonelli's Warbler","scientific_name":"Phylloscopus orientalis","overview":"东博氏柳莺（英文名：Eastern Bonelli's Warbler，学名：Phylloscopus orientalis），是雀形目柳莺科柳莺属的鸟类。属于欧柳莺科的小型鸟类，曾被视为更广泛意义上的博氏欧柳莺的东部亚种，但现代分类学将其视为独立物种。其分布于欧洲东南部至土耳其西部、叙利亚和黎巴嫩，冬季迁徙至非洲中东部。该鸟背部灰绿色，翼部带绿调，下体白色，喙尖小，腿棕色，雌雄外观相似。","appearance":"该欧柳莺长约11.5厘米，体重介于5.5至10.5克之间。其特征为灰白眉线，眼上具淡褐色斑点，脸颊棕褐色，耳羽有时与灰冠和颈背形成对比。上体呈冷灰色，略带绿色，臀部颜色较淡，尾羽和飞羽边缘呈暗绿色，次级飞羽边缘白色，下体白色，翅膀下覆羽淡黄或白色。虹膜深棕色，喙角质色，下颌基部有小片淡色区域，腿深灰色或黑棕色。幼鸟与成鸟相似。","call":"其歌声为短暂的颤音，与西方博氏欧柳莺相似但略柔和且持续时间稍短。叫声独特，为短促、尖锐、响亮或远传的“chip”、“chirp”或“khip”，偶尔发出“chirrip”，音调干燥或尖锐，类似家麻雀或远处普通交嘴雀的声音。","habits":"栖息于温暖的落叶林，主要为橡树和山毛榉森林，以及混合林和纯松树林，植被层丰富，海拔约200米至1800米，主要位于800米以上。非繁殖季节，居住在非洲的开阔林地、灌木草原和灌丛中。迁徙期间，沿撒哈拉沙漠南缘的金合欢带度过非繁殖季。","breeding":"繁殖季节为4月至8月。巢呈穹顶状，由草、叶、苔藓和毛发构成，隐藏于地面。每窝产4至6枚蛋；孵化期和雏鸟期信息未知，但可能与西方博氏欧柳莺相似，即各为12至13天。","identification":"与西方博氏欧柳莺相比，东博氏柳莺上体颜色偏冷灰色，缺乏褐色调，耳羽与灰冠和颈背对比明显，眉线更白且突出，眼上淡褐色斑点更明显，翼和尾的绿色边缘较暗，翅膀下覆羽颜色较浅，腿色更深。","protection":"IUCN：LC（无危）","distribution":"繁殖于东南欧从克罗地亚南部至阿尔巴尼亚，东至罗马尼亚南部、保加利亚、希腊北部和土耳其西部及西南部；在安纳托利亚东部、叙利亚、黎巴嫩和伊朗西部有孤立种群。非繁殖期分布于非洲东部（乍得东部、苏丹南部和厄立特里亚）。","other":"近年来在马其顿和保加利亚的数量和分布范围有所增加，估计当地有数千对繁殖。"},{"name":"林柳莺","english_name":"Wood Warbler","scientific_name":"Phylloscopus sibilatrix","overview":"林柳莺（英文名：Wood Warbler，学名：Phylloscopus sibilatrix），是雀形目柳莺科柳莺属的鸟类。广泛分布于欧亚大陆北部和温带地区的常见小型鸟类，以独特的口哨般鸣声得名。其繁殖地横跨欧洲至俄罗斯中部，冬季迁徙至非洲热带地区。","appearance":"体长约11-12.5厘米，上体呈淡绿色，下体白色，喉部和胸部显黄色，具有明显的黄色眉纹和长而尖的翅膀。幼鸟较成鸟颜色更暗淡，喉部和胸部的黄色面积较小。","call":"拥有两种歌曲类型，一种是高音流利的金属颤音，节奏逐渐加快，持续2-3秒；另一种是一系列3至5个下降的管状音符，音调较低。","habits":"偏好阴凉成熟的森林环境，如山毛榉和栓皮栎林，常在树冠层活动，主要以昆虫为食。在非繁殖季节，栖息于非洲的湿润森林和干燥的林地。","breeding":"繁殖期为5月至7月，一般一窝产5-7枚卵，由雌鸟孵化约12-14天，雏鸟11-13天后离巢，双亲共同照顾。在比利时的研究中，84枚卵中成功孵出66只幼鸟，成功率为79%。","identification":"与相似物种如黄眉柳莺和柳莺的区别在于黄色的眉纹、喉咙和上胸，以及更长的初级飞羽和较短但更宽的尾巴。","protection":"IUCN：LC（无危）；欧洲种群稳定，估计在600万到700万对之间，主要分布在德国、爱沙尼亚和拉脱维亚。","distribution":"繁殖区域覆盖欧洲至哈萨克斯坦北部和俄罗斯中部；非繁殖区域主要位于西非和中非。","other":"在英国，尽管近年来数量有所下降，但仍有稳定的繁殖种群。在爱尔兰，存在一个很小但稳定的繁殖种群。"},{"name":"褐柳莺","english_name":"Dusky Warbler","scientific_name":"Phylloscopus fuscatus","overview":"褐柳莺（英文名：Dusky Warbler，学名：Phylloscopus fuscatus），是雀形目柳莺科柳莺属的鸟类。别名: 达达跳、嘎叭嘴、褐色柳莺，分布于亚洲东北部和中国中北部的柳莺科鸟类。其羽色呈泥褐色，上体较下体颜色更深，偏好沿溪流、沼泽周围及森林中潮湿灌丛的浓密低植被，栖息高度可达海拔4500米。体型小，约11-12厘米，活动于底层植被低处，常突然窜出探索周围环境。","appearance":"褐柳莺羽色泥褐色，上体深于下体，头部有细贯眼纹和淡黄褐色眉纹，喙小且色深，眉纹后端沾褐色。体型中等偏小，约11-12厘米长，体重8.5-13.5克，尾部相对短，喙细长。幼鸟羽色更显橄榄绿。雌雄外观相似。","call":"鸣叫声为生硬的'嘎叭、嘎叭...'或'答、答、答...'，繁殖期间持续鸣唱，声似'欺、欺、欺、欺...'的连续叫声，声音单调，类似石头摩擦或撞击的颤音。","habits":"主要栖息于亚洲东北部的山地森林边缘，活动于海拔4500米以下的地带，偏好湿润环境，如溪流沿岸的灌丛。以昆虫为主食，偶尔摄取小种子。独居或成对活动，善于在树枝间跳跃，飞行灵活。冬季迁往南亚和东南亚。","breeding":"繁殖期为5月至8月中旬，筑巢于低矮灌木或地面，每窝产卵4-6枚。幼鸟孵化后，双亲共同育雏。","identification":"与巨嘴柳莺区别在于嘴型更细、腿较细、体型略小，约11-12厘米，巨嘴柳莺体型更大，约12-13厘米，且嘴型异常粗壮。褐柳莺眉纹较窄短，后端棕色，眼先上部眉纹有深褐色边，腰部无橄榄绿色渲染。叫声为颤抖感强烈的'刺拉~'声，与巨嘴柳莺的石子撞击声不同。","protection":"IUCN：LC（无危）","distribution":"繁殖于亚洲东北部和中国中北部，非繁殖期迁往南亚和东南亚，偶有迷鸟出现在北美阿拉斯加和加州。在中国，分布于河北、河南、山东、山西、陕西、湖北、湖南、四川、贵州、云南、西藏、广西、广东、香港、福建和海南岛等地。","other":"褐柳莺为典型的迁徙鸟种，冬季迁徙至南亚和东南亚地区，夏季返回繁殖地。"},{"name":"烟柳莺","english_name":"Smoky Warbler","scientific_name":"Phylloscopus fuligiventer","overview":"烟柳莺（英文名：Smoky Warbler，学名：Phylloscopus fuligiventer），是雀形目柳莺科柳莺属的鸟类。其全身呈灰褐色，具有一条偏黄色的眉纹。主要分布在中国西藏地区，模式产地位于尼泊尔。烟柳莺在外观上与褐柳莺极其相似，但平均体型较小，整体颜色较暗，具有较短且不太明显的眉纹。","appearance":"烟柳莺是一种小型至中型的、色泽暗淡的棕褐色柳莺，眉纹模糊不清。标准亚种具有暗淡的白色或淡黄白色至黄色的眉纹，延伸至耳羽上方，眼下方有明显的半新月形斑纹，宽黑眼线，淡黄褐色的颊和耳羽；背部、翅膀和尾巴通常呈均匀的烟灰色；下部淡黄褐色，喉咙、胸部和腹部中央为暗淡或灰暗的黄色，下尾覆羽微染淡黄；在磨损的羽毛下部变得更灰。虹膜深棕色；喙棕色至角棕色，下颌基部黄色；腿呈棕色至黑色。两性相似。幼鸟未被描述。Tibetanus亚种比标准亚种上部更暗棕色，眉纹和下部更灰或更白。Weigoldi亚种比标准亚种上部更暗棕色，眉纹和下部（包括下翼覆羽）为灰白色，腹部微染奶油色。","call":"烟柳莺的鸣唱是一系列重复的清澈音符。叫声干燥而硬，通常为“chuck”或“tick”的音节。","habits":"烟柳莺繁殖于海拔3900至5000米的岩石高山草甸及灌木丛之上，非繁殖季节则下降至平原较低的地区，通常低于1000米，在高草地上、密生的灌木下层或靠近水边或沿小溪至急流河岸的高草中活动。夏季在岩石和巨石间攀爬，冬季则常见于水边植被中。食物主要是小型昆虫和幼虫，单独或成对觅食，低矮的植被或地面觅食，夏季攀爬于岩石和巨石之间，冬季常在水边植被中；也会在短暂悬停于水面或水上植被上捕食昆虫。在茂密的植被中潜行，经常快速扇动翅膀和尾巴。","breeding":"繁殖信息了解不多，已知繁殖季节在5月至8月间，8月在尼泊尔见到离巢的幼鸟。","identification":"烟柳莺与褐柳莺相比，体型较小，上部颜色更深，眉纹较短且不明显，下部颜色较暗淡，几乎与上部颜色一致；与灰柳莺相比，上部颜色更深，眉纹颜色不同，下部颜色暗淡。通过体型、颜色和细节特征进行区分。","protection":"IUCN：LC（无危）；烟柳莺在不丹局部常见，在中国西南部稀少；在尼泊尔不常见或局部常见，在印度北部也不常见。","distribution":"繁殖区域位于喜马拉雅山脉东部和青藏高原中部及东部，非繁殖区域则在印度次大陆北部。偶尔作为迷鸟出现在缅甸。","other":"烟柳莺是一种海拔迁移鸟，繁殖后会下降至更低的海拔区域。"},{"name":"黄腹柳莺","english_name":"Tickell's Leaf Warbler","scientific_name":"Phylloscopus affinis","overview":"黄腹柳莺（英文名：Tickell's Leaf Warbler，学名：Phylloscopus affinis），是雀形目柳莺科柳莺属的鸟类。分布于亚洲的柳莺科鸟类，广泛见于喜马拉雅山脉，从巴基斯坦北部到中国西南部，包括西藏、青海、甘肃、云南和四川。以橄榄棕色的上体和黄色的下体为特征，无翼带，常在高海拔地区繁殖，冬季迁移到较低海拔，遍布印度次大陆南部。在印度东北平原和西部山地的灌木丛中最为常见。","appearance":"小型至中等体型（约10-11厘米），具淡黄色眉纹和下体，无翼带。眉纹长且呈淡黄色，过耳羽变白，有时带稍暗的上眉线；黑色眼纹，与黄色颊和耳羽形成对比；头冠和整个上体均匀灰棕色，新羽时略带橄榄绿或黄色；翅膀和尾羽棕色，多数羽毛边缘橄榄色，最外侧三根尾羽尖端和内缘有窄白色；下体主要为淡黄或柠檬黄，至腹处颜色渐浅，臀部和下尾羽覆羽更浅或泛白，胸侧和两胁有时带微黄褐色调；虹膜深棕色；喙上颚棕色，下颚黄色（少数可能有尖端少量深色）；腿色变化，从深棕色至黄棕色。雌雄相似。幼鸟上体更暖棕色，下体黄色调变化大，有些泛灰黄色。","call":"发出类似‘tack-tack’的声音，以及一系列快速重复的单一音符，通常由较高音的音符引出，组成其歌曲。此外，还有‘Chick’或‘Chrip’的叫声，频率高且尖锐，以及在繁殖季节用于警告或领土声明的‘Grunt’和‘Tsew’叫声。","habits":"栖息于干燥贫瘠山区的岩石和矮树丛中，包括高山柳树、矮柏树、矮竹和小檗灌木丛，以及杜鹃花边缘、森林和农田边缘；繁殖期海拔3050-4880米，一般高于棕腹柳莺的栖息地。非繁殖期则下降至2100米以下，活动于低矮灌木和树木间，通常在森林边缘，包括次生林、金合欢树和柳树，以及农田。","breeding":"繁殖期为5月至8月，雏鸟于7月初离巢；每年繁殖一窝。巢由干草、植物纤维（含柏树纤维）和羽毛编织而成，置于离地面最多1米的灌木丛中。每窝产卵3-5枚，双亲共同孵化和抚育幼鸟；孵化期和育雏期的持续时间未知。","identification":"与棕腹柳莺的区别在于更明亮和突出的眉纹，尾较短，耳羽更多黄色，腹部颜色更浅且更黄；与灰柳莺的区别在于更淡的橄榄棕色上体和边缘的飞羽，更亮的黄色下体，以及更亮的眉纹（新羽时）。与绿柳莺旧羽的区别在于更深的绿色上体和明亮的黄色下体。","protection":"IUCN：LC（无危）；在国家林业局2000年发布的《国家保护的有益的或者有重要经济、科学研究价值的陆生野生动物名录》中被列为保护对象。","distribution":"繁殖区位于喜马拉雅山脉，从巴基斯坦北部到中国西南部；非繁殖期分布于尼泊尔东南部、印度中央、西南和东北部、中国南部（西藏东南部、云南、贵州）、缅甸北部、中部和东部以及泰国西北部。","other":"曾将华西柳莺视为独立物种，现归入黄腹柳莺，基于2019年比较核基因组数据的研究。"},{"name":"华西柳莺","english_name":"Alpine Leaf Warbler","scientific_name":"Phylloscopus occisinensis","overview":"华西柳莺（英文名：Alpine Leaf Warbler，学名：Phylloscopus occisinensis），是雀形目柳莺科柳莺属的特有鸟类。分布于中国西部，包括甘肃、青海、四川等地，云南亦有记录。该物种原被认为是黄腹柳莺的一个亚种，后基于2019年的一项核基因组数据分析研究，被归类于黄腹柳莺。华西柳莺的模式产地位于中国青海省果洛州玛多县花石峡镇的冬给措纳湖附近。","appearance":"华西柳莺体长约10至11厘米，体重约7克。其为中型柳莺，无翼纹。具有长而明亮的黄色眉纹，以及在眼前方明显的一条宽暗色眼纹；上部呈暗灰褐色，带有橄榄绿的色调，飞羽和尾羽边缘带橄榄色；腹部鲜黄色，两侧的胸带呈棕灰色，中央部分在新鲜羽毛状态下趋向橙色，两胁部位颜色转为灰白；虹膜深色；喙呈暗棕色，边缘橙色，下颌基部橙色；腿色为暗棕色，脚常较浅，足底富黄色。雄雌相似。幼鸟下部似乎泛黄白色调，胸带更偏灰色。","call":"其叫声覆盖比Himalayan P. affinis更低且稍宽的频率范围，快速的双音甚至三音颤音，但存在多种歌曲变体。","habits":"华西柳莺栖息于干燥贫瘠山地的岩石和灌木丛中，包括高山柳（Salix）、矮小杜松（Juniperus）、矮竹和Berberis灌丛，有时在完全荒芜的高山环境中也能见到；活动高度介于3000至4500米之间。","breeding":"华西柳莺在5月至8月期间筑巢，巢由干草和植物纤维构成。它们在岩石和低矮灌木丛中的贫瘠山脉中繁殖。","identification":"与相似物种区别的关键特征在于其清晰的黄白色下部羽毛和缺乏翼纹，瘦长的暗色腿以及大部分苍白的下颌和灰白色的翼面。","protection":"IUCN：LC（无危）","distribution":"繁殖区域主要位于中国中部的高海拔山区（青海、甘肃、四川）；在非繁殖季节，记录于中国南部（云南）。","other":"原被视为独立物种华西柳莺（学名：P. a. occisinensis），现已并入黄腹柳莺。"},{"name":"棕腹柳莺","english_name":"Buff-throated Warbler","scientific_name":"Phylloscopus subaffinis","overview":"棕腹柳莺（英文名：Buff-throated Warbler，学名：Phylloscopus subaffinis），是雀形目柳莺科柳莺属的鸟类。直译: 棕喉柳莺，亦被称为棕喉柳莺，该物种主要特征为橄榄绿色上部，淡黄色腹部带黄色调，具有微弱而明显的黄色眉纹。分布于中国中部、南部以及越南北部，夏季栖息于山地森林，冬季下移至低地。在中国，其模式产地位于贵州。","appearance":"体型小至中等，长度约10.5-11厘米，重量6.25-7.5克。上体灰棕色，边缘略带橄榄绿或黄色（新羽时更明显），翅和尾较暗。下体呈淡黄色至黄色，喉部及腹部颜色较浅。眉纹黄色，眼纹模糊，耳羽暗色。喙上部暗角褐色，边缘黄色，下部基部黄色，尖端或远端半部暗色。腿深棕色。雌雄相似。幼鸟上体较成鸟更棕色。","call":"鸣唱为一系列柔和音符，‘tuee-tuee-tuee-tuee-tuee’，与黄腹柳莺类似但通常更慢弱，有时以‘trr’或‘trr trr’开始。叫声为柔软而近似昆虫声的‘chirrup’、‘chrrip’、‘trrup’或‘tirrik’。","habits":"栖息于海拔1800-3600米的山地森林，冬季移至低地的草甸和灌木丛。垂直迁移的候鸟，夏季活跃于开放灌丛环境，冬季集结小群。主要在低矮植被中觅食。","breeding":"繁殖期为5月至7月。筑巢于低矮植被中的小型穹顶状巢，侧面有入口，每窝产卵4枚。","identification":"与黄腹柳莺的区别在于嘴型更短粗，头部更为圆润，头顶羽毛更深，使黄色眉纹更为突出，且更喜鸣叫。与Tickell’s和Alpine Leaf Warblers相比，其眉纹较弱，喙较短，下体颜色较暗。","protection":"IUCN：LC（无危）。在中国繁殖范围内较为罕见，在东南亚越冬区常见。","distribution":"繁殖于中国中部至南部（从青海东南至陕西南部，江西和福建，南至云南北部和东部，广西南部和广东北部和东部），及越南北部。非繁殖季节分布于中国南部至亚洲北部东南部，包括缅甸北部和东部，泰国西北部，老挝北部和越南北部。","other":"棕腹柳莺曾被归入‘旧世界莺’组合中，现已明确分类于Phylloscopidae家族。"},{"name":"灰柳莺","english_name":"Sulphur-bellied Warbler","scientific_name":"Phylloscopus griseolus","overview":"灰柳莺（英文名：Sulphur-bellied Warbler，学名：Phylloscopus griseolus），是雀形目柳莺科柳莺属的鸟类。又名:灰柳莺莺，小型冷褐色柳莺，下体呈硫磺色。繁殖于南亚及中国西部山区，常见于干燥的山地斜坡，主要分布于新疆省。其色彩较冷，少橄榄色调，具有明亮的黄色眉线。","appearance":"灰柳莺体长约10.5厘米，体重7-9克。头部有明亮的黄色眉线，从喙基延伸到耳羽上方，眼纹深棕色，脸颊和耳羽泛橄榄色。冠部和背部冷棕色，无橄榄色，翼和尾部暗棕色，飞羽边缘灰色带白色。喉咙和腹部亮柠檬黄色，胸侧和两胁淡黄色泛橄榄色。下尾覆羽黄白色，下翼覆羽黄褐色。虹膜深棕色，上喙黑色，下喙黄至淡棕色尖端，腿色变化大，从黄褐色到绿黄色或橄榄棕色。雄雌相似，幼鸟上体略暖棕色，下体淡黄色。","call":"鸣唱短暂高音颤音，由数个相同音高的音符组成，开始为高音哨声，如'tseeep-tyi-tyi-tyi-tyi-tyi'或'tsi-tsi-tsi-tsi-tsi'。叫声为'chip'、'quip'或'quit'，类似麻雀的叫声，还有尖锐的'tack'。","habits":"栖息于干燥的岩石山地和碎石坡面，有低矮植被、杜松和矮松林，海拔2590-4575米。非繁殖季节在印度中部的密林下层、岩石区、陡峭峡谷及旧墙或建筑附近。以小昆虫为主食，偶尔食用软体动物。","breeding":"繁殖期为4月末至8月初，筑巢期4-10天，由雌鸟完成。巢置于离地1.5米内的密集灌木中，由干草、植物纤维和羽毛构成。每窝产4-5枚卵，孵化期14-17天，幼鸟由双亲喂养，离巢期14-15天，父母继续喂养幼鸟15天。","identification":"与烟柳莺相比，灰柳莺色彩较冷，眉线前端橘黄后转为黄色。与黄腹柳莺区别在于色彩更淡且亮丽。与褐柳莺区别在于色彩较冷，喉部无黄色细纹。","protection":"IUCN：LC（无危）","distribution":"繁殖区覆盖从哈萨克斯坦东南部至中国西北和中部，南至乌兹别克斯坦东部、阿富汗和喜马拉雅山脉东北部。非繁殖区主要在印度中部。","other":"迁徙性鸟类，冬季在印度中部度过。"},{"name":"棕眉柳莺","english_name":"Yellow-streaked Warbler","scientific_name":"Phylloscopus armandii","overview":"棕眉柳莺（英文名：Yellow-streaked Warbler，学名：Phylloscopus armandii），是雀形目柳莺科柳莺属的小型鸟类。其显著特征包括橄榄褐色的上体，橄榄色的飞羽、覆羽及尾缘，以及明显的白色长眉纹和皮黄色的眼先。最独特的是喉部至腹部的黄色纵纹，尾下覆羽呈现黄褐色。繁殖于中国东北部和中部地区，冬季南迁至云南和东南亚北部。","appearance":"体长约12-14厘米，体重8-10.5克。外形丰满，体羽以褐色为主，上体橄榄褐色，下体黄褐色。头部具有一条狭窄的淡色眉纹，眼圈奶油白色，眼睛上方有深色边缘。上体和翼羽橄榄色，下体从喉部到腹部有明亮的黄色纵纹，尾下覆羽黄褐色。喙短而尖，上颌暗棕色，下颌大部分为黄色，腿为黄褐色。","call":"鸣声为一系列急促的颤音，带有金属质感的‘tink’声。","habits":"栖息于亚高山地带的云杉林中，尤其偏好柳树和杨树的低矮灌木丛。繁殖季节活动于海拔1220-3500米之间，非繁殖季节下降至1500米以下的平原和丘陵地带。觅食时常见于低枝和地面，以昆虫为主食。","breeding":"繁殖期信息稀少，已知6月间筑巢，每窝产4-5枚卵，具体繁殖细节未知。","identification":"与巨嘴柳莺相比，头较小，喙更细，腿色较淡，眉纹定义更清晰，胸部有细微的黄色纵纹。与烟柳莺、棕腹柳莺、灰柳莺和黄腹柳莺在体羽色彩、体型和嘴色上有明显差异。","protection":"IUCN：LC（无危）","distribution":"繁殖于中国东北部和中部，冬季迁徙至云南和东南亚北部。在中国大陆地区，分布于内蒙古、辽宁、河北等地。"},{"name":"巨嘴柳莺","english_name":"Radde's Warbler","scientific_name":"Phylloscopus schwarzi","overview":"巨嘴柳莺（英文名：Radde's Warbler，学名：Phylloscopus schwarzi），是雀形目柳莺科柳莺属的鸟类。俗名: 大眉草串儿、健嘴丛树莺，中等体型（约12.5厘米）的橄榄褐色柳莺，嘴形厚实，类似于山雀。主要繁殖于欧亚地区的哈萨克斯坦东部至俄罗斯东南部和北韩，冬季迁徙至东南亚。","appearance":"巨嘴柳莺体态圆润，全身呈橄榄褐色，喉部白色，具有边缘黑色的白色眉纹，眉纹前端逐渐呈黄褐色。成鸟体长12.5-13.5厘米，体重8-15克，腿较粗壮，喙厚实。幼鸟上体颜色比成鸟更橄榄绿，胸部和腹部呈淡黄色，两胁呈红棕色。","call":"巨嘴柳莺的鸣唱包括一系列短促而响亮的旋律短语，类似于新疆歌鸲的歌唱，以及快速的颤音。叫声有软弱的‘tec’、‘check’、‘chep’或‘chack’，以及模仿西鹌鹑的柔软‘pwit’、‘prit’或‘treet’哨声。","habits":"巨嘴柳莺偏好开阔的泰加森林和森林边缘，尤其喜欢湿润的灌木丛或溪流旁。它们常隐匿于地面附近的植被中觅食，表现出笨拙而沉重的姿态。迁徙时会出现在沼泽地带、河流谷地的白桦和柳树灌丛以及长满芦苇或莎草的沟渠中。","breeding":"巨嘴柳莺的繁殖期在6月至8月初。它们在低矮的灌木丛中建造由柳枝、草茎和细植物纤维构成的巢，离地高度可达1米。每窝产4-5枚蛋。","identification":"巨嘴柳莺与褐柳莺相比，体型更大，嘴形更粗壮；与棕眉柳莺相比，巨嘴柳莺的眉纹更长更宽，且带橄榄色；与褐柳莺相比，巨嘴柳莺喉部无细纹。","protection":"IUCN：LC（无危）","distribution":"巨嘴柳莺的繁殖区位于欧亚：哈萨克斯坦东部和俄罗斯南部至俄罗斯东南部和北韩。冬季它们迁徙至东南亚，包括泰国、缅甸、印度支那，偶尔会出现在中国东南部（广东）。","other":"巨嘴柳莺有迁徙至欧洲西部的迷鸟记录，最远到达英国和爱尔兰。"},{"name":"橙斑翅柳莺","english_name":"Buff-barred Warbler","scientific_name":"Phylloscopus pulcher","overview":"橙斑翅柳莺（英文名：Buff-barred Warbler，学名：Phylloscopus pulcher），是雀形目柳莺科柳莺属的鸟类。以其鲜明的黄色眉纹和淡色臀部为显著特征。整体呈黄橄榄色，双翼上有两条色差明显的翼斑，其中一条尤为突出。分布于喜马拉雅山脉至中国南部及越南西北部的山地森林，常出现在混种林中。","appearance":"体长10-11厘米，体重5.5-7.5克。头部具长眉纹，翼部有两条翼斑，臀部淡黄色，尾羽外侧白色。雄雌相似，幼鸟色彩略暗淡。指名亚种为淡黄色眉纹，橄榄绿眼纹，头颈暗橄榄色，背部和肩部带橄榄色的赭石色，臀部呈淡黄色，上覆羽与肩羽相似，中覆羽尖端橄榄黄色，大覆羽宽翼斑橙色或黄色，飞羽深棕色，边缘橄榄绿色，尾羽深棕色或黑色，最外侧三根尾羽外侧白色。腹部颜色较暗淡，最亮处位于腹部和下尾羽覆羽。虹膜深棕色，喙黑色，下颌基部黄色至角质色，腿棕色或粉棕色。","call":"叫声为尖锐而响亮的‘tit’、‘tsit’、‘zip’或‘swit’，有时连续发出，与灰喉柳莺类似但更为尖锐；还有一种上升调的‘tsi-i-i-i-i’。歌声由一个或多个叫声后跟快速尖锐的颤音组成，类似于林柳莺的‘tzzzzzzzzzzzzzt’。","habits":"栖息于海拔2100米至4300米的亚高山带，常见于桦树、杜松、橡树和杜鹃花林，冬季降至较低海拔，通常低于2800米，甚至低至1000米，在常绿落叶林中活动。以昆虫为主食，偶尔吸食开花树木的花蜜和橡树的树液。繁殖季节结束后向更低海拔迁徙，冬季停留时间为10月至翌年3月，具体时间取决于高海拔地区的天气状况。春季返回繁殖地的时间为3月末至4月初。","breeding":"繁殖期为4月至7月。巢为干燥草、桦树皮条、地衣、绿苔和羽毛构成的不规则球状，通常建于浓密灌木中，距离地面3-4米，或靠树干、树枝分叉处、针叶树的外枝。每窝产卵3-4枚，关于孵化和雏鸟期的信息未知。巢可能被小杜鹃寄生。","identification":"与黄腰柳莺区别在于后者尾部无白色，翼斑黄色；与灰喉柳莺区别在于后者喉部和上胸部为灰色，胸部以下黄色。橙斑翅柳莺翼斑橙色，尾羽外侧白色。","protection":"IUCN：LC（无危）。在中国西南地区分布，种群数量不丰富。","distribution":"繁殖区域主要在喜马拉雅山脉、中国南部和越南西北部，非繁殖季节可见于东南亚部分区域。"},{"name":"灰喉柳莺","english_name":"Ashy-throated Warbler","scientific_name":"Phylloscopus maculipennis","overview":"灰喉柳莺（英文名：Ashy-throated Warbler，学名：Phylloscopus maculipennis），是雀形目柳莺科柳莺属的鸟类。最显著的外部特征是头部的灰白色调和雪白的眉线，分布于喜马拉雅山脉及东南亚北部的温带森林和亚热带湿润低地森林中。在中国，主要见于四川、云南、西藏等地区。","appearance":"灰喉柳莺体长约9至10厘米，体重5至7克，拥有小巧精致的喙，与戴菊相似，但具有明显的头纹、翼纹和淡色臀部。成鸟的头顶和颈侧呈深灰绿色，眉线白色且长，眼纹暗棕色同样长。背部、肩羽和上翼覆羽为鲜绿色，翼羽和尾羽暗褐色，外侧三根尾羽内缘白色。下体上部灰白色，其余部分鲜黄色。幼鸟上体较成鸟更棕色，翼纹带有淡褐色，喉咙和胸部颜色比成鸟浅。","call":"灰喉柳莺的鸣唱是一系列尖锐刺耳的哨声，短暂而急促。叫声为高音的‘tzit’声，尖锐且清脆。","habits":"栖息于混合橡树和针叶林区，海拔1800至3500米，尤其偏好杜鹃花和灌木丛生的环境。非繁殖季节，可在山麓和低地的阔叶林和次生林中找到它们，高度通常在600至2100米之间。它们是垂直迁移者，繁殖后会从高地迁至低地和山麓地带。冬季在尼泊尔中部加德满都谷地越冬。主要以小昆虫和幼虫为食，常在树冠层活跃觅食，同时频繁展示白色尾缘。","breeding":"繁殖信息知之甚少。繁殖期在3月至7月。巢悬挂在树枝上，离地面可达5米。其他繁殖细节未知。","identification":"灰喉柳莺与橙斑翅柳莺相比，体型较小，下体黄色；与黄腰柳莺及四川柳莺相比，喉部浅灰色，顶纹为灰色而非黄色。与黄腰柳莺相比，具有更白的眉线、更深的顶侧、更暗的顶纹、更黄的翼纹、尾羽外侧的白色以及黄色下体。","protection":"IUCN：LC（无危）。在中国南部较为罕见，在尼泊尔和印度较为常见，在不丹普遍。泰国西北部的Doi Inthanon地区非常常见，缅甸西部、北部和东部，老挝北部和南部，越南北部和南部（W Tonkin和S Annam）也有局部常见。","distribution":"繁殖于喜马拉雅山脉，非繁殖季节分布于东南亚北部的山麓和低地森林，主要在海拔600至2100米之间。","other":"灰喉柳莺曾被归入旧世界莺类的集合中，现已明确属于柳莺科。"},{"name":"甘肃柳莺","english_name":"Gansu Leaf Warbler","scientific_name":"Phylloscopus kansuensis","overview":"甘肃柳莺（英文名：Gansu Leaf Warbler，学名：Phylloscopus kansuensis），是雀形目柳莺科柳莺属的小型鸟类，仅分布于中国中北部地区。曾被视为黄腰柳莺的亚种，但现在基于声音差异和基因序列的不同，被确认为独立物种。体长约10厘米，略大于黄腰柳莺，上体橄榄绿，下体淡色，臀部泛黄。","appearance":"该鸟具有橄榄绿色的背部，黄色的眉纹，双翼上有明显的条纹，头部有浅色的冠纹。与黄腰柳莺相比，它的眉纹更亮黄，而云南柳莺的头部图案较弱，黑色眼纹末端有小钩。视觉上与黄腰柳莺极为相似，但平均而言，其眉纹更浅，下体颜色更深。","call":"鸣唱由一系列尖锐的快速芯片声组成，随后是一串颤音；叫声包括一系列清脆的芯片声。","habits":"栖息于中海拔森林，偏好灌木状的白杨和桦树林丛，其分布海拔低于云南柳莺。在落叶林中活动，海拔高度可达3200米，林中有云杉和桧树。","breeding":"确切的繁殖行为尚未详细研究，但已知在甘肃省和青海省北部繁殖。冬季迁徙地不确定，可能位于中国南方的云南省。","identification":"与黄腰柳莺的区别在于更亮的黄色眉纹，与云南柳莺的区别在于头部图案的强度和眼纹末端的小钩。","protection":"IUCN：LC（无危）","distribution":"繁殖于中国中北部（包括青海东北部和甘肃西南部）。非繁殖季节的分布未知，但可能在中国中南部。"},{"name":"云南柳莺","english_name":"Chinese Leaf Warbler","scientific_name":"Phylloscopus yunnanensis","overview":"云南柳莺（英文名：Chinese Leaf Warbler，学名：Phylloscopus yunnanensis），是雀形目柳莺科柳莺属的鸟类。原名四川柳莺，后根据国际动物命名法则更正为现名。体型圆滚，长度约10厘米，翼展5至6厘米，上体呈橄榄绿色，腰及冠纹黄色，头部特征鲜明。分布于中国北部、中部，冬季迁往东南亚。","appearance":"云南柳莺体型稍长而紧凑，尾部略呈方形，喙尖短，暗褐色，下颌呈褐黄色。上体橄榄绿至浅绿色，臀部黄白。头部具明显的淡色眉纹，模糊的黄色中冠纹，侧冠纹深橄榄灰。初级飞羽色深，具白色端点。雌雄相似，春季成鸟羽毛亮丽，夏季成鸟羽毛略显磨损。","call":"独特的鸣声长达一分钟以上，音质干涩单调，重复五次‘tsiridi’。叫声清脆多变，一系列责备似的哨声‘tueet’重复五次，随后四组递减，最后以五音符结束，近距叫声为柔和的‘trr-trr’。","habits":"栖息于低地落叶次生林，高度不超过2600米，偏好冷杉和云杉森林。繁殖季节单独或成对出现，性格相对大胆，常在树冠层觅食昆虫，雄鸟从树顶唱歌。","breeding":"关于繁殖习性的具体信息未详述。","identification":"与黄腰柳莺相比，眉纹和冠纹更淡，整体黄色调更淡，第一道翼斑不明显或缺失。与甘肃柳莺和淡黄腰柳莺区别在于身型略长而非矮胖，头部花纹更黄但不清晰，二级飞羽颜色更淡。","protection":"IUCN状态未知。","distribution":"繁殖于中国北部和中部，包括青海东部、甘肃南部、陕西、山西和河北至四川；非繁殖季节分布于东南亚。","other":"历史上的中文名‘四川柳莺’现已用于指代另一物种（学名：，英文名：四川柳莺）。"},{"name":"黄腰柳莺","english_name":"Pallas's Leaf Warbler","scientific_name":"Phylloscopus proregulus","overview":"黄腰柳莺（英文名：Pallas's Leaf Warbler，学名：Phylloscopus proregulus），是雀形目柳莺科柳莺属的鸟类。俗名: 槐树串儿、黄尾根柳莺、黄腰丝、帕氏柳莺、树串儿，又称槐树串儿、黄尾根柳莺、黄腰丝、帕氏柳莺、树串儿。这种小型柳莺体长约9厘米，以其鲜亮的绿色背部和独特的柠檬黄色腰部著称。广泛分布于俄罗斯南部至中国东北部的山地森林中，迁徙期间几乎遍及中国全境。其模式产地位于西伯利亚。","appearance":"黄腰柳莺拥有短尾和大头，头部具三道亮黄色条纹，前额黄色，后部淡黄或白色。上体绿色，翼上有鲜明的双黄色条纹，腰部为醒目的柠檬黄色，腹部白色微带黄色。幼鸟与成鸟相似，但色泽较暗，上体略带棕色，下体呈灰白色，眉纹较淡。雌雄羽色相近，但雌鸟体型平均小于雄鸟。","call":"黄腰柳莺的鸣声复杂且持续，由清晰的哨音和颤音组成，有时类似戴菊的歌唱，夹杂着重复的短语。叫声为轻微的‘jwee’声。","habits":"栖息于针叶林和混合林，高可达1,500至1,700米。非繁殖季节，可在各种森林和半林地环境中发现。以昆虫为主食，包括苍蝇、蚜虫、小蛾子及其幼虫和蛹，也会捕食蜘蛛。活动时常常悬停于树叶间捕食，有时加入多种鸟类组成的觅食群。","breeding":"繁殖期为6月至7月，筑巢于树上，高度0.5至10米，靠近树干。巢由干燥的枝条、树皮纤维、苔藓、树叶和地衣构成，内衬细草、桦树皮、羽毛和毛发。一窝产卵4至6枚，孵化期12至13天，雌鸟为主要孵卵者。雏鸟在12至14天后离巢，之后一周内仍由双亲喂养。","identification":"与淡黄腰柳莺相比，黄腰柳莺的头顶条纹更为鲜亮黄色，下体颜色更黄。与橙斑翅柳莺及灰喉柳莺的区别在于顶纹为黄色。与黄眉柳莺的区别在于黄腰柳莺的眉纹更粗且黄色，而黄眉柳莺的眉纹偏白，无明显的顶冠纹。","protection":"IUCN：LC（无危）","distribution":"繁殖于欧亚大陆的俄罗斯南部和蒙古北部至俄罗斯东部和中国东北部。非繁殖期分布在中国东南部和亚洲北部的东南部，包括南中国、北泰国、老挝北部和越南北部。","other":"近年来，在欧洲秋季发现黄腰柳莺的数量有所增加，特别是在英国、瑞典、芬兰和丹麦。"},{"name":"淡黄腰柳莺","english_name":"Lemon-rumped Warbler","scientific_name":"Phylloscopus chloronotus","overview":"淡黄腰柳莺（英文名：Lemon-rumped Warbler，学名：Phylloscopus chloronotus），是雀形目柳莺科柳莺属的小型鸟类。拥有独特的白色顶纹和长眉纹，两道偏黄色的翼纹，三级飞羽羽端呈现白色。在形态上与云南柳莺极其相似，但通过其特有的声音和生境可加以区分。分布于喜马拉雅山脉至中国中部。","appearance":"体长9-10厘米，体重4.6-5.1克。淡黄腰柳莺体态丰满，羽毛图案清晰。头部有明确的淡色冠纹，侧冠纹呈暗橄榄色；超眼纹浅黄褐色，后部渐白；眼纹深褐色，常向下勾；耳羽淡黄或黄白色，带有暗色斑点；上体灰绿，臀部黄色或黄白色明显；翼暗褐，除次级飞羽基部形成对比鲜明的暗色条纹外，边缘黄绿色；中覆羽尖端淡色，形成明显的翼纹；最长和中央三级飞羽外缘有灰白色尖端；尾羽暗褐，边缘黄绿色；下体淡黄白或黄白色，胸部两侧有时带有淡淡暗色。雌雄羽毛相似，雌鸟平均较雄鸟小。幼鸟与成鸟非常相像。simlaensis亚种的侧冠纹更淡更绿，上体颜色更绿，下体更黄。","call":"有两种截然不同的鸣唱类型，通常只有一种会连续长时间鸣唱。'A型'鸣唱为拉长的直颤音紧接着较低频率的更长颤音，每节约2-4秒，声音比四川柳莺的对应鸣唱更薄（频率跨度更窄）、更快。'B型'鸣唱为异常冗长（可达十分钟以上）的断续音串，由几种不同的单音或长短不一的组合构成，整体鸣唱的频率范围更广，元素间隔更紧密。叫声为高调尖锐的'pist'或'psit'声，比四川柳莺的叫声短。","habits":"繁殖季节主要栖息于云杉-冷杉森林，与一些落叶阔叶和杜鹃花森林混杂，亦可见于松树或混合针阔叶林中；在海拔约2200-4200米处繁殖，冬季则降至300-2700米高度。以昆虫及其幼虫为食，单独或成对觅食，冬季常与其他种类混群。觅食高度从树冠到林下层均有涉及，冬季活动范围低于淡眉柳莺。频繁悬停和空中捕食。","breeding":"繁殖期为4月至7月，主季为5月底至6月；在克什米尔，5月末至6月末产卵，7月末观察到幼鸟离巢；尼泊尔和印度东北部（北孟加拉）5月中旬和5月末记录到卵。巢由雌鸟构建，形状为带侧面入口的球状，由草、苔藓、地衣和桦木皮制成，内衬羽毛，通常位于距地面2-15米（常见3-6米）的针叶树枝上。每窝产3-5枚卵，一般为4枚；仅雌鸟孵化，双亲共同喂养雏鸟；关于孵化和离巢周期的持续时间未知；幼鸟离巢后被父母喂养超过一周。","identification":"与黄腰柳莺相比，上体多为灰绿的橄榄色，头部黄色斑纹不明显，眼前缺少黄色眉纹，下体多为灰色而非白色，体型略大，翼上的图案有异。","protection":"IUCN：LC（无危）。普遍分布且在局部地区数量丰富。在整个北印度次大陆的适宜海拔高度处为常见繁殖鸟。虽然没有具体的人口估计数据，但该物种的数量被认为相对稳定，且目前没有已知的重大威胁。","distribution":"分布于喜马拉雅山脉和中国。在繁殖季节，主要分布于喜马拉雅山脉至中国中部，包括巴基斯坦、尼泊尔等地。非繁殖季节，可降至更低海拔，如印度东北部阿萨姆邦的山丘。","other":"淡黄腰柳莺的某些亚种已被提升为独立的鸟种。"},{"name":"布氏柳莺","english_name":"Brooks's Leaf Warbler","scientific_name":"Phylloscopus subviridis","overview":"布氏柳莺（英文名：Brooks's Leaf Warbler，学名：Phylloscopus subviridis），是雀形目柳莺科柳莺属的鸟类。小型的旧世界莺科鸟类，以独特的黄色面部和胸部、黄色的冠纹和至少一条白色翼纹（通常两条）而著称。该物种分布于阿富汗东部、巴基斯坦北部至印度西北部。","appearance":"布氏柳莺体长9-10厘米，体重5-6克。外观为中等大小的橄榄绿色，具有明显的眉纹和两条翼纹。头顶中央有模糊的淡黄色冠纹，眼上方的金色眉纹在前额汇合，眼后至耳羽后逐渐变白。脸颊呈黄色，耳羽边缘带有暗橄榄色。上体大部分为橄榄绿色，臀部略显淡黄。飞羽和尾羽为棕色，中覆羽和大覆羽有宽广的黄白色尖端形成两条明显的翼纹。喉部和下体为淡黄白色。虹膜深棕色，喙为褐色或深褐色，下颚基部黄色。腿为深棕色。雌雄相似，幼鸟与成鸟类似，但上体颜色较深，下体带污白色，胸腹部微带肉色。","call":"其鸣唱由一系列高音的“zip-zip-zip-...”音符组成，随后是一段干涩的颤音。叫声为短暂的“chee-up”，与暗绿柳莺的叫声相似。","habits":"夏季在云杉和冷杉林中活跃，冬季转至干燥的灌木林。栖息于海拔2100米至2700米间的针叶林，主要为云杉、银杉和雪松，以及混合阔叶林。非繁殖季节栖息于灌木丛、橄榄树园、果园、花园、荆棘树和路边灌木丛。以小昆虫和幼虫为食，单独或成对觅食，冬季常加入混群，与其它小型莺鸟和白眼共同活动。","breeding":"繁殖季节为5月至7月。巢为粗草制成的球形，内部铺有细植物纤维和动物毛发，建于地面，通常位于陡峭的岩石旁或灌木下。每窝产卵3-4枚，关于孵卵和育雏期的信息尚未公开。","identification":"与淡眉柳莺的区别在于淡绿黄色的冠纹、黄色而非灰白色的眉纹、更绿色的上体和更广泛的下颚基部黄色。与Arctic Leaf Warbler的区别在于冠色与背部一致、喉咙和胸部有黄色色调、不太明显的中冠纹和臀斑，以及无对比鲜明的翼羽基部。","protection":"IUCN：LC（无危）。在北巴基斯坦局部常见，而在北印度较为罕见或分布局限。","distribution":"繁殖于欧亚地区的阿富汗东部、巴基斯坦北部和印度西北部。非繁殖期分布至巴基斯坦中部和印度中北部。","other":"由鸟类学家William Edwin Brooks首次描述，他是加拿大鸟类插画家Allan Brooks的父亲。"},{"name":"黄眉柳莺","english_name":"Yellow-browed Warbler","scientific_name":"Phylloscopus inornatus","overview":"黄眉柳莺（英文名：Yellow-browed Warbler，学名：Phylloscopus inornatus），是雀形目柳莺科柳莺属的鸟类。俗名: 树串儿、槐串儿、树叶儿、白目眶丝，体型小于暗绿柳莺和叽喳柳莺，背部呈橄榄绿色，下体白色，具有显著的淡黄色眉纹。繁殖于欧亚大陆的东部，包括俄罗斯中部至东部、中国东北部及北韩，冬季迁徙至南亚及东南亚，小部分群体甚至到达西欧过冬。在中国，是常见的食虫鸟类。","appearance":"黄眉柳莺体长10-11厘米，体重4.3-6.5克，上体橄榄绿色，下体白色，具明显的淡黄色眉纹和两道白色翼斑，靠上的翼斑较短且不那么明显。成鸟与幼鸟颜色相似，但幼鸟上体带橄榄棕色，头部颜色更深，翅膀和尾巴为暗棕色。","call":"鸣叫声独特，为双音节上扬的“tsu-weet”声，鸣唱时发出一系列交替的长音和短音，形成非常高的、细薄的声音序列。","habits":"繁殖季节活动于1000米至2440米的阔叶林地带，冬季则广泛出现在各种林地和灌木丛中。食物主要是小型无脊椎动物，包括多种昆虫。活动于树冠层，偶尔下降至地面。迁徙期间，会穿越欧洲至其南亚和东南亚的越冬地。","breeding":"繁殖期在6月至7月，每窝产2-4枚蛋，孵化期11-14天，幼鸟孵化后12-13天离巢，父母喂养幼鸟长达13天。可能在一年龄时首次繁殖。","identification":"黄眉柳莺与黄腰柳莺、暗绿柳莺、双斑绿柳莺、四川柳莺、暗绿柳莺有明显的区别，主要在于上体颜色、翼纹、顶纹和体型大小。黄眉柳莺与黄腰柳莺的区别在于无浅色顶纹，与暗绿柳莺的区别在于上体更鲜亮，与双斑绿柳莺的区别在于上体更浓绿。","protection":"IUCN：LC（无危）","distribution":"繁殖于欧亚大陆的东部，包括俄罗斯中部至东部、中国东北部及北韩；冬季迁徙至南亚及东南亚，小部分群体到达西欧过冬。","other":"黄眉柳莺的欧洲西部种群在过去几十年向西扩展，1990年估计有45,000-46,000对繁殖于乌拉尔山脉以西的俄罗斯。"},{"name":"淡眉柳莺","english_name":"Hume's Leaf Warbler","scientific_name":"Phylloscopus humei","overview":"淡眉柳莺（英文名：Hume's Leaf Warbler，学名：Phylloscopus humei），是雀形目柳莺科柳莺属的鸟类。体长10厘米的小型柳莺，以英国驻印度公务员兼鸟类学家Allan Octavian Hume命名。拥有橄榄灰色的上体，两道显著的翼斑，以及不明显的顶冠纹。繁殖于中亚山区，冬季迁徙至印度及周边地区。","appearance":"淡眉柳莺体长10-11厘米，体重5-8.8克，身形修长，活跃，具有细长的喙、突出的眉纹和翼斑。头部和上体主要为橄榄绿色，顶部和肩部略带灰色，顶冠纹较宽但模糊。翼覆羽边缘呈淡黄白色，形成两道翼斑，其中一道较小或不明显。飞羽呈暗褐色，带有淡黄色边缘，尾羽基部白色。下体白色，喉部和胸部灰白色。虹膜深棕色，喙几乎全黑，下颌基部有时带有小块淡橙色或暗橙色，腿色为暗棕色或略带橙色。幼鸟的上体更偏褐色，翼斑泛黄，眉纹和下体通常为污白色，两侧泛黄。mandellii亚种的顶冠更灰，上体颜色较暗，更偏褐色，上翼斑很少明显，三级飞羽边缘和飞羽尖端为灰绿色，眉纹和下体为暗黄白色。","call":"叫声包括\"tooee\"、\"tsui\"、\"chwee\"或\"weesoo\"，比的叫声更干涩，还有类似麻雀的\"chirp\"声，\"scewp\"或\"tiss-yip\"音符，mandellii亚种会重复发出尖锐的后者叫声。鸣声有两种类型：一是生动的\"weesoo\"叫声重复版；另一种是长而渐弱的，嘶哑的\"eeeeeeeeeeeeezzzzzzzzzzzz\"，往往持续数秒。","habits":"栖息于海拔高达3500米的落叶松和松树林，惧生，常加入混合群。活跃的林栖型莺，主要以昆虫为食，包括甲虫、膜翅目昆虫、鳞翅目昆虫、蜻蜓、双翅目昆虫、半翅目昆虫、蚜虫和小型蟑螂，偶尔也吃蜘蛛和软体动物。通常单独或成对活动，非繁殖季节常在多种物种的群体中。在所有层次觅食，既在树冠内也在树冠外，主要从树叶中获取食物；经常悬停以检查最外层的叶子；也会敏捷地追逐昆虫飞行。偶尔在地上觅食。","breeding":"繁殖期为5月底至8月初，一般一窝，但在天山地区偶尔会有两窝。一夫一妻制，已知在天山地区的配偶关系可持续三年。领域性强。配偶形成时，雌鸟进入雄鸟的鸣叫领地，双方落在同一枝条上，互相接近，翅膀半张，尾巴展开（有时会抬起高于背部水平），随后雄鸟追着雌鸟飞行。巢由植物纤维、苔藓、草和动物毛发构成的球状结构，位于地面、苔藓覆盖的根或石头之间，或隐藏在草丛中，通常在灌木、小树或低矮蔓延的杜鹃花下，有时在树洞里。每窝产卵4-5枚，偶尔6枚；仅由雌鸟孵化，周期11-14天；雏鸟由双亲喂养和照顾，离巢期11-15天；幼鸟独立于21天后。巢可能被小杜鹃寄生。繁殖成功率高。","identification":"与黄眉柳莺非常相似，但翼斑更为单一，整体色彩更暗淡，下颌基部橙色较少。mandellii亚种与指名亚种的区别在于顶冠更灰，上体颜色更暗，更偏褐色，上翼斑不明显，三级飞羽边缘和飞羽尖端为灰绿色，眉纹和下体为暗黄白色。","protection":"IUCN：LC（无危）","distribution":"繁殖于欧亚大陆的中国中南部、中国中部；越冬于印度及邻近区域。","other":"本种为迁徙性鸟类，冬季迁徙至印度和相邻地区。在秋季迁徙期间，易于远离其繁殖地，最远可达欧洲西部，尽管与繁殖地相隔3000公里。在英国，它是罕见的迷鸟。"},{"name":"极北柳莺","english_name":"Arctic Warbler","scientific_name":"Phylloscopus borealis","overview":"极北柳莺（英文名：Arctic Warbler，学名：Phylloscopus borealis），是雀形目柳莺科柳莺属的鸟类。俗名: 柳串儿、北寒带柳莺，小型偏灰橄榄色的柳莺。其最显著的外部特征是具有明显的黄白色长眉纹，繁殖于欧洲北部、亚洲北部及阿拉斯加，冬季则迁徙至中国南方、东南亚、菲律宾及印度尼西亚。","appearance":"体长11-13厘米，上体灰橄榄色，下体略白，两胁呈褐橄榄色，具明显的黄白色长眉纹，翼部有甚浅的白色翼斑，中覆羽羽尖形成第二道模糊的翼斑；眼先及过眼纹近黑色。嘴较粗大且上弯，尾看似短，头上图纹较醒目。","call":"其鸣唱为快速的颤音，类似于白腰朱顶雀的嘈杂颤音。","habits":"极北柳莺偏好开阔有林地区、红树林、次生林及林缘地带，常加入混合鸟群，在树叶间寻食。它在繁殖季节栖息于欧亚大陆北部的亚北极地带森林，尤其是靠近水源的地方，冬季迁徙至东南亚低地和丘陵森林、森林边缘和花园。","breeding":"繁殖期在春季，营巢于地面低矮的灌木中。营巢、交配、产卵、孵化和育雏等具体细节尚需更多研究。","identification":"与黄眉柳莺的区别在于嘴型较粗大且上弯，尾部显得较短，头部图纹更醒目。与淡脚柳莺相比，色彩更鲜亮且绿色更浓，顶冠颜色较淡。与乌嘴柳莺的不同在于下嘴基部颜色较浅。","protection":"IUCN：LC（无危）","distribution":"繁殖区域包括从欧洲北部到俄罗斯远东地区（除堪察加半岛）直至中国东北部，以及阿拉斯加西部。非繁殖区域主要集中在亚洲东南部，包括中国东南部、台湾、菲律宾和印度尼西亚。","other":"极北柳莺的名称来源于其繁殖地的地理位置，被称为‘北寒带柳莺’。"},{"name":"堪察加柳莺","english_name":"Kamchatka Leaf Warbler","scientific_name":"Phylloscopus examinandus","overview":"堪察加柳莺（英文名：Kamchatka Leaf Warbler，学名：Phylloscopus examinandus），是雀形目柳莺科柳莺属的小型鸟类。原被视作极北柳莺的同种，现已确认为独立物种。分布于堪察加半岛、库页岛、千岛群岛和北海道的北方针叶林和林缘地区。迁徙途经中国沿海，冬季栖息于菲律宾和印尼中部东部。","appearance":"体长约13厘米，体重9至13克，羽色单一，与极北柳莺和日本柳莺相似，但体型略大，头顶和背部橄榄绿略暗淡，喉部和腹部颜色较灰暗，黄色较淡，喙稍粗。性别间差异不大，幼鸟色彩更为灰暗，上部色调更暗，下部偏黄褐色。","call":"鸣叫声为低沉的\"喳\"声，比日本柳莺和极北柳莺的叫声更低。鸣唱声为一系列破碎的啾啾声，音节分散，与极北柳莺连续高音的鸣唱声有别。","habits":"迁徙性鸟类，非繁殖季节栖息于菲律宾南部至巴厘岛和小巽他群岛的极端东南亚洲。春季迁徙期为5月至6月，秋季迁徙期为8月中旬至10月初，途经日本、韩国等地。以小型昆虫和其他小型无脊椎动物为食，通常单独或成对觅食，有时加入混合物种的群落。行为与极北柳莺相似。","breeding":"繁殖季节为6月末至8月，通常一窝，偶尔两窝。主要为一夫一妻制，偶尔出现多配偶制。巢由草茎、芦苇、苔藓、植物纤维和嫩枝构成，位于近树根处的植被地面上。每窝产5至6枚卵，孵化期约14天，由雌鸟承担，雏鸟离巢期约为13至14天。","identification":"与极北柳莺和日本柳莺相比，堪察加柳莺体型略大，羽色较暗，鸣叫声更低沉。区别辨识需结合形态、声音和分布地。","protection":"IUCN：LC（无危）","distribution":"繁殖于堪察加半岛、库页岛、千岛群岛和北海道的北方针叶林和林缘地区。迁徙途经中国沿海地区，越冬于菲律宾和印度尼西亚中部、东部。","other":"2021年7月18日，芬兰Enontekiö的Kilpisjärvi首次记录到欧洲的堪察加柳莺观察报告。"},{"name":"日本柳莺","english_name":"Japanese Leaf Warbler","scientific_name":"Phylloscopus xanthodryas","overview":"日本柳莺（英文名：Japanese Leaf Warbler，学名：Phylloscopus xanthodryas），是雀形目柳莺科柳莺属的鸟类。小型鸣禽，曾被认为是极北柳莺的一个亚种，外观上与极北柳莺和堪察加柳莺极为相似，但其整体色调更为均匀的黄色。在日本除北海道以外的所有地区繁殖，主要栖息于森林地带。","appearance":"体长约12-13厘米，体重约9.8-13克。头部略斜，长翼，喙宽厚，具明显黄白色眉纹，向下由深橄榄绿色眼纹环绕。成鸟新鲜羽毛下耳羽呈淡黄色，斑点较暗；头顶和背部亮橄榄绿；翼上有明显的白色翼带；飞行羽暗棕色，边缘绿色；尾巴主要绿色；喉咙和下体颜色多变，偏黄，腹部白色或近白色；虹膜深褐色；喙暗褐或灰褐色，基部微黄；腿色从淡黄色到橙棕色不等。雌雄相似，幼鸟上体更暗，灰棕色，胸部和侧腹有淡棕色或淡黄棕色的洗染。","call":"鸣唱声似‘树德瑞特-树德瑞特-树德瑞特…’或‘茨奇茨奇茨奇…’，持续1.5-2秒，重复多次，常夹杂‘brrt’音节，节奏与极北柳莺类似但音调更低，节奏不同，比堪察加柳莺的鸣唱更慢，含有更粗糙或尖锐的音符。叫声为干涩的‘brrt’或‘brr-brrrt’，音调略低，不如堪察加柳莺和极北柳莺的叫声嘶哑。","habits":"繁殖季节栖息于落叶林、混交林、针叶林及灌木丛，海拔1500-2500米，偏好茂密的下层植被。非繁殖季节，常见于海拔1800米以下的混合落叶和常绿林地边缘、雨林边缘、次生林、农田边缘、种植园和花园。迁徙性鸟类，秋季经岛屿和中国东部迁往台湾、菲律宾、婆罗洲、爪哇和摩鹿加群岛。","breeding":"繁殖季从中到晚六月至八月，通常会育两窝。主要为一夫一妻制，偶尔观察到一夫多妻制。领地意识强，雄鸟通过鸣叫建立领地。巢由雌鸟建造，球形，侧面入口，主要由苔藓制成，内部衬以细根、草茎、芦苇碎片，有时混入动物毛发和细根形成内杯，位于地面植被中或树根之间。每窝产4-5枚白色蛋，带小暗斑，雌鸟孵卵，周期12-13天；幼鸟由雌鸟照顾，双亲喂食，离巢期13-14天。中杜鹃频繁寄生其巢。","identification":"与极北柳莺和堪察加柳莺区别主要在于繁殖地范围和鸣唱声的差异，以及整体色调更均匀的黄色。","protection":"IUCN：LC（无危）","distribution":"繁殖于日本中部和南部（本州至九州），非繁殖期分布于台湾、菲律宾和印度尼西亚北部。"},{"name":"绿柳莺","english_name":"Green Warbler","scientific_name":"Phylloscopus nitidus","overview":"绿柳莺（英文名：Green Warbler，学名：Phylloscopus nitidus），是雀形目柳莺科柳莺属的鸟类。体型纤小的柳莺科鸟类，体长约10–11厘米，重6.5–9克。其显著特征为两道白色翼斑（常只显现一道），上体呈橄榄绿至亮绿色，面部带黄色晕染，下嘴橙黄色。夏季繁殖于高加索山地的山毛榉、栎树或杜松林；冬季主要迁至南印度及斯里兰卡，与外貌相似的暗绿柳莺同域越冬，但可通过更亮丽的绿色上体、面部黄色及响亮的三音节“chi-su-wi”叫声加以区分。","appearance":"雌雄同色，成鸟具长而鲜明的黄色眉纹，向后延伸至耳羽后缘，眉纹下方为深橄榄色眼纹，眼纹内可见明显的白色下眼圈。颊部与耳羽亮黄，边缘略带橄榄斑点；头顶与上体及飞羽、尾羽边缘均为鲜橄榄绿，磨损时转为灰褐。中覆羽与大覆羽末端淡黄，形成两道翼斑，春季新羽时中覆羽翼斑常较明显。下体白色，常带不同程度的黄色晕染，部分个体颏、喉及尾下覆羽全黄，磨损时黄色可能消退；翼下覆羽黄色，松散羽端在翼弯处显露。虹膜深褐；上嘴暗角褐色，下嘴亮橙、黄或带粉色；足色多变，灰色至橄榄绿，后缘或带黄、淡褐或粉色。幼鸟似成鸟，但下体通体黄色。","call":"鸣唱期自4月下旬至7月末，歌声高亢悦耳，兼具上扬与下滑的啭鸣声，似白鹡鸰与煤山雀之歌，常以“swee-oo”或“che-wee”起始，后接连续“chewee chewee chui chui chui”，或更悠长带颤音“cheweeee”。联络叫声为响亮尖细的“chi-wee”“chee-wee”，另有“chirr-ir-ip”“tissick”“thirririp”及清脆“zilip”；受惊或兴奋时发出急促重复的“chi-vii chi-viii”，以及更长、更圆润、近似三音节的“chi-ru-weet”。叫声与歌声与暗绿柳莺亚种 viridanus 极为相似。","habits":"繁殖期栖于海拔由山麓至约3000米的高山林地，偏好山毛榉、栎树、杜松组成的混交林，林下灌木繁茂，或含赤杨、柳树的针阔混交林及亚高山草甸的灌丛、沟壑、河岸林。非繁殖期活动于海拔不超过2400米的森林、花园、公园、果园及农田边缘。迁徙性，8月离巢，9月至10月抵达南印度及斯里兰卡，少量个体亦至南巴基斯坦。春季3月北返，5月上旬回到繁殖地。觅食时单独或成对，秋季亦混群于山雀等小型食虫鸟中。活跃于林冠层，常边飞边振翼，从叶表或空中悬停捕食小型节肢动物，如甲虫、蜘蛛、石蝇、蛾类、蝇类及蚜虫等。","breeding":"繁殖期5月至7月末，一夫一妻制。雄鸟在雌鸟筑巢时长时间近距离鸣唱以宣示领域，驱赶同属其他种（特别是叽喳柳莺叽喳柳莺及山柳莺P. sindianus lorenzii）。巢为球形，由干草、叶、绿苔、植物纤维及兽毛构成，常置于地面高草丛、溪边苔藓或坡地植物下。每窝4–5枚卵，高加索地区偶见6枚；雌鸟孵卵14–16天，双亲共同育雏，雏鸟14–16天离巢。在西北高加索一研究地点的6巢中，3巢成功出飞，其余因捕食及牲畜践踏失败。","identification":"与暗绿柳莺相比，绿柳莺上体绿色更均匀鲜亮，面颊及耳羽呈黄色而非灰绿；新羽期下体黄色晕染更重，且常具第二道翼斑。鸣声虽相似，但绿柳莺的典型三音节“chi-su-wi”更为响亮快速，可作辅助鉴别。","protection":"IUCN: LC（无危）","distribution":"繁殖区：土耳其北部、北高加索至格鲁吉亚北部，亦见于伊朗北部厄尔布尔士山脉，可能延伸至阿富汗西北部及巴基斯坦俾路支省。非繁殖区：印度南部西高止山脉、喀拉拉邦、泰米尔纳德邦及斯里兰卡为主，少量个体冬季见于巴基斯坦信德省南部。","other":"曾被视作暗绿柳莺的同一物种，但现行分类列为单型种。自1930年代起，其繁殖范围在高加索西北部及土耳其西北部有所扩展，并可能在巴基斯坦西部出现新的繁殖记录。"},{"name":"暗绿柳莺","english_name":"Greenish Warbler","scientific_name":"Phylloscopus trochiloides","overview":"暗绿柳莺（英文名：Greenish Warbler，学名：Phylloscopus trochiloides），是雀形目柳莺科柳莺属的鸟类。中小型林莺，背部暗绿，腹面淡色，具醒目的白色眉纹，眉纹在眼后加宽并延伸至额前。繁殖于欧洲至中亚的落叶林及针阔混交林，迁徙至南亚越冬。常在树冠层活动，鸣唱高亢而冗长，叫声为特征性的二音节“t-sli”。与同属种类辨识需借助鸣声、羽色及分布信息。","appearance":"体长10–11.5厘米，体重6.5–10.5克。成鸟上体橄榄绿或暗绿，具长而宽的白眉纹，眉纹在额前相接并延至颈侧；眼纹暗橄榄色，过眼达耳羽；眼圈细白，下眼弧最明显。翅上覆羽缘淡黄白，形成一道明显的翼斑；飞羽暗褐，外缘亮绿，新鲜羽时初级飞羽内缘具白尖。尾羽褐色，外缘亮橄榄绿，外侧3–4枚尾羽内缘淡黄白。下体黄白，喉、胸侧及胁带灰，胸下部至尾下覆羽染黄。虹膜暗褐；上嘴角褐，下嘴基黄、橙或粉橙；脚灰褐至暗褐。雌雄同色；幼鸟上体略暗。亚种viridanus上体较浅带灰，冠部不如指名亚种暗，翼斑常缺；ludlowi体型稍大，上体更淡，眉纹更白；obscuratus上体更鲜亮，覆羽端常黄，形成上翼斑。","call":"全年发出尖锐、穿透力强的双音节叫声“chee-wee”或“chi-vee”，似白鹡鸰。viridanus亚种叫声为拖长而急促的“chiree”或“chit-wee”。警戒声为重复“si-chiwee”及“ti-ti-ti”。雄鸟鸣唱期4–10月，欧洲种群以“chis-wee”起音，随后是快速混杂的啭鸣与下降音阶，结尾带颤音；指名亚种结构更简单，重复“chiree”短语。雌鸟繁殖季亦会发出较弱的雄鸟式歌声。","habits":"繁殖期栖息于海拔可达4500米的低山及高山桦木、针阔混交林，亦见于山毛榉、槭、椴等阔叶林及河岸灌丛、公园花园。非繁殖季降至低地常绿林、路旁树、荆棘灌丛、耕地边缘、红树林等。单独或成对在繁殖地活动，迁徙及越冬期常混群。在树冠至灌丛各层积极觅食，从叶上、空中或地面捕虫，冬季建立并守护觅食领域。","breeding":"繁殖期5月至8月中，一年一窝。雄鸟以持续鸣唱、振翅、驱赶及喂雌等方式求偶并防御领域。巢址由雌鸟选定，雄鸟在旁鸣唱；巢由雌鸟用苔藓、草茎、枯叶及兽毛筑成，置于地面岩石下、倒木根际、土壁裂缝或树洞，距地可达3米。领域0.5–2公顷，可连续多年使用。每窝3–7枚卵，雌鸟孵卵12–13天，双亲育雏，雏期12–14天，离巢后15天独立。天山研究288枚卵孵化率96%，70巢中73%成功出飞，20%被捕食。1岁即可繁殖，已知最长寿命6年。","identification":"与同属种类区分：较极北柳莺体型略小、嘴小、头更圆、初级飞羽露出短、眉纹更宽且延至额前、脚色更暗；较亮绿柳莺上体暗、下体更白；与双斑绿柳莺相比上体略浅、下体更黄、大覆羽翼斑更窄。与越冬地同域的绿柳莺最好以鸣声区分，且绿柳莺背部更亮、腹面更黄。","protection":"IUCN: LC（无危）","distribution":"繁殖区：指名亚种分布于中、东喜马拉雅至中国西南（西藏东南至四川、云南西北）；ludlowi亚种分布于阿富汗北部、巴基斯坦北部及克什米尔至库蒙；viridanus亚种分布于中、东北欧至中西伯利亚，南至帕米尔、新疆西北及蒙古西北；obscuratus亚种分布于中国中部（青海东部、西藏东部及南部至甘肃、四川）。越冬区：指名亚种越冬于印度东北、孟加拉、云南南部、缅甸、泰国、老挝、越南北部及安达曼群岛；ludlowi主要在印度；viridanus越冬于尼泊尔、印度及斯里兰卡；obscuratus越冬于云南西南、海南、缅甸、泰国及北印度支那。","other":"系统发育地位复杂，曾与绿柳莺、双斑绿柳莺被视为同种，但线粒体DNA及鸣声回放实验显示应为独立种。四个亚种有时被处理为三个独立种，尚需进一步研究。与欧柳莺有杂交记录。"},{"name":"双斑绿柳莺","english_name":"Two-barred Warbler","scientific_name":"Phylloscopus plumbeitarsus","overview":"双斑绿柳莺（英文名：Two-barred Warbler，学名：Phylloscopus plumbeitarsus），是雀形目柳莺科柳莺属的鸟类。中型绿柳莺，由Robert Swinhoe于1861年首次描述。与暗绿柳莺关系密切，曾一度被视为同一物种。其上体呈绿色，下体白色，具有独特的黑色边框白色眉纹和明显的双翼条纹，区别于黄眉柳莺和极北柳莺。分布于北方蒙古、中国东北、俄罗斯东部和南部西伯利亚。","appearance":"体长约11.5至12厘米，体重约9克。中型绿柳莺，上体深绿色，冬季羽毛稍偏褐色；头顶和背部橄榄绿，下体灰白色，喉部、胸部和两胁略带灰色。眉纹黄白色，眼纹深色，翼上有两个清晰的翼条纹，初级飞羽尖端有狭窄的白色边缘。尾巴棕色，边缘橄榄绿。虹膜深棕色，上喙棕色，下喙从黄色到粉红色，腿色变异，从暗红棕色到灰棕色或蓝灰色。幼鸟与成鸟相似，但上体颜色略偏褐色，眉纹黄褐色，翼条纹黄色，下体灰白色。","call":"叫声为干燥而平坦的双音节“tissheep”或“chi-ree-wee”。从抵达繁殖地到8月初，鸣唱声为一系列快速的哨音、颤音和叽叽喳喳的声音，速度稍快，音符更加模糊和混乱。","habits":"繁殖于针叶和落叶混交林、白桦及白杨树丛，最高可达海拔4000米。越冬于次生灌木丛及竹林，高度可达1000米。主要食物为小型昆虫，如膜翅目、双翅目、鞘翅目、同翅目和半翅目的昆虫。迁徙期间，分布广泛，对控制害虫有重要作用。","breeding":"繁殖季节为5月至8月初，雏鸟离巢时间为6月末，幼鸟出现于8月初，但在8月中旬仍可见到成鸟喂养雏鸟。领地性。巢为球形，由苔藓、草茎、树叶和毛发构成，置于地面、斜坡或河岸。一窝产卵5-6枚，偶尔7枚，关于孵化和离巢期的信息未知。","identification":"与暗绿柳莺相比，双斑绿柳莺的翼条纹更宽更显眼，上体颜色更深且绿色更浓，下体更白。与极北柳莺相比，体型较小且更圆。与黄眉柳莺的区别在于嘴较长，下嘴基粉红色，三级飞羽无浅色羽端。","protection":"IUCN状态未知，具体保护级别未提及。","distribution":"繁殖区位于欧亚大陆，从俄罗斯中部和蒙古东北部至俄罗斯东部，东南部，中国东北部和北韩。非繁殖区分布在中国南部和东南亚，包括缅甸、泰国、老挝、柬埔寨和越南。","other":"迁徙时，双斑绿柳莺的分布几乎遍及中国全境，在园林害虫控制方面发挥重要作用。"},{"name":"淡脚柳莺","english_name":"Pale-legged Leaf Warbler","scientific_name":"Phylloscopus tenellipes","overview":"淡脚柳莺（英文名：Pale-legged Leaf Warbler，学名：Phylloscopus tenellipes），是雀形目柳莺科柳莺属的小型鸟类。分布在中国东北的中部和东南部繁殖，迁徙时途经沿海各省直至云南。其脚为浅粉色，因此建议中文名改为淡脚柳莺，与英文名一致。该物种模式产地在福建，被列入《国家保护的有益的或者有重要经济、科学研究价值的陆生野生动物名录》。","appearance":"淡脚柳莺体长约12厘米，上体呈暗橄榄褐色，具有一条显著的白色眉纹，黑色眼线，脸颊上有斑驳的淡棕色。喉咙部分为白色，胸腹部为淡白色，略带浅棕色。尾下覆羽白色，与较淡的橄榄棕色臀部和尾上覆羽形成对比，缺乏绿意。头部有时呈现灰色调，与背部颜色形成对比。","call":"鸣唱为连续的高音颤鸣，音调类似蟋蟀叫声，这一特征有助于与库页岛柳莺相区分。","habits":"栖息于山间茂密的林下植被，高可达海拔1800米。冬季出现在红树林及灌丛地带。常在较低层活动，活泼地来回跳跃，具有独特的向下弹尾的习惯。","breeding":"繁殖期为5月至7月，具体繁殖生态细节未详。","identification":"淡脚柳莺与极北柳莺较为相似，但头部颜色偏灰，与背部的橄榄绿色形成鲜明对比。它不像极北柳莺那样活动于高处，更偏好接近地面的灌丛。","protection":"IUCN：LC（无危）","distribution":"繁殖于欧亚地区的俄罗斯东部至中国东北部和北韩；非繁殖期分布于东南亚，包括缅甸南部至柬埔寨、越南南部至马来半岛，偶尔出现于海南。","other":"淡脚柳莺的英文名和学名反映了其脚部的浅色特征，这一特征是其命名的基础。"},{"name":"库页岛柳莺","english_name":"Sakhalin Leaf Warbler","scientific_name":"Phylloscopus borealoides","overview":"库页岛柳莺（英文名：Sakhalin Leaf Warbler，学名：Phylloscopus borealoides），是雀形目柳莺科柳莺属的小型鸟类。又名:库页岛柳莺莺，曾被认为是淡脚柳莺的一个亚种，现因形态、鸣叫及繁殖区的差异，已被确认为独立物种。在日本北部和库页岛繁殖，冬季迁往东南亚地区。","appearance":"体长约11.5厘米，体重约10.7克。具有长长的奶油白色眉纹和宽阔的深棕色眼纹。头顶和上体呈橄榄褐色，颊部和耳羽具斑驳的浅暗色。飞行羽和尾羽为棕色，腹部污白色，两胁略带褐色。虹膜深棕色，喙部棕色，下颚基部肉粉色，腿色多为淡粉棕色。雌雄相似，幼鸟未详述。","call":"叫声柔和的“tyu”声和更响亮的口哨“heep”或“peet”。鸣唱为一系列清晰延长的三到四个口哨式短语，以叫声开头：“hee-tsoo-kee”或“tyu-tsi-ti-tyu”。","habits":"栖息于森林边缘、林间空地和树木丛生地带；在日本中部，它生活在海拔900米至1800米的山地混合林和亚高山林木中；在北海道，它存在于类似的栖息地，从低地到树线。迁徙期间可见于低地树林、城市公园和花园。","breeding":"在灌木丛中筑巢。","identification":"与淡脚柳莺非常相似，主要区别在于上体颜色更为绿色，缺乏翼斑。鸣叫声频率较低，但与淡脚柳莺存在部分重叠。","protection":"IUCN状态未知。","distribution":"繁殖区位于库页岛（俄罗斯东南部）、千岛群岛南部、北海道和本州（日本北部、中部）。非繁殖期分布于琉球群岛（日本南部）、亚洲东南部，最近在新加坡有越冬记录。","other":"在春秋迁徙季节，于中国东部沿海地区有出现记录，香港地区有环志记录。"},{"name":"乌嘴柳莺","english_name":"Large-billed Leaf Warbler","scientific_name":"Phylloscopus magnirostris","overview":"乌嘴柳莺（英文名：Large-billed Leaf Warbler，学名：Phylloscopus magnirostris），是雀形目柳莺科柳莺属的鸟类。体型较大的迁徙型柳莺科鸟类。其最显著的外部特征是拥有宽大的暗色喙，以及独特的黄白色眉纹。分布于亚洲，繁殖于喜马拉雅山脉和中国中部，冬季南迁至印度南部、斯里兰卡及缅甸。","appearance":"乌嘴柳莺拥有两道明显的白色翼带，上体呈暗绿灰色，眼上方有一条长而醒目的白眉，喙部健壮且色深。头部冠羽较暗，耳羽灰，脸颊及下体常带黄色调，与暗绿柳莺、极北柳莺及灰脚柳莺相比，嘴更大，颜色更深，上体绿色更浓，翼斑亦呈绿色。","call":"其鸣叫特征为独特的双音节dir-tee声，第二音节明显更高，另一种叫声则为一串渐降的配对音符，前有微弱单音，叫声频繁且规律，使其即使藏于密叶之中也容易被察觉。","habits":"乌嘴柳莺栖息于海拔2000至4000米的多草林间空地和林隙，冬季则迁徙至较低海拔。它们主要在树枝上觅食，飞行轻快，偏好密集植被环境，偶尔可见于城市地带。","breeding":"乌嘴柳莺的繁殖季节在喜马拉雅山脉和中国中部，具体细节未知，但一般柳莺会在春季营巢，产卵并育雏。","identification":"与暗绿柳莺相比，乌嘴柳莺体型更大，嘴更大，眉纹更长，脸颊及下体带有更多黄色；与极北柳莺的区别在于嘴色更深，上体绿色更浓；与灰脚柳莺的区别在于腿色更深，嘴更大，眉线、脸颊及下体多黄色。声音是区分这些相似物种的关键。","protection":"IUCN状态未知，未列入CITES附录，未见于中国国家重点保护野生动物名录。","distribution":"繁殖于喜马拉雅山脉和中国中部，包括东北青藏高原、西南甘肃、四川、云南和西藏北部。冬季迁徙至印度南部的西高止山脉、斯里兰卡和缅甸中部与南部。"},{"name":"泰氏柳莺","english_name":"Tytler's Leaf Warbler","scientific_name":"Phylloscopus tytleri","overview":"泰氏柳莺（英文名：Tytler's Leaf Warbler，学名：Phylloscopus tytleri），是雀形目柳莺科柳莺属的鸟类。名称纪念英国自然学家罗伯特·克里斯托弗·泰特勒。该物种以纤细的体态、无翼纹的绿色翅膀和灰色背部为显著特征，拥有长长的对比鲜明的白色眉纹和暗色尖嘴。仅分布于印度次大陆，繁殖于克什米尔周边，越冬于印度南部山区的灌木丛中。","appearance":"体长约10-12厘米，体重约7-8克。中等体型的柳莺，具较长而细的喙和短尾，眉纹明显。上体灰绿带褐色调，下体污白至灰白色，侧腹和腹部微黄。虹膜深棕色，喙主要为暗角质色，下颚基部暗淡角质色，腿为深橄榄棕色。与暗绿柳莺相比，喙更长更细，尾更短，眉纹更窄，耳羽微黄，无翼纹，下体颜色更暗淡。雌雄相似，幼鸟上体更绿，下体更黄。","call":"鸣唱为独特而节奏均匀的高音调‘pi-tsi-pi-tsu’或‘kitchu-qwishu kitchu-qwishu’，也可发出更长的‘chitsu-chuwitssu-chitsu-chuwitssu’，常反复吟唱。叫声为双音节‘chiwee chiwee’或‘tsee-it’，第二声较高且带有上扬的音调，全年皆可听到。","habits":"繁殖于常绿森林、针叶林（尤喜蓝松和银冷杉）、橡树-杜鹃林及高山矮柳和桦树林，海拔2400-3600米。非繁殖季节出现在海拔900米以上的阔叶林和shola森林。迁徙性鸟类，秋季通过北巴基斯坦和印度北部，春季沿中央印度和尼泊尔西部向北迁移。","breeding":"繁殖于西北喜马拉雅山脉，疑似也在Garhwal和Kumaon喜马拉雅山脉繁殖。生态需求尚不清楚，需进一步调查以确定其数量。","identification":"与Siberian Chiffchaff的区别在于其较长的暗眼纹，与暗绿柳莺的区别在于喙、对比明显的上体、偏好灌木丛，以及独特的上升Chiffchaff式‘sweee’叫声。","protection":"IUCN：LC（无危）。受威胁于栖息地丧失，包括砍伐、燃料和饲料采集、牲畜放牧和焚烧。非繁殖地同样面临森林破坏、水电开发、道路建设和木材、竹子和藤条的采伐，以及过度放牧的压力。","distribution":"繁殖区位于阿富汗东北部、巴基斯坦北部和印度西北部。非繁殖区主要为印度西南部，特别是在西高止山脉和Nilgiris。","other":"生态要求大体未知，需要开展调查以确定其丰度。同时，应在繁殖和越冬关键区域实施保护措施。"},{"name":"大冕柳莺","english_name":"Western Crowned Warbler","scientific_name":"Phylloscopus occipitalis","overview":"大冕柳莺（英文名：Western Crowned Warbler，学名：Phylloscopus occipitalis），是雀形目柳莺科柳莺属的鸟类，具有独特的两翼条纹，绿色上体与灰色头部形成对比，白色下体鲜明，明显的冠纹和长而淡色的喙。主要分布在印度次大陆，繁殖于喜马拉雅山脉西部和中部，越冬于印度半岛南部。","appearance":"体长11至13厘米，体重8至9克。中到大型柳莺，具长眉线、双翼条纹和不显眼的冠纹。头部中央有黄灰色的冠纹（常不明显），冠侧暗橄榄色，颈背灰洗。上体灰绿，大覆羽和中覆羽尖端白色（翼条纹最突出在大覆羽上，中覆羽上的翼条纹常不明显，尤其是在磨损的羽毛上）；飞羽和尾羽边缘浅橄榄绿，最外三根尾羽内缘狭窄白色；喉部和下体大部分白色，带灰色晕染；腋羽亮黄绿色；虹膜深棕色；喙棕色，下颚基部橙黄色；腿灰或板岩褐色。雌雄相似。幼鸟上体比成鸟更棕色，飞羽边缘鲜绿色，胸部带灰色晕染。","call":"频繁发出‘chip’、‘chit-wee’或‘cheep-wip’的叫声，受惊时会大声或尖锐地连续叫几分钟。歌唱时，通常边移动边唱，从3月到8月初，是一系列吱吱声的较长和较响亮版本，如‘cha-chi cha-chi cha-chi’或‘chit-wee chit-wee chit-wee chit-wee-wee-wee’。","habits":"栖息于云杉和混合针叶林与落叶林，如蓝松与桦树或橡树林，海拔1800至3200米之间；冬季在低海拔的湿润常绿森林中。迁徙性鸟类，秋季通过塔吉克斯坦和巴基斯坦北部，到达印度半岛越冬地的时间主要是10月，但也有个体早至8月，持续至次年4月。春季北返始于3月末，多数在当月底离开越冬地；4月中旬到达巴基斯坦北部，4月至5月初通过印度北部和巴基斯坦。","breeding":"繁殖期为5月至7月，一窝。领域性强。巢由雌鸟建造，主要由干草、苔藓和动物毛发构成，建于墙洞（包括房屋的空洞）、树桩距地面高达6米处，或旧鼠洞、石下或树根下；在巴基斯坦北部的某些领地约0.1公顷。一窝3至4枚蛋，偶尔5枚；仅雌鸟孵卵，雏鸟由双方父母照料和喂食；孵化期和育雏期未知；离巢雏鸟至少被喂养一周。巢可能被中杜鹃和小杜鹃寄生。","identification":"与非常相似的西南冠纹柳莺主要区别在于略大的体型、略大且稍长的喙、不太引人注目的头部图案、灰调的上体、略暗淡的黄色眉线和下体灰洗，仅胸部和腹部有黄色痕迹；与冕柳莺主要区别在于更白（而非黄色）的尾下覆羽、更灰的上体和更均匀的淡黄色眉线。","protection":"IUCN：LC（无危）","distribution":"繁殖于乌兹别克斯坦东部、塔吉克斯坦西部、阿富汗北部和东部、喜马拉雅山脉西北部，从巴基斯坦的奇特拉尔向南至穆里山丘，向东至印度北部（北阿坎德邦），可能至尼泊尔西部；越冬于印度半岛（西高止山脉和印度中部的山丘以及东高止山脉）。"},{"name":"冕柳莺","english_name":"Eastern Crowned Warbler","scientific_name":"Phylloscopus coronatus","overview":"冕柳莺（英文名：Eastern Crowned Warbler，学名：Phylloscopus coronatus），是雀形目柳莺科柳莺属的鸟类。体型较大的柳莺属鸣禽，俗名“东冠柳莺”。头顶具淡色中央冠纹，黑色侧冠纹与白色眉纹形成强烈对比；上体橄榄绿带黄，下体乳白，尾下覆羽鲜黄，橙黄色宽嘴为其关键特征。繁殖于俄罗斯东南部、中国东北至华中及日本，非繁殖期迁至东南亚低地森林。","appearance":"体长11–12厘米，体重8–10.5克。上体黄绿橄榄色，翼上覆羽尖端黄白，形成一条狭窄而明显的翼斑；新鲜羽衣时翼斑显著，磨损后变淡。头部具长而白的眉纹（眼先略黄），黑色侧冠纹与中央淡色冠纹对比强烈，但冠纹常不延伸至前额，野外有时不可见。耳羽及下方白色微黄，腹部至尾下覆羽柠檬黄色。虹膜深褐；上嘴褐色，下嘴鲜黄；脚蓝绿至灰褐色。雌雄同色。幼鸟上体较褐，冠纹模糊，尾下覆羽暗黄。","call":"繁殖期自树梢发出清晰上扬的哨音歌曲，通常为“pitschu-pitsch-wii”或更长的“tuweeu tuweeu tuweeu tsu-eet, tsu-eet-tzaa”，末音嘶哑；另有柔和的“cheroo cheroo”及短促“tsi-it tsi-it tsyaa”。常见叫声为轻柔的“phit phit”，偶尔发出粗糙鼻音“dwee”或“zweet”。非繁殖期极少鸣叫，偶发短促“fit”或甜美“chi”，后者类似艾吉柳莺常见叫声。","habits":"繁殖季选择泰加林内海拔约1830米以上的阔叶林、针阔混交林及河岸林的林缘和林中空地，亦见于雪松、云杉林。非繁殖期迁至低地和丘陵的常绿、混交林及红树林，活动高度低于2000米。完全迁徙，8月下半月自繁殖地经中国东部、泰国北部、老挝南下，3月北返，4月下旬至5月中旬过华中、南乌苏里地区。冬季极少量见于苏门答腊，欧洲有迷鸟记录。单独或繁殖季后在混群中觅食，活动于灌丛至林冠，以小型昆虫和蜘蛛为食。","breeding":"繁殖期5月中旬至7月，幼鸟6月末至7月离巢。具领域性，巢受侵扰时强烈驱赶入侵者。巢呈球形，由干草、叶、苔藓构成，置于地面或岸坡灌木下、小树低枝间。每窝4–7枚卵，孵化及育雏期尚无确切数据。巢常被Cuculus horsfieldi寄生。","identification":"与冠纹柳莺、西南冠纹柳莺、华南冠纹柳莺相似，但冕柳莺头纹对比更强烈，具单条翼斑，体型较大，嘴长而粗，下嘴全黄；与西南冠纹柳莺相比，体型更大，身形更修长，仅一条窄翼斑，覆羽基部绿色而非暗色，下体除尾下覆羽外更白，眉纹后部更白，侧冠纹色浅。","protection":"IUCN: LC（无危）。全球未受威胁，在繁殖区常见至局部丰富，为俄罗斯乌苏里地区森林中最常见的繁殖鸣禽之一。","distribution":"繁殖区：俄罗斯东南部的阿穆尔地区、乌苏里地区，中国东北及华中（内蒙古北部、黑龙江北部和东部、吉林东部，四川东部及重庆），萨哈林岛、朝鲜半岛及日本。非繁殖区：缅甸南部向东至柬埔寨南部，南抵苏门答腊和爪哇。迷鸟记录：德国、芬兰、荷兰、挪威、英国、孟加拉国及柬埔寨。","other":"历史上曾与饭岛柳莺视为同种，现单型种，无亚种分化。"},{"name":"饭岛柳莺","english_name":"Ijima's Leaf Warbler","scientific_name":"Phylloscopus ijimae","overview":"饭岛柳莺（英文名：Ijima's Leaf Warbler，学名：Phylloscopus ijimae），是雀形目柳莺科柳莺属的鸟类。又称: 艾吉柳莺，东亚特有种。该鸟种在日本伊豆群岛和吐噶喇群岛的特定繁殖地较为常见，具有橄榄绿色背部和淡灰白色腹部，下嘴黄色，腿粉棕色。在台湾和菲律宾北部有记录，是一个易危物种。","appearance":"饭岛柳莺体长约11.5厘米，重约10克，上体亮橄榄绿，下体白，侧腹带灰，翼上有模糊的翼斑。头部有长而宽的眉线，黑色眼纹，细白眼环，灰颊和耳羽。头顶和颈背绿色带灰，下嘴全黄或橙粉色，腿色淡粉至角棕色。雌雄相似，幼鸟特征未详述。","call":"鸣唱由一系列颤音组成，包括“swss, swss, swss”、“swee-swee-swee-swee-swee”等，叫声多样，包括柔和的“se-chui, se-chui, se-chui”和“phi-phi-phi”。","habits":"栖息于低地落叶及混合亚热带常绿森林，包括森林边缘、桤木和竹林地带，以及灌木丛。迁徙期间偏好成熟海岸阔叶林，但也利用竹林和针叶林。以昆虫为主食，也吃种子，单独或小群觅食，有时与其他鸟类混群。","breeding":"繁殖季节从4月持续到6月或7月。巢建于地面以上0.5-2米的阔叶树上或竹林中，不同于冕柳莺的地面或土堤筑巢。每窝产卵2-4枚，通常为3或4枚。","identification":"与冕柳莺区别在于无中央冠纹，整体色调偏灰，且下嘴浅色无暗斑。与极北柳莺的区别在于下嘴颜色浅，无暗色斑点，头顶灰色。","protection":"IUCN：VU（易危）","distribution":"繁殖于日本伊豆群岛（东京南）和吐噶喇群岛的中岛。越冬地不明，可能包括日本南部琉球群岛、台湾和菲律宾北部的吕宋岛。","other":"由于其特定的繁殖地和越冬地的丧失，饭岛柳莺受到栖息地破坏和碎片化的威胁，全球数量估计少于10,000只。"},{"name":"西南冠纹柳莺","english_name":"Blyth's Leaf Warbler","scientific_name":"Phylloscopus reguloides","overview":"西南冠纹柳莺（英文名：Blyth's Leaf Warbler，学名：Phylloscopus reguloides），是雀形目柳莺科柳莺属的鸟类。又名: 布氏冠纹柳莺，曾被归入'旧大陆莺'分类中。主要分布在东南亚、南部中国以及喜马拉雅山脉直至北巴基斯坦地区。其自然栖息地为亚热带或热带湿润的山地森林。此鸟以英国动物学家Edward Blyth命名。","appearance":"体型中等偏小，身长10.5-12厘米，体重6.2-9.4克。具有明显的特征，头顶有一条宽广的黄橄榄色中央冠纹，前额较模糊，两侧由暗橄榄色边界，后方颜色加深；上体呈橄榄绿色，翼覆羽尖端黄色形成两道宽阔的翼带；尾羽和飞羽深棕色，最外侧两根尾羽的内缘狭窄白色；喉部和下体白色泛黄，尾下覆羽淡黄色；腋羽亮黄色。虹膜深棕色，上喙黑色，下喙黄色或橙黄色，腿色变化大，从绿到黄色不等。雌雄相似，幼鸟类似成鸟但色彩较暗淡。","call":"叫声为频繁重复的双音节'pit-cha'或'pit-chee'，或三音节'pit-chew-a'或'tiss-oo-eet'。鸣唱自3月中旬至8月末，是叫声的颤音延伸，如'pit-chew-ee pit-chew-ee pit-chew-ee'或'zit...wher-chee-tee, whee-chee-te-wheet'，还有'chi-ti chi-ti ch-ti chi-chi pit-chew pit-chew'。","habits":"繁殖季节在1500米至3700米的杜鹃花(Rhododendron)和橡树(Quercus)森林中，或局部在针叶林和湿润落叶林中生活。非繁殖季节下降至较低海拔（大多低于1500米），在常绿森林边缘、次生林、空地、丘陵地带的灌木丛中活动，亦可见于农田边缘。","breeding":"繁殖季为2月至8月。巢由两性共同建造，由草、茎和其他材料构成球状，置于树桩洞、树根下的地面、土堤或石墙中。每窝产4-5枚卵，孵化由雌鸟承担，寄生现象见于中杜鹃和小杜鹃。","identification":"与非常相似的云南白斑尾柳莺相比，头和下体的黄色较少，尾部的白色也通常较少；与峨眉柳莺的区别在于更清晰的冠纹和尾部更多的白色。独特的翼拍行为帮助区分于白尾柳莺：西南冠纹柳莺交替缓慢拍打翅膀，而白尾柳莺同时拍打。","protection":"IUCN：LC（无危）。在大部分分布区内常见且广泛分布。在印度次大陆北部尤其东北部常见，但在北巴基斯坦稀少且局部分布；在中国较为常见；缅甸和越南部分地区常见。在东南亚大部分地区为常见的非繁殖访客。未识别出重大威胁。","distribution":"主要分布在喜马拉雅山脉西北部、中部和东部至中南半岛西部和中部。在中国大陆，主要见于喜马拉雅山区和云南省。","other":"关于其鸣唱复杂性的研究显示，由于歌曲类型间的变异性增加，西南冠纹柳莺的高复杂度鸣唱是其特征之一。"},{"name":"冠纹柳莺","english_name":"Claudia's Leaf Warbler","scientific_name":"Phylloscopus claudiae","appearance":"体型较大的柳莺，长约10厘米，体重介于7.5至10克之间。特征为长而淡黄色的眉纹，至后部渐变为白色，黑色橄榄色的细眼线和较宽的眼纹；头部中央有一条宽阔的浅绿色顶纹，至颈部逐渐变白，两侧的暗橄榄色顶纹后部转为更深的黑色；背部橄榄绿，中上翼覆羽尖端黄色，形成两道宽的翼斑；飞羽和尾羽深棕色，边缘宽广的橄榄绿色，最外侧两根尾羽内侧边缘窄带白色；喉部和下体白色，微微泛黄，尤其在两侧；腋下羽毛黄色；虹膜深色；上喙深色，下喙橙黄色或粉红色；腿色变化大，从绿色到粉色。雌雄相似，幼鸟比成鸟颜色暗淡，头部图案不明显。","call":"鸣唱为一系列几乎类似颤音的连续音符，'chi-chi-chi-chi-chi-chi-chi-chi-chi-chi-chi-pit-chi'；另一种歌声非常类似于西南冠纹柳莺的鸣唱。叫声为'pit-it-chu'。","habits":"栖息于温带森林，繁殖季节在茂密林区，冬季可能出现在稀疏林缘。迁徙性鸟类，主要在东南亚度过冬季，自中国南部至缅甸、泰国北部和越南北部。觅食于树冠层，有时会像山雀一样倒挂，缓慢交替拍打翅膀。","breeding":"繁殖习性可能与近缘种西南冠纹柳莺相似，具体细节尚不清楚。","identification":"与黑眉柳莺相比，冠纹柳莺的侧顶纹颜色较淡，两道翼斑更为显眼，下体黄色较少；与白斑尾柳莺相比，冠纹柳莺体型更大，下体黄色更少，且两翼交替振动。","protection":"IUCN：LC（无危）","distribution":"在中国的分布主要在中部和东部，包括四川东部至湖北，北至甘肃南部，山西南部和陕西南部，以及河北。在非繁殖季节，可能出现在印度东北部、缅甸中部和南部、中国南部（云南南部）、泰国西北部和东北部、越南北部（东京西部）。","other":"在2017年3月，香港的Ng Tung Chai有迁徙个体的报道，若确认，将是该物种在香港的首次记录。"},{"name":"华南冠纹柳莺","english_name":"Hartert's Leaf Warbler","scientific_name":"Phylloscopus goodsoni","overview":"华南冠纹柳莺（英文名：Hartert's Leaf Warbler，学名：Phylloscopus goodsoni），是雀形目柳莺科柳莺属的鸟类。又名: 哈氏冠纹柳莺，是中国特有种，主要分布在东南部的温带森林和亚热带湿润低地森林。曾被认为是西南冠纹柳莺的一个亚种，现已提升为独立物种。与冠纹柳莺相比，其顶冠纹更深更宽，具有明显的浅黄色中央冠纹。","appearance":"中等体型（10.5-12厘米），标志性的叶莺。指名亚种有淡黄色眉纹，暗橄榄色的眼线和眼先，宽阔的黄白色中央顶冠纹（前部不太明显），两侧由暗黑色橄榄色的顶冠边缘包围，后部颜色加深；上体呈亮橄榄绿，中覆羽和大覆羽尖端呈淡黄色（形成两道宽翼带）；飞羽和尾羽深棕色，边缘宽绿色，最外侧两枚尾羽内缘狭窄白色；喉咙和下体黄色，腋羽亮黄色；虹膜深棕色至黑色；喙上颚深色，下颚黄色或橙黄色；腿绿色或蓝绿色至黄色。雌雄相似。幼鸟似成鸟但色彩较暗淡，顶冠纹不明显。fokiensis亚种与指名亚种类似，但上方色彩较暗淡，下方多为白色或灰白色。","call":"鸣唱为甜美的高音“whee-cheet-a whee cheet-a...”或“chi-ti chi-ti ch-ti chi-chi...”，缺乏冠纹柳莺和西南冠纹柳莺清晰的前奏音符。叫声为“pit-cha”和类似。","habits":"繁殖于杜鹃花（Rhododendron）和橡树林（Quercus），以及湿润落叶林，主要海拔在1500-3700米；非繁殖季节在较低海拔（通常低于1500米）的常绿林边缘、次生林、以及山脚下的开阔地带和灌木丛中发现。迁徙习性，部分种群可能留居。春季在上海附近，迁徙主要发生在4月初至5月底，秋季在10月中旬至11月中旬，记录到最早可至12月初。","breeding":"繁殖资料有限。推测繁殖季节为3/4月-8月。巢穴由草和其他类似材料制成球状，隐蔽在树桩洞穴、树根下或类似地点；一巢位于贵州，距离地面约2米，在土壤斜坡上的洞穴，由苔藓制成，入口边缘环绕着一些干草叶，宽38毫米，深72毫米。一窝蛋有三枚白色，尺寸约13.4-15.2mm x 11.6-12mm，重量约1-1.2克。推测其他细节与西南冠纹柳莺相似。被中杜鹃和翠金鹃寄生。","identification":"与极北柳莺和淡脚柳莺相比，其顶冠纹和宽橙基喙可作为辨识特征。与Blyth's和Claudia's leaf warblers一样，有交替拍打翅膀的习惯，与Kloss's和Davison's leaf warblers不同，后者同时拍打双翅。","protection":"IUCN：LC（无危）","distribution":"繁殖在中国东南部，越冬区主要从中国南部（云南）向南延伸至老挝北部，可能还包括越南北部。","other":"无"},{"name":"峨眉柳莺","english_name":"Emei Leaf Warbler","scientific_name":"Phylloscopus emeiensis","overview":"峨眉柳莺（英文名：Emei Leaf Warbler，学名：Phylloscopus emeiensis），是雀形目柳莺科柳莺属的鸟类。偏绿色的小型柳莺，仅在中国中部特定地区发现。其特征为上体亮黄绿色，具两条明显的黄色翼斑，下体白色，眼眉淡黄，顶纹清晰。分布于中国四川、云南、贵州和广东等省份的亚热带阔叶林，最高可达海拔1900米。","appearance":"峨眉柳莺长约11-12厘米，头顶灰绿略深，顶纹明显，耳羽淡色带暗斑。背部淡绿色，翼尾主色为绿，中覆羽尖端和大覆羽末端呈淡黄色，形成显著的翼斑。下体白色，尾下覆羽微黄，虹膜深棕色，上喙黑色，下喙橙色，脚爪粉灰色。","call":"其鸣唱为清晰、微颤的直线颤音，频率约4-6千赫兹，持续3-4秒，每只雄鸟有多样化的歌型。叫声为轻柔的‘tu-du-du’，与欧洲绿雀相似但有区别。","habits":"栖息于温带落叶阔叶林，偏好次生和再植的阔叶林环境，而非原始森林。主要在树冠层及灌木层觅食昆虫，振翅迅速，不似冠纹柳莺缓慢交替。活动范围主要限于中国中部省份，高度从1000至2200米。","breeding":"基于雄鸟的歌唱活动，推测繁殖季节从四月中下旬开始，具体细节尚缺乏数据支持。已知在特定区域内繁殖，但对其非繁殖期活动知之甚少。","identification":"与冠纹柳莺相比，峨眉柳莺的顶纹对比度较低，侧顶纹更浅，中顶纹更深。与白斑尾柳莺和冠纹柳莺的歌曲和叫声有明显差异。","protection":"IUCN：LC（无危）","distribution":"主要繁殖于中国四川、云南、贵州和广东的亚热带阔叶林，局部存在于陕西南部。有记录显示其在缅甸东南部非繁殖期出现。","other":"关于其非繁殖期分布和确切数量的数据有限，但总体看来种群稳定。"},{"name":"云南白斑尾柳莺","english_name":"Davison's Leaf Warbler","scientific_name":"Phylloscopus intensior","overview":"云南白斑尾柳莺（英文名：Davison's Leaf Warbler，学名：Phylloscopus intensior），是雀形目柳莺科柳莺属的鸟类。色彩鲜艳的柳莺科鸟类，最显著的外部特征是具有亮黄色的眉纹，以及外侧尾羽的白色边缘，明显区别于冠纹柳莺和峨眉柳莺。分布于亚洲东南部，包括中国云南、四川、贵州、湖南等地。","appearance":"体长10-11厘米，体重5.7-8.1克。头部有明亮的黄色眉纹，深橄榄色的颊纹和眼纹，中央冠纹宽而黄，侧面暗橄榄色；背部呈鲜橄榄绿色，翅膀上覆羽更亮，具两道宽阔的黄色翼纹，翼弯黄色；飞羽和尾羽深棕色，外侧两根尾羽内缘狭窄白色；喉部淡黄色，下体黄色；腋下鲜黄；虹膜深棕色；喙上部深棕色，下部橙色或肉粉色；腿棕色。雄雌相似。幼鸟与成鸟类似，但上体颜色较暗，黄色减少。muleyitensis亚种与指名亚种为近似，但亮度稍逊，尾部白色更多。","call":"歌曲短而甜美，重复上升或下降的音节，如“wih-chew-chee wih-chew-chee-wih”。叫声高亢而清澈，如“chew-wee”或“wit-chew-wee”。","habits":"栖息于落叶阔叶林和混合山地森林，繁殖季节后会降至山脚林区。活动范围广泛，常在树冠层和林下灌木丛中觅食，以昆虫为主食。性情活跃，行动迅速，难以观察。","breeding":"繁殖期具体细节未详述，但一般在春季进行，筑巢、交配、产卵和育雏过程符合柳莺科的一般模式。","identification":"与西南冠纹柳莺及峨眉柳莺相比，云南白斑尾柳莺拥有更明亮的黄色眉纹，更清晰的头纹，下体更黄，尾部白色部分更多。叫声和行为亦可作为辨识依据。","protection":"IUCN：LC（无危）","distribution":"分布于中国云南、四川、贵州、湖南等地，以及东南亚的泰国、老挝、缅甸、越南。在繁殖季节主要位于海拔较高的森林，非繁殖季节会下移到较低的林区。","other":"物种历史分类复杂，曾被视为Phylloscopus davisoni的成员之一，后因分子研究被确认为独立物种。"},{"name":"白斑尾柳莺","english_name":"Kloss's Leaf Warbler","scientific_name":"Phylloscopus ogilviegranti","overview":"白斑尾柳莺（英文名：Kloss's Leaf Warbler，学名：Phylloscopus ogilviegranti），是雀形目柳莺科柳莺属的鸟类。原为云南白斑尾柳莺的一个亚种，后基于分子遗传和鸣叫研究证据被提升为独立物种。该鸟具有明显的黄色顶纹和两道黄色翼纹，下体呈污白色并带有黄色纵纹，外侧三枚尾羽有白色内缘。分布于中国东南部（包括四川、云南）、柬埔寨、泰国、老挝和越南中南部。","appearance":"白斑尾柳莺体长约10-11厘米，中等体型，特征明显。头顶有明亮的黄色顶纹，两侧暗橄榄色，上体呈亮橄榄绿，翼覆羽尖端黄色形成两道宽翼纹，下体黄色偏白，翼下覆羽鲜黄。虹膜深褐色，喙上颌暗棕至黑色，下颌粉红，腿脚粉棕色。雌雄相似，幼鸟颜色较淡，黄色较少。亚种disturbans上体绿色较淡，顶纹黄色较少，尾羽白色限于边缘；klossi亚种上体更绿，脸和眉纹亮黄，下体淡黄色带深黄色条纹，尾羽白色量变。","call":"鸣叫声为约1.5秒长的短促颤音，如'ti-see-chee-sui'，缺乏明确的重复模式。叫声为'pitsiu'类似。","habits":"栖息于海拔3000米以下的森林，包括落叶和常绿阔叶林、针阔叶混交林和针叶林，也见于次生林和林缘灌丛地带。通常成对或小群体活动，活跃于树冠层，偶尔下降至灌木丛中觅食。主要以小型无脊椎动物为食，通过在空中扑跳捕捉昆虫。","breeding":"繁殖期在5月至7月，筑巢于地面，每窝产卵3-4枚。","identification":"与冠纹柳莺和峨眉柳莺相似，但外侧尾羽的白色较多。冠纹柳莺上体绿色较少，下体更白，顶纹不清晰且少黄色。可通过声音和行为区分。","protection":"IUCN：LC（无危）。在中国相对少见，在东南亚较为常见。","distribution":"远东地区，包括四川东南部、中部，云南东南部，至越南中南部、南部。","other":"曾被认为是云南白斑尾柳莺的亚种，后因科学研究被认定为独立物种。"},{"name":"海南柳莺","english_name":"Hainan Leaf Warbler","scientific_name":"Phylloscopus hainanus","overview":"海南柳莺（英文名：Hainan Leaf Warbler，学名：Phylloscopus hainanus），是雀形目柳莺科柳莺属的特有鸟类，分布于中国海南岛的山地森林。其全身鲜亮的黄色羽毛，尤其是翅膀和头部较暗，形成明显的翼斑和眉纹，使它在有限的分布范围内较为独特。","appearance":"海南柳莺全身覆盖着亮丽的黄色羽毛，翅膀和头部颜色稍暗，这使得其翼斑和眉纹格外显眼。雌雄鸟在外观上相似，幼鸟的特征描述较少。体型较小，与同属其他种类相比，具有更紧凑的外观。","call":"鸣声是一连串尖细而高音的杂乱音符，如同生锈机器发出的声音，极具辨识度。","habits":"栖息于海拔640至1500米的山地森林，偏好原始林、选择性砍伐后的林地和次生林，偶尔也出现在灌木丛中。在中上层活跃，有时会加入混合鸟群。由于低地森林的减少，可能已不再栖息于此。","breeding":"繁殖信息未详述。","identification":"与华南冠纹柳莺相比，海南柳莺的整体色彩更为鲜艳，体型更小，外观更加紧凑。","protection":"IUCN：VU（易危）。海南柳莺是高度限制分布的物种，仅限于海南岛东部鸟类区。虽然在当地可能相对常见，但总体数量稀少，估计成熟个体数在1500至7000之间，且分布点有限。受到栖息地丧失和碎片化的威胁。","distribution":"分布于中国海南岛南部山区。","other":"该物种被列入中国国家林业局2000年发布的《国家保护的有益的或者有重要经济、科学研究价值的陆生野生动物名录》。"},{"name":"四川柳莺","english_name":"Sichuan Leaf Warbler","scientific_name":"Phylloscopus forresti","overview":"四川柳莺（英文名：Sichuan Leaf Warbler，学名：Phylloscopus forresti），是雀形目柳莺科柳莺属的鸟类。体型小巧，活跃于森林上层。其名称来源于发现地四川省。四川柳莺曾被认为是淡黄腰柳莺的一个亚种，后被提升为独立物种。分布在中国中南部，主要栖息于高海拔的针叶林与混交林。","appearance":"四川柳莺长约9至10厘米，体态丰满，羽色复杂。头部具有明显的淡色冠纹和暗橄榄色侧冠纹，眼纹深褐色向下弯曲，耳羽淡色带斑点。背部灰绿偏暗，臀部硫磺黄色鲜明，翼羽暗褐边缘泛黄绿，下体淡黄白或灰白色。与近似种淡黄腰柳莺相比，四川柳莺上体颜色更深，臀部更亮黄。","call":"鸣唱有两种类型，皆与淡黄腰柳莺相似但节奏较慢。叫声为清脆的‘tsuist’音，比淡黄腰柳莺的叫声更长。","habits":"栖息于2000至4000米的针叶林和混交林，冬季会下降至山麓地带。以昆虫及其幼虫为食，单个觅食，冬季常与其他种类混合群居。飞行中常悬停捕食。","breeding":"繁殖季节主要在5月底至6月，关于筑巢、窝卵数等细节尚缺乏信息，但预计与淡黄腰柳莺相近。","identification":"与淡黄腰柳莺的区别在于颜色更深的上体和更鲜亮的黄色臀部。叫声和鸣唱与淡黄腰柳莺类似，但节奏更慢。","protection":"IUCN：LC（无危）","distribution":"繁殖于中国中南部，包括西藏东部至陕西南部，南至云南和四川西部，可能还分布于缅甸西部和北部。非繁殖季节分布从西藏东南部和四川南部向南至缅甸东部、泰国西北部和越南北部。","other":"历史上，云南柳莺曾使用过四川柳莺的中文名，但二者是不同的物种。"},{"name":"黄胸柳莺","english_name":"Yellow-vented Warbler","scientific_name":"Phylloscopus cantator","overview":"黄胸柳莺（英文名：Yellow-vented Warbler，学名：Phylloscopus cantator），是雀形目柳莺科柳莺属的小型鸟类。其最显著的特征是明亮的黄色顶纹和眉纹与近黑色的侧冠纹形成鲜明对比，喉部、上胸部及臀部呈现黄色。该物种主要分布于东洋界，从尼泊尔东部至老挝中部，包括中国云南、西藏等地。","appearance":"黄胸柳莺体型中等，长度约10-11厘米，重量约为6-7克。头部特征明显，具有黑亮的侧冠纹，中央冠纹和超眼线呈鲜黄色，脸颊和耳羽黄色并带有橄榄色调。背部灰绿色，大覆羽尖端黄色，形成明显的翼斑，有时中覆羽尖端也有模糊的翼斑。飞羽和尾羽棕色，边缘为鲜亮的黄绿色。下体从颏到上胸鲜黄色，与丝白色下胸至腹部形成对比，侧面略带灰色，尾下覆羽鲜黄色。虹膜深棕色，上喙棕色，下喙稻草黄色，腿色可变，粉红或黄褐色。雌雄相似，幼鸟与成鸟类似，但上体颜色较暗淡，下体黄色较淡或呈黄白色。","call":"其歌声是一系列高音调的音符，以几个滑音结尾，听起来像是'sit weet weet seep, seep, seep si-chu-chu to-you'，最后一个音符下降。叫声为柔和的双音节'see-chew'，重音在第二个音节，偶尔发出'see-chew-chew'声。鸣叫时会张开尾巴并向上抖动。","habits":"繁殖季节时单独或成对活动，较为害羞，通常隐藏在树冠覆盖下；冬季常结成松散的小群，也会加入混合物种的觅食队伍。在大型树木、灌木和竹丛的较低和中间层次活跃觅食，从叶间取食，也会短暂疾飞追逐昆虫。","breeding":"繁殖期为4月底至6月。巢由两性共同建造，形状像一个草制的球状结构，位于地面落叶中的大树根部，或是在河岸的凹洞中，或是低矮的茂密灌木丛中。每窝产卵3-4枚；孵化由两性共同承担；关于孵化期和雏鸟期的持续时间尚无具体信息。","identification":"与黑眉柳莺非常相似，但黄胸柳莺的腹部为米白色而非黄色。头部的黑白黄三色对比明显，是与其他大多数柳莺区别的关键特征。","protection":"IUCN：LC（无危）","distribution":"主要分布于东洋界，从尼泊尔东部至老挝中部，包括中国南部的部分地区，如云南、西藏等地。冬季会降至低地和山脚的类似生境中。","other":"该物种曾被归入'旧大陆莺'的组合中。"},{"name":"灰岩柳莺","english_name":"Limestone Leaf Warbler","scientific_name":"Phylloscopus calciatilis","overview":"灰岩柳莺（英文名：Limestone Leaf Warbler，学名：Phylloscopus calciatilis），是雀形目柳莺科柳莺属的鸟类。最初于1994年被误认为黑眉柳莺。体型小巧，翼圆，喙大而比例较长。其名'calciatilis'意为'居住在石灰岩上'，反映了它在越南北部、老挝北部及中国广西的喀斯特山地森林中的独特栖息环境。","appearance":"灰岩柳莺体长约10至11厘米，头部具黄黑条纹，下体呈鲜艳黄色，头顶条纹黑色贯穿，中间冠纹及眉纹绿黄，眼纹黑色，脸颊和耳羽带绿黄，翼下有明显的黄色斑点形成翼带。上体灰绿，翼羽和尾羽暗褐，边缘橄榄绿至黄橄榄。喙大部分黑色，腿色淡灰。雌雄相似，幼鸟色彩较淡，翼覆羽白尖更明显。","call":"歌声由7至9个音调各异、持续时间和结构不同的柔和哨音组成，以轻微下降的音阶形成短暂的诗节，比黑眉柳莺和黄腹柳莺的歌声更少变化音符，频率范围窄。叫声为短促柔和的'pi-tsu'或'pi-tsiu'，常在受惊时发出间隔有序的系列叫声。","habits":"栖息于低地至中海拔的喀斯特山地森林，活动高度约700至1200米。以活跃的方式在树冠层觅食，通常集群行动。食物包括昆虫和其他小生物。","breeding":"在2月中旬开始鸣唱，在4月中观察到携带食物的雄鸟。5月期间，领地内的个体频繁鸣唱，暗示繁殖季节。具体繁殖细节尚待研究。","identification":"与硫胸柳莺相比，灰岩柳莺体型略小，翅膀更圆，下体颜色偏冷黄，上体略带灰色。虽然与黑眉柳莺在羽毛上难以区分，但通过声音和形态特征可以识别。","protection":"IUCN：LC（无危）。在已知分布区内常见于保护区，如老挝的Hin Namno国家保护区、越南的Cuc Phuong和Phong Nha-Ke国家公园，以及中国的Nonggang国家自然保护区等。目前栖息地威胁较小。","distribution":"繁殖于越南北部、中部和老挝北部、中部的喀斯特地区，可能也分布于中国广西南部的喀斯特地带。","other":"自1994年首次发现以来，灰岩柳莺的研究逐渐增加，揭示了其在东南亚喀斯特山地的独特生态角色。"},{"name":"黑眉柳莺","english_name":"Sulphur-breasted Warbler","scientific_name":"Phylloscopus ricketti","overview":"黑眉柳莺（英文名：Sulphur-breasted Warbler，学名：Phylloscopus ricketti），是雀形目柳莺科柳莺属的小型鸟类，体长约为10-11厘米。其最显著的外部特征是橄榄绿色的上体，头部中央有一条醒目的淡绿黄色冠纹，两侧则是黑色侧冠纹，黄色眉纹和黑色贯眼纹。下体呈现亮黄色，两胁略带绿色。分布在中国中东部和南部，冬季迁徙至东南亚国家如老挝、泰国和柬埔寨。","appearance":"黑眉柳莺体型较小，体长约10-11厘米。其上体为橄榄绿色，头顶中央有一条鲜明的淡绿黄色中央冠纹，两侧有黑色侧冠纹，黄色眉纹和黑色贯眼纹，形成明显的头部图案。翅膀上有两道淡黄色的翼斑，下体亮黄色，两胁略带绿色。虹膜深棕色，上喙暗褐色，下喙基部或大部分为黄色或橙色，腿色变化较大，从黄绿色到紫灰色或灰粉色。雌雄相似，幼鸟上体较成鸟更暗绿，下体黄绿色；初冬鸟羽色稍亮，翼斑更为突出。","call":"黑眉柳莺的鸣唱是一系列高音的短促快速短语，逐渐加速至结尾，听起来像“sit siri sii-sii see-chew, sit sweety sweety sweety swee-chew”。叫声为双音节的“pitch-you, pitch-you”。","habits":"黑眉柳莺栖息于混合落叶林和半常绿林，以及山坡上的杜松林和稀疏植被。迁徙期间可见于多种林木环境，最高可达海拔1500米。它们主要以小昆虫为食，单个或成对觅食，经常参与多种鸟类混群。在树冠层活动，非常活跃，奔跑跳跃于树叶间，从叶子和树枝上觅食，频繁地从树梢追捕昆虫。","breeding":"关于繁殖习性的了解不多，繁殖期在5月至7月，筑巢于地面岩石间或离地1米内的植被中，巢由苔藓构成。每窝产卵6枚，卵白色无斑点，大小约15.5-16.5mm×10.5-12.5mm。","identification":"与黄胸柳莺相比，黑眉柳莺下体全为黄色；与海南柳莺相比，侧冠纹更深；与金眶鹟莺相比，缺少黄色眼圈；与白斑尾柳莺和冠纹柳莺相比，侧冠纹较深，下体更黄。","protection":"IUCN：LC（无危）。在中国繁殖范围内较为罕见，泰国和印度支那地区为不常见至局部常见的非繁殖季节访客。近年来种群数量明显减少，可能与人口增长和环境变化有关，目前无特别保护措施。","distribution":"繁殖区位于中国中东部和南部，非繁殖区主要在东南亚，包括泰国、印度支那等地。迁徙期间会出现在中国南部和香港。","other":"黑眉柳莺曾在中国福建、云南一带丰富，但在迁徙期间已变得少见。"},{"name":"菲律宾柳莺","english_name":"Philippine Leaf Warbler","scientific_name":"Phylloscopus olivaceus","overview":"菲律宾柳莺（英文名：Philippine Leaf Warbler，学名：Phylloscopus olivaceus），是雀形目柳莺科柳莺属的鸟类。菲律宾特有的小型森林鸟类。橄榄绿的背部，金橄榄色的翅膀和尾巴，以及深色的冠羽和眼纹，白色腹部和喉部，淡黄色的眉纹和尾根下的黄色。具有暗粉红色腿和上下颜色不同的喙，上黑下橙。其鸣唱由高音哨声的起伏序列组成。","appearance":"体型小巧，背部橄榄绿色，翼和尾金橄榄色，头顶部和眼纹深色。腹部和喉部白色，眉纹淡黄，尾根下缘黄色。腿色偏暗粉红，喙二色，上部暗色，下部橙色。","call":"鸣唱由一系列高音哨声构成，形成上扬和下降的旋律。","habits":"栖息于低地至山地低海拔的森林环境。在菲律宾南部和中部的岛屿上广泛分布。","breeding":"具体繁殖细节未详述。","identification":"与道氏柳莺的区别在于喉部白色，不同于北极型柳莺，其翅膀上无翼带。","distribution":"分布于菲律宾的米沙鄢群岛、棉兰老岛群、苏禄群岛，包括萨马岛、比里兰岛、莱特岛、内格罗斯岛、保和岛等地。"},{"name":"道氏柳莺","english_name":"Lemon-throated Leaf Warbler","scientific_name":"Phylloscopus cebuensis","overview":"道氏柳莺（英文名：Lemon-throated Leaf Warbler，学名：Phylloscopus cebuensis），是雀形目柳莺科柳莺属的鸟类。直译: 柠喉柳莺，因其喉部柠檬黄色而得名。这种小型森林鸟类分布于菲律宾的吕宋岛和米沙鄢群岛西部。","appearance":"体型小，长11-12厘米，属中等大小的柳莺，具有长眉纹。成鸟的头顶至背部呈淡橄榄绿色，翼和尾羽边缘带亮绿黄色，翼弯处亦呈黄色。下巴、喉部淡黄，胸腹部分更显白黄色或灰白色，尾下覆羽淡黄。眼睛深棕色，上喙暗角棕色，下喙黄褐色，腿脚蓝灰色。雌雄外观相似，幼鸟未详述。吕宋岛亚种上体颜色较暗，喉部黄色较淡，有时几乎不可见。","call":"叫声为响亮的“chi-chi-oo”或“chip chi-u”，经常重复。","habits":"栖息于低地至约1800米的山地森林及其边缘，以小型节肢动物为食。单独觅食或加入混合物种群。在内格罗斯岛，其分布高度高于菲律宾柳莺。","breeding":"繁殖季节为3月至6月。","identification":"与菲律宾柳莺的区别在于具有淡黄色的喉部。与北极型柳莺的区别在于缺乏翼斑。","protection":"IUCN：LC（无危）；在菲律宾较为常见，但了解程度不高。","distribution":"分布于菲律宾吕宋岛和米沙鄢群岛西部，包括北部和中西部。","other":"属于Phylloscopidae科的旧世界柳莺。"},{"name":"山柳莺","english_name":"Mountain Leaf Warbler","scientific_name":"Phylloscopus trivirgatus","overview":"山柳莺（英文名：Mountain Leaf Warbler，学名：Phylloscopus trivirgatus），是雀形目柳莺科柳莺属的小型鸟类。其最显著的外部特征为头部强烈的对比图案，包括黑色眼纹、淡色眉线和中央明亮的黄色冠纹两侧的黑色条纹。山柳莺主要分布于马来半岛山区、大巽他群岛和小巽他群岛西部的山地雨林中。","appearance":"山柳莺体长10至11厘米，体重约9克，是一种小型到中等大小的叶莺，上体颜色多变，从橄榄绿到灰绿色，下体通常为鲜黄色，但也有灰绿色和米白色的变化。头部具有鲜明的图案，包括宽而亮黄的中冠纹、黑色的冠侧、明亮的黄色眉线，以及由深橄榄色的颊和耳羽覆盖的暗橄榄色眼纹。喙部暗角质色，下颌基部白色或淡粉棕色，腿灰色或粉红色。幼鸟比成鸟颜色较暗淡，下体颜色更少黄色，带有橄榄色。不同亚种在色彩上有细微差异。","call":"山柳莺的鸣唱为一系列高音的颤音，如同滚动的颤音符，声音连续而急促，有时被描述为‘tisiwi-tsuwiri-swit’或更快速、模糊的高音短语，类似某些白眼（Zosterops）的鸣声。叫声多变，包括‘cheecheechee’或金属般的‘tersiwit’，以及警告叫声。","habits":"山柳莺生活在海拔800米以上的山地和亚山地常绿阔叶森林中，偶尔也在次生林和卡苏里纳（Casuarina）森林中出现。它们是留鸟，以单独或成对的形式觅食，也常见于单种或混合物种的鸟群中。主要食物为小昆虫和幼虫，尤其是蚂蚁和鳞翅目幼虫。它们在森林中层和树冠活动，从树叶和附生植物中寻找食物，有时会笨拙地悬停以捕获叶缘的昆虫。","breeding":"山柳莺的繁殖期为2月至8月。它们的巢呈穹顶状，放置于地面或河岸洞穴中。每窝产2至3枚蛋，关于孵化期和雏鸟成长期的信息尚不明确。山柳莺的巢常被中杜鹃和暗色鹰鹃寄生。","identification":"山柳莺与其他叶莺的区别在于其独特的头部图案，以及上体颜色和下体颜色的对比。亚种间的辨识主要基于色彩差异，特别是在头冠的颜色上，有的亚种缺乏鲜明的黄色中冠纹和黑色冠侧。","protection":"IUCN：LC（无危）","distribution":"山柳莺主要分布在马来半岛山区、大巽他群岛和小巽他群岛西部的山地雨林中，包括印尼和马来西亚的亚山地和山地环境。","other":"山柳莺的系统学历史涉及其分类位置的调整，曾一度被归入‘旧世界莺’的组合中。"},{"name":"内岛柳莺","english_name":"Negros Leaf Warbler","scientific_name":"Phylloscopus nigrorum","overview":"内岛柳莺（英文名：Negros Leaf Warbler，学名：Phylloscopus nigrorum），是雀形目柳莺科柳莺属的鸟类。小型森林鸟类，广泛分布于菲律宾的山地雨林。原被视为山柳莺的一个亚种。","appearance":"这种柳莺拥有深色的头部，没有明显的冠纹，眼纹深邃，眉纹淡雅，有时可见微弱的翼斑，尾羽外侧白色。其颜色随地理位置而变化，眼纹可能呈现黄色、灰白色或浅黄色；背部色彩可为棕色或橄榄绿色；腹部通常为白色，也可能带有黄色或黄纹。","call":"其鸣唱为一系列高音的颤音，形成连贯的乐章。","habits":"内岛柳莺活跃于森林上层，常加入混合鸟群中觅食，偏好在热带或亚热带湿润的低地森林和山地森林中生活。","identification":"与迁徙型柳莺相比，内岛柳莺具有独特的地理变异性，可通过其颜色模式和栖息地选择加以区分。","distribution":"主要分布在菲律宾的山地地区，除了米沙鄢群岛东部和Zamboanga半岛至苏禄群岛以外的区域。"},{"name":"苏拉柳莺","english_name":"Sulawesi Leaf Warbler","scientific_name":"Phylloscopus nesophilus","appearance":"外观暗淡，具有苍白的眼眉，大部分黑色的喙，深色的腿，暗橄榄褐色的上体，以及浅黄色的腹部。翅膀上没有明显的翼斑。与北极柳莺、日本柳莺和堪察加柳莺相比，其颜色更深的棕色，腿部颜色暗淡，腹部黄色，且无明显翼斑。","call":"鸣唱为高度变化的颤音和颤鸣混合。","habits":"栖息于山地森林及其边缘地带，常见于混群中。具体活动范围、迁徙模式和食物偏好等细节尚待进一步研究。","breeding":"关于繁殖行为、求偶、筑巢、交配、产卵、孵化和育雏的具体信息目前资料有限。","identification":"与近似种如北极柳莺、日本柳莺和堪察加柳莺的区别在于更暗的棕色调、暗淡的腿色、黄色的腹面，以及缺乏明显的翼斑。","protection":"IUCN状态未提供，具体保护措施和威胁状况未知。","distribution":"仅限于印尼的苏拉威西岛，分布于该岛的北部、中部和东南部山区。","other":"系统分类历史上，曾与隆山柳莺合并为同一物种，后经分析确认为独立种类。"},{"name":"帝汶柳莺","english_name":"Timor Leaf Warbler","scientific_name":"Phylloscopus presbytes","overview":"帝汶柳莺（英文名：Timor Leaf Warbler，学名：Phylloscopus presbytes），是雀形目柳莺科柳莺属的鸟类。分布于小巽他群岛帝汶岛和弗洛勒斯岛的中型柳莺，体长约11厘米，上体橄榄褐，具长黄色眉纹，下体淡黄，外侧尾羽基部白色。该种为帝汶-韦塔东洋区（EBA）的特有种，目前分为两个亚种：指名亚种分布于帝汶岛及阿陶罗岛，floresianus亚种仅见于弗洛勒斯岛。","appearance":"帝汶柳莺体长约11厘米，属中型柳莺。指名亚种上体呈暗褐橄榄色，头顶两侧偏褐，中央具不明显淡黄纵纹；长黄白色眉纹延伸至耳羽后缘；眼先与过眼纹橄榄褐；颊与耳羽黄白；翼上覆羽尖端有时可见淡黄翼斑；尾羽褐色，外侧三对尾羽内缘纯白；下体淡黄白，喉部更白，胸具黄色纵纹，腹部及尾下覆羽最黄。部分个体存在变异：拉梅兰山（Mt Ramelan）标本头顶更灰，背灰绿，下体黄色更淡；穆蒂斯山（Mt Mutis）标本头顶橄榄褐，背橄榄绿。虹膜暗褐；上嘴暗角褐，下嘴黄色；跗蹠深灰色。两性相似。幼鸟较成鸟更褐，头顶无纵纹。floresianus亚种嘴较指名亚种短，中冠纹极弱，翼缘绿色，下体黄色更均匀且略深。","call":"指名亚种鸣声为短促而快速的几乎断奏般的高音甜美音符串；floresianus亚种鸣声为3–4个高音哨音上下滑动的短甜颤音，间隔短暂重复。","habits":"帝汶柳莺为留鸟，栖息于低地及山丘半常绿林和林地，指名亚种海拔分布自海平面至2300米，floresianus亚种在弗洛勒斯岛见于1000–2400米的原生林、轻度退化的山地林、次生灌丛及木麻黄林。单个、成对或混群觅食，活动于林中层及树冠，以小型节肢动物为食，自叶簇中取食。","breeding":"8月下旬于海拔1450米处曾见个体衔巢材；9月曾见一对喂养一只巽他中杜鹃幼鸟，其余繁殖信息缺乏。","identification":"与同属其他柳莺相比，帝汶柳莺外侧尾羽基部纯白、长眉纹及下体黄色具胸纹为重要特征。两亚种间差异：floresianus嘴更短，中冠纹极弱，翼缘偏绿，下体黄色更深且均匀。","protection":"IUCN: LC（无危）","distribution":"繁殖区与非繁殖区相同：指名亚种分布于东南小巽他群岛的帝汶岛及阿陶罗岛；floresianus亚种分布于中西小巽他群岛的弗洛勒斯岛。","other":"指名亚种帝汶岛内部存在形态及鸣声差异，拉梅兰山种群色浅而灰，穆蒂斯山种群色深且橄榄，阿陶罗岛种群鸣声独特，需进一步研究以明确分类地位。罗地岛（Roti I.）种群原归入指名亚种，现已被描述为新种罗地岛柳莺。"},{"name":"海岛柳莺","english_name":"Island Leaf Warbler","scientific_name":"Phylloscopus poliocephalus","overview":"海岛柳莺（英文名：Island Leaf Warbler，学名：Phylloscopus poliocephalus），是雀形目柳莺科柳莺属的鸟类。头部呈灰白色，具黑色过眼纹，身体余部黄绿色。广泛分布于印度尼西亚、巴布亚新几内亚和所罗门群岛，拥有19个亚种。国际鸟类联盟（IOC）10.1版中，maforensis独立成为农福尔柳莺，misoriensis独立成为比岛柳莺。","appearance":"海岛柳莺是一种小型柳莺，体长约10厘米，重量介于7至11.5克之间。成年个体的头部灰白，冠部和面部略带橄榄色，没有明显的冠纹。上体为灰橄榄色，大覆羽的黄色尖端形成模糊的翼带，飞羽边缘亮黄绿色，尾上覆羽暗棕色，尾羽边缘黄橄榄色。喉部脏白色，胸部灰色，两胁橄榄色，腹部淡黄色。虹膜深色，喙角质色，腿的颜色未详述。雄雌同型，幼鸟描述不明。","call":"海岛柳莺的鸣唱多样，包含相对长的滑音，频率可达10kHz，较之的歌曲更为缓慢和高亢，且有‘wispy’的描述，短语更短且间隔更大。叫声在觅食时常发，为细长或高音的‘sissiiiweee’。","habits":"海岛柳莺广泛分布于蒙塔纳原始和次生森林（包括选择性砍伐地区）以及海拔750米以上的灌木丛，仅matthiae亚种也出现在低地。在新几内亚，通常生活在海拔1400米以上（最高至2400米），但在非繁殖季节会降至更低高度（最低至640米）。在美拉尼西亚，如新爱尔兰岛海拔840米以上，新不列颠岛海拔1100米以上，布干维尔岛海拔700米以上，马基拉岛海拔500米以上。在印度尼西亚，如塔利阿布岛海拔450米以上，佩伦岛海拔700米以上，塞拉姆岛海拔300米以上，布鲁岛海拔800米以上，以及凯岛和奥比岛海拔350米以上（后者最高至1550米）。","breeding":"海岛柳莺的繁殖、求偶、筑巢、交配、产卵、孵化和育雏等生长繁殖信息未提供。","identification":"海岛柳莺与其他同属物种的区别在于体型较小，下体更黄，上体颜色更深，有时可见中央冠纹。与其他亚种相比，有细微的外观和分布差异，例如henrietta亚种灰度更高，less brownish-olive色冠，everetti亚种灰棕色冠，淡灰色超眉，水白色内网边缘的外尾羽，喉咙到上胸白色，其余下体硫磺黄色除绿色两胁；waterstradti亚种灰冠更淡，上体更绿。","protection":"IUCN：VU（易危）。海岛柳莺是一个受限制分布的物种，局限于Geelvink群岛EBA。在Numfor岛上被认为数量稀少，全球范围内可能不超过10,000只成熟个体，估计在2500-9999只成熟个体之间。Numfor岛上大量森林已被破坏或退化，导致其栖息地丧失，全球范围内种群数量缓慢下降。目前在Numfor上没有保护区，需要紧急调查以获得更好的种群估计和趋势。计划在Numfor建立自然保护区值得支持。","distribution":"海岛柳莺分布于澳大利亚-新西兰地区，包括印尼邦盖群岛和印尼苏拉群岛（东部，印尼苏拉威西岛）、印尼摩鹿加群岛至新几内亚、俾斯麦群岛和所罗门群岛。","other":"海岛柳莺的多个亚种在分布区域和外观上有细微差别，其中paniaiae亚种在西新几内亚较为罕见；avicola亚种（Kai岛）仅知从模式标本中记录。becki亚种近期在伊莎贝尔和马莱塔岛没有记录。在塔利阿布岛上常见，但当地种群的分类状态需要进一步研究。"},{"name":"圣岛柳莺","english_name":"Makira Leaf Warbler","scientific_name":"Phylloscopus makirensis","appearance":"体型微小，头部主要呈灰色，有明显的深色眼纹和淡色眉纹。背部与翅膀强烈绿色调，具有两道浅色翼带。腹部黄绿色，向后渐淡。","call":"鸣叫为金属质感的“dzip”声，歌声高亢，旋律婉转。","habits":"栖息于海拔500米以上的山地森林，通常在树冠层活动，常出现在混杂物种的鸟群中。","identification":"通过其独特的灰头、绿背、黄腹及清晰的两道翼带来辨别。","protection":"IUCN：LC（无危）","distribution":"仅分布于所罗门群岛的马基拉岛（Solomon Islands: Makira）。"},{"name":"库岛柳莺","english_name":"Kolombangara Leaf Warbler","scientific_name":"Phylloscopus amoenus","overview":"库岛柳莺（英文名：Kolombangara Leaf Warbler，学名：Phylloscopus amoenus），是雀形目柳莺科柳莺属的小型鸟类。主要分布于南太平洋的所罗门群岛中的Kolombangara山区，拥有暗色的头盖和眼纹，黄色的眉纹，下部呈鲜亮的黄色，上部为深栗褐色。由于栖息地丧失，该物种面临易危状态。","appearance":"库岛柳莺是一种小型的鸟类，具有显著的暗色帽状头部和眼纹，以及醒目的黄色眉纹。它的腹部强烈地呈现出黄色，而背部则为深栗褐色。喙和腿均为淡色。该鸟种在海拔1200米以上的苔藓森林中被发现。","call":"其鸣唱为清脆的颤音，但更常听到的是安静的‘tzik’声叫声。","habits":"库岛柳莺栖息于海拔较高的苔藓森林中，偏好湿润的山地环境。","identification":"与海岛柳莺非常相似，但库岛柳莺的下部为黄色而非浅灰色，且喙和腿为淡色。","protection":"IUCN：NT（近危）","distribution":"库岛柳莺仅分布于所罗门群岛的Kolombangara山区。"},{"name":"灰头柳莺","english_name":"Grey-hooded Warbler","scientific_name":"Phylloscopus xanthoschistos","overview":"灰头柳莺（英文名：Grey-hooded Warbler，学名：Phylloscopus xanthoschistos），是雀形目柳莺科柳莺属的鸟类，又名灰头鹟莺。该鸟种拥有绿色背部，柠檬黄色腹部，烟灰色头部和鲜明的白色眉纹。主要分布在喜马拉雅山脉，包括中国西藏等地，是该地区较为常见的鸟种。","appearance":"小巧精致的灰头柳莺，体长约10-11厘米，体重6-9克。其背部呈绿色，腹部鲜黄，头部灰暗，具白色眉纹。成年鸟的冠部为中灰色，延伸至耳羽和肩部，侧冠纹和眼纹较深，上体橄榄绿，翅膀亦然，臀部和尾上覆羽最黄。飞羽棕色，边缘黄绿色；尾羽棕色，广泛黄橄榄色边缘，最外一对尾羽内网白色；喉咙和全身下部金黄色，两胁和腹侧带橄榄色；翼下覆羽淡黄；虹膜深褐色，有狭窄的白色眼环；上喙深褐色，下喙肉橙色；腿肉黄色至棕色，足底更浅。雌雄相似。幼鸟类似成鸟，但头部颜色较淡，偏橄榄色，上体较暗，下体颜色较淡。","call":"鸣唱为一系列短而欢快的音节，如‘tsi-tsi-tsi-weetee’或‘tsi-weetsi-weetsi-weetu-ti-tu’，经常连续重复。叫声为高音重复的‘psit-psit’；还有一种凄婉的‘tyee-tyee’声，可能是焦虑或警报叫声。","habits":"栖息于蒙特森林，包括阔叶林和混合阔叶针叶林，尤其是开阔的林区。繁殖季节主要在900米至2750米之间，最佳地带位于1500至2100米。非繁殖季节会降至低海拔，包括山脚，甚至进入平原地区的花园和水边树木。","breeding":"繁殖期为3月至8月（主要是5月至6月），与雨季开始同步。巢由双方共同建造，主要由雌鸟完成，是一个由绿色苔藓和草茎构成的球形穹顶巢，内衬毛发和绒羽，隐蔽于地面，隐藏在灌木下，常在树根间，或斜坡的凹陷处。每窝产卵3-5枚，通常4枚；孵卵主要由雌鸟承担，雄鸟也会参与，孵化期为10或11天；关于雏鸟期的信息尚缺。巢可能被中杜鹃寄生。","identification":"灰头柳莺与鹟莺属的其他柳莺区别在于上背灰及眉纹白，与其他羽色相似的柳莺区别在于无翼斑且眼圈白。不同亚种主要在羽毛颜色深度上有所不同。","protection":"IUCN：LC（无危）","distribution":"分布于喜马拉雅山脉，包括尼泊尔、不丹和印度北部，向西和向东逐渐稀少，直至巴基斯坦、克什米尔和缅甸。在中国西藏也有分布。"},{"name":"白眶鹟莺","english_name":"White-spectacled Warbler","scientific_name":"Phylloscopus intermedius","overview":"白眶鹟莺（英文名：White-spectacled Warbler，学名：Phylloscopus intermedius），是雀形目柳莺科柳莺属的鸟类。中等体型的柳莺科鸟类，以其显著的淡色‘眼镜’状眼圈闻名。头部呈灰色调，眼先部分为黄色与黑色相间，喉部亮黄色。广泛分布于亚洲东部，自喜马拉雅山脉东部至中国东南部，南至越南南部。","appearance":"白眶鹟莺体长约11-12厘米。zosterops亚种特征明显，冠部中央有明亮的灰色条纹，两侧冠条为黑色，额部尤其显眼，几乎延伸至喙基部；冠侧和颈后为灰色，耳羽上部通常绿色，下部可能呈现绿灰色或灰绿色，与上部耳羽颜色略有差异；眉纹处绿色，常混有淡黄色；眼圈白色，前上方断裂，通常带有淡黄色；背部绿色，翼上覆羽和尾羽为褐灰色，边缘略带绿色，大覆羽尖端淡黄色形成明显的浅色翼斑，最外两对尾羽内侧有显著的白色楔状斑；腹部亮黄色，胸部侧面和胁部可能带有不同程度的淡绿色；虹膜深棕色；上喙黑褐色，下喙橙色；腿灰粉色。雌雄羽毛相似，但雌鸟体型平均小于雄鸟。幼鸟头部和耳羽略带绿色，侧冠条不如成鸟鲜明，下体颜色较淡，黄色更暗淡，略带尘土色。ocularis亚种与zosterops难以区分，仅可通过地理位置分辨；指名亚种为intermedius亚种，主要特征为黄色眼圈，存在两种形态，一种冠纹似zosterops，但冠侧颜色较浅，未达到耳羽位置，前额通常绿色；另一种（cognitus）冠部绿色。","call":"白眶鹟莺的鸣唱由短暂（约1-1.9秒）的变奏吹哨音组成，通常以1-2个断续音开始，随后重复相同的音节或1-4个不同的音节，结尾时会有2-3个元素的双或三重音节（慢速颤音）或快速单元素颤音，使鸣唱似乎起初犹豫而后加速，各小节之间通常间隔几秒。其鸣唱包含比灰脸鹟莺更高的颤音比例，且音调更低，频率范围更窄，起始更为犹豫。","habits":"白眶鹟莺栖息于热带湿润阔叶林区上部至凉温带落叶阔叶林区下部，偏好成熟森林中的茂密灌木层。繁殖季节在喜马拉雅山脉海拔约1400-2600米，越南南部约1500-2000米，中国约1000-1750米。zosterops亚种为高度迁移，非繁殖季下降至山脚和平原边缘。intermedius亚种冬季分布于其繁殖区内，但也出现在香港、越南和老挝。","breeding":"繁殖季节为4月至6月，在喜马拉雅山脉；在中国，雄鸟主要在4月中旬至6月初鸣唱。巢为苔藓、细根和少量叶子构成的球状结构，内部衬有细腻的植物绒毛，置于陡峭河岸的洞穴中或密集苔藓中，偶尔位于树洞内。每窝产卵4-5枚，由双亲共同孵化。具体繁殖细节未知。","identification":"白眶鹟莺与金眶鹟莺的区别在于眼圈颜色（白眶鹟莺为白色而非黄色）、头侧颜色（白眶鹟莺为灰色）和翼斑（有时白眶鹟莺具有黄色）。与灰脸鹟莺的区别在于颏和喉部的颜色（白眶鹟莺为黄色），眼先颜色（白眶鹟莺为黄黑相间）。与灰头鹟莺的区别在于眉纹（白眶鹟莺无白色眉纹）和背部颜色（白眶鹟莺背部接近绿色）。","protection":"IUCN：LC（无危）","distribution":"分布于喜马拉雅山脉东部至中国东南部，越南南部。在繁殖季节，白眶鹟莺可见于喜马拉雅山脉、中国东南部和越南南部的高海拔地区，非繁殖季节则下降至较低海拔。","other":"曾被归类于Seicercus属，后因分子系统学研究发现Seicercus和Phylloscopus并非单系群，两属合并入Phylloscopus，由于affinis名称已被占用，引入新名称zosterops替代，但根据国际动物命名法规，intermedius亚种现为指名亚种片种。"},{"name":"金眶鹟莺","english_name":"Green-crowned Warbler","scientific_name":"Phylloscopus burkii","overview":"金眶鹟莺（英文名：Green-crowned Warbler，学名：Phylloscopus burkii），是雀形目柳莺科柳莺属的鸟类。俗名: 大吉黄、灰顶鹟莺、竹叶青，体长约13厘米，具宽阔的绿色顶纹，眼圈鲜黄，活跃于森林下层，分布于喜马拉雅山脉，冬季迁至低地。","appearance":"中等体型的金眶鹟莺，长约11-12厘米，体重约7.3克。拥有宽基喙和强颚须，绿色的中线冠纹，通常带有稀疏的灰色细条纹，黑色侧冠纹清晰可见，绿色侧冠、耳羽和眉线，眉线略带黄色。上体绿色，翼和尾部呈棕灰色，边缘绿色，无明显淡色横斑。尾羽外侧有明显的白色楔形斑点。下体明亮黄色，胸侧和两胁常泛绿。雌雄羽色相似，但雌鸟平均较小。","call":"鸣唱由一系列短暂（约0.6-1秒）的吹哨音节组成，有时无序，常以2-4个音节的短组排列，每组重复2-4次，结尾有时为快速的颤音。叫声为轻柔的鞭打声，类似高音的红腹灰雀叫声。","habits":"繁殖于热带、亚热带的常绿阔叶林和落叶阔叶林，偏好茂密的林下植被和次生灌木丛。海拔分布范围在1700-2600米，冬季迁徙至印度东部和孟加拉国西南部的低地。","breeding":"繁殖季节可能始于4月，确切信息因过去与韦氏鹟莺混淆而缺乏。","identification":"通过眼圈黄色、更短的尾巴、较大的喙、黑色侧冠纹更加鲜明以及上体更鲜艳的绿色等特征与韦氏鹟莺区分。","protection":"IUCN：LC（无危）","distribution":"繁殖于喜马拉雅山脉，非繁殖期分布于印度北部。","other":"过去曾被归入Seicercus属，现已合并至Phylloscopus属。"},{"name":"灰冠鹟莺","english_name":"Grey-crowned Warbler","scientific_name":"Phylloscopus tephrocephalus","overview":"灰冠鹟莺（英文名：Grey-crowned Warbler，学名：Phylloscopus tephrocephalus），是雀形目柳莺科柳莺属的鸟类。旧称金眶鹟莺的一种亚种，现提升为独立物种。最显著的特征是拥有明亮的黄色眼环、灰色与黑色相间的王冠状羽冠，绿色的上体及淡黄色的下体。分布于中国中部、印度东北部至越南北部，冬季则可见于东南亚北部。","appearance":"灰冠鹟莺体型中等，约10-11厘米。头部特征明显，具有亮灰色的中央冠纹，几乎不含绿色，两侧冠纹呈黑色，通常在前额清晰可见，延伸至喙边。头部侧面和颈背沿两侧冠纹边缘为灰色，形成独特的“楔形”。耳羽和眉线呈灰绿色，有时微黄。眼环黄色鲜明，后方略断开。上体绿色，翼上覆羽和尾羽棕色带绿边。外侧两枚尾羽内缘有白色楔形斑。下体亮黄色，胸部侧面和两胁可能带有淡绿色。虹膜深棕色，上喙黑色，下喙橙色，腿呈淡灰粉色。幼鸟的冠纹为绿色，缺乏灰色，两侧冠纹较淡，下体颜色较暗。","call":"鸣唱由短暂（约0.8-1.7秒）且突然的乐句组成，通常以1-2个简短的前奏音开始，随后是若干音符，以单一或多元素颤音结尾。乐句间通常间隔几秒。叫声为短促而柔和的‘trrup’或‘turup’，与金眶鹟莺双音节叫声相似但更为模糊和单音。","habits":"栖息于温暖温带常绿阔叶林的上层，以及凉爽温带落叶阔叶林的下层。偏好成熟森林中的茂密下层植被，以及近期内被清理的地区的次生低矮至中等高度灌木和树木。繁殖季节在海拔约1200-2500米之间，冬季则下降至较低海拔的开阔森林和森林边缘。","breeding":"关于繁殖的资料有限，可能的繁殖季节为中国和越南的5月至6月，缅甸西部则可能从4月初开始。巢呈穹顶状，由粗草构成，内部铺有苔藓和绒毛。一窝产4-5枚蛋。","identification":"与峨眉鹟莺、淡尾鹟莺和比氏鹟莺相比，灰冠鹟莺的头部图案对比更强烈，上体绿色更鲜亮，下体黄色更丰富，尾羽白色更多，翼条斑点更少明显。","protection":"IUCN：LC（无危）","distribution":"繁殖于印度东北部（那加兰邦、米佐拉姆邦）、缅甸西部和北部、中国南部、东部及中部（云南、四川、贵州、陕西、湖北、浙江）和越南北部。非繁殖季主要分布于缅甸东部和南部、泰国西北部至中国南部和印度支那北部。","other":"曾被归入Seicercus属，但分子系统发育研究显示Seicercus并非单系群，因此与Phylloscopus属合并，统一归入Phylloscopus属。"},{"name":"韦氏鹟莺","english_name":"Whistler's Warbler","scientific_name":"Phylloscopus whistleri","overview":"韦氏鹟莺（英文名：Whistler's Warbler，学名：Phylloscopus whistleri），是雀形目柳莺科柳莺属的鸟类。曾被归类于柳莺科金眶鹟莺的亚种，现提升为独立物种。其命名纪念英国鸟类学家Hugh Whistler。拥有明亮黄色眼环，灰绿色冠部带有两条长黑条纹，翼斑模糊而淡。分布于喜马拉雅山脉至缅甸一带的高海拔温带森林。","appearance":"中等体型，长11-12厘米。具明亮黄色眼环，头部中央条纹通常呈绿色，侧边黑色条纹，上体灰绿，翼和尾部棕色边缘灰绿。下体黄色，胸侧和两胁可能带绿色或褐色调。嘴部上喙黑色，下喙橙色，腿浅灰色。雌雄羽毛相似，幼鸟头部中线无灰色。","call":"鸣唱简单，由短促（0.6-1.2秒）、快速的乐句组成，先有微弱的‘chu’音，随后2-3个短而柔和的哨音，形成短语组，重复2-3次，间歇几秒。与比氏鹟莺的鸣唱相似，但音调更高。","habits":"栖息于温带森林的上层灌木丛，偏好混合有常绿和落叶阔叶树的环境，如橡树、杜鹃花和针叶树。活动于海拔2000-3500米之间，繁殖季节后会下降到较低高度。","breeding":"筑巢于地面或接近地面处，以苔藓、草、竹叶等材料搭建。一窝产卵通常4枚，由双亲共同孵化，具体孵化和育雏期未知。","identification":"与金眶鹟莺相比，韦氏鹟莺尾部较长，喙较小，眼环完整，上体较暗，下体黄色更淡，第三根外侧尾羽有明显白色楔形斑点。","protection":"IUCN：LC（无危）","distribution":"主要分布在喜马拉雅山脉至缅甸的繁殖区域，包括印度的Uttaranchal、West Bengal和缅甸西部。","other":"曾被错误分类于Seicercus属，分子研究证实Phylloscopus和Seicercus并非单系群，现已统一归入Phylloscopus属。"},{"name":"比氏鹟莺","english_name":"Bianchi's Warbler","scientific_name":"Phylloscopus valentini","overview":"比氏鹟莺（英文名：Bianchi's Warbler，学名：Phylloscopus valentini），是雀形目柳莺科柳莺属的鸟类。曾作为金眶鹟莺的一个亚种，现已提升为独立物种。该鸟上体黄绿色，下体亮黄色，具有不明显的翅斑和黄色眼圈。头顶有两道黑色侧顶纹，顶纹呈灰色，较白眶鹟莺和淡尾鹟莺的深灰色顶纹更浅。分布于中国中部、东南部以及越南北部的温带森林和亚热带湿润山地森林。","appearance":"体长约11-12厘米。头顶中间的冠纹为暗淡的灰绿色，两侧冠纹灰黑，前额处常混有浅绿色。耳羽和眼先为灰绿，眼圈明显黄色，有时前上方较模糊。上体灰绿，翅膀和尾羽棕色带灰绿边缘，大覆羽尖端通常为淡色形成薄翼斑。尾羽内侧有白色楔形斑。下体黄色，胸部侧面和胁部有时带有浅绿色。虹膜深棕色，上喙黑色，下喙浅橙色，腿淡灰粉色。雌雄羽毛相似，雌鸟平均比雄鸟小。幼鸟头顶中间的冠纹全为绿色，无灰色，两侧冠纹较淡且偏褐色，下体颜色较成鸟暗淡。","call":"鸣唱简单，由短促（约0.7至1.2秒）且快速的歌节组成，通常以轻微的'chu'开始，随后是2-3个短而变化的、柔和的哨音，排列成短语，重复2-3次（最后一次往往在结尾不完整），歌节间通常间隔数秒。与韦氏鹟莺的鸣唱极其相似，但音调略低，频率范围较窄。","habits":"繁殖季节栖息于凉爽温带森林的茂密下层植被中，有混合落叶阔叶和常绿阔叶树，如橡树和杜鹃花，以及针叶树，如冷杉。在树线以下活动，记录的繁殖高度在中国中部约为2100-3100米，在越南北部为1760-1900米。非繁殖季节在泰国，一般在1200米以上的常绿阔叶林下层。以昆虫为食，主要在下层觅食，偶尔也在树冠较低处捕食。","breeding":"确切繁殖信息不明，基于雄鸟鸣唱活动，主要繁殖季可能在6月和7月，即其近缘物种之后，因繁殖地海拔较高。","identification":"与极相似的淡尾鹟莺相比，尾部有更多白色；与非常相似的灰冠鹟莺和峨眉鹟莺相比，头部图案不那么鲜明；与韦氏鹟莺相比，有灰色中间冠纹且倒数第二根尾羽无白色。性别在羽毛上相似，雌鸟平均比雄鸟小。","protection":"IUCN：LC（无危）","distribution":"繁殖于中国中部、东南部，越南北部；非繁殖期分布于中国南部、东南亚北部。","other":"无"},{"name":"峨眉鹟莺","english_name":"Martens's Warbler","scientific_name":"Phylloscopus omeiensis","overview":"峨眉鹟莺（英文名：Martens's Warbler，学名：Phylloscopus omeiensis），是雀形目柳莺科柳莺属的鸟类。原被认为是金眶鹟莺的一个亚种，后提升为独立物种。分布于中国中部和缅甸的温带森林和亚热带湿润山地森林中。拥有绿色背部和黄色腹部，头部具有灰黑条纹和明亮的黄色眼环。","appearance":"体长11-12厘米，上部绿色，下部黄色，头顶有灰色和黑色条纹，侧冠条黑色，延伸至喙部。耳羽和眼先呈绿色，眼环黄色，上翼和尾部棕色带绿边。外侧尾羽具白色楔状斑点，下体黄色，两性羽毛相似，雌鸟平均比雄鸟小。幼鸟描述不明。","call":"鸣唱由短暂的哨音和啾啾声组成，形成断续的乐节，乐节间有数秒停顿。声音与灰冠鹟莺相似，但颤音比例较低，且与金眶鹟莺有别，颤音和乐句比例较少。","habits":"繁殖季节栖息于温带常绿阔叶林的上部和凉温带落叶阔叶林的下部，偏好成熟林下的茂密植被。非繁殖季节下降至更低海拔，常见于泰国的大陆地区，主要在常绿阔叶林的下层活动。迁徙性鸟类，冬季分布记录不足。","breeding":"确切繁殖信息未知，基于雄鸟鸣唱活动，推测繁殖季可能在五月到六月之间。","identification":"与比氏鹟莺的区别在于更纯净的灰色中冠条，黑色侧冠条更靠近喙部，绿色上部更鲜艳，下体黄色饱和度更高。与灰冠鹟莺相比，体型略大，喙相对较小，头纹不那么明显，尾部白色较少，翼部淡色条纹更常见。","protection":"IUCN：LC（无危）","distribution":"繁殖于中国中部，包括四川和陕西的山区。非繁殖期分布于东南亚北部，如泰国和柬埔寨。","other":"曾被归入Seicercus属，后分子系统发育研究将其归入Phylloscopus属。"},{"name":"淡尾鹟莺","english_name":"Alström's Warbler","scientific_name":"Phylloscopus soror","overview":"淡尾鹟莺（英文名：Alström's Warbler，学名：Phylloscopus soror），是雀形目柳莺科柳莺属的鸟类。从金眶鹟莺的亚种提升为独立鸟种。上体暗橄榄绿，下体黄色，具亮黄色眼圈，头顶灰色，侧冠纹黑色。分布于中国中部与东南部，繁殖季节可远至泰国、老挝、柬埔寨及越南过冬。","appearance":"中型柳莺，体长11-12厘米，雌鸟平均小于雄鸟。上体暗橄榄绿色，下体黄绿色，具独特的黄色眼圈，翼斑不明显或缺失。喙略大于峨眉鹟莺和灰冠鹟莺，尾羽较短，外侧尾羽的白色范围较小。","call":"鸣声简单而短促，由快速的短节组成，通常以短促的chip音开始，随后是2-5个吹口哨般的音符，形成一组元素，通常重复2-4次，之后是一段停顿，简化为“che-witchy-chew-witchy-chew”，音调高于比氏鹟莺。","habits":"偏好温带森林的低矮密集植被中觅食，主要以昆虫为食。繁殖季节位于中国中部和东部的温带森林，冬季迁徙至东南亚北部。在非繁殖季节，会下降到森林低地，此时识别难度增大。","breeding":"基于雄鸟的歌唱活动，繁殖季节为5月至6月。在中国南部的非繁殖范围内，自9月初至10月初可见，泰国中旬和越南南部晚9月亦有观察记录。具体非繁殖分布和迁徙时间尚不完全清楚。","identification":"与峨眉鹟莺, 灰冠鹟莺, 白眶鹟莺, 和比氏鹟莺s极为相似，尤其在繁殖区域重叠时难以识别。可通过翼斑、喙的大小、尾羽长度及外侧尾羽的白色范围进行区分。","protection":"IUCN：LC（无危）","distribution":"繁殖于中国中部（陕西南部、四川、贵州、广西、河南最近发现）及东南部（江西东北、福建北部），非繁殖季节分布于中国极南部及东南亚北部。","other":"曾被归类于Seicercus属，后因分子系统发育研究显示Phylloscopus和Seicercus都不是单系群，故两属合并入Phylloscopus，以遵循国际动物命名法规则。"},{"name":"灰脸鹟莺","english_name":"Grey-cheeked Warbler","scientific_name":"Phylloscopus poliogenys","overview":"灰脸鹟莺（英文名：Grey-cheeked Warbler，学名：Phylloscopus poliogenys），是雀形目柳莺科柳莺属的鸟类。原属Seicercus，现归入Phylloscopus属。这小型、色彩鲜明的莺类，以其独特的灰头部和明亮的白色眼圈著称。广泛分布于南亚和东南亚，包括印度北部至越南南部的湿润森林地带。","appearance":"灰脸鹟莺长约10-11厘米，体重约6.3克。其特征为头顶、颈背、耳羽及喉侧边缘呈淡灰色，眼先处混有白色；侧顶纹暗灰色，与头顶颜色对比不强烈；背部绿色，翅膀和尾巴棕色带绿色边缘，翼上有明显的淡色条纹；尾羽外缘三对有白色楔状斑点；下体亮黄色，胸部侧面及两胁常带有不同程度的淡绿色，喉部上方为灰白色；眼睛深褐色，喙黑色基部灰粉，腿灰粉色或浅棕色。雌雄羽毛相似，雌鸟体型略小于雄鸟。幼鸟具有接近单一灰色的头顶，前额略带绿色，下体呈黄褐色，喉部较淡。","call":"灰脸鹟莺的鸣唱由短暂（约0.8-1.7秒）的哨音组成，通常排列成2-3个音符的短语，每组短语重复2-6次，节奏快速且带颤音，但快速单音颤音较少见。叫声在地理上有所变化，喜马拉雅山脉的鸟叫声更复杂。","habits":"栖息于海拔600至3000米的湿润森林，冬季会下降至山脚地带。偏好森林下层，加入混合鸟群。主要以昆虫为食，但具体的饮食细节研究不足。","identification":"灰脸鹟莺与白眶鹟莺的主要区别在于前者头部灰色更深，暗色侧顶纹不明显，颏及上胸偏白。与白眶鹟莺相比，灰脸鹟莺上背绿色，无白色眉纹，后者具冠羽，无白色眼圈，且两者姿势不同。","protection":"IUCN：LC（无危）","distribution":"分布于东洋界，从印度北部至越南南部，包括喜马拉雅山脉、中国西南部及缅甸。"},{"name":"栗头鹟莺","english_name":"Chestnut-crowned Warbler","scientific_name":"Phylloscopus castaniceps","overview":"栗头鹟莺（英文名：Chestnut-crowned Warbler，学名：Phylloscopus castaniceps），是雀形目柳莺科柳莺属的鸟类。小型橄榄色莺，顶冠呈独特的红褐色，腰和两胁黄色，胸部灰色，腹部呈现黄灰色。广泛分布于远东地区的喜马拉雅山脉，自印度西北部至中国东部，越南和印尼苏门答腊岛。","appearance":"栗头鹟莺体型甚小，约9-10.5厘米长，体重4-6克。具有明显的浅色翼条，顶冠和眉纹为红褐栗色，侧面冠纹由黑变宽向颈背延伸；颈侧常可见断续的白色条纹，颈背、头部侧面、肩和背部为灰色，背部和翅膀呈橄榄黄色，形成两条黄色的翼带。上尾覆羽和臀部鲜明黄色；尾羽为灰褐色，边缘橄榄黄色，最外侧尾羽内缘白色；喉部和胸部至上腹部为灰色，其余下体为柠檬黄色，中心部分白色，下翼覆羽淡黄色；虹膜深棕色，眼圈清晰白色；上喙深棕色，下喙肉黄色；腿为肉黄色，足底近白色。性别相似，幼鸟仅顶冠短暂呈暗灰褐色，其他部位较成鸟暗淡，下体更偏黄色。存在多个亚种，如sinensis亚种的上体更绿，胸腹部黄色更广；laurentei亚种背部绿色，腹部白色；collinsi亚种背部灰色，臀部和下体泛绿色；stresemanni亚种顶冠更红，背部灰色更明显；annamensis亚种顶冠红，背部绿色，臀部黄色减少；youngi亚种臀部灰，下体白色，仅侧部黄色；butleri亚种顶冠暗红，上体更深，臀部黄色略减；muelleri亚种臀部和上尾覆羽黄色类似指名亚种，下体白色，侧部黄色。","call":"栗头鹟莺的歌声具有飘渺的质感，非常纤细且高音，由5-7个向上弯曲的音符组成，例如“see see see-see-see-see-see”。叫声包括反复的低沉“chik”和双重的“chee-cheee”。","habits":"栗头鹟莺栖息于山地森林中，活跃于树冠层，以昆虫为主的微小无脊椎动物为食。它在繁殖季节外与其他物种混群。非迁徙性，但可能随季节作高低海拔的小规模移动。","breeding":"繁殖期从2月至7月，与雨季开始相关联，印度喜马拉雅山区主要在4月至6月。巢由两性共同构建，由绿色苔藓编织成紧实的卵圆形球状，内部衬以密集的苔藓和细丝。巢隐蔽于地面，被悬垂的苔藓和藤蔓遮掩，常位于灌木下或树干底部的凹陷处，或在河岸或陡峭山坡上。每窝产卵3-5枚；两性共同孵化，孵化期未知；关于雏鸟成长期的信息未记录。巢穴可能受到中杜鹃和翠金鹃的寄生。","identification":"栗头鹟莺的独特组合——橙色顶冠、白色喉部、绿色翅膀和黄色腹面，使其在区域内容易与其他莺类区分开来。不同的亚种在颜色深浅和分布上有所区别。","protection":"IUCN：LC（无危）","distribution":"繁殖区域与非繁殖区域分布于喜马拉雅山脉，从印度西北部至中国东部，越南和印尼苏门答腊岛。","other":"虽然过去曾归入\"旧大陆莺\"集合，但分子系统发生学研究发现Phylloscopus和Seicercus均非单系群，随后这两个属合并入Phylloscopus，该属享有优先权。"},{"name":"黄胸鹟莺","english_name":"Yellow-breasted Warbler","scientific_name":"Phylloscopus montis","overview":"黄胸鹟莺（英文名：Yellow-breasted Warbler，学名：Phylloscopus montis），是雀形目柳莺科柳莺属的鸟类。常与混合鸟群一同觅食。繁殖季节在1月至7月间，常见于印尼的苏门答腊和婆罗洲。筑巢于河岸洞穴中，每次产卵2枚。","appearance":"体长9.5-10厘米，体重约5克。具深黄色下体，冠羽、眉纹和耳羽呈栗色，侧面有黑色冠纹延伸至颈背；上体橄榄绿，臀部和尾上覆羽转为黄色；双翼有两道由中翼和大翼覆羽尖端形成的黄色条纹；尾羽暗棕色，边缘橄榄绿；喉咙和下体深黄色，胸部有少许栗色条纹；翼下覆羽黄色；虹膜深棕色，有明显的白色眼环；上喙深棕色，下喙肉黄色；腿肉褐色，足底较浅。雌雄相似，幼鸟整体较暗淡，头上的栗色不延伸至胸部，侧面冠纹定义不清晰，下体颜色较淡。","call":"发出一系列高音、细弱的音符，如同‘zizizizizizi-azuuuu’，音调先上升后渐弱，每分钟重复5-6次，其间穿插尖锐的‘chit chit’声。与栗头鹟莺的歌声有相同的超凡脱俗品质。","habits":"以昆虫和其他小型无脊椎动物为食。在森林边缘的下层或中冠层积极觅食；偶尔会下降到低矮的灌木丛，但通常在中冠层的叶丛中觅食。会悬停取食叶子下的昆虫，也进行快速飞扑捕食。在非繁殖季节，常与游荡的混合物种群相伴。","breeding":"繁殖信息有限。在马来半岛，繁殖期为1月至7月；雄鸟在6月和8月的弗洛勒斯岛上处于繁殖状态。据报道，会在河岸边的洞穴中建造穹顶状巢穴。已知产卵数为2枚，但无更多细节。","identification":"与栗头鹟莺的区别在于整个下体均为黄色，栗色帽覆盖耳羽，羽毛中无灰色，尾巴无白色。不同亚种差异较小，主要体现在头部栗色的范围和强度。","protection":"IUCN：LC（无危）。黄胸鹟莺分布广泛，种群数量稳定。","distribution":"分布于远东地区的马来半岛、大巽他群岛（除爪哇岛）、弗洛勒斯岛、帝汶岛（小巽他群岛中部和东部）和巴拉望岛（菲律宾西南部）。在中国，见于台湾省、东沙群岛、西沙群岛、中沙群岛、南沙群岛。","other":"曾被归入Seicercus属，但分子系统发育研究显示Phylloscopus和Seicercus都不是单系群，因此两属被合并入Phylloscopus，后者在国际动物命名法规下具有优先权。"},{"name":"纹顶鹟莺","english_name":"Sunda Warbler","scientific_name":"Phylloscopus grammiceps","overview":"纹顶鹟莺（英文名：Sunda Warbler，学名：Phylloscopus grammiceps），是雀形目柳莺科柳莺属的鸟类。因分子系统学研究显示Seicercus和Phylloscopus均非单系群，两属被合并至Phylloscopus。该鸟种具有鲜明的橙色头部，白色眼环，绿色翅膀带白色翼斑，灰背。分布于印尼苏门答腊山地、爪哇岛和巴厘岛。","appearance":"体长约10厘米，体重约5克。活泼的小型鹟莺，具橙褐色头冠、眉纹、耳羽和颈侧，黑色侧冠纹延伸至颈背；上体灰色，略带橄榄色，臀部渐变为白色；翅膀橄榄绿，中大翼覆羽尖端形成黄色翼斑；尾羽暗棕色，边缘橄榄绿；喉部及腹部白色，胸侧带有橙色和少许灰色；虹膜深红褐色，眼环明亮白色；喙上黑下橙黄；腿橙色。雄雌相似。幼鸟未详述，但头部颜色较暗，背部混有绿色，翼斑不明显。","call":"鸣唱为一系列高音清脆的‘chee-chee-chechee’声，与栗头鹟莺和黄胸鹟莺的歌曲品质相似。叫声为短促鼻音。","habits":"在森林边缘的下层和低层树冠积极觅食昆虫和其他小型无脊椎动物。非繁殖季节常与混合物种群一同游荡。","breeding":"未知具体繁殖信息。","identification":"与栗头鹟莺和黄胸鹟莺的区别在于其全身下部全白，羽毛无黄色。雄雌外观一致。","protection":"IUCN：LC（无危）。在爪哇和巴厘森林EBA及苏门答腊和马来半岛EBA为限域物种。在爪哇和巴厘岛的山林中局部常见至相当常见，种群稳定，未识别显著威胁。","distribution":"分布于印尼的苏门答腊山脉、爪哇岛和巴厘岛。在繁殖季节，分布于苏门答腊山地、爪哇和巴厘。","other":"之前分类于Seicercus属，后因分子系统学研究归入Phylloscopus。"},{"name":"罗地岛柳莺","english_name":"Rote Leaf Warbler","scientific_name":"Phylloscopus rotiensis","overview":"罗地岛柳莺（英文名：Rote Leaf Warbler，学名：Phylloscopus rotiensis），是雀形目柳莺科柳莺属的鸟类。一种小型柳莺科鸟类，特有于印尼小巽他群岛中的罗地岛。拥有显著的黄色至橙色下喙，独特的冠纹和橄榄色上体，单翼斑，以及黄色腹部。分布于罗地岛的森林和林地，是岛上唯一的常驻柳莺。","appearance":"罗地岛柳莺体型小巧，喙长而尖锐，呈黄橙色。具宽黄色眉纹，暗色冠部中央有一条淡柠檬黄色冠纹，橄榄色上体，单翼斑模糊，下体泛黄。","call":"鸣声为高音的起伏颤音，'chit-swee-swer-swoo'，也发出双音节'tchewit'叫声，与区域内其他柳莺的叫声相似。","habits":"栖息于罗地岛森林各海拔高度的树冠层，偏好干燥的林地和热带干林，以昆虫为食，具有独特的树皮觅食行为。全年留居于罗地岛，通常单独或成对出现。","breeding":"关于繁殖行为的资料尚无记录。","identification":"与其他南亚柳莺通过喙的长度、颜色、冠纹、上体色彩及下体色调加以区分。与帝汶柳莺相比，具有更明显的冠纹，整体色彩较暗淡，下体较浅黄，上体橄榄褐色较淡。","protection":"IUCN：NT（近危）","distribution":"分布局限于印尼的小巽他群岛罗地岛，特别是在东北部的干旱林地和热带干林。","other":"罗地岛柳莺是基于形态学和基因组数据首次描述的鸟类物种之一，可能因罗地岛的干旱环境而演化出了较长的喙。"},{"name":"农福尔柳莺","english_name":"Numfor Leaf Warbler","scientific_name":"Phylloscopus maforensis","overview":"农福尔柳莺（英文名：Numfor Leaf Warbler，学名：Phylloscopus maforensis），是雀形目柳莺科柳莺属的小型鸟类。原被视为海岛柳莺的亚种，近期研究确认其独立物种地位。具有灰绿色上体，淡黄色下体，以及不明显的翼纹，生活在印尼新几内亚西北部的Numfor岛上。","appearance":"农福尔柳莺体型小，约10厘米长，外观较为暗淡。头部呈灰橄榄色，无明显的冠纹，脸侧灰色带微弱的橄榄色调，有模糊的浅色眉纹和深色眼线。背部橄榄灰，大覆羽末端形成隐约的翼纹，飞羽边缘黄绿，尾羽上部深棕色，尾羽下部橄榄黄色。喉咙污白色，胸部灰色，两胁橄榄色，腹部泛淡黄色。虹膜深色，喙角质色，腿色未详述。雌雄同色，幼鸟特征未详。","call":"其鸣唱包含变化多端的高音颤鸣与啾啾声，声音清脆，比近缘种的歌声更慢、更高，且短句之间间隔较大。","habits":"栖息于低地和丘陵地带的原生林和次生林，常见于混合物种群落中。以小型昆虫和其他无脊椎动物为食。","breeding":"关于繁殖行为的信息目前未知。","identification":"与其他小型黄绿色鸟类如花蜜鸟和太阳鸟通过喙型差异易于区分。在有限的分布范围内，是唯一可见的柳莺种类。","protection":"IUCN：NT（近危）。该物种仅分布于Numfor岛，估计成熟个体数量可能不超过10,000只，且由于森林破坏和退化，其全球范围内生境丧失导致种群数量缓慢下降。","distribution":"仅分布于印尼的Numfor岛，位于鸟头湾（Geelvink Bay），新几内亚西北部。","other":"急需对该物种进行调查，以获得更准确的种群规模和趋势数据。建立自然保护区的计划值得支持。"},{"name":"比岛柳莺","english_name":"Biak Leaf Warbler","scientific_name":"Phylloscopus misoriensis","overview":"比岛柳莺（英文名：Biak Leaf Warbler，学名：Phylloscopus misoriensis），是雀形目柳莺科柳莺属的鸟类。一种小型、色彩暗淡的旧世界柳莺，仅分布于印度尼西亚的Biak岛，属于澳新界的特有种。其外部特征明显，上体呈绿色，翼上有本能的条纹，喉部颜色较浅，下体黄色调明显。","appearance":"体长约10厘米，是一种中等体型的橄榄绿柳莺，尾巴显得较短，腿较长。成鸟的冠部和上体为深橄榄绿色，无中央冠纹，有细长的暗色眼纹，双翼有两道由中覆羽和大覆羽尖端形成的不明显翼条；脸颊和喉部为淡黄色，下体主要为橄榄绿色，侧面灰色，从胸中部到肛门处更显黄色。虹膜深棕色；喙上颌深角质色，下颌黄色；腿黄色。雌雄相似，幼鸟特征未详述。","call":"发出独特的鸣唱，由4至5个变音高的哨声组成，穿插以柔和的啾啾声。","habits":"单个、成对或小群体出现在低地和山地森林中，包括次生林，经常加入混合物种群。饮食推测为小型无脊椎动物。","breeding":"关于繁殖行为的信息未知。","identification":"在有限的范围内，与比岛白眼鸟最为相似，但比岛柳莺的下体更为均匀的黄色。通过喙的形状与花蜜鸟和太阳鸟等小型黄绿色鸟类区分开来。","protection":"IUCN：NT（近危）。该物种受威胁，仅限于Biak岛，数量稀少。由于森林砍伐和自给农业的长期威胁，预计种群数量正在缓慢而稳定地下降。","distribution":"分布于Biak岛，位于鸟头湾（Geelvink Bay）的西北新几内亚。","other":"直到最近，还被认为与海岛柳莺和农福尔柳莺同种，但已有的证据显示了它们之间的差异。"},{"name":"隆山柳莺","english_name":"Lompobattang Leaf Warbler","scientific_name":"Phylloscopus sarasinorum","overview":"隆山柳莺（英文名：Lompobattang Leaf Warbler，学名：Phylloscopus sarasinorum），是雀形目柳莺科柳莺属的鸟类。曾与苏拉威西柳莺视为同一物种，现已确认为独立物种。","appearance":"这是一种外观较为暗淡的柳莺，具有浅色的眉纹和中央冠纹，喙大部分呈黑色，腿色较暗，背部橄榄褐色略显陈旧，腹部为淡黄色。雌雄幼鸟的羽毛颜色和成鸟相似，但可能更为暗淡。","call":"其鸣唱为多变的颤音和颤鸣混合，展现出丰富的变化。","habits":"栖息于山地森林及其边缘地带，常见于混杂物种的鸟群中。活动范围涵盖山坡至山顶的林区。","identification":"与北极柳莺、日本柳莺和堪察加柳莺相比，隆山柳莺的色泽更偏深棕，腿色暗淡，腹部呈黄色，且缺乏明显的翼带。","protection":"IUCN：NT（近危）","distribution":"仅分布于印尼苏拉威西岛山区西南部。"},{"name":"佛罗柳莺","english_name":"Flores Leaf Warbler","scientific_name":"Phylloscopus floresianus","overview":"佛罗柳莺（英文名：Flores Leaf Warbler，学名：Phylloscopus floresianus），是雀形目柳莺科柳莺属的鸟类。一种属于旧世界柳莺科（Phylloscopidae）的小型鸣禽，特有于印度尼西亚弗洛勒斯岛的山地森林中。曾一度与帝汶柳莺视为同一物种。","appearance":"具体外观特征资料有限，但作为柳莺科的一员，佛罗柳莺通常具有小巧的身体，尖细的喙，以及活跃的飞行姿态。其羽毛色彩可能呈现橄榄绿色调，腹部偏淡色，两翼和尾部较深。性别间可能存在细微差异。","habits":"佛罗柳莺栖息于弗洛勒斯岛的山地环境，偏好茂密的森林地带。它们可能展现出季节性的迁徙行为，活动范围限于岛屿内部。以昆虫为食，通过在树冠层中跳跃或飞行捕捉猎物。","identification":"与近缘种帝汶柳莺相比，佛罗柳莺在体型、鸣声或羽毛颜色上可能有细微差别，这些特征有助于野外辨识。","distribution":"佛罗柳莺仅分布于印度尼西亚的弗洛勒斯岛山区，位于小巽他群岛中部。","other":"现为帝汶柳莺亚种。"},{"name":"锈脸地莺","english_name":"Cordillera Ground Warbler","scientific_name":"Robsonius rabori","overview":"锈脸地莺（英文名：Cordillera Ground Warbler，学名：Robsonius rabori），是雀形目蝗莺科吕宋鹪鹛属的鸟类。特有于菲律宾吕宋岛西北部的Cordillera山脚地带。其特征为锈色面部与前额，灰下体带有黑色斑纹和白色条纹，以及明显的白色翼斑。鸣声高亢，类似‘tseeee sip tseeee!’。面临栖息地丧失威胁。","appearance":"体型中等，约20-22厘米，具长腿和长喙。上体棕色，头部锈红，胸部灰色并带有三角形灰纹，腹部白色。翅膀胸褐色，边缘暗淡，两排白色翼斑显著。虹膜榛色至棕色，上喙深角棕色，下喙珍珠灰色，腿呈珍珠角棕色。雌雄相似，幼鸟上体暗褐，下体灰褐，喉部灰白，侧翼羽缘长而苍白。","call":"鸣声极为高音，类似昆虫声，‘tseeee sip tseeee！’，持续时间约1.6至2.2秒。具体声音细节与发声行为仍需更多样本研究。","habits":"栖息于低地森林和次生林，海拔高度从海平面至约500米。居民性，缓慢行走于林地地面，偶尔跳跃，常翘尾。通过翻动落叶和木屑寻找食物，主要以昆虫为食。","breeding":"关于繁殖行为的信息有限。已知幼鸟在五月被收集。筑巢习性未知。","identification":"与灰斑地莺和吕宋地莺的区别在于腹下部的灰三角形标记。外形、行为和地理分布帮助辨别种类。","protection":"IUCN：NT（近危）","distribution":"分布于菲律宾吕宋岛北部的Cordillera Central，主要位于西北部。在Ilocos Norte、Apayao、Kalinga和Mountain省份的低地森林中仍有生存。","other":"面临森林破坏威胁，人口数量估计少于10,000只，范围仅约8,500平方公里。"},{"name":"吕宋地莺","english_name":"Sierra Madre Ground Warbler","scientific_name":"Robsonius thompsoni","overview":"吕宋地莺（英文名：Sierra Madre Ground Warbler，学名：Robsonius thompsoni），是雀形目蝗莺科吕宋鹪鹛属的鸟类。中等体型的地栖鸟，主要分布于菲律宾吕宋岛东北部的Sierra Madre山脉低地至山地较低海拔处。具有独特的外观和叫声，是当地特有种。","appearance":"吕宋地莺体长20-22厘米，体重52.5-65克。头部冠羽和颈背呈琥珀色，耳羽同样为琥珀色而眉线白色，喙基部具有一小片灰色裸露皮肤。喉部白色，羽毛尖端黑色，形成一道明显的黑色颊纹。下喉至胸上部的黑色羽尖形成斑点项链，将主要白色的喉部与灰褐色的胸部区分开来。腹部白色，两胁呈暗褐色，带红棕色或栗色调。背部红棕色，羽尖暗褐。臀部长而蓬松的羽毛为暗褐色带栗色，白色羽尖构成隐藏的臀带；尾羽和覆羽暗褐色带栗色调。翅膀红棕色至暗褐色，翼小覆羽和初级飞羽外三枚具白色羽尖。喙上颌深棕色，下颌淡灰色；虹膜深棕色，眼周有薄白环；腿和脚淡棕色。雄雌相似，幼鸟上部暗红棕色，具两排浅色翼斑，下部淡灰红褐色，喉部淡灰棕色，两胁羽毛边缘连续白色。","call":"吕宋地莺的鸣唱为变化多端、极高音的、细弱、滑音、似昆虫的“tsui-ts’siiuu’ee”或“tsui-ts’ssuu’ee”，尾音上升，持续1.6-2.2秒，间隔7-10秒重复（兴奋时间隔更短）。有时以短促的前导音“tit-tuui’ts’ssu’eeet”开始，持续2.2-2.5秒，或“twit-twee’tswit’tsssuuu”。叫声包括类似蟋蟀的高音颤音，可能是在警戒时发出。","habits":"栖息于阔叶低地和低山森林，包括原始森林、次生林、林缘、采伐后的次生植被和喀斯特地貌上的森林，海拔高度从海平面至1300米。已知在Aurora省的Mt Anacuao发现其踪迹。幼鸟曾在草地池塘附近次生林边缘被发现。","breeding":"吕宋地莺的繁殖记录显示，雏鸟出现在2月、3月、4月、7月和8月。6月中旬发现的巢穴中仅有一枚卵，尽管雌鸟被收集，另一枚即将产下的卵还在其输卵管中。巢穴由干枝、树枝和树叶堆积而成，前门直径8厘米，穹顶状结构宽19厘米，靠在距离地面50厘米的岩石和泥土斜坡上支撑。卵为乳白色，带有灰色和浅棕色斑点，尺寸约为28.9毫米×18.5毫米。","identification":"吕宋地莺具有独特的琥珀色头部、黑色颊纹、红棕色翅膀和暗褐色尾羽，与同属其他物种区别明显。幼鸟与米岛旋木雀在当前知识水平下难以区分。","protection":"IUCN：LC（无危）","distribution":"分布于菲律宾吕宋岛东北部的Cagayan、Isabela、Aurora和Nueva Vizcaya省的Sierra Madre山脉。","other":"吕宋地莺因隐蔽的生活习性，其真实数量难以确定，但被认为较为罕见。录音回放显示其实际数量可能比野外观察到的要多。然而，其栖息地内的森林破坏严重，导致种群数量正在下降。目前在Northern Sierra Madre Natural Park内有分布。"},{"name":"灰斑地莺","english_name":"Bicol Ground Warbler","scientific_name":"Robsonius sorsogonensis","appearance":"灰斑地莺体长约20至22厘米，体重约57至65克。头部前额呈灰橄榄色，逐渐变为橄榄色，带有淡暗鳞片状图案。上体橄榄色，背部转为均匀棕色，臀部白色羽毛尖形成半隐蔽条纹，翼羽和尾羽边缘红褐色。喉咙白色，胸前有灰色带纹，腹部白色，侧腹毛发呈淡锈褐色。眼睛褐色，喙黑色偏褐，下颌基部灰色，腿脚浅棕色。雄雌相似，幼鸟喉部和脸颊较淡，亚成体特征不明显。","call":"灰斑地莺的鸣唱声非常尖锐高亢，类似“tit'tsu—tsuuuu-tsiiiiii”的音调，持续1.2至1.9秒，间隔2至7秒重复。叫声尚未详细描述。","habits":"灰斑地莺栖息于低地湿润的热带森林，偏好岩石环境，包括石灰岩出露、竹林和苔藓覆盖的岩石。它们通常在地面活动，以昆虫为主要食物来源。","identification":"与近缘种米岛旋木雀相比，灰斑地莺头部顶部颜色更少锈色，侧面灰白有斑点，胸部白色至腹部渐变为白色，上体鳞片状图案较少。两者可通过上述特征加以区分。","protection":"IUCN：NT（近危）。灰斑地莺面临的主要威胁是栖息地丧失，包括森林砍伐、农业开发和采矿活动。目前在Quezon保护区和Mount Isarog国家公园中有所分布，但保护力度不足。","distribution":"灰斑地莺主要分布于菲律宾吕宋岛南部，包括吕宋岛的中部和南部以及Catanduanes岛。","other":"灰斑地莺是吕宋岛特有的鸟类，由于其隐秘的习性和难以确定的状况，其保护级别曾被列为易危，后下调至近危。"},{"name":"高山短翅蝗莺","english_name":"Russet Bush Warbler","scientific_name":"Locustella mandelli","overview":"高山短翅蝗莺（英文名：Russet Bush Warbler，学名：Locustella mandelli），是雀形目蝗莺科蝗莺属的小型鸟类，以意大利自然学家Louis Mandelli命名。分布广泛，从喜马拉雅山脉东部到中国中部和东南部，包括不丹、印度东北部、老挝、缅甸、泰国、越南、菲律宾以及中国大陆南部和台湾。此鸟善于隐匿，常出现在林缘和开阔山麓的密丛中，最高可达海拔2800米。","appearance":"体长约13-14厘米，体重约10克。外观呈中等大小的栗褐色，颜色强度可变，通常显得非常暗淡，尤其是翅膀和尾部。头顶、耳羽、颈背和上体，包括翅膀和尾巴，呈锈褐色或栗褐色，部分个体具有几乎白色的眉纹，与暗色的面颊形成对比；喉咙白色、灰色或淡黄色，两侧有时带有斑点；胸部、侧腹和尾下覆羽深褐色，有时胸部非常灰暗，尾下覆羽边缘较浅；虹膜棕色；喙黑色，下颚基部有黑色裸皮；腿粉红棕色。雌雄相似，幼鸟可能非常暗褐色，头部几乎纯暗，腹部中央较淡黄褐色，尾巴比成鸟短，尾羽尖锐而非钝圆，下颚基部灰粉色。","call":"发出一系列的鸣叫声，始于嗡嗡的起音，随后是一连串的双音节的‘tick’声。","habits":"栖息于较为开放的灌木边缘环境，偏好密集植被的纠缠和灌丛。可在过度生长的耕地上和田边发现。海拔迁移和居住，冬季下降到较低高度，甚至到达喜马拉雅山脚下的平原；北部的melanorhyncha亚种似乎是长途迁徙者，冬季在香港（中国东南部）相当常见。","identification":"与棕褐短翅蝗莺区别在于喙相对粗壮且全黑，面颊暗色，喉部斑点稀疏，尾下覆羽图案丰富；与斑胸短翅蝗莺和北短翅蝗莺的区别在于整体羽毛颜色更深，尾下覆羽上的斑点不那么明显，尾巴更长，喙更大。","protection":"IUCN：LC（无危）","distribution":"繁殖区域主要在喜马拉雅山脉东部至中国中部和东南部。在中国大陆，分布于南部和台湾。"},{"name":"大叻短翅莺","english_name":"Dalat Bush Warbler","scientific_name":"Locustella idonea","appearance":"大叻短翅蝗莺体长约13至14厘米，体重约10克，呈中等体型的栗棕色。其羽色强度可变，通常显得相当暗淡，尤其是翅膀和尾部。头顶、耳羽、颈背及上体，包括翅膀和尾巴，为锈褐色或栗棕色，有些个体具有几乎白色的眉纹，与深色的面颊形成对比；喉部为灰白色或浅黄色，侧边常有斑点；胸部、胁腹和尾下覆羽为深棕色，有时胸部呈现出灰色调，尾下覆羽边缘颜色较浅；虹膜棕色；喙黑色，下颚基部裸露皮肤黑色；腿为淡粉色。雄雌相似，幼鸟可能非常暗棕，头部几乎纯暗，腹部中央可能呈现较淡的黄褐色，尾巴较成鸟短且尾羽尖端，下颚基部为灰粉色。","call":"其鸣唱为连续的嗡嗡声，重复发出“bizee, bizee, bizee, bizee”的叫声，通常从密集的草丛或灌木丛中发出。","habits":"大叻短翅蝗莺为高海拔迁移和留鸟，冬季会下降到较低海拔，可达喜马拉雅山麓平原以外的地方。极北的melanorhyncha亚种似乎为长距离迁移者，是中国香港地区较为常见的冬候鸟。","identification":"与棕褐短翅蝗莺的区别在于喙更粗壮且全黑，面颊较暗，喉咙斑点稀疏，尾下覆羽图案明显；与斑胸短翅蝗莺和北短翅蝗莺相比，一般羽毛颜色更深，尾下覆羽的斑点标记不那么大胆，尾巴较长，喙较大。","protection":"IUCN状态未知，需查阅最新数据。","distribution":"大叻短翅蝗莺主要分布在越南中南部，特别是在Kon Tum和Dalat高原。"},{"name":"爪哇短翅蝗莺","english_name":"Javan Bush Warbler","scientific_name":"Locustella montis","overview":"爪哇短翅蝗莺（英文名：Javan Bush Warbler，学名：Locustella montis），是雀形目蝗莺科蝗莺属的鸟类。一种隐秘的棕色鸣禽，拥有浅色的腹部和喉部隐约的条纹。其活动范围局限于爪哇中部和东部、巴厘岛、帝汶岛以及阿洛尔岛的山区森林边缘地带，偏好密集的草丛和灌木丛生环境。如同其它蝗莺科成员，更常闻其声而难见其形，其鸣叫声由一系列奇特的嗡鸣音组成。","appearance":"体长约14至15厘米，体重约11至14克。成年鸟的头部、颈背和上体呈暗红棕色，翼和尾深灰色带有赤褐色晕染；下巴和喉咙白色，伴有灰色黑斑点，胸部形成灰黑色条纹项圈；胸腹暗灰色，两胁赤褐，中央腹部白色；尾羽覆面棕色，具白色鳞状斑；虹膜深棕色，喙黑色，腿灰粉红色。雌雄相似，幼鸟下体有明显黄褐色调，喙较淡，腿色更偏粉。帝汶亚种timorensis体型略小，尾羽更细长，整体羽色不如其他亚种鲜艳，上体赤褐色较淡，下体颜色更浅，眉纹较长，眼周无暗色标记。","call":"鸣唱通常自低矮密丛发出，为连续快速重复的嗡鸣音“zeeep”，类似高山短翅蝗莺，但少有双音节，前有短促的双击声“klpklpzeeep”。巴厘岛个体的主歌旋律有明显的降调。阿洛尔岛的timorensis亚种音调显著更高，高于东帝汶的同类，但仍低于高山短翅蝗莺和本格特短翅蝗莺。","habits":"栖息于森林边缘的灌木丛和草地，清山斜坡上散落着Casuarina树和其他灌木覆盖；也在火山口边缘海拔1500米以上的开阔荒废山坡上，高达2100米。在巴厘岛，该物种被发现在森林边缘的蕨类植物和其他茂密植被中，海拔1200米和1500米。在帝汶岛，于1720至2100米的高草地上被记录；在阿洛尔岛，则在树林和森林边缘下方的灌木和草地中，海拔约860至1250米。","identification":"与同属其他物种的区别在于其特有的鸣唱模式、体型大小、羽色以及分布区域。不同亚种间，尤其是timorensis，可通过体型、羽色差异和声音频率加以辨认。","protection":"IUCN：LC（无危）。爪哇和巴厘岛亚种普遍且广泛分布于火山斜坡；其生存环境压力较小，喜好开阔斜坡，这有助于其种群稳定甚至增长。帝汶和阿洛尔岛的timorensis亚种分布地相隔约100公里，栖息地受到不同程度的威胁。","distribution":"繁殖区域主要位于爪哇岛、巴厘岛、帝汶岛及阿洛尔岛的山区。在爪哇和巴厘岛，分布于森林边缘的较高海拔地带；在帝汶岛，于1720至2100米的高草地上；在阿洛尔岛，海拔约860至1250米的灌木和草地中。"},{"name":"台湾短翅蝗莺","english_name":"Taiwan Bush Warbler","scientific_name":"Locustella alishanensis","appearance":"中等体型，约14厘米长，体重约10克。整体呈暗淡的棕褐色，缺乏强烈的红褐色调。头部、耳羽、脸颊区及整个上体，包括翅膀和尾巴，均为均匀的暗淡棕褐色。眉纹狭窄而明显，呈淡黄白色，从眼上方延伸至后方逐渐变淡。喉部白色，带有可变的小棕色斑点，集中于下方中央。胸带灰色，腹部中央白色，与两侧暗褐色形成对比。虹膜中等棕色，喙黑色或暗灰色，脚趾稍大，呈粉灰色。雌雄相似，幼鸟可能非常暗棕，超眉纹不明显。","call":"鸣唱独特，一系列响亮、清晰的单调音符，每个音符以2至3个咔哒声结束，重复率约为每秒2次，类似点击响板的声音。叫声是粗糙、急促的‘ksh ksh ksh’声，有时包含啾啾和笛音。","habits":"栖息于台湾岛海拔1200至3000米的箭竹丛、灌木丛和草丛中。冬季会降至500至1000米的低海拔山区。行为隐蔽，如同老鼠穿梭于灌木丛下，其代表性如电报般的歌声“嘀嗒嗒，嘀嗒嗒嘀”易于察觉。","breeding":"繁殖季节为5月至6月，可能延续至8月。巢建于草丛中，每窝产两枚卵。","identification":"与强脚树莺和黄腹树莺相比，台湾短翅蝗莺体型更大，颜色更暗淡，缺乏鲜明的对比眉纹。","protection":"IUCN：LC（无危）","distribution":"分布于台湾中部和东北部山脉。"},{"name":"四川短翅蝗莺","english_name":"Sichuan Bush Warbler","scientific_name":"Locustella chengi","overview":"四川短翅蝗莺（英文名：Sichuan Bush Warbler，学名：Locustella chengi），是雀形目蝗莺科蝗莺属的鸟类。又译: 四川灌木莺，体型较小的雀形目鸟类，平均长度约13厘米，体重约为10克。主要栖息于中国中部山地的茂密植被和茶种植园中，海拔介于1000至2275米之间。与近亲高山短翅蝗莺相比，偏好较低的海拔环境。本物种的拉丁学名‘chengi’是为了纪念中国鸟类地理学先驱郑作新。","appearance":"四川短翅蝗莺拥有温暖灰褐色的上体和翅膀，具有一条狭窄的淡灰白色眉纹和眼线，喉咙呈白色，胸部为淡棕灰色，两侧稍深且带棕色，喉咙与胸部交汇处有几乎看不见的暗斑。两翼下方为冷灰棕色，腹部为白色，带有淡淡的黄褐色调，下尾羽覆羽为冷灰棕色，边缘略显灰白。喙为黑色，下颌稍浅，脚趾为淡灰粉色，虹膜为暗灰棕色。性别相似，幼鸟上体极暗，脸部近乎无斑点的深棕色，胸腹中央为黄绿色，侧腹和下尾羽覆羽为暗橄榄棕色，末端有微弱的淡色。与高山短翅蝗莺相比，其上体和胸部侧面及侧腹更为灰暗，虽然差异并非绝对，但上体颜色明显不同。","call":"其鸣唱为一系列持续重复的、较为粗糙、类似蛙鸣的声音，音调变化少，结构简单，比的鸣声低沉，两者通过听觉容易区分。","habits":"夏季栖息于开阔地带的密集低矮植被中，如草本植物和蕨类，常与树木相伴，包括森林空地、稀疏的次生林和茶种植园，既可见于斜坡也可见于平地。极为隐秘，通常在密集覆盖下匍匐移动，能迅速奔跑过地面。","breeding":"繁殖季节大致在5月前后，具体繁殖行为未知。","identification":"与高山短翅蝗莺相比，四川短翅蝗莺的上体颜色更偏向灰色，胸部侧面和侧腹也更为灰暗，虽然差异不是绝对的，但上体颜色明显不同。此外，其鸣声更低沉，结构简单。","protection":"IUCN：LC（无危）","distribution":"分布于中国中部的陕西、四川、贵州、湖北及湖南地区的山地，非繁殖期分布未知。","other":"与高山短翅蝗莺生活在同一区域，但叫声更尖锐。"},{"name":"喜山短翅蝗莺","english_name":"West Himalayan Bush Warbler","scientific_name":"Locustella kashmirensis","overview":"喜山短翅蝗莺（英文名：West Himalayan Bush Warbler，学名：Locustella kashmirensis），是雀形目蝗莺科蝗莺属的鸟类。显著特征包括棕色的外观、厚实的圆尾、黑色喙、灰色腹部以及灰暗的胸部两侧。主要分布于喜马拉雅山脉西部，包括印度西北部的喜马偕尔邦、北阿坎德邦以及尼泊尔西部。","appearance":"喜山短翅蝗莺体长约12至14厘米，拥有棕色体羽和较短的圆尾。其上体颜色略淡，耳覆羽和颈侧带浅灰色，超眉纹灰白至近白色。喉部斑点变化大，胸部偏灰，两胁和下尾覆羽呈淡锈褐色，端部显著白色。成鸟有两种形态：正常形态和较为罕见的暖黄色胸部形态。后者超眉纹和胸部为暖黄色，缺乏明显的灰色调，喉部通常无斑点，有时可见项链状条纹。翼型与斑胸短翅蝗莺相似，雌雄同形，幼鸟特征未详述。","call":"其歌声独特，开始于一两个快速的中音音乐般的咔哒声，随后是2至3个极高的咔哒声，紧接着是突然的嗡嗡声，之后是更多的咔哒声和嗡嗡声，整个序列持续时间不到1秒，之后几乎无间断地重复。叫声包括短暂、粗糙、强调的“shtak”，频率为每秒1至4个音符。","habits":"繁殖季节生活在湿润的高山植被中，海拔高度在3200至4000米之间，以苔草为主。迁徙习性不明，推测冬季可能在北阿坎德邦平原过冬。食物主要是昆虫，觅食行为与斑胸短翅蝗莺相似。","breeding":"关于繁殖的信息非常有限，但在尼泊尔有记录到雏鸟和巢穴，推测繁殖期可能在夏季。","identification":"与斑胸短翅蝗莺极为相似，主要通过分布区域和歌声进行区分。喜山短翅蝗莺的歌声包含两次嗡嗡声，而后者仅含一次低音嗡嗡声。","protection":"IUCN：LC（无危）。在尼泊尔西部的安纳普尔那保护区可能局部常见，但在克什米尔的状态不确定，自旧标本记录以来无确认记录。","distribution":"主要分布在喜马拉雅山脉西部，包括印度的喜马偕尔邦和北阿坎德邦，以及尼泊尔西部。繁殖地在高山地区，非繁殖地可能位于北阿坎德邦的平原。","other":"由于其隐秘的生活习性、类似昆虫的歌声、暗淡的色彩和小巧的体型，这种不起眼的鸟被记录得较少。"},{"name":"斑胸短翅蝗莺","english_name":"Spotted Bush Warbler","scientific_name":"Locustella thoracica","overview":"斑胸短翅蝗莺（英文名：Spotted Bush Warbler，学名：Locustella thoracica），是雀形目蝗莺科蝗莺属的鸟类。下体偏淡，腹部有条纹，胸部斑点变异大，从暗色斑点到轻柔的斑点不等。繁殖于喜马拉雅山脉至中国中部的高海拔地区，冬季迁徙至较低海拔和平原地带。","appearance":"体长约12至14厘米，体重约9至13.4克。具有短而圆尾，长而棕色的下尾覆羽，白色羽尖，细长而尖的短喙。繁殖期的指名亚种头部常带赤褐色，眼眉白色，侧头灰，喉部白色，胸部有灰色底色及深色斑点，下体有明显的白色横纹。非繁殖期斑点不明显，下体可能显黄色调，下颌基部淡色。幼鸟下体模糊斑点，更黄，眼眉淡黄。亚种prevalskii颜色较浅，更赤褐色，翼尖更尖，但差异不一致。","call":"鸣唱独特且传播远，由一系列机械点击声和嗡嗡声组成，开始于中音点击，随后是五次极高音点击和一次嗡嗡声，形成两组相同0.5秒的短语，之后短暂停顿，再重复两组，频率在4至7千赫兹之间。叫声包括尖锐的'shtak'和较轻的'chut'。","habits":"繁殖于林线以上的桧树及杜鹃灌丛，高度可达海拔4300米，冬季迁徙至山麓地带和平原。行为隐秘，偏好密集的灌木和矮树丛，冬季栖息于芦苇床、湿地草地边缘。","breeding":"到达繁殖地的时间较晚，通常在5月中旬至6月初。关于非繁殖期的行为知之甚少。","identification":"与北短翅蝗莺难以区分，但斑胸短翅蝗莺颈部和胸部灰色调更强，上体色调温暖。与四川短翅蝗莺和中华短翅蝗莺相比，平均色彩更暖，下体更平滑。亚种间辨识基于颜色深浅和翼尖形状。","protection":"IUCN：LC（无危）。在某些地区，由于放牧和植被燃料的开采，繁殖栖息地可能受到威胁。","distribution":"繁殖于喜马拉雅山脉中部至中国中部，越冬至东南亚，包括印度北部、缅甸和泰国。在中国大陆，夏季在东喜马拉雅至中部山区繁殖。","other":"因隐蔽的生活习性和类似昆虫的鸣声，记录较少。"},{"name":"北短翅蝗莺","english_name":"Baikal Bush Warbler","scientific_name":"Locustella davidi","overview":"北短翅蝗莺（英文名：Baikal Bush Warbler，学名：Locustella davidi），是雀形目蝗莺科蝗莺属的旧大陆候鸟。繁殖于俄罗斯远东地区南部至中国东北（黑龙江南部至河北南部）及朝鲜北部的泰加森林，尤其偏好林间空地或溪流旁的环境；越冬区则自中国南部延伸至泰国北部。","appearance":"体长约12厘米，体重平均9.7克，是一种体型较小、棕褐色的灌丛莺。尾部较短且圆钝，下覆羽长而棕色，尖端带有白色。喙细长呈尖刺状，相对短小。繁殖季节的指名亚种背部暗橄榄棕色，具短白眉纹；腹部白色，喉部及上胸有灰褐色斑点组成的颈环，胸部下方及胁部有棕色浸染，下覆羽深棕色并有明显的白色鳞片状斑点。非繁殖季时，斑点变得模糊，羽色泛黄，下颚通常全白。雌雄相似，幼鸟与非繁殖季成鸟相似，但黄色调更明显。","call":"发出令人混淆的昆虫似的鸣唱，为一系列单调的短促嗡嗡声，类似于蟋蟀或蝗虫的叫声。","habits":"栖息于海拔1200米左右的泰加林，偏好靠近溪流的灌丛生境。性情隐匿，以昆虫为食，叫声略带鼻音的连续‘dzeep’声。冬季迁徙至山脚或平原的灌丛环境，有时也可见于芦苇丛中。","breeding":"繁殖于欧亚大陆中南部的泰加林，偏好林间空地或溪流边的环境。","identification":"与斑胸短翅蝗莺相比，体型略小，背部颜色更偏向橄榄棕色，头部侧面无灰色调，胸部浸染棕色而非灰色，在非繁殖季时下颚全白而非仅基部。手握时，翼尖更为尖锐。","protection":"IUCN状态未提供。","distribution":"繁殖于西伯利亚中南部至中国中部，越冬区从中国南部延伸至泰国北部。"},{"name":"栗背短翅蝗莺","english_name":"Sulawesi Bush Warbler","scientific_name":"Locustella castanea","overview":"栗背短翅蝗莺（英文名：Sulawesi Bush Warbler，学名：Locustella castanea），是雀形目蝗莺科蝗莺属的鸟类。仅见于印度尼西亚苏拉威西岛。栖息于海拔950米以上的湿润山地森林底层。","appearance":"这种体型似麻雀的暗色蝗莺，上体呈深栗褐色，眉纹淡白，喉部显白，下体灰淡。雌雄羽毛相似，尾羽略显凌乱，尖端渐变。冠羽从额至颈为丰富的棕色，翼和尾羽为深灰色，边缘有明亮的栗褐色，形成闭合翅膀上的亮铜色斑块。","call":"叫声包括尖锐的金属音\"chit\"和拖长的波动嗡嗡声\"tzeeoooreee\"。鸣唱通常由三个高音的嗡嗡音组成，最后音调较高。","habits":"栗背短翅蝗莺偏好阴湿的山地森林环境，常在落叶层和潮湿苔藓覆盖的岩石附近活动，以昆虫为食。它非常隐蔽，活动时类似鼠类，但在低枝上也会发出鸣叫。","breeding":"繁殖习性尚不清楚，但已观察到八月时有完全长成的幼鸟。","identification":"与苍眉蝗莺和北蝗莺相比，栗背短翅蝗莺上体更暗，下体更灰暗，且喉部清晰白色。与布鲁短翅蝗莺和塞兰短翅蝗莺相似，但分布区不重叠。","protection":"IUCN：LC（无危）","distribution":"繁殖区域：仅限于印度尼西亚苏拉威西岛的山区。","other":"该物种曾与布鲁短翅蝗莺和塞兰短翅蝗莺共同归于\"Chestnut-backed Bush Warbler\"复合种群，现已分拆独立。"},{"name":"长尾短翅蝗莺","english_name":"Long-tailed Bush Warbler","scientific_name":"Locustella caudata","overview":"长尾短翅蝗莺（英文名：Long-tailed Bush Warbler，学名：Locustella caudata），是雀形目蝗莺科蝗莺属的鸟类。小型的、尾羽较长的森林鸟类，仅分布于菲律宾的吕宋岛山区和棉兰老岛（菲律宾北部和南部），在山地森林的灌木丛中栖息。","appearance":"长尾短翅蝗莺上体呈深棕色，腹部橙棕色，胸部灰色，喉部和眼前方有一明显的白色斑纹，最显著的特点是其长而逐渐变细的尾巴，常常翘起。体型较小，与Benguet和Philippine Bush-Warblers相似，但尾更长，腹色更深。","call":"鸣唱由尖锐的‘tik！’声开始，随后是一连串高音的嗡鸣。","habits":"长尾短翅蝗莺生活于山地森林的低矮植被中，习性隐秘，不易察觉。它们在地面或低枝上觅食，主要以昆虫为食。","breeding":"关于长尾短翅蝗莺的繁殖信息有限，一般在山地森林中筑巢繁殖。","identification":"与Benguet和Philippine Bush-Warblers相比，长尾短翅蝗莺具有更长的尾巴和更深的腹部颜色，通过这些特征可以将其区分开来。","protection":"IUCN：LC（无危）","distribution":"长尾短翅蝗莺的分布局限于菲律宾的吕宋岛和棉兰老岛的山地森林。","other":"历史上，长尾短翅蝗莺曾被归入旧世界莺类的分类中，后来独立为蝗莺科的一员。"},{"name":"黑斑蝗莺","english_name":"Common Grasshopper Warbler","scientific_name":"Locustella naevia","overview":"黑斑蝗莺（英文名：Common Grasshopper Warbler，学名：Locustella naevia），是雀形目蝗莺科蝗莺属的鸟类。隐秘生活的旧世界莺类，体型中等，约13厘米长，背部斑驳呈橄榄棕色，腹部白灰色，仅在尾下覆羽处可见斑纹。广泛分布于欧洲温带地区及西部古北界，为迁徙性鸟类，冬季移至北非和西非。","appearance":"黑斑蝗莺身长12.5厘米左右，重12-18克。外观为小型、尖细的橄榄棕色或灰褐色莺类，背部有斑点或条纹，尾巴较长且渐变。头部顶部和上部橄榄棕色或暖棕色，具深棕色斑点/斑驳，背部有窄的深色条纹；侧面头部较素，眼眉线淡棕色或白色，眼圈浅而狭窄，有暗色的眼角斑（无明显眼纹），耳羽盖上有微弱的深色条纹；尾巴上部深棕色，下部灰色无斑纹；上翼覆羽和三级飞羽深棕色，边缘宽广的橄榄棕色或暖棕色；下部，胸和上侧腹轻橄榄棕色，与白色喉部和腹部形成对比；喉侧有斑点，下喉和上胸（有时侧腹）有深棕色条纹；尾下覆羽土黄色，有长而窄的深棕色条纹；虹膜深橄榄棕色；喙上部深棕色，下部黄肉色到黄灰色；腿粉色肉色到灰粉色。黄色型常见，具有强烈的黄色色调在眼眉线、脸颊区域和下部；灰褐色型偶尔出现，羽毛更偏灰棕色。雌雄相似。幼鸟与换羽成鸟相似，羽毛变化范围相近。obscurior亚种比指名亚种更偏橄榄色；straminea亚种比指名亚种小，上部更苍白和灰，有更重的斑驳，下部更苍白，胸部更灰，通常条纹不那么显眼，尾下覆羽灰或土白色；mongolica亚种类似straminea，但上部更灰，下部更苍白。","call":"其叫声独特，为连续的、高音调的、似昆虫般的颤音，音量似乎随鸟头转向而变化；经常连续，但有时被短暂的停顿打断。叫声包括一个高音的“pik”。","habits":"栖息于开阔林地边缘、湿润牧场、高草丛、荨麻(Urtica)和荆棘(Rubus fruticosus)丛、芦苇或香蒲沼泽、田间边缘、高地泥炭地带有柳树(Salix)和桦树(Betula)灌木丛。海拔高度从海平面到500米，在高加索地区海拔600-1500米，偶尔在阿尔卑斯山草原高达1800米。在非洲非繁殖季节，出现在灌木草本覆盖或高草丛中，包括开放林地下的灌木层、泛滥地边缘、高草空地；主要在低地，但在埃塞俄比亚和肯尼亚可达2000米。在印度，栖息于湖边和沼泽边缘、厚草和柽柳(Tamarix)灌木丛、稻田、散布着灌木的草地斜坡；低地，至西高止山脉1800米。","breeding":"繁殖期从4月末至7月中旬，在西欧通常双窝育雏。一夫一妻制，独居，领地性。巢为厚实的杯状草巢，由干叶基部的草茎和叶片构成，内衬细腻材料，有时加入羽毛或毛发，置于地面或接近地面的茂密植被中，通常位于草丛、荆棘或香蒲中。每窝产卵3-7枚，通常5-6枚；孵化期12-15天；幼鸟离巢期10-12天。","identification":"黑斑蝗莺与其他莺类的区别在于其橄榄棕色或灰褐色的上部，带有深色条纹和斑点，以及其独特的虫鸣般叫声。与同属其他物种如、和相比，其叫声和羽毛颜色有细微差异。","protection":"IUCN：LC（无危）","distribution":"繁殖区域遍布欧洲温带和西部古北界，非繁殖季节迁至亚洲南部和非洲北部。具体而言，繁殖于西班牙、法国、中央意大利、罗马尼亚、南斯拉夫、英国、比利时、荷兰、德国、丹麦、瑞典南部、芬兰南部、波罗的海国家、俄罗斯西部等地区。非繁殖季节，迁徙至北非、印度和斯里兰卡等地过冬。","other":"该物种历史上的系统学研究和分类历史复杂，涉及多个亚种的识别和描述。"},{"name":"巨嘴短翅蝗莺","english_name":"Long-billed Bush Warbler","scientific_name":"Locustella major","overview":"巨嘴短翅蝗莺（英文名：Long-billed Bush Warbler，学名：Locustella major），是雀形目蝗莺科蝗莺属的鸟类。分布在中国、印度、巴基斯坦和塔吉克斯坦，以克什米尔为模式产地。此鸟具有显著的长而细的喙，体色呈棕色，常隐匿于草丛与灌木丛中。","appearance":"这是一种体型较大的棕色蝗莺，拥有细长的喙，粉红色的腿，以及相对长的黑色嘴巴。其头部有一条棕色的眉纹，胸部与喉咙呈淡色，整体外观与喜山短翅蝗莺、中华短翅蝗莺、北短翅蝗莺和斑胸短翅蝗莺相似，但分布区域并不重叠。","call":"鸣唱时发出连续的咔嗒声，类似草蜢的声音，但音质较为沉闷。","habits":"栖息于开阔的高山和亚高山地带的杂草坡地与灌木丛中，偏好躲藏，遇威胁时倾向于奔跑而非飞行。对于越冬地的理解尚不充分，但预计为低海拔的类似环境。","breeding":"具体繁殖信息不详，但通常在适宜的栖息地中营巢繁殖。","identification":"与其他几种蝗莺相比，巨嘴短翅蝗莺的喙更长，且栖息地选择有所不同。","protection":"IUCN：NT（近危）；已列入《国家保护的有益的或者有重要经济、科学研究价值的陆生野生动物名录》。","distribution":"分布于喜马拉雅山脉西部与中国西部，具体包括塔吉克斯坦、巴基斯坦、拉达克和克什米尔地区，以及中国新疆昆仑山区。近年来，目击记录极为罕见。","other":"自20世纪中叶以来，目击间隔年份增加，曾经常见的地点现已不见踪影，特别是在克什米尔地区，过度放牧导致理想栖息地几乎消失。"},{"name":"中华短翅蝗莺","english_name":"Chinese Bush Warbler","scientific_name":"Locustella tacsanowskia","overview":"中华短翅蝗莺（英文名：Chinese Bush Warbler，学名：Locustella tacsanowskia），是雀形目蝗莺科蝗莺属的鸟类。地方性常见的鸟类，繁殖于中国东北至广西、云南、四川、青海东部及甘肃西南部，多见于海拔2800~3600米之间。越冬于云南南部，可能亦于西藏东南部。","appearance":"中华短翅蝗莺体长约13厘米，体重介于9.8至12.4克之间。上体呈橄榄褐色，翅膀和尾巴同样色调；耳羽带有细白条纹，下耳羽常有褐色斑点；喉部和腹部中心为白色或微带黄色，胸部和两胁为灰褐色或黄褐色，偶尔可见轻微的褐色斑点；下尾覆羽为褐色，边缘宽大而白，使得在野外观察时显得较为苍白；虹膜深褐色，喙在繁殖季节全黑，非繁殖季上喙黑褐色，下喙粉红色；跗蹠为粉红色。幼鸟羽毛强烈泛硫磺黄色，有暗色胸斑，头部和身体羽毛在十月/十一月大部分被替换，此时外观与成鸟相似，仅翼羽磨损，尚未完全换羽。","call":"鸣声独特且明显，似虫鸣，与北短翅蝗莺相似，但更粗糙，具有砂纸摩擦般的质感。","habits":"中华短翅蝗莺偏好潮湿环境，如落叶松林间隙的稠密灌丛，冬季则栖息于草地和芦苇地。其活动范围广泛，从东帕拉尔地区（东西伯利亚到西藏和华南）到东南亚，冬季迁徙至印度东北部、云南和东南亚。","breeding":"繁殖于东帕拉尔地区，包括东西伯利亚至西藏和华南；越冬于东北印度、云南和东南亚。","identification":"与斑胸短翅蝗莺相比，中华短翅蝗莺体形略显修长，尾巴相对更长，嘴和初级飞羽稍长，羽色更为朴素，尤其是下尾覆羽。雌雄外观相似。","protection":"IUCN：LC（无危）","distribution":"繁殖于欧亚大陆中部至中国东北部，非繁殖期分布于东南亚。"},{"name":"棕褐短翅蝗莺","english_name":"Brown Bush Warbler","scientific_name":"Locustella luteoventris","overview":"棕褐短翅蝗莺（英文名：Brown Bush Warbler，学名：Locustella luteoventris），是雀形目蝗莺科蝗莺属的鸟类。小型隐秘，主要栖息于喜马拉雅山脉东部至越南北部，中国中部和东南部的山区。其分布范围广泛，包括孟加拉国、不丹、中国大陆、印度、缅甸、尼泊尔、泰国和越南。此鸟种在繁殖季节偏好于居住在北方森林，而在冬季则移居至亚热带和热带森林。","appearance":"体长约13至14.5厘米，体重约10克。棕褐色为主调，全身上下无斑点，毛色缺乏红褐色或橄榄绿的色调。头部、耳羽、颈背、胸部及整个上体呈现单一的棕色；深色的眉纹、颊部、胁腹及尾下覆羽为淡黄色；喉部和胸部中央为无斑点的白色，腹部中部相似颜色；在换羽期间，下体颜色可能变得更白。眼睛为深褐色，上喙呈黑褐色，下喙基部肉黄色尖端黑褐色，腿色为肉褐色至肉黄色。与近似种高山短翅蝗莺的区别在于其尾下覆羽为无斑点的黄褐色，喙稍弱且下喙颜色较浅。雌雄外观相似。幼鸟比成鸟上体颜色更深，下体略带黄色，喉部可能有微弱的斑纹。","call":"发出一连串类似机器摩擦的干涩重复音符，形成其特有的响亮叫声。","habits":"偏好生活在海拔1200至3300米的次生灌木丛、草地及蕨类植物丛生的秃山和松树林空地。行踪隐秘，站立时身体姿态较为扁平。","identification":"与高山短翅蝗莺相比，棕褐短翅蝗莺的尾下覆羽无斑点，呈黄褐色，喙部较弱且下喙颜色偏浅，这是识别两者的主要特征。","protection":"IUCN：LC（无危）","distribution":"繁殖区域覆盖东喜马拉雅山脉至北越南，中国中部和东南部。冬季迁徙至亚热带和热带森林。"},{"name":"河蝗莺","english_name":"River Warbler","scientific_name":"Locustella fluviatilis","overview":"河蝗莺（英文名：River Warbler，学名：Locustella fluviatilis），是雀形目蝗莺科蝗莺属的鸟类。在欧亚大陆东部和中部繁殖的鸟类。以河流附近的密集植被为栖息地，冬季则迁徙至非洲南部。这种鸟因接近水边的草丛生境和独特的‘dzi-dzi-dzi’机械般叫声而易于识别。","appearance":"河蝗莺是一种中等体型的鸟类，长约14厘米，体重13-19克，迁徙前可达23克。它的背部呈单一的暗橄榄褐色，上体无条纹，尾羽较长，尾下覆羽宽大，翼尖尖锐。上体颜色为深橄榄棕色，略带绿色调；具不明显的淡色眉纹；飞羽和尾羽深棕色，边缘呈淡橄榄色；下体淡橄榄色，喉部和腹部中央更白，喉咙和上胸有宽大的暗褐色条纹；两胁橄榄棕色，尾下覆羽淡橄榄棕色，有宽大的白色尖端；有些个体下方有黄色调。虹膜棕色，略带栗色；喙上部角质色，下部淡粉色；腿粉棕色至淡粉色。雄雌相似，幼鸟与成鸟相似，但上方可能更锈色，面部和下体更明显黄色。","call":"河蝗莺的叫声为高音、震颤、类似昆虫的‘dzi-dzi-dzi-dzi-dzi-dzi…’连续声；接触报警声为尖锐的‘phit’，常重复发出。","habits":"河蝗莺偏好生活在靠近水源的密集低矮植被中，如沼泽、草地灌木丛、荨麻丛和杂草丛生的草地。在非洲非繁殖季节，它们栖息在茂密的绿色灌木和灌丛、高草和林下植被中。迁徙时利用雨后新长的植被。它们主要出现在低海拔至中等海拔，迁徙期间在肯尼亚最高可达1700米。","breeding":"繁殖期，河蝗莺在靠近水边的密集植被中筑巢，通常在苔藓或地面。一窝产卵5到7枚。河蝗莺是长途迁徙者，从欧洲迁往非洲南部过冬。","identification":"河蝗莺与鸲蝗莺的区别在于其胸部有条纹，上体颜色更偏橄榄色。虽然有些河蝗莺的尾下覆羽的暗色标记减少，使它们看起来更接近鸲蝗莺，但河蝗莺通常仍具有条纹胸部和更多的橄榄色上体。","protection":"IUCN：LC（无危）。在欧洲部分地区常见，尽管分布局部化。1990年代欧洲（不包括俄罗斯）的估计数量约为352,000至448,000对，其中白俄罗斯的数量最多，达到100,000至140,000对。20世纪初在中欧记录了范围逐渐扩大，但在之后有所收缩。自1950年以来，南斯堪的纳维亚半岛、德国和保加利亚的边际种群有所增加，芬兰的种群在1980年代增加了100%。","distribution":"繁殖于欧洲中部和东部，东至西伯利亚西南部和哈萨克斯坦西北部；冬季迁徙至非洲南部和东南部，主要在赞比西河以南至南非普利托里亚附近。在迁徙途中，穿越中东和东北非的狭窄路线到达南非。","other":"河蝗莺偶尔会迷途至西欧，如英国，1995年在大曼彻斯特有一只雄鸟建立了领地，2017年10月在美国阿拉斯加州的甘贝尔有一个罕见的迷鸟记录。"},{"name":"鸲蝗莺","english_name":"Savi's Warbler","scientific_name":"Locustella luscinioides","overview":"鸲蝗莺（英文名：Savi's Warbler，学名：Locustella luscinioides），是雀形目蝗莺科蝗莺属的小型鸟类，以其独特而不连续的金属质感鸣声著称。分布于欧洲和西亚，迁徙至非洲北部和撒哈拉以南地区过冬。其体长约14厘米，上体呈均匀的深红棕色，下体灰白至沙棕色，具有明显的喉部无条纹特征，与河蝗莺形成对比。","appearance":"成年鸲蝗莺体长约13-13.5厘米，体重12-21克。头部顶部和侧面、上体为无条纹的暗暖棕色，上翼覆羽、三级飞羽边缘和飞羽均为暗暖棕色，与上体颜色一致。下体为淡褐色，下巴和喉咙为白色，腹部中心白色，下喉有时带有灰色斑点的围巾，尾下覆羽通常有较浅的灰色尖端。虹膜深橄榄棕色或栗棕色，喙上部暗角质色或黑色，下部淡黄色粉红色，腿为淡棕色或粉棕色。雌雄相似，幼鸟可能更偏赤褐色。三个亚种在颜色上有细微差别。","call":"鸣声为连续的金属质感低音，类似蚱蜢的叫声，但音调更低沉。叫声包括低沉的‘tik tik tik’以及更高的‘tsip’。","habits":"栖息于湿地、沼泽和湖边，偏好有芦苇床覆盖浅水的环境，通常与莎草和灯心草共生，有时伴以散落的灌木。在俄罗斯，也可见于河流沿岸高草和灌木，以及稀疏森林内的芦苇运河。迁徙性长距离迁徙，整个种群冬季移至非洲。主要以昆虫为食，包括石蛾、蜻蜓、小蚱蜢、鳞翅目昆虫、双翅目昆虫、蚂蚁和甲虫等。","breeding":"繁殖季节从5月中旬到7月初，但南部欧洲从4月底开始，在黎凡特地区从4月初开始。通常一夫一妻制，独居，领地性强。巢建于水面或沼泽地50厘米以下的水生植被中，深度杯状，由死水生植物叶和草茎松散搭建，内部铺有细叶和植物纤维。每窝产卵2-6枚，通常4-5枚，孵化期10-12天，偶尔13天；幼鸟离巢期11-15天。波兰的73个巢穴中，44%因捕食而损失，靠近浅水的巢穴损失更频繁。","identification":"与其他蝗莺科鸟类相比，鸲蝗莺的上体颜色更均匀，无条纹，下体颜色更为单一，喉部无条纹。鸣声为连续的机械质感，与河蝗莺和黑斑蝗莺有明显区别。","protection":"IUCN：LC（无危）","distribution":"繁殖区域包括欧亚大陆的中部、西部、西南部以及非洲西北部。非繁殖区域主要集中在非洲，包括阿尔及利亚、摩洛哥、苏丹和埃塞俄比亚等地。","other":"鸲蝗莺在欧洲的数量估计在15万至22万对之间，主要分布在罗马尼亚和匈牙利。过去三十年间，欧洲范围内数量趋势起伏不平，中部和东部欧洲数量似乎有所增加，而在西部和南部边缘地区则有明显下降。"},{"name":"矛斑蝗莺","english_name":"Lanceolated Warbler","scientific_name":"Locustella lanceolata","overview":"矛斑蝗莺（英文名：Lanceolated Warbler，学名：Locustella lanceolata），是雀形目蝗莺科蝗莺属的鸟类。俗名: 黑纹蝗莺、竖纹蚂蚱，小型的旧世界莺科鸟类，分布广泛，从东北欧俄罗斯至日本北部，迁徙至东南亚过冬。以草地上带有浓密的灌木或树木的环境为家，通常靠近湿地或沼泽地带。这种鸟以其独特的‘矛状’胸部条纹命名。","appearance":"矛斑蝗莺体长12.5厘米左右，体重9-13克，是蝗莺属中最小且条纹最密集的种类。头部顶部橄榄褐色，有黑色斑点；侧面较为单一，有狭窄的灰白色眉纹，深色眼后纹不明显；背部橄榄褐色，布满宽大的黑色条纹，延伸至臀部和尾上覆羽；尾巴橄榄褐色，底部更暗淡和灰色；翅膀有狭窄的橄榄褐色边缘；三级飞羽和大覆羽有鲜明的橄榄褐色边缘，与黑色中心形成对比；下体灰黄褐色，喉部和腹部更白，两胁更橄榄褐色或赭色；下喉、胸和两胁通常有锐利的暗灰色条纹；尾下覆羽暖褐色，中央有暗色斑点或条纹；虹膜温暖的深棕色；喙上部深棕色，下部粉红色带暗尖；腿浅粉色或粉棕色。雌雄相似，幼鸟头部可能显得更平淡，下体条纹灰色且更模糊，通常下体有淡黄色调。","call":"矛斑蝗莺的鸣声为连续的细弱颤音，有‘传声筒’效果，因鸟转动头部而产生。叫声为略带爆炸性的‘tzhk-tzhk-tzhk’，常重复，还有‘pit’的叫声。","habits":"栖息于湿润稻田、沼泽灌丛、近水的休耕地及蕨丛。主要以成虫和幼虫的昆虫为食，尤其是甲虫和蚂蚁，也吃蜘蛛和种子。在植物茎上觅食，有时在地上穿梭于根和茎之间。","breeding":"繁殖期在5月中旬至6月中旬，于草丛中筑巢，每窝产五枚卵。迁徙时经过中国东部和东南亚。","identification":"与黑斑蝗莺相比，矛斑蝗莺体型更小，上体和胸部的条纹更粗重，顶冠颜色更深。","protection":"IUCN：LC（无危）","distribution":"繁殖于欧亚大陆北部和东北部，包括俄罗斯北部、日本北部的北海道。越冬于东南亚，包括印度次大陆东北部、缅甸、中南半岛、马来半岛、苏门答腊、菲律宾北部、婆罗洲北部和爪哇西部，以及安达曼群岛和尼科巴群岛。偶尔迷鸟出现在西欧。","other":"在欧洲西部，矛斑蝗莺偶尔会出现迷鸟现象，其中在苏格兰设得兰群岛的费尔岛是观察这一迷鸟的好地方。"},{"name":"本省短翅蝗莺","english_name":"Benguet Bush Warbler","scientific_name":"Locustella seebohmi","appearance":"中等体型，约13.5厘米长，体重约12克。全身呈现暖棕色，上体橄榄褐色带些许棕色，尾部颜色更深，颏与喉部白色并带有黑色纵纹，其余下体白色，颈部侧面灰白，胸部及腹部橄榄棕色。尾下覆羽有近白色的尖端形成鳞状斑纹。虹膜为褐色，上喙黑，下喙粉色，脚也为粉色。雌雄外观相似，幼鸟特征未详述。","call":"鸣声为机械性重复的摩擦音‘zee-ut, zee-ut’，叫声为兴奋的嚓嚓声和爆破音‘rink-tink-tink’。","habits":"栖息于山地草谷，高度在800至1800米之间，偏好干燥环境，无论是否有松树存在。隐匿于林缘及开阔而多灌丛的山麓，最高可达海拔2800米。其活动范围、食物及捕食者信息尚不明确。","breeding":"关于繁殖习性的资料有限，包括繁殖期、求偶、筑巢、交配、产卵、孵化和育雏等信息尚待研究。","identification":"与长尾短翅蝗莺相似，但尾巴较短，下体呈灰色而非深棕色。与菲律宾树莺相比，眉线不那么明显。通过观察尾巴长度、下体颜色和眉线清晰度可进行辨识。","protection":"IUCN：LC（无危）。种群被认为稳定，但需要进一步调查以确定其是否罕见或受到威胁。","distribution":"分布于菲律宾吕宋岛北部山区。","other":"对于其生态习性和对生境退化耐受性的研究仍有待进行。"},{"name":"岩短翅蝗莺","english_name":"Friendly Bush Warbler","scientific_name":"Locustella accentor","overview":"岩短翅蝗莺（英文名：Friendly Bush Warbler，学名：Locustella accentor），是雀形目蝗莺科蝗莺属的鸟类。特有于婆罗洲的山林。这种鸟虽小巧，但在浓密的林下显得相当胆大，尤其以其穿透力强的三声哨音歌曲而易于被发现。","appearance":"体长约15厘米，体重约14克，外观呈暗褐色，喉部斑驳灰白，胸部和腹部带有灰色调，尾羽宽长。上身和侧翼呈均匀的深暖褐色，头部和颈部侧面转为较深的灰色，翅膀和尾巴几乎漆黑，边缘有棕色羽缘。下巴和喉部中心为白色，逐渐融入灰色的胸部和颊区，整个喉部区域布满深色斑点。下体，包括胸部和大腿，为深灰色，散布着细薄的白色羽缘和自下巴至肛门中央的点状图案。虹膜深棕色，喙黑色，腿为深灰褐色。雄鸟和雌鸟相似，幼鸟颜色比成鸟更深，喉部不显白色。","call":"其歌曲通常在密集覆盖下的低处重复发出短暂单调的嗡嗡声，先由结巴的前奏引出，例如“dzhee-dzhee-zeeeeee-ah”或“trrp, trrrp, trzzzzz”，每分钟可能重复多达40次。另一种较弱、音调更低、节奏更慢的版本，由4个短音组成，如“tu di dzu-yu”，每分钟重复约20次，有时也能听到。","habits":"生活在潮湿阴暗的雨林下层，偏好覆盖苔藓的枯树干和倒下的树枝环境，主要活动在海拔2135至2745米之间，但也有报告在高达3660米的地方出现。单独或成对觅食，接近地面，经常翘起尾巴。有独特的跟随人类行走的习惯，跳跃在人的脚边，拍打翅膀和尾巴，从落叶中拾取被人类脚步惊扰的昆虫。","breeding":"关于繁殖的信息尚无具体记录，但观察到在7月和8月间强烈鸣唱。","identification":"与长尾短翅蝗莺相比，体型较小，尾羽为10根而非12根，更为整齐（不散乱和分解），脚部明显较弱。幼鸟比成鸟颜色更均匀且更深，喉部不呈现白色。","protection":"IUCN：LC（无危）；尽管全球范围内并不受威胁，但其种群密度较低，仅在特定海拔范围内较为常见，近年来观鸟者似乎在较高海拔搜寻，而该物种在1000米以下更为集中。","distribution":"远东：婆罗洲东北部山区，主要分布于基纳巴卢山及其相邻的Trus Madi和Tam Boyukan山峰。","other":"饮食方面，以小圆黑甲虫（Coleoptera）、微小的蝇（Diptera）和小型蜘蛛（Araneae）为主。"},{"name":"竹短翅莺","english_name":"Bamboo Warbler","scientific_name":"Locustella alfredi","appearance":"体长约15厘米，是一种暗褐色与灰色相间的战鸟，尾羽短而宽，共十二片，尾下覆羽灰棕色带灰白尖端。头部顶部和侧面暗橄榄褐色，眉纹不明显，上体及翼缘橄榄褐色略带肉桂色调，下体橄榄灰，颏和喉部白色，腹部中央亦然，尾下覆羽灰棕色，尖端灰白。虹膜棕色，喙上黑下蓝灰，腿棕色。雌雄相似，幼鸟下体微黄。亚种kungwensis比指名亚种颜色更深，上体更冷、更暗的橄榄褐色，下体更暗的橄榄灰色。","call":"鸣唱为一系列坚硬的双音节音符，‘tchi-ka, tchi-ka, tchi-ka’，每秒重复2.5至3次，持续5至20秒；叫声为短促的‘whitt’。","habits":"栖息于中海拔的湿润森林和灌木丛，偏好密集的地面覆盖，包括竹林、森林、沼泽和茂盛的草地。迁徙习性不明，但似乎为留鸟。","breeding":"繁殖信息有限，但推测其繁殖期、筑巢和育雏习性与其他蝗莺科成员类似。","identification":"与喀麦隆短翅莺极为相似，主要通过不同的鸣唱声来区分。","protection":"IUCN：LC（无危）","distribution":"分布于非洲中部，具体包括刚果民主共和国、埃塞俄比亚、南苏丹、坦桑尼亚、乌干达和赞比亚。"},{"name":"斯兰短翅莺","english_name":"Seram Bush Warbler","scientific_name":"Locustella musculus","appearance":"体型似麻雀，上体呈深烟灰褐色，头部暗灰，具模糊的灰色眉纹，喉部白色，下体灰暗。翅膀和尾巴颜色与上体一致，胸腹部暗淡，带有少许斑点，下腹部偏棕色。雌雄羽色相似，但幼鸟上体略深，下体棕色，侧腹更暗。","call":"叫声为干涩、刺耳的一系列音符：“tzit-tzit-tzeet”。其鸣唱声异常，类似蛙鸣，发出“creek-grrg-creek”的叫声。","habits":"偏好山地和丘陵森林环境，常在林下层或接近地面处活动，行为隐秘，以鼠类般的方式觅食。在冬季可能迁徙至较低海拔。","breeding":"具体繁殖细节未知，一般于山地森林中营巢。","identification":"与其他蝗莺属物种相比，塞兰短翅蝗莺是最暗的种类之一，上体更暗，下体较暗淡，与栗背短翅蝗莺、布鲁短翅蝗莺和塔里短翅蝗莺的区别在于色彩深浅和斑点差异。","protection":"IUCN：LC（无危）","distribution":"繁殖于印尼斯兰岛的山地森林。在澳大利亚新几内亚界，仅见于斯兰岛的山区。","other":"由于其分布区域狭窄，种群数量及生存状况需持续关注。"},{"name":"塔里短翅莺","english_name":"Taliabu Bush Warbler","scientific_name":"Locustella portenta","appearance":"塔里短翅蝗莺是一种中等体型的蝗莺，上体呈深褐色，头部至颈背为富丽的棕色，羽缘稍暗形成微弱的鳞状外观。眉线狭窄，偏黄白色，从喙基延伸至眼后逐渐变细。面部的颊纹为暗褐色，耳羽呈土褐色，饰有细淡色条纹。背部、肩羽至尾上覆羽的颜色与冠羽一致，但缺乏鳞状斑纹。翅膀大多为冷暗褐色，外缘较暖，与背部颜色相仿。尾羽窄而深褐色。下巴和喉咙为鲜明的白色，与脸部形成强烈对比。胸部灰色，渐变为赭黄色的腹部，下体颜色更深，至尾下覆羽和两胁更加丰富。成年个体的平均体长约为13.9厘米，翼展可达184毫米。","call":"塔里短翅蝗莺的叫声独特，通常由一系列高音调的吱吱声组成，描述为“tit'tzeeeet tit'tzeeeet tit'tzeeeet...”，持续约一秒，每十秒发出五声，连续发出的声音一般不超过30秒。此外，还发出嗡嗡重复的‘chew’tzzt’tzzt’叫声，初始音节下滑，持续约一秒，以及嘶哑的‘where-wheer-wheer-wheer...’。","habits":"塔里短翅蝗莺主要生活在塔利亚布岛上部的山地森林，高度在1,050米以上，偏好未受干扰的森林环境。它们通常是独居或成对出现，大部分时间在地面或接近地面的地方觅食，偶尔在离地不超过2米的高度活动。其饮食以昆虫为主。","breeding":"关于塔里短翅蝗莺的繁殖信息尚不明确，但观察到在不同月份都有鸣唱的个体，这可能意味着它们全年都在维护领地。","identification":"塔里短翅蝗莺与苏拉威西、塞拉姆和布鲁岛的蝗莺属物种在外观上非常相似，但可以通过叫声和遗传特征进行区分。与栗背短翅蝗莺相比，塔里短翅蝗莺的胸部斑点更不明显，冠羽较为均匀，上体颜色更淡，下体颜色更灰。与塞兰短翅蝗莺相比，中央胸部的斑点更不突出，眉线颜色更灰，下体灰色范围更广。与布鲁短翅蝗莺相比，胸部白色更为广泛。","protection":"IUCN：VU（易危）","distribution":"塔里短翅蝗莺仅分布于印尼苏拉群岛的塔利亚布岛，位于苏拉威西岛东部。具体来说，该物种局限于海拔1,050米以上的残存森林，面积不足150平方公里。","other":"塔里短翅蝗莺是在2009年至2013年间一系列调查中发现的，当时共发现了10个新的鸟类物种和亚种，这是过去一个多世纪以来最大的一次新物种发现。"},{"name":"布鲁短翅莺","english_name":"Buru Bush Warbler","scientific_name":"Locustella disturbans","appearance":"这种鸟体型接近麻雀大小，上部呈深栗褐色，具有一条不整齐的渐变尾巴，眉纹白色，喉部洁白，下体灰暗。雌雄同色，成鸟的头部、翅膀和尾巴为棕色，上体边缘可见灰色，形成鳞片状外观。胸前无斑点，腹部偏暖棕色。","call":"鸣声独特，高音嘶哑，包括尖锐金属感的‘chit’声和拉长颤音的‘tzeeoooreee’声。歌曲由三个高音嗡鸣音组成，最后一个音调更高。","habits":"栖息于山地和丘陵森林，偏好地面或近地面活动，主要以昆虫为食。活动范围受限于其特定的生境。","identification":"与苍眉蝗莺和北蝗莺相比，上体更暗，下体更暗淡，喉部清晰洁白；与苏拉威西和塞兰短翅蝗莺极为相似，但分布区不重叠。","protection":"IUCN：LC（无危）","distribution":"分布于印尼的布鲁岛山区。","other":"是四种前‘栗背短翅莺’复合群中的一个物种，与其它三种因生物声学和基因差异而分离。"},{"name":"北蝗莺","english_name":"Middendorff's Grasshopper Warbler","scientific_name":"Helopsaltes ochotensis","overview":"北蝗莺（英文名：Middendorff's Grasshopper Warbler，学名：Helopsaltes ochotensis），是雀形目蝗莺科Helopsaltes的鸟类。以德国-俄国自然学家Alexander Theodor von Middendorff的名字命名，他在西伯利亚广泛旅行。该物种分布于东亚的有限海域，繁殖于俄罗斯远东至日本北部，冬季迁徙至菲律宾、婆罗洲和苏拉威西岛。","appearance":"北蝗莺长约15.5厘米（6.1英寸），头部、颈背、眼纹呈灰褐色，肩部更偏橄榄色。眉线呈淡奶油色，延伸至耳羽。臀部和尾上覆羽带有黄色或红褐色。其尾羽分级，尖端白色，外观似圆。其鸣唱高音、间隔明显，以‘chit, chit’开始，随后是连串的‘trrrrrrrr-schoy-schoy-schoy’叫声，还伴有短促的歌飞表演。","call":"其鸣唱高音、间隔明显，以‘chit, chit’开始，随后是连串的‘trrrrrrrr-schoy-schoy-schoy’叫声，还伴有短促的歌飞表演。","habits":"北蝗莺偏好靠近水源的森林和灌木丛地带。它是长距离迁徙的鸟类，秋季离开繁殖地，春季返回，迁徙路线主要通过日本，直达菲律宾，部分继续前往婆罗洲，偶尔迷鸟出现在苏拉威西和东小巽他群岛。","breeding":"北蝗莺在东部西伯利亚到日本北部、堪察加半岛和库页岛北部繁殖。","identification":"与Pleske's和Gray's Grasshopper-Warblers相似，但北蝗莺的眉毛和腹部对比更为鲜明，体型较后者小。","protection":"IUCN：LC（无危）。在受限的东亚海域范围内常见，局部地区数量丰富。在日本北海道北部和东部常见；在中国沿海为罕见过境鸟。","distribution":"繁殖区位于俄罗斯远东部和日本北部，非繁殖区覆盖菲律宾、婆罗洲和苏拉威西岛，零星分布于中国大陆、台湾岛、韩国、马来西亚和美国。","other":"北蝗莺是长距离迁徙者，其迁徙模式和时间在不同地区有所不同，春季迁徙快速而直接，秋季迁徙则较为缓慢。"},{"name":"东亚蝗莺","english_name":"Styan's Grasshopper Warbler","scientific_name":"Helopsaltes pleskei","overview":"东亚蝗莺（英文名：Styan's Grasshopper Warbler，学名：Helopsaltes pleskei），是雀形目蝗莺科Helopsaltes的鸟类。繁殖于东亚，包括俄罗斯远东地区的群岛、朝鲜半岛及日本南部，冬季则迁移至中国东南沿海及越南北部。该鸟以褐色为主，拥有不明显的眉纹和深色腹部。","appearance":"东亚蝗莺体长16-17厘米，体重16-24克，外观朴实，喙大，尾羽长且呈渐变状。上体呈灰橄榄褐色，背部有淡色斑点，头部颜色更深，两翼和尾羽暗棕色，下体白色，胸部略带灰黄色，侧腹和两肋灰褐。虹膜深棕至橙棕色，喙上部灰暗，下部灰粉或黄粉，脚呈肉粉色。","call":"鸣唱简单，通常只重复单一音符，由清脆的薄荷状音节组成，尾声拉长，节奏缓慢，与L. ochotensis相似但速度更慢，间隔更长。","habits":"栖息于潮湿地带，偏好厚实的草丛和芦苇，伴有灌木和低矮常绿树或矮竹。在繁殖季节，活动于海拔高达350米的火山山坡、废弃田地等地。非繁殖季节则出现在沿海红树林、芦苇丛和邻近灌丛。","breeding":"繁殖期为5月至6月，记录于日本伊豆群岛和俄罗斯东部。筑巢于低矮灌木间，一窝产3-6枚蛋，详细繁殖信息有限。","identification":"与L. ochotensis相比，东亚蝗莺的鸣唱节奏更慢，停顿更长，体型稍大，颜色更深，且更常在开阔地带活动。","protection":"IUCN：VU（易危）。总数量可能在减少，估计不超过数千只，因岛屿火山爆发和栖息地破坏而受到威胁。建议保护日本岛上的Miscanthus condensatus。","distribution":"繁殖于俄罗斯远东群岛、朝鲜半岛南部、日本南部（包括伊豆群岛和九州附近小岛），非繁殖期分布于中国东南沿海和越南北部。","other":"曾在日本伊豆群岛的三宅岛大量存在，但2000年火山爆发后数量锐减。"},{"name":"小蝗莺","english_name":"Pallas's Grasshopper Warbler","scientific_name":"Helopsaltes certhiola","overview":"小蝗莺（英文名：Pallas's Grasshopper Warbler，学名：Helopsaltes certhiola），是雀形目蝗莺科Helopsaltes的鸟类。在东亚繁殖，越冬于南亚至东南亚。此鸟种在西伯利亚首次被描述。其体长介于13-14厘米，体重13-18克，迁徙前可达22克。小蝗莺善于隐藏，多见于高草丛和湿地环境。","appearance":"小蝗莺身长13-14厘米，体重13-18克（迁徙前可达22克）。上体呈暖橄榄褐色，至腰部渐变为肉桂棕色至红褐色，有明显的黑色纵纹从额头延伸至上尾覆羽；头部侧面为温暖的棕色，有深色眼线和显著的淡黄色眉纹；三级飞羽和上翼覆羽为黑褐色，边缘有清晰的淡黄色边，最内侧三级飞羽顶端内缘有白色缺口；中央尾羽为棕褐色，有黑色端部纵纹，其余尾羽为灰褐色，有黑色次端斑点和白色端斑；喉部和下体为灰白色，胸部染有淡黄褐色，两胁呈温暖的橄榄褐色，有时下喉有细小暗斑；尾下覆羽为温暖的黄色，尖端颜色较浅；虹膜为棕色或红棕色；喙上部暗角棕色或黑褐色，下部淡黄色或粉红色，尖端深色；腿为淡粉色或粉棕色。性别相似。幼鸟比成鸟更显赭色，背至尾覆羽为温暖的肉桂棕色，纵纹定义不甚清晰，尾羽尖端偏黄白色，下体淡黄色，两胁和尾下覆羽为肉桂棕色，喉部和上胸部有短黑纹。","call":"小蝗莺的鸣唱从暴露的灌木或植物茎或飞行中发出，包含轻柔、多变的高音颤音，随后是清脆的口哨声'che-che-che-che-che'，整个乐句持续约4秒，每隔几秒重复一次。叫声为轻柔的重复'pwit'；还会发出快速的细薄'tiktiktiktiktik'。","habits":"小蝗莺栖息于河流岸边的高草丛、山谷草地、湿润的泰加林地和灌木草原；在分布区东部，也可见于干燥的灌木斜坡、柳树（Salix）丛和河流与湖泊边缘的芦苇丛中；主要生活在低地，但在极东北部（雅库蒂亚）的高山草甸和山地沼泽可高达1900米。在非繁殖季节，它们频繁出现在沼泽、芦苇地边缘、泛滥的草地和稻田。","breeding":"在西伯利亚，小蝗莺的产卵期为6月底至7月初，在黑龙江谷地则为6月上半月。领域性强；雄鸟有短暂的鸣唱飞行，上升至约10米高度，短暂盘旋后斜向下降。巢为深而结实的杯状，位于潮湿地面的厚草丛中。每窝产4-6枚卵；孵卵由雌鸟负责，持续约12天；关于雏鸟期的持续时间尚无资料。","identification":"小蝗莺与矛斑蝗莺的区别在于：小蝗莺体形较大，头顶和背部具黑色粗纵纹，但较矛斑蝗莺偏棕红色，眉纹白色更为明显，下体白色，两胁橄榄褐色但无纵纹（第一年幼鸟在胸和两胁具黑色纵纹，但不如矛斑蝗莺明显），尾羽具黑色亚端斑和白色端斑。","protection":"IUCN：LC（无危）","distribution":"繁殖区：从阿尔泰山脉、蒙古、外贝加尔地区到中国东北部、朝鲜半岛和鄂霍茨克海岛屿（萨哈林岛和千岛群岛）。非繁殖区：从印度向东至印尼。"},{"name":"斑背大尾莺","english_name":"Marsh Grassbird","scientific_name":"Helopsaltes pryeri","overview":"斑背大尾莺（英文名：Marsh Grassbird，学名：Helopsaltes pryeri），是雀形目蝗莺科Helopsaltes的鸟类。分布于东亚，包括中国、日本、韩国、蒙古国和俄罗斯。这种羞怯隐匿的鸟类，体长约12至14厘米，重11.1至17.2克，主要栖息于湿地芦苇丛中。其特征为暖棕色的羽毛，下体颜色较浅，翅膀、背部和尾部有明显的黑色纵纹。","appearance":"斑背大尾莺是一种中等体型的莺，体长12至14厘米，体重11.1至17.2克，雌雄差异不大。其上体羽毛呈暖棕色，具有鲜明的黑色纵纹，下体颜色较浅，翼尖尖锐，尾羽呈“满”状，尾下覆羽长。雄鸟的眉纹较为明显，眼线淡暗，头部棕色，背部与翅膀的黑色纵纹形成鲜明对比，腹部白色，胸侧及两胁带锈色。","call":"鸣唱特征为低沉重复的‘djuk-djuk-djuk’声，叫声为低音的‘chuk’。","habits":"栖息于湿地芦苇丛，偏好浅水湖泊边的芦苇与香蒲混生地带。繁殖季节外，非常难以发现，常在芦苇或密集草丛低处觅食。食物以小昆虫为主，包括蛾类和蝇类的幼虫，偶尔捕食小甲虫。善于在芦苇间敏捷攀爬。","breeding":"繁殖始于雨季，大约6月20日左右，雏鸟通常在7月中旬至8月中旬离巢。在上海附近4月已有携带巢材的记录。一窝产5至6枚卵，平均孵化期11.3天，雏鸟约在13至14天后离巢。雄鸟可能在某些情况下为多配偶制。","identification":"与类似的Locustella certhiola相比，斑背大尾莺的背部和肩部纵纹更为鲜明。","protection":"IUCN：NT（近危）。在中国，斑背大尾莺被列为国家保护的有益或有重要经济、科研价值的陆生野生动物。","distribution":"分布于欧亚东部，自蒙古东北部至俄罗斯远东南部Primorskiy，中国东北部、东部及日本本州中部。在中国，已知繁殖于黑龙江扎龙自然保护区、辽宁双台河口自然保护区等地。","other":"斑背大尾莺对枯芦苇丛的依赖性高，枯芦苇不仅用于筑巢，也是雄鸟鸣唱和求偶的场所。"},{"name":"苍眉蝗莺","english_name":"Gray's Grasshopper Warbler","scientific_name":"Helopsaltes fasciolatus","overview":"苍眉蝗莺（英文名：Gray's Grasshopper Warbler，学名：Helopsaltes fasciolatus），是雀形目蝗莺科Helopsaltes的鸟类。体型略大。外表奇特似鸫，性情极为羞怯，常匿于茂密的底层植被中。上体橄榄褐色，具明显的白色眉纹和深色眼纹，脸颊灰暗。分布于中国北方、朝鲜半岛、日本北部，冬季迁至印尼群岛和新几内亚西部。在中国大陆，见于内蒙古、黑龙江、辽宁等多地，是国家三有保护鸟类。","appearance":"体长16.5-18厘米，体重24-31克。体型大，喙强健，尾长渐尖，羽端尖锐，体羽无纵纹。成鸟上体橄榄褐色，臀部更为橙黄，头顶略带灰色；头部两侧橄榄褐色，眼周颜色较深，有明显白色眉纹；脸颊斑驳灰黄色；背部、翼覆羽、三级飞羽边缘和飞行羽橄榄褐色，与背部颜色一致；尾羽暗橙褐色；下体白色，胸部、喉部和上胸通常带有暗色斑点；两胁橄榄褐色，尾下覆羽肉桂色；虹膜深棕色或中棕色；喙上颚深棕色或黑色，下颚灰肉色或淡灰棕色，前端较暗；腿肉粉色或肉黄色至淡棕色。幼鸟上体比成鸟更暗，常带锈色，眉纹、脸颊和下体泛橄榄黄色，从下巴到胸部有更明显的深棕色斑点。","call":"鸣唱由丰富、柔和、悦耳的音符组成，声音响亮、爆发力强，类似八哥的“tryt-to tryt-to trytorytoryt”，结尾部分快速，持续约2-3秒，频率在1-5千赫兹之间，间隔约2秒连续重复长达20分钟；接触叫声为颤音“cherr-cherr…”，独特的“tek-tek”，或“terreck-terreck, terreck terreck-terreck...”，以及尖锐的“chuck”。秋季迁徙时很少鸣叫，但春季迁徙的个体非常善鸣。冬季也能听到鸣唱，但在繁殖季节主要在黎明和黄昏时分。","habits":"栖息于河流谷地草甸、针叶林边缘、森林空地和竹丛中，偏好高草丛、草地灌丛、荨麻（Urtica）丛和灌木丛，以及次生植被。主要见于低地和沿海地区。非繁殖期主要栖息于灌木丛、森林边缘和高草丛中，海拔可达1000米（华莱士地区苏拉威西岛）和1800米（新几内亚）。","breeding":"繁殖期为6月中旬至7月初。领域性强。巢为大型深杯状，由枯叶和干草茎构成，内部衬以更细的茎，置于湿润土壤上，覆盖着树叶和树枝，位于荨麻丛中、草丛旁或小灌木下。每窝产卵3-4枚；孵化期约15天；雏鸟期约14天。","identification":"苍眉蝗莺与北蝗莺、小蝗莺的区别在于完全无纵纹；与史氏蝗莺的区别在于白色的喉部和灰白色的眉纹；与库页岛蝗莺的区别在于喉部颜色、眉纹宽度和下体褐色程度。","protection":"IUCN：LC（无危）。在中欧和东欧的广泛范围内常见至相当常见。在西伯利亚局部地区常见，在中国较为少见。朝鲜北部的繁殖报告未经证实，仅记录了五次。在非繁殖区内广泛分布且常见，多个岛屿的记录（如苏卢、布罗、安汶、塞拉姆、奥比、巴坎、哈马黑拉、特尔纳特和莫罗泰）表明种群健康。印度尼西亚和新几内亚的森林砍伐可能改善了该物种在其越冬地的生存条件。","distribution":"繁殖于欧亚：俄罗斯南部和蒙古北部至俄罗斯东南部，中国东北部，朝鲜半岛和日本北部；非繁殖于印尼群岛和新几内亚西部。","other":"曾与库页岛蝗莺视为同一物种。"},{"name":"库页岛蝗莺","english_name":"Sakhalin Grasshopper Warbler","scientific_name":"Helopsaltes amnicola","overview":"库页岛蝗莺（英文名：Sakhalin Grasshopper Warbler，学名：Helopsaltes amnicola），是雀形目蝗莺科Helopsaltes的鸟类。主要分布于库页岛和千岛群岛南部（俄罗斯）以及北海道（日本北部）。具有橄榄褐色的背部，灰色胸部和淡黄色腹部，以及独特的高亢鸣声，比小蝗莺更具韵律感。","appearance":"库页岛蝗莺体型较大，接近大苇莺的尺寸，长度约16.5至18厘米，体重介于23.9至33克。其背部呈温暖的橄榄褐色，胸部均匀灰白，腹部呈现淡黄色。成鸟的上部色调较灰蝗莺更暖和，带有较窄的、不太显眼的眉纹，延伸至耳羽后方。下巴和喉咙颜色为白色或浅黄白色，喉部下方有微弱的条纹，脸颊有条纹，颈部两侧为灰黄色。翼下覆羽呈温暖的橙色，比灰蝗莺更明亮。","call":"其鸣声为短促的响亮短语，开始时有几个断续音符迅速加速至下降的颤音结尾，持续时间约为4秒，比灰蝗莺的节奏明显更慢，声音更柔和。","habits":"库页岛蝗莺栖息于低地和沿海地区，常在森林或灌木丛中筑巢。其活动范围包括库页岛、南千岛群岛和北海道。迁徙路径经由日本西部和中部以及韩国南部，具体越冬地未知，可能在菲律宾和华莱西亚一带。","breeding":"在日本的繁殖季节从6月至8月，产卵期在6月初到7月底之间。巢通常位于树或灌木中，距离地面1.5至4.5米高，由枯叶和干草茎构成，内部铺有细茎。每窝产卵数为1至5枚，孵化期大约15天，雏鸟喂养期约为14天。","identification":"库页岛蝗莺与灰蝗莺相似，但平均色调更暖和，棕色更深，喉咙颜色可能更浅。鸣声也有所不同，库页岛蝗莺的鸣声更为缓慢且富有旋律。","protection":"IUCN：LC（无危）","distribution":"繁殖区位于库页岛和千岛群岛南部（俄罗斯）以及北海道（日本北部）。非繁殖区确切位置未知，但可能在菲律宾和华莱西亚。","other":"库页岛蝗莺的迁徙路线和越冬地尚待更多研究以明确。"},{"name":"蒲草短翅莺","english_name":"Little Rush Warbler","scientific_name":"Bradypterus baboecala","overview":"蒲草短翅莺（英文名：Little Rush Warbler，学名：Bradypterus baboecala），是雀形目蝗莺科短翅莺属的鸟类。遍及非洲多个地区，包括安哥拉、博茨瓦纳、布隆迪、喀麦隆等国。该鸟种以其独特的歌声和适应多种湿地环境的能力而著称。","appearance":"蒲草短翅莺是一种中等体型的莺鸟，拥有短翼、12根圆尾羽构成的渐变尾、细长的喙和深色的喉部条纹。性别间外观相似。幼鸟的上部呈较丰富的棕色，下部略带黄色，胸纹更细窄。亚种间的差异不大。","call":"其鸣唱开始缓慢，随后加速，最后以翅膀快速拍打产生的颤音结束，整个过程如同弹跳球的节奏。这种低沉的歌声至少在北、西和南部的亚种中十分显著。","habits":"主要栖息于永久性沼泽地带，包括芦苇、莎草和高草丛中的湿地环境。在西非和东北至东非，常见于湖泊、水坝和高地沼泽附近的莎草和纸莎草丛中。分布海拔从海平面至2300米，偏好永久水源附近的芦苇和沼泽植被。","breeding":"繁殖季节记录显示，蒲草短翅莺在埃塞俄比亚、刚果民主共和国和东非等地的繁殖期从8月至9月，南非南部为9月至翌年1月，马拉维则为3月至5月。筑巢通常在水边或湿地上，巢由干燥的芦苇和草编织而成，内部铺有细纤维和根须，巢高不超过1.2米。每窝产2至4枚卵，孵化期约12至14天，雏鸟在双亲照料下约12至13天后离巢。","identification":"与其他苇莺和沼泽莺相比，其胸部条纹的变异有助于识别。与高地短翅莺非常相似，但两者分布范围极少重叠，且蒲草短翅莺的歌声音调更低。","protection":"IUCN：LC（无危）","distribution":"分布于非洲大陆的多个国家，包括安哥拉、博茨瓦纳、布隆迪、喀麦隆、乍得、刚果共和国、刚果民主共和国、埃塞俄比亚、肯尼亚、马拉维、莫桑比克、纳米比亚、尼日利亚、卢旺达、南非、斯威士兰、坦桑尼亚、多哥、乌干达、赞比亚和津巴布韦。","other":"在2002年托哥、2005年加纳以及2012年贝宁东南部均有新发现。在乌干达可能被低估，记录较少。"},{"name":"高地短翅莺","english_name":"Highland Rush Warbler","scientific_name":"Bradypterus centralis","appearance":"这是一种外观朴素的长尾长喙战鸟，整体呈锈褐色，胸部有模糊的条纹。两性相似，上部橄榄棕色，腹部白色，侧翼和下尾羽为橄榄棕色，喉咙和胸部有明显的条纹。","call":"其歌声以缓慢、犹豫、金属质感的嗡嗡声开始，随后速度加快，最终以翅膀快速拍打产生的颤音结束。","habits":"栖息于湿地，尤其是芦苇丛生的环境，如湖泊、沼泽边缘的芦苇、莎草和草地。分布范围从西非加纳至东非埃塞俄比亚，南至坦桑尼亚。","breeding":"繁殖季节在不同地区有所差异，如在埃塞俄比亚记录到8月至9月产卵，而在刚果民主共和国和东非则为4月至11月。筑巢于水边或湿地的草丛中，巢为深而紧密的杯状，由干芦苇和草编织而成。每窝产卵2至4枚，孵化期约为12至14天，雏鸟在父母双方照料下约12至13天后离巢。","identification":"与蒲草短翅莺相比，高地短翅莺的歌声频率更高，但在地理分布上两者基本不重叠，有助于区分。","protection":"IUCN：LC（无危）","distribution":"分布于非洲中部高地，具体包括布隆迪、刚果民主共和国、肯尼亚、卢旺达和乌干达。","other":"高地短翅莺在2012年于西非贝宁东南部被发现，可能在乌干达被低估，记录稀少。"},{"name":"白翅短翅莺","english_name":"White-winged Swamp Warbler","scientific_name":"Bradypterus carpalis","overview":"白翅短翅莺（英文名：White-winged Swamp Warbler，学名：Bradypterus carpalis），是雀形目蝗莺科短翅莺属的鸟类。主要分布于非洲中南部的刚果民主共和国东部、乌干达、肯尼亚西部、卢旺达和布隆迪等地。这暗色、长尾、长喙的湿地生鸟，其特征性的白色肩斑和厚重的胸部条纹使其易于识别。","appearance":"白翅短翅莺体型较大，约16.5至17厘米长，体重介于19至26克之间。头部顶部和侧面、背部呈深橄榄褐色，具有明显的淡黄色眼眉。翅膀深棕色，翼折处有白色边缘，尤其是雄鸟个体，使翼弯部分显得主要是白色。尾巴由十根较长、较厚且渐尖的羽毛组成，颜色为深棕色。腹部白色，喉部和胸部有明显的黑色条纹，两侧橄榄褐色，尾下覆羽深灰褐色，带有宽幅白色边缘。虹膜为棕色，喙黑色，下颚基部灰色或黄绿色，跗跖呈粉红棕色或暗粉色。雌雄外观相似，但雌鸟翼折处的白色较少。幼鸟喉部奶油色，条纹不明显，下体微带棕色，翼上覆羽的白色标记减少。","call":"其鸣唱开始时音符缓慢而犹豫，随后加快，最后以翅膀快速拍打产生的颤音结束，这种特殊的声音特征有助于在隐秘环境中定位它。","habits":"栖息于纸莎草沼泽地带，是一种羞怯且难以观察到的鸟类，通常通过其声音被发现。白翅短翅莺的生活习性与湿地环境紧密相关，它们在沼泽中觅食，食物种类多样。","breeding":"有关白翅短翅莺的繁殖信息有限，但已知它们在适宜的栖息地中筑巢繁殖。","identification":"白翅短翅莺与其他沼泽莺类的区别在于其独特的白色肩斑和重条纹的胸部，这帮助它与苇莺和其他沼泽莺类区分开来。","protection":"IUCN：LC（无危）","distribution":"分布于刚果民主共和国东北部和东部、乌干达西南部和东南部、卢旺达北部、中部和东部、布隆迪中部和东部、肯尼亚西南部（维多利亚湖地区，从亚拉沼泽南至基苏木和肯杜湾）以及赞比亚北部（卢阿普拉河区域）。"},{"name":"谷氏短翅莺","english_name":"Grauer's Swamp Warbler","scientific_name":"Bradypterus graueri","overview":"谷氏短翅莺（英文名：Grauer's Swamp Warbler，学名：Bradypterus graueri），是雀形目蝗莺科短翅莺属的湿地鸟类，以德国自然学家鲁道夫·格劳尔命名。这种鸟拥有独特的白眉纹和喉部至胸部的暗斑，主要分布在非洲中部的高海拔沼泽地带，包括刚果民主共和国东部、乌干达南部、卢旺达和布隆迪。","appearance":"谷氏短翅莺长约17厘米，体重15至19克。它是一种体型较大的短翅莺，具有长而逐渐变细的十二根尾羽和明显的喉部条纹。头部顶部和侧面呈深橄榄棕色，有明显的白色眉纹；上体橄榄棕色，臀部和尾上覆羽变为温暖的棕褐色；上翼深棕色，三级飞羽和大覆羽边缘呈棕黄色；尾巴棕黄色；下体白色，胸部带有淡棕黄色，两胁和下尾覆羽暖棕色，下巴到上胸有突出的黑色短条纹；眼睛深色；喙黑色，下颌灰白色；跗跖浅棕色或粉红色。雌雄相似，幼鸟下体带淡黄色，喉部条纹比成年鸟窄。","call":"其鸣唱为从茎顶和细枝发出的短促（约1.5秒）的几声尖锐重复音，随后是干燥的颤音，'tchew-tchew-tchew-tchr-r-r-r-r-r-r-r'，在展示时会连续重复，有时伴有翅膀拍打的短距离飞行；伴侣可能合唱，雌鸟加入兴奋的叽叽喳喳声。","habits":"谷氏短翅莺栖息在1950至2600米的高山沼泽中，既在森林内也分布于森林外。它偏好各种类型的沼泽植被，包括短草、苔藓、矮莎草与芦苇、蕨类、高草和莎草，以及茂密的灌木丛，但避免生长着纸莎草（Cyperus papyrus）的区域。它是一种留鸟，以昆虫（包括小甲虫和毛虫）、蜘蛛和小种子为食，通常在低层近地面觅食，常出现在开阔地带或漂浮植物上。非繁殖季节会形成群体。","breeding":"繁殖期可能在刚果民主共和国的2月至3月。一夫一妻制并具有领地性，关于其繁殖的其他信息尚不清楚。","identification":"与小苇莺非常相似，但谷氏短翅莺具有更显眼的白眉纹、深色胸斑和截然不同的鸣唱。其胸部的条纹与苇莺属（Acrocephalus）的物种不同，后者胸部条纹较不明显。","protection":"IUCN：VU（易危）","distribution":"在非洲中部，分布于刚果民主共和国东部（爱德华湖西部高地、基伍湖西部高地、卡胡齐沼泽）、乌干达西南部（埃楚亚森林保护区、布温迪不可穿越森林）、卢旺达（鲁盖齐沼泽、维龙加火山、尼翁格韦森林）和布隆迪北部。","other":"谷氏短翅莺与沼泽短翅莺、蒲草短翅莺和白翅短翅莺组成了一组栖息于沼泽的物种。"},{"name":"褐短翅莺","english_name":"Brown Emutail","scientific_name":"Bradypterus brunneus","overview":"褐短翅莺（英文名：Brown Emutail，学名：Bradypterus brunneus），是雀形目蝗莺科短翅莺属的鸟类。中等体型的、深褐色的鸟类，以其独特的尖刺状尾巴著称。这种稀有且异常害羞的鸟种仅在马达加斯加东部的中高海拔雨林中发现，为当地特有种。其生境偏好为茂密的矮竹林。","appearance":"体长约15厘米，全身呈淡褐色，翅膀短小，拥有非常长且呈强烈梯级状的六根尾羽，仅剩下深褐色的羽轴。头部顶部和侧面为深淡褐色，具有一条狭窄的浅肉桂棕色眉纹；上体、上翼覆羽和三级飞羽为深锈褐色；下巴和喉咙中央为黄白色，下体为橙褐色；虹膜为深棕色；喙为黑褐色；腿为粉红色。雌雄相似，幼鸟整体为深淡褐色，尾羽完全呈羽轴状。","call":"其歌声通常来自遮蔽处，偶尔从可见的栖木发出，由伴侣二重唱，先是2到3个短促的“whit”或“wee”音符，随后是短暂的呼噜声“querrrrr”。叫声为短促的滚动摩擦声。","habits":"栖息于中至高山的湿润常绿森林中密集的草本植被中，海拔高度为500至2500米。在低矮纠结的植被深处迅速移动，很少飞行，即使飞行也是短距离。以小型昆虫为食。","breeding":"巢建于地面附近密集的植被中，每窝产2枚卵。关于繁殖行为的其他信息尚缺。","identification":"与其他鸟类相比，如常见的马达加斯加刷莺，褐短翅莺更难以见到。可通过其温暖的褐色色调和细长的尾巴来识别。","protection":"IUCN：LC（无危）","distribution":"分布于非洲的马达加斯加山区西北部和东部，具体而言，在东马达加斯加中部的雨林中局部较为常见；在Sakanaka森林和Fierenana森林中数量丰富，同时在Nangarana的部分被开发的森林中也有分布。","other":"虽然目前全球不受威胁，但由于持续的森林破坏，未来可能会导致其数量下降。"},{"name":"灌丛短翅莺","english_name":"Knysna Warbler","scientific_name":"Bradypterus sylvaticus","overview":"灌丛短翅莺（英文名：Knysna Warbler，学名：Bradypterus sylvaticus），是雀形目蝗莺科短翅莺属的鸟类。特有于南非沿海地区。其种群数量较小，可能正因自然与人为因素导致的栖息地破碎化而减少。","appearance":"整体呈橄榄褐色，上体羽色略带橄榄色，翅膀和尾巴亦然。腹部中部白色，下腹橄榄褐。下巴和喉咙橄榄褐色，点缀以白色斑点和细纹。尾部相对短小且末端平齐。眼、喙、腿和脚为棕色，下颌较淡，角质色。","call":"拥有独特且加速的颤音鸣唱，由一系列‘tslip’音符组成，最终以芦苇般的颤音结束。","habits":"栖息于森林边缘的浓密纠结灌木丛，适应了非本土的荆棘丛生地带，偶尔在郊区河岸林地出现。偏好地面活动，难于观察。其叫声和歌曲可用于吸引其现身。","breeding":"繁殖领地通常位于溪流旁的密集植被中，筑巢位置接近地面。可能表现出高度的领域忠诚性，一例中，一只环志的雏鸟一年后占据了其父母的领地。可能存在局部迁移。","identification":"与薮短翅莺相似，但后者尾部长，喉咙有斑点，叫声和歌曲可区分。","protection":"IUCN：VU（易危）","distribution":"分布于南非南部和东部沿海地区，包括西开普省和东开普省，以及夸祖鲁-纳塔尔省的部分地区。在杜班附近因栖息地丧失已灭绝。在桌山、兰格贝格山脉的森林山谷及24个自然保护区中有记录，包括阿多大象国家公园。","other":"种群受到沿海森林破坏、河流沿岸植被清理以及非本土荆棘清除的威胁。"},{"name":"桂红短翅莺","english_name":"Cinnamon Bracken Warbler","scientific_name":"Bradypterus cinnamomeus","overview":"桂红短翅莺（英文名：Cinnamon Bracken Warbler，学名：Bradypterus cinnamomeus），是雀形目蝗莺科短翅莺属的中型鸟类。其显著特征为通体呈赤褐色，拥有白色的喉部和淡色的眼纹。广泛分布于非洲中部、东部及东南部的高海拔地带，如肯尼亚的海拔可达3300米。","appearance":"该鸟体长14至15厘米，体重15至22克，体色丰富，具有长而渐尖的尾羽。头部顶部和侧面为深橄榄棕色，具有一条突出的淡色眉线；背部和翅膀上覆羽为肉桂棕色，臀部和尾巴颜色更偏红棕色；喉部和腹部白色，与肉桂棕色的胸部形成鲜明对比；两胁和下尾覆羽也为肉桂棕色；虹膜为榛子色；喙暗棕色；腿浅棕色。雌雄相似，幼鸟上体颜色更偏棕色，下体泛黄，喉部条纹模糊，胸部带状斑纹不明显。不同亚种间存在细微差异。","call":"鸣唱为一段短暂的乐句（约2至5秒），以数个前导音符开始，随后是一串清脆的颤音，如'chew chee chiriririririri'或'cheew chewichewichewichewi'，间隔短暂时间后重复。另一只鸟常以高音调的音符异步应答。叫声包括低沉的责备声'trrr'和尖锐的'schreep'。","habits":"桂红短翅莺栖息于森林边缘、竹林、山地森林、灌木丛生的路边、高草丛、沼泽边缘、山地灌木和蕨类灌木丛中，主要活动于海拔1800米以上，但在马拉维可低至1300米。该物种为留鸟，主要以小型昆虫为食，如甲虫、蚂蚁和毛虫，通过类似鼠类的动作在地面覆盖物中觅食，通常单独或成对活动。","breeding":"繁殖期在埃塞俄比亚为5月和10月，在苏丹为5月，在肯尼亚和坦桑尼亚北部为8月至2月，在刚果东部为2月至6月，在马拉维为11月至2月；似乎在东非为旱季繁殖者。一夫一妻制；独居，有领地性。巢为深而大的杯状，由干草和叶子构成，外部覆盖植物绒毛和羽毛，内部衬有细草和绒毛，建于近地面的草丛或杂乱植被中。每窝产2至3枚蛋；关于孵卵和育雏期的信息尚缺。","identification":"与喀麦隆短翅莺相似，但在大部分分布区内，可通过更为赤褐色的整体色彩来区分。在阿尔伯丁裂谷附近，与当地赤褐色亚种的喀麦隆短翅莺的区别在于明显的白色喉部。","protection":"IUCN：LC（无危）；在分布范围内大多数高地地区常见，目前没有紧迫威胁，因其并不依赖于原始森林，而是频繁出现于边缘栖息地、次生植被和半开放区域，而非未受干扰的森林。","distribution":"分布于布隆迪、刚果民主共和国、埃塞俄比亚、肯尼亚、马拉维、莫桑比克、卢旺达、南苏丹、坦桑尼亚、乌干达和赞比亚。自然栖息地包括亚热带或热带湿润山地森林和亚热带或热带湿润灌木丛。"},{"name":"喀麦隆短翅莺","english_name":"Evergreen Forest Warbler","scientific_name":"Bradypterus lopezi","overview":"喀麦隆短翅莺（英文名：Evergreen Forest Warbler，学名：Bradypterus lopezi），是雀形目蝗莺科短翅莺属的鸟类。中等体型的草莺，属于蝗莺科。曾被归类于旧大陆莺的集合中。该物种广泛分布于非洲中南部，包括安哥拉、喀麦隆、刚果民主共和国、赤道几内亚、肯尼亚、马拉维、莫桑比克、卢旺达、坦桑尼亚、乌干达和赞比亚。","appearance":"喀麦隆短翅莺体长约13至14.5厘米，体重介于15至21克。其特征为深棕色或肉桂棕色，喙细长，尾部窄而陡峭，由十根通常磨损的羽毛组成。成鸟上身呈温暖的暗棕色，有狭窄的肉桂色眉纹；下身肉桂色，胸、侧腹和下尾覆羽为丰富暖棕色。虹膜棕色，喙黑色，下颚较淡，腿淡粉棕色。雌雄相似，幼鸟喉部和腹部中心带有黄色调。不同亚种颜色各异，如mariae亚种上体和翅膀为暗橄榄棕色，臀部和上尾覆羽带肉桂色或红褐色。","call":"其鸣唱形式在所有亚种中相似，是一系列响亮的单音或双音，音量逐渐增强，持续几秒，如“wee-wee-wee-wee-wee-wee-wéé-wéé”，或“weeya-weeya-weeya-weeya-wééyá-wééyá”。叫声包括响亮的“tchik”、尖锐的“tchew”和有力的“weet-weet”。","habits":"喀麦隆短翅莺栖息于中高海拔的森林中，偏好茂密的灌木丛，行为极为隐秘，难以发现。它们在自然栖息地中寻找食物，主要在亚热带或热带湿润的山地森林和亚热带或热带湿润的灌木丛中活动。","breeding":"关于喀麦隆短翅莺的繁殖信息有限，但可以推测它们在适宜的季节进行繁殖，营巢于地面或低矮植被中。","identification":"与桂红短翅莺相比，喀麦隆短翅莺的超眉纹不那么突出，尾羽更窄。在阿尔伯丁裂谷附近，与桂红短翅莺的区别在于缺乏明显的白色喉部。喀麦隆短翅莺的亚种之间也有颜色上的差异，如mariae亚种上体和翅膀的色调。","protection":"IUCN：LC（无危）","distribution":"喀麦隆短翅莺在非洲中东部有分布，具体包括安哥拉、喀麦隆、刚果民主共和国、赤道几内亚、肯尼亚、马拉维、莫桑比克、卢旺达、坦桑尼亚、乌干达和赞比亚。其亚种 mariae在肯尼亚中部和西部到坦桑尼亚北部可见。","other":"喀麦隆短翅莺的系统学历史涉及其分类的演变，它最初被归类于旧大陆莺的分类群中，后被重新归入蝗莺科。"},{"name":"班戈短翅莺","english_name":"Bangwa Forest Warbler","scientific_name":"Bradypterus bangwaensis","overview":"班戈短翅莺（英文名：Bangwa Forest Warbler，学名：Bradypterus bangwaensis），是雀形目蝗莺科短翅莺属的鸟类。面部略深，喉部和腹部呈淡色。该物种仅限于尼日利亚东南部和喀麦隆西北部的几个高原地带，居住在海拔1600至3000米的山地森林和灌木丛中。","appearance":"成年班戈短翅莺拥有鲜明的锈肉桂色羽毛，其尾巴长而呈阶梯状。面部颜色稍深，喉部和腹部为浅色调。幼鸟比成鸟暗淡，下体带有黄褐色。体长约为13厘米，翼展约20厘米，体重在10到12克之间。","call":"其特有的鸣唱是一种连续的、音量逐渐增大的‘chee-lip’声，每秒重复3到4次，每次持续约10秒，音量逐渐增强。还有一种尖锐的警报叫声‘krrr’。","habits":"班戈短翅莺不迁徙，具有领地性，常在茂密的植被中活动，如同小鼠般穿梭。它们生活在高海拔的山地森林和灌木丛中，主要栖息在1600至3000米的高度。","breeding":"繁殖季节为10月至11月。雄鸟的典型鸣唱由相同的音调开始，音量逐渐增大。雌鸟有时会通过降低音调的鸣唱与雄鸟二重唱，但未观察到雌鸟单独鸣唱。","identification":"与相似的喀麦隆短翅莺相比，班戈短翅莺的下体颜色更暗淡，且鸣唱有所不同。","protection":"IUCN：LC（无危）","distribution":"分布于非洲的尼日利亚东南部（包括Obudu高原、Mambilla高原、Gotel山脉）和喀麦隆西部（如Oku山、Banso山脉、Bamenda高地、Bamboutos高原、Manengouba山、Adamawa高地西部、Poli）。"},{"name":"薮短翅莺","english_name":"Barratt's Warbler","scientific_name":"Bradypterus barratti","overview":"薮短翅莺（英文名：Barratt's Warbler，学名：Bradypterus barratti），是雀形目蝗莺科短翅莺属的鸟类。主要分布在非洲中南部地区的东南部，包括东部南非、莱索托、东部津巴布韦及邻近的莫桑比克西部。其自然栖息地为亚热带或热带湿润山地森林。","appearance":"这种小鸟体型约15厘米，平均体重15克，性别间外观相似。成鸟的下体呈巧克力棕色，头部至尾部、臀部及尾巴均带有赤褐色，具深褐色的眼纹、颊部及耳羽，眉线灰黄色。上翼覆羽赤褐色，上翼边缘黄白色，初级飞羽赤褐色，次级飞羽赤褐色带肉桂色外缘，腋羽和下翼灰褐色。喉咙和下巴黄白色，喉咙有暗褐色纵纹，胸部和腹部中央白色，两侧灰色纵纹。下体橄榄棕色。眼睛榛色至深棕色，喙黑色，腿和脚深棕色。幼鸟特征尚不明，但一般具有较短的尾巴，上体颜色更偏橄榄色，眉线和下体黄色。","call":"其歌声始于高音节的‘tik, tik, tik...’，随后低音节加速至颤音。报警声为轻微的‘chrr-chrr’。","habits":"栖息于沿溪流的密集纠缠灌丛、蕨类植物、荆棘及外来悬钩子属植物，以及林地和种植园边缘的杜鹃花丛。冬季期间，可能会离开繁殖地向较低海拔迁移，最远可达东开普省海岸。","breeding":"一夫一妻制，单独筑巢，领域性。巢由植物残屑、树枝、草和树叶构成，置于地面或低处枝干间。在津巴布韦，产卵期为10月至12月；在夸祖鲁-纳塔尔省，为9月至11月；在东开普省，为11月。每窝产卵2枚，卵形椭圆，粉白底色带棕色和灰色斑点。孵化期未知，雏鸟由双亲共同喂养。已知黄腹金鹃曾寄生其巢。","identification":"与灌丛短翅莺极为相似，但后者尾巴较短，下体条纹较少。叫声也有细微差别，灌丛短翅莺的开头部分更长、更响亮。","protection":"IUCN：LC（无危）。在南非温带地区广泛分布，于适宜栖息地中常见。适应性强，能占据并利用次生植被的小片区域，因此不受森林清除威胁。","distribution":"分布于非洲东南部，具体包括津巴布韦东部高地、莫桑比克、南非、莱索托及东开普省。","other":"历史上与喀麦隆短翅莺视为同种，但因声音和形态差异而现被划分为独立物种。"},{"name":"沼泽短翅莺","english_name":"Dja River Scrub Warbler","scientific_name":"Bradypterus grandis","overview":"沼泽短翅莺（英文名：Dja River Scrub Warbler，学名：Bradypterus grandis），是雀形目蝗莺科短翅莺属的鸟类。体型较大，以灰褐色为主，具长而渐尖的尾巴，喉部白色，上胸有明显的条纹。分布于非洲喀麦隆东南部、中非共和国西南部和加蓬南部的湿地和沼泽地带。","appearance":"体长约18厘米，喙强健，尾羽十枚，较长且略呈尖状。头部顶部及侧面为深橄榄棕色，眉纹狭窄且模糊；背部暖橄榄棕色，翅膀暗棕色边缘呈暖棕色；尾羽为肉桂棕色；腹部白色，胸部带有暖棕色色调，侧胸、两胁和臀下覆羽为肉桂棕色，喉部和上胸有显著的短暗棕色条纹。虹膜棕色，喙黑色，下颚基部灰色，腿灰色。雌雄相似，幼鸟未详细描述。","call":"鸣唱独特，由一系列音符引导至响亮的颤音高潮，类似“twuit-twuit-twuit-tr-r-r-r-r-r-r-r-r-r”的重复，间歇短暂；其形式与谷氏短翅莺类似，但起始音调更高，颤音更响亮。","habits":"栖息于高密的芦苇沼泽（Rhynchospora corymbosa），常位于森林地带内的小型孤立沼泽，海拔400-800米；亦见于高象草（Pennisetum）中。活动范围近地面，以短跳的方式在密集植被中移动。生活方式定居。","breeding":"会在领地上空进行展示飞行，伴有翅膀拍打声。","identification":"与蒲草短翅莺相比，沼泽短翅莺体型更大，鸣唱不同。","protection":"IUCN：NT（近危）。在喀麦隆和加蓬低地EBA内有分布。尽管已知的分布点有限，但可能比之前认为的更为普遍。在加蓬的Lopé国家公园和喀麦隆的Nki及Lobeke保护区受到保护，后者可能升级为国家公园。","distribution":"非洲：喀麦隆东南部，中非共和国西南部和加蓬南部。在喀麦隆的Bitye（位于Dja河）、Nki保护区和Lobeke，中非共和国的Dzanga-Ndoki国家公园，以及加蓬的Mimongo和M’Bigou（位于Chaillu高原）、Lopé国家公园和Langhoue均有记录。","other":"其偏好的栖息地主要是难以接近的，实际分布可能比现有记录更广泛，可能占据加蓬东部、喀麦隆东南部和中非共和国南部许多小的Rhynchospora沼泽。"},{"name":"灰短翅莺","english_name":"Grey Emutail","scientific_name":"Bradypterus seebohmi","overview":"灰短翅莺（英文名：Grey Emutail，学名：Bradypterus seebohmi），是雀形目蝗莺科短翅莺属的鸟类。又被称为马达加斯加草鸟或羽尾莺。马达加斯加特有种，仅在该岛的东部雨林附近的山地沼泽地带可见。其独特的尖刺状尾巴和灰褐色的外观使其易于识别。","appearance":"灰短翅莺是一种中等体型的鸟，全身覆盖着灰褐色的羽毛，背部和腹部有淡色的条纹。最显著的特点是其怪异的尖刺状尾巴，尾巴上的羽毛细长而松散，给人一种毛茸茸的感觉。雌雄鸟在外观上相似，但幼鸟的条纹可能更为明显。","call":"灰短翅莺的鸣唱是一串弹跳式的颤音，通常由一对鸟儿以二重唱的形式发出，歌声在它们隐秘的生活环境中显得格外悦耳。","habits":"这种鸟偏好生活在海拔较高的东部雨林边缘的芦苇沼泽中，它的生活方式极为隐蔽，很少在开阔地带活动。灰短翅莺的食性以昆虫为主，偶尔也会食用小型无脊椎动物。","breeding":"关于灰短翅莺的繁殖习性的具体信息较为有限，但已知它们会在雨季期间筑巢，巢通常建在密集的植被中，以提供良好的隐蔽。","identification":"与马达加斯加常见的刷莺或沼泽莺相比，灰短翅莺体型更小，背部条纹更加明显，尾部呈现独特的尖刺状，这些特征帮助区分于其他种类。","protection":"IUCN：LC（无危）","distribution":"灰短翅莺仅分布在马达加斯加的东北部至中东部山区，特别是在东部雨林附近的沼泽地带。","other":"灰短翅莺的名字Seebohmi是为了纪念Henry Seebohm，他是19世纪的英国鸟类学家。"},{"name":"帕氏短翅莺","english_name":"Sri Lanka Bush Warbler","scientific_name":"Elaphrornis palliseri","overview":"帕氏短翅蝗莺（英文名：Sri Lanka Bush Warbler，学名：Elaphrornis palliseri），是雀形目蝗莺科帕氏短翅莺属的小型、不起眼、土褐色鸟类，拥有渐层式尾巴。其最显著的特征是富丽的淡黄色喉咙，短而模糊的灰色眉纹，以及淡色的眼睛。这种鸟在斯里兰卡的山地和丘陵地区的湿润森林中活动，常单独或成对出现，隐秘地在植被底层或靠近地面的地方栖息。","appearance":"体长15至16厘米，体重9至14克。体型丰满，喙细长，腿长且细。雄鸟上体几乎均匀的橄榄棕色，臀部和上尾覆羽呈红褐色；头部侧面和眉纹呈灰色，耳羽后部颜色渐淡；翅膀和尾巴深棕色，边缘红褐色；喉咙为桃色，胸部橄榄灰，中央腹部橄榄黄；胁部和下尾覆羽橄榄棕色；虹膜红色；上颌黑色，下颌较浅；腿淡棕色或紫棕色，足底粉红色。雌鸟与雄鸟相似，但虹膜为淡黄色或白色。幼鸟色泽更均匀的橄榄棕色，缺乏桃色喉咙，喉咙为暗白色，常带斑点。","call":"短促的歌曲声如同‘chiwee-chiwee-chiwee’，叫声包括短而尖锐的‘wit’和湿漉漉的‘chip’音。","habits":"栖息在湿润地带的草丛凹陷处和边缘，偏好竹子和Strobilanthes混生的环境，高海拔可达1500米以上的湿润山地栎树林，偶尔下降至900米，也会出现在森林边缘的茶园边界。以昆虫为食，尤其是软体幼虫阶段的昆虫，如小蜘蛛、毛虫、小蠕虫，特别喜爱小型绿蟋蟀的幼虫。通常成对出现，有时家族群或单独活动。在低矮的草丛中觅食，不一定会在地面上，轻松跳跃穿过密集植被，同时不断摆动尾巴，从叶子下方捕捉蟋蟀。","breeding":"繁殖季节主要在3月至5月，通常在每年的两个雨季期间，可能是双窝产。巢为深杯状，由苔藓、地衣、根须和枯叶构成，内部铺垫着叶片骨架，有时整个巢由竹叶制成，内衬细草。巢隐藏在距离地面不超过1米的草丛或竹丛中，常常靠近森林小径。每窝产2枚卵；孵化主要由雌鸟承担，非常谨慎（即使受到干扰也不会离开巢附近）。两性共同喂养雏鸟，但关于孵化期和育雏期的信息未知。","identification":"帕氏短翅蝗莺与范围内的其他小型棕色鸟类相比，其均匀的外观、淡黄色的喉咙和不显眼的灰色眉纹是识别的关键。","protection":"IUCN：NT（近危）","distribution":"主要分布在斯里兰卡的湿润地带山丘。具体而言，在斯里兰卡南部的湿润山地，海拔高度从900米到1500米以上。","other":"其最大的威胁是栖息地破坏，这可能严重分割其自然静止的种群，使其难以向新区域扩散。核心种群在霍顿平原国家公园得到保护。"},{"name":"阔尾芦莺","english_name":"Broad-tailed Grassbird","scientific_name":"Schoenicola platyurus","overview":"阔尾芦莺（英文名：Broad-tailed Grassbird，学名：Schoenicola platyurus），是雀形目蝗莺科芦莺属的鸟类。特殊的旧世界莺鸟，仅分布于印度西部高止山脉的湿润高山草甸，罕见的留鸟。其显著特征是拥有宽阔、呈圆形且分级明显的尾巴。雄鸟在繁殖季节会展示独特的空中歌唱行为。","appearance":"阔尾芦莺体长约18厘米，体重约20克。上体呈现红褐色，尾羽长而宽，尾端黑色，每根尾羽尖端有白色。下体白色，胸部和两胁呈温暖的黄褐色，腹部下方有棕色羽毛带有淡色斑点。雄鸟的喙在繁殖季节全黑，雌鸟喙较淡。幼鸟的上体统一红褐色，尾羽较窄，没有白色尖端。","call":"雄鸟的鸣唱类似于云雀，是一种清脆且悦耳的颤音，伴随扇尾和起伏的飞行。叫声包括“pink pink”，类似但比红领雀更响亮。","habits":"阔尾芦莺生活在海拔900至2000米的草甸和蕨类覆盖的山丘顶部。它们通常是孤独的，善于潜行，主要在地面觅食，以小昆虫为主。早晨和黄昏最为活跃，此时它们会在草丛中唱歌和鸣叫。","breeding":"繁殖期在7月至9月，也可能在3月至5月。雄鸟在繁殖季节会进行展示飞行，巢穴由干草构成，入口侧向，隐藏在高草中。每次产卵2至3枚。","identification":"阔尾芦莺与S. brevirostris相似，但体型更大，尾部条纹更明显，上体有模糊的横斑。雌雄外观相似，但雌鸟体型较小，喙色较淡。","protection":"IUCN：NT（近危）","distribution":"阔尾芦莺主要分布在印度西南部的西高止山脉，从马哈拉施特拉邦西部南至喀拉拉邦东部和泰米尔纳德邦西部。","other":"尽管有记录表明阔尾芦莺可能涉及局部运动或迁徙，甚至可能出现在斯里兰卡，但这些报道的可靠性有待证实。"},{"name":"须草莺","english_name":"Bristled Grassbird","scientific_name":"Schoenicola striatus","overview":"须草莺（英文名：Bristled Grassbird，学名：Schoenicola striatus），是雀形目蝗莺科芦莺属的鸟类。体型较大，主要分布于印度次大陆，包括巴基斯坦东北部、孟加拉国、印度东北部和尼泊尔的部分地区。其显著特征为棕色羽衣带深色条纹，尾羽宽大，尾羽尖端白色。栖息于低地高草丛中，偏好河岸平原的湿润草地，偶尔可见于混合草丛和芦苇地带。","appearance":"须草莺是一种大型棕色莺鸟，背部带有明显的条纹，尾羽宽大且渐长，尾羽尖端呈现白色。头部羽毛有深色条纹，尾巴的主轴为暗色，尾羽具有暗色肋骨。喙部强壮，胫部呈棕色，喙黑色，下颚尖端呈蓝灰色。眼上方有一条淡色眉纹，下体颜色较浅且无斑点。雌雄羽毛相似，幼鸟特征不详。","call":"鸣叫声为弹簧般的‘wee-chew, chewa-wee！’，通常从植被顶端或飞行中发出。","habits":"须草莺栖息于低地草丛，尤其是河岸平原上的高草和灌木丛生地带。偏好干燥的湿地边缘，如枣树（Ziziphus jujuba）和柽柳（Tamarix）生长的环境。它们在繁殖季节进行空中展示，飞行路线呈波浪状或圆形，飞行高度约3米，翅膀振动发出响声，持续约60秒，同时反复鸣唱。","breeding":"繁殖季节为5月至9月，但最早可在3月末发现处于繁殖状态的个体，最晚至9月中旬。在孟加拉国曾于4月观察到有雏鸟的巢穴。空中展示飞行中，雄鸟进行波动飞行，同时鸣唱。巢由干草编织成球状，入口靠近顶部，建于地面附近或草丛中。一窝产卵4至5枚；孵化由雌鸟单独承担。","identification":"须草莺比体型较大的沼泽大尾莺更为粗壮，尾巴较短。其独特的叫声和栖息环境有助于与其他莺鸟种类区分开来。","protection":"IUCN：VU（易危）","distribution":"分布于巴基斯坦东北部至孟加拉国，印度东北部（阿萨姆中部），以及印度西部（马哈拉施特拉）。在印度半岛的东部中央邦至奥里萨邦中部，南至安得拉邦北部为非繁殖季节的分布区域。","other":"须草莺在尼泊尔的几个保护区中被发现，包括皇家奇特旺国家公园、皇家苏克利丰塔野生动物保护区，以及罕见的科希塔普野生动物保护区。"},{"name":"扇尾芦莺","english_name":"Fan-tailed Grassbird","scientific_name":"Catriscus brevirostris","overview":"扇尾芦莺（英文名：Fan-tailed Grassbird，学名：Catriscus brevirostris），是雀形目蝗莺科Catriscus的鸟类。非洲的旧世界莺科鸟类，与印度的阔尾芦莺关系密切，有时被视作同一物种，但一项2018年的研究发现两者并不紧密相关。分布于非洲多个国家，包括安哥拉、布隆迪、刚果共和国、刚果民主共和国、斯威士兰等地，栖息于靠近水源的草地，海拔介于350至2150米之间。","appearance":"扇尾芦莺具有独特的外形，头部相对较小，喙短，头顶扁平，后身较大，尾巴宽大且层次分明，上覆羽长至尾部一半。成年鸟上半身呈灰褐色，逐渐变为黄褐色或红褐色，背部颜色较深，近似黑色；尾羽黑色带淡色尖端，中央尾羽有微弱的横纹；腹部白色，侧胸、两胁及腹下部呈黄色，下覆羽黑色带斑点。幼鸟颜色更均匀，下体泛黄，尾巴较长且不那么宽。","call":"其鸣唱为从高大的草丛中发出的微弱但传播远的金属质感的‘sweep’声，重复2至4次，间隔1.6至1.8秒。此外，还有三音节的‘jur-jur-jur’、尖锐的‘prit-rit’、粗糙的‘chick’、快速粗糙的咔哒声和嘶哑的‘tzzzt-tzzt’叫声。","habits":"扇尾芦莺栖息于潮湿的高地草地，靠近溪流、河流或湖泊，尤其偏好高草丛生地带；也见于莎草沼泽和多草灌木的山地斜坡。它们通常独居，除繁殖季节外，行为隐秘。主要以小昆虫为食，如甲虫、蚱蜢和无毛毛虫。早晨最活跃，有时在清晨雾气或细雨中会站立于草尖、栅栏甚至电线上。","breeding":"繁殖期在不同地区有所不同，如塞拉利昂的7月、肯尼亚西部的7月至8月、刚果东部的3月至10月等。繁殖期间，雄鸟会在空中表演独特飞行，尾巴上下摆动，翅膀快速拍打产生呼呼声，随后滑翔降落。巢隐蔽在干草丛深处，离水面或湿地5至30厘米，由粗干草编织而成。每窝产2至3枚卵，间隔24小时产一枚；孵化和育雏时间未知，但双亲共同喂养幼鸟。","identification":"扇尾芦莺的特殊外形使其容易识别，尤其是其扁平的头部、宽大的尾巴和相对较小的喙。与相似的阔尾芦莺相比，体型略小，尾部横纹更淡，上体无模糊的条纹。","protection":"IUCN：LC（无危）；虽然在南非部分地区因商业林木种植、湿地围垦和过度放牧导致栖息地受威胁，数量有所下降，但全球范围内并未构成严重威胁。","distribution":"扇尾芦莺在非洲广泛分布，主要栖息在靠近水源的草地上，海拔高度在350至2150米之间。分布国家包括但不限于安哥拉、布隆迪、刚果共和国、刚果民主共和国、斯威士兰、赤道几内亚、埃塞俄比亚、加蓬、几内亚、肯尼亚、马拉维、莫桑比克、尼日利亚、卢旺达、塞拉利昂、南非、南苏丹、坦桑尼亚、乌干达、赞比亚和津巴布韦。","other":"扇尾芦莺的分布范围虽广，但在一些地区的种群数量因过度放牧和栖息地退化而受到威胁，尤其是在塞拉利昂、几内亚、喀麦隆、加蓬、苏丹和埃塞俄比亚。"}];
